2	{"act": "IT_ACT_2000", "title": "Extent and Application", "doc_id": "ITACT_SEC_1_SUB_2", "topics": ["jurisdiction", "extra_territorial_application"], "entities": [], "keywords": ["extent", "India", "extra-territorial", "offence outside India", "contravention"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": [], "clause_text": "It shall extend to the whole of India and, save as otherwise provided in this Act, it applies also to any offence or contravention thereunder committed outside India by any person.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 1(2) of the Information Technology Act 2000. The Act extends to the whole of India and has extra-territorial application, covering offences or contraventions committed outside India by any person, subject to provisions otherwise specified in the Act.", "section_number": "1", "subsection_number": "2", "validation_status": "validated", "plain_english_summary": "The Act applies to the whole of India and also covers offences or contraventions committed outside India by any person."}	[0.72768563,0.85315716,-3.3869698,-0.063833594,0.913021,0.385452,-0.2535306,0.30832347,0.62954825,-0.6974845,0.06398907,1.1413963,1.1754092,-0.42894506,-0.42833236,-0.7633485,0.29000548,-0.45258653,-0.25191903,0.42247644,0.15857194,0.2027352,-0.32335368,0.089138396,1.1090704,-0.0072008697,1.8687452,-0.062578775,-0.83586353,-1.0201344,0.61629665,-0.7986898,0.3397799,-0.98702496,-0.47882637,-1.0924934,0.45451546,-0.20589603,-1.3591149,-0.04665718,0.39355895,0.17666598,-0.38088918,-0.5623623,0.74132156,-0.20236711,1.0770295,0.31404942,0.5452796,-0.45803714,-0.39017612,-1.1617991,-0.12712006,-0.6968065,0.66895336,0.59541845,-2.0072024,-0.07138885,1.0110569,0.38818547,1.1535634,1.1872634,-0.41987458,1.4784529,0.28039345,-0.36705184,-0.18094312,1.001403,-0.14921069,-0.5507925,1.4773135,-0.110500924,0.68097806,-0.034287862,-0.5766332,-0.8683372,-0.20325364,-0.7100148,-0.15262643,1.332