3	{"act": "IT_ACT_2000", "title": "Exclusion of Specified Documents and Transactions", "doc_id": "ITACT_SEC_1_SUB_4", "topics": ["exemption", "exclusion", "scope"], "entities": ["Central Government"], "keywords": ["First Schedule", "excluded documents", "excluded transactions", "Central Government", "notification", "amendment"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": ["ITACT_FIRST_SCHEDULE"], "clause_text": "Nothing in this Act shall apply to documents or transactions specified in the First Schedule: Provided that the Central Government may, by notification in the Official Gazette, amend the First Schedule by way of addition or deletion of entries thereto.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 1(4) of the Information Technology Act 2000. The Act does not apply to documents or transactions specified in the First Schedule, which includes instruments like negotiable instruments, powers of attorney, trusts, wills, and contracts for immovable property. The Central Government may amend the First Schedule by notification.", "section_number": "1", "subsection_number": "4", "validation_status": "validated", "plain_english_summary": "The Act does not apply to documents or transactions listed in the First Schedule. The Central Government may amend this list by notification."}	[0.15497848,0.25782925,-2.9792204,-0.49313003,0.24217296,0.3898651,-0.1279595,0.49986756,0.7796156,-0.20713566,-0.22357535,0.72259057,0.41130343,-0.3654292,-0.46142188,0.22463658,0.33032125,-0.24818845,-0.5124861,0.8395927,0.9155828,-0.6362282,-1.530269,-0.10452422,0.60795265,-0.047554884,1.0114017,-0.3450597,-0.80732363,-1.2619146,0.34514588,0.3217345,1.0859401,-0.76369387,-0.3790551,-1.4394381,0.8608512,0.12712526,-1.1954412,-0.100931086,0.4591436,-0.07016712,0.034908496,-0.77536964,1.0881717,-0.12859043,1.6094813,0.94657046,0.10640333,0.07991781,1.0323943,-0.56487304,-0.18134682,-0.2828808,0.50097173,1.2670126,-0.810033