4	{"act": "IT_ACT_2000", "title": "Definition - Access", "doc_id": "ITACT_DEF_ACCESS", "topics": ["definition", "cyber_offence"], "entities": [], "keywords": ["access", "computer", "computer system", "computer network", "logical function", "memory function"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": [], "clause_text": "\\"access\\" with its grammatical variations and cognate expressions means gaining entry into, instructing or communicating with the logical, arithmetical, or memory function resources of a computer, computer system or computer network.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 2(1)(a) of the Information Technology Act 2000 defines access as gaining entry into, instructing or communicating with the logical, arithmetical, or memory function resources of a computer, computer system or computer network. This definition is relevant to offences involving unauthorised access to computer systems.", "section_number": "2", "subsection_number": "1(a)", "validation_status": "validated", "plain_english_summary": "Access means gaining entry into, instructing, or communicating with the logical, arithmetic, or memory functions of a computer, computer system, or computer network."}	[0.66722155,1.2323934,-3.0822213,-0.93287575,1.3649992,0.36429223,1.0656431,0.67822206,0.33819702,0.19489467,-0.139141,1.0651895,0.62650156,-0.28039384,0.21776898,-0.075543165,-0.061561935,-0.3170876,-0.47273964,-0.41344965,1.0461109,-0.48593682,-0.8798125,-0.13541692,1.4306469,-0.41038615,0.70788014,-0.70759356,-1.2032306,-0.518095,0.692786,-0.85001016,0.67025423,-0.7729429,-1.1062717,-1.1439595,-0.013180287,0.26965123,-1.1982019,-0.19186465,-0.014949646,0.12786788,-0.42299646,-0.44379085,-0.3937279,0.8685224,0.015836949,0.23514399,0.06386818,-0.7851337,0.61329854,-0.9250494,-0.18796691,0.109120496,1.7420417,0.32498705,-0.3058621,0.3176754,0.47051796,0.35948524,1.9169762,2.1836157,-0.46328104,0.8236347,0.6760449