6	{"act": "IT_ACT_2000", "title": "Definition - Adjudicating Officer", "doc_id": "ITACT_DEF_ADJUDICATING_OFFICER", "topics": ["definition", "adjudication", "governance"], "entities": ["adjudicating officer"], "keywords": ["adjudicating officer", "appointment", "adjudication"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": ["ITACT_SEC_46"], "clause_text": "\\"adjudicating officer\\" means an adjudicating officer appointed under sub-section (1) of section 46.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 2(1)(c) of the Information Technology Act 2000 defines adjudicating officer as a person appointed under section 46(1) to hear and adjudicate contraventions of the Act and award penalties or compensation.", "section_number": "2", "subsection_number": "1(c)", "validation_status": "validated", "plain_english_summary": "An adjudicating officer is an officer appointed under section 46(1) to determine contraventions and penalties under the Act."}	[0.7355634,0.5160899,-3.195552,-0.7235864,1.1116357,-0.014829716,0.14074397,0.63138115,0.7169544,0.14279984,-0.18284476,1.5052174,0.50852245,-0.42800978,0.48796967,-0.9086771,-0.054533638,-1.1651117,-0.67028296,-0.9076831,0.90009457,-0.9789451,-0.8271137,-0.3391286,1.7663274,-0.07955682,1.4771012,-0.13123977,-0.7785229,-0.40703517,0.4144659,0.4727314,1.0754983,-0.53311837,-0.84093827,-1.2392598,1.1944137,0.58329284,-0.6760418,-0.1209162,0.069769114,0.06423889,0.040476907,-0.4897192,-0.008238784,-0.25543478,0.24842565,0.74406374,-0.5838868,-0.86205447,-0.33401856,-1.1076014,0.6781027,-0.52190405,0.6582378,0.4724545,-1.2377436,0.92078376,-0.014092733,0.11683111,1.7580327,1.2085189,-0.687706,0.84674174,-0.5604329,0.2214177,0.20263545,1.3915895,0.004434462,-0.6430315,0.6205678,0.20607673,0.8079266,-0.3754525,0.078600675,-0.37803236,-0.4697296,-0.4037141,0.050990596,0.93315715,0.433277,-0.50682354,1.4821196,0.6441466,0.37184775,-0.32305112,-0.5644091,0.013242789,-0.252