7	{"act": "IT_ACT_2000", "title": "Definition - Appellate Tribunal", "doc_id": "ITACT_DEF_APPELLATE_TRIBUNAL", "topics": ["definition", "governance", "appeals"], "entities": ["Appellate Tribunal"], "keywords": ["Appellate Tribunal", "TDSAT", "appeals"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": ["ITACT_SEC_48"], "clause_text": "\\"Appellate Tribunal\\" means the Appellate Tribunal referred to in sub-section (1) of section 48.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 2(1)(da) of the Information Technology Act 2000 defines the Appellate Tribunal as the body referred to in section 48(1), which is the Telecom Disputes Settlement and Appellate Tribunal, empowered to hear appeals against orders of the Controller or adjudicating officers.", "section_number": "2", "subsection_number": "1(da)", "validation_status": "validated", "plain_english_summary": "The Appellate Tribunal refers to the body designated under section 48(1) to hear appeals under this Act."}	[0.8171404,0.57789046,-3.198585,-1.1767547,1.1915188,0.20388295,0.30659905,0.642364,0.719676,-0.2723333,0.36927858,1.2245376,1.2093372,-0.493666,-0.46044645,-1.2100523,-0.84536994,-0.17487259,-0.35107684,-0.5820174,0.8831626,-0.91294235,-1.2459238,-0.11737837,1.5155149,0.043546703,0.645533,0.26299375,-1.109448,-0.88119155,0.5092537,-0.11229233,1.1451876,-0.71615714,-0.9369645,-0.3801261,1.7883987,0.63356984,-1.6535681,-0.18887575,0.43954176,-1.1063173,-0.48191482,-0.41614175,0.55823165,-0.34245068,0.88039345,0.82325333,-0.6111502,-1.138525,0.08452106,-0.7711316,0.28495252,-0.93364227,-0.16673952,-0.31183872,-1.104144,0.80363494,0.0007162858,0.41270626,0.75685847,1.1163073,-0.7293371,0.6385578,0.9095044,-0.77959055,-0.23269515,0.7237201,-0.19594902,-0.6093276,1.5116725,0.019889293,0.027028203,-0.6885509,-0.8588707,-0.9576387,-0.076822035,-1.1340778,-0.01726951,0.38982472,0.4886459,-0.53367627,1.1680081,0.2332777,-0.28863788,0.6411707,-0.04641063