9	{"act": "IT_ACT_2000", "title": "Definition - Communication Device", "doc_id": "ITACT_DEF_COMMUNICATION_DEVICE", "topics": ["definition", "cyber_offence", "communication"], "entities": [], "keywords": ["communication device", "cell phone", "PDA", "text", "video", "audio", "image"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": [], "clause_text": "\\"communication device\\" means cell phones, personal digital assistance or combination of both or any other device used to communicate, send or transmit any text, video, audio or image.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 2(1)(ha) of the Information Technology Act 2000 defines communication device as cell phones, personal digital assistants or combination of both or any other device used to communicate, send or transmit any text, video, audio or image. This definition is relevant to offences under sections 66B, 66C, 66D, and 66E.", "section_number": "2", "subsection_number": "1(ha)", "validation_status": "validated", "plain_english_summary": "A communication device includes cell phones, PDAs, or any other device used to communicate, send, or transmit text, video, audio, or images."}	[0.75619936,0.123381935,-3.3335686,-0.10264537,1.5726817,0.045907367,0.32902226,0.0323353,0.23058386,0.08565373,-0.39061522,1.0066817,0.26028582,-0.22748397,-0.003484284,-1.0613928,-0.016866717,-0.5879626,-0.53373736,0.919011,0.2616716,0.23652484,-1.2359519,-0.42171854,0.47295982,0.10154537,1.2503917,0.09302811,-1.6074078,-1.0551252,1.232144,-0.64715505,-0.16397281,-0.28074712,-1.7613503,-0.90644526,0.6561852,-0.47961044,-1.1205773,0.9126935,0.19238706,-0.0390114,-0.7167427,-0.52456135,0.6544464,-0.15353368,0.38865876,0.0060556564,0.73187685,-0.46397406,-0.13867606,-0.9585433,0.217395,-0.3200636,1.6852103,-0.11664054,-1.1627325,0.3057348,-0.23659325,0.013540489,0.72828746,1.9880929,-0.9428316,0.9512516,1.0611613,-0.0031233353,-0.6557448,1.1810168,-0.2926198,-0.630