10	{"act": "IT_ACT_2000", "title": "Definition - Computer", "doc_id": "ITACT_DEF_COMPUTER", "topics": ["definition", "computer_systems"], "entities": [], "keywords": ["computer", "data processing", "electronic", "magnetic", "optical", "logical functions", "memory", "computer system"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": [], "clause_text": "\\"computer\\" means any electronic, magnetic, optical or other high-speed data processing device or system which performs logical, arithmetic, and memory functions by manipulations of electronic, magnetic or optical impulses, and includes all input, output, processing, storage, computer software or communication facilities which are connected or related to the computer in a computer system or computer network.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 2(1)(i) of the Information Technology Act 2000 defines computer broadly as any electronic, magnetic, optical or other high-speed data processing device performing logical, arithmetic and memory functions, including all connected input, output, processing, storage, software and communication facilities in a computer system or network.", "section_number": "2", "subsection_number": "1(i)", "validation_status": "validated", "plain_english_summary": "A computer is any electronic, magnetic, or optical data processing device that performs logical, arithmetic, and memory functions, including all connected input, output, storage, and communication facilities."}	[0.5905909,1.161434,-2.9966912,-0.6963581,0.76007,0.5569037,0.9155886,0.22214225,-0.6310596,-0.677209,0.27659807,1.2768638,0.70459926,0.041290686,-0.08588523,-0.45242196,-0.92695796,-0.0379489,0.440415,1.1783769,1.0954628,-0.09341658,-0.9281888,-0.62389463,0.71600735,0.99255764,0.58471847,-0.9272312,-1.1080375,-0.6926965,0.6665102,-1.0643134,0.84291565,-0.63108146,-1.3063885,-1.3005525,0.11099394,-0.16123414,0.11391099,0.9009913,0.0024308246,-0.4437117,