11	{"act": "IT_ACT_2000", "title": "Definition - Computer Network", "doc_id": "ITACT_DEF_COMPUTER_NETWORK", "topics": ["definition", "computer_systems", "network"], "entities": [], "keywords": ["computer network", "interconnection", "satellite", "wireless", "communication media"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": [], "clause_text": "\\"computer network\\" means the inter-connection of one or more computers or computer systems or communication device through— (i) the use of satellite, microwave, terrestrial line, wire, wireless or other communication media; and (ii) terminals or a complex consisting of two or more interconnected computers or communication device whether or not the inter-connection is continuously maintained.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 2(1)(j) of the Information Technology Act 2000 defines computer network as the interconnection of one or more computers or communication devices through satellite, microwave, terrestrial line, wire, wireless or other communication media, including terminals or complexes of two or more interconnected computers, whether or not continuously connected.", "section_number": "2", "subsection_number": "1(j)", "validation_status": "validated", "plain_english_summary": "A computer network is an interconnection of computers or communication devices through satellite, microwave, wire, wireless, or other media, regardless of whether the connection is continuously maintained."}	[0.44650042,0.9530604,-3.1700633,-0.7548687,1.0010141,0.54111814,0.3209274,-0.2227089,-0.46091598,-1.2201177,-0.26195106,0.74033266,0.29599193,0.30158624,0.013501249,-1.1644748,-1.4687214,0.3637999,0.30267984,0.6628792,0.26275584,-1.1086946,-0.15503976,-0.5876425,0.6414359,0.8123949,0.84466267,-0.6885527,-1.7502245,-1.5048789,0.818965,-1.8838791,0.8207894,-0.78022224,-2.619994,-1.1621646,-0.41584834,-0.23611075,-0.49732158,0.18804225,0.24844122,-0.62020767,-0.7