13	{"act": "IT_ACT_2000", "title": "Definition - Controller", "doc_id": "ITACT_DEF_CONTROLLER", "topics": ["definition", "certifying_authority", "governance"], "entities": ["Controller of Certifying Authorities"], "keywords": ["Controller", "Controller of Certifying Authorities", "appointment", "section 17"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": ["ITACT_SEC_17"], "clause_text": "\\"Controller\\" means the Controller of Certifying Authorities appointed under sub-section (1) of section 17.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 2(1)(m) of the Information Technology Act 2000 defines Controller as the Controller of Certifying Authorities appointed under section 17(1). The Controller supervises Certifying Authorities, certifies public keys, and maintains standards for issuance of electronic signature certificates.", "section_number": "2", "subsection_number": "1(m)", "validation_status": "validated", "plain_english_summary": "The Controller refers to the Controller of Certifying Authorities appointed under section 17(1) to regulate Certifying Authorities."}	[0.31886473,0.070071995,-3.4212644,-0.51094806,0.93520594,-0.101876415,0.55220467,0.5348298,0.14387466,-0.44535318,-0.5236093,-0.1489503,1.3252745,-0.49392244,1.5196629,-1.0389731,0.11877122,-0.77546245,0.34052566,-0.56469303,1.1849866,-1.3255862,-0.6122789,0.0033469647,1.7318759,0.47146675,0.97313267,-0.6525238,-0.62460434,-1.1714057,0.17173685,-0.16251303,1.597966,-0.30197105,-0.009716524,-1.4654226,0.408816,0.68904984,-1.095904,0.4820259,0.33845538,0.21989067,-0.53730786,-0.8761486,-0.23812298,0.6819862,0.2719302,0.45917338,-0.113548584,-0.38857585,0.02190298,-1.0129756,-0.08711266,-0.20032667,0.8729667,0.2906106,-0.10986973,0.6571078,-0.6360608,-0.73549813,0.85730076,1.2176547,-0.08956165,0.8236059,0.8559865,-0.00010940868,0.21556303,1.6499327,-0.6465821,-0.42934638,0.9541311,-0.42593732,1.2081556,0.35637823,0.16150862,-1.669684,-