14	{"act": "IT_ACT_2000", "title": "Definition - Cyber Cafe", "doc_id": "ITACT_DEF_CYBER_CAFE", "topics": ["definition", "internet_access"], "entities": [], "keywords": ["cyber cafe", "internet access", "public", "business"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": [], "clause_text": "\\"cyber cafe\\" means any facility from where access to the internet is offered by any person in the ordinary course of business to the members of the public.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 2(1)(na) of the Information Technology Act 2000 defines cyber cafe as any facility from where access to the internet is offered by any person in the ordinary course of business to the members of the public.", "section_number": "2", "subsection_number": "1(na)", "validation_status": "validated", "plain_english_summary": "A cyber cafe is any facility that offers public internet access in the ordinary course of business."}	[-0.9800104,2.0066159,-3.4944558,-0.68328255,0.81927437,0.77000105,0.86612624,1.0302706,0.1399885,-0.16645315,0.071103446,0.55310327,-0.0031717364,-0.12758999,-0.35089535,-1.4255002,-0.61736304,-0.089156635,-0.18079515,0.7578229,0.9212403,-0.46507177,-0.4671026,-1.1705363,0.9671743,-0.423937,0.84389055,0.45965478,-0.9591745,-0.56818247,-0.552692,-1.0531865,1.0505228,0.2304,-0.6888914,-0.9956603,0.32063574,0.25332797,-1.7266505,0.17842156,0.26608416,0.20966549,-0.029951574,-0.5461213,0.46608195,0.3583458,-0.2632703,0.33401746,0.4698125,-0.5474803,0.4479254,-0.73793864,0.24324593,-0.36636987,1.2242316,-0.18698011,0.66831833,1.1937543,-0.27736035,0.5848504,2.1274357,1.1349813,-0.1769683,2.0874507,0.98416245,0.60329115,-0.37896317,0.98966426,0.058504786,-1.1016079,0.693755,0.18045917,1.251274,0.43433392,-0.21091229,-1.0219716,-0.7858736,-0.9503708,-0.24550653,1.1965184,0.34928656,0.01235635,0.94530016,-1.1082791,0.46661487,0.62596935,-0.043722756,-0.4335861,0.53789264,1.3466046,0.23896016,0.1802307