15	{"act": "IT_ACT_2000", "title": "Definition - Cyber Security", "doc_id": "ITACT_DEF_CYBER_SECURITY", "topics": ["definition", "cyber_security", "data_protection"], "entities": [], "keywords": ["cyber security", "unauthorised access", "disruption", "modification", "destruction", "information protection"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": [], "clause_text": "\\"cyber security\\" means protecting information, equipment, devices, computer, computer resource, communication device and information stored therein from unauthorised access, use, disclosure, disruption, modification or destruction.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 2(1)(nb) of the Information Technology Act 2000 defines cyber security as protecting information, equipment, devices, computers, computer resources, communication devices and information stored therein from unauthorised access, use, disclosure, disruption, modification or destruction. This definition underpins obligations relating to CERT-In and protected systems.", "section_number": "2", "subsection_number": "1(nb)", "validation_status": "validated", "plain_english_summary": "Cyber security means protecting information, devices, computers, and communication devices from unauthorised access, use, disclosure, disruption, modification, or destruction."}	[0.64439785,0.9729255,-2.870648,-0.14387524,1.2319795,1.1296141,0.87823814,0.56637037,0.36577073,-0.31464875,-0.7814473,0.658553,0.013629143,-0.38825879,0.22968677,-0.49722797,0.060937442,0.17545108,-0.019072756,-0.050087493,0.7911273,-1.1613169,-0.54707247,-0.5780852,0.9635355,0.840288,1.6254785,-0.43655777,-0.87449193,-1.0191697,0.44842473,-0.35148162,0.70096475,-0.62907624,-1.0363443,-1.6503204,-0.325363,0.42683467,-1.7077309,-0.13647601,0.504762,0.3643049,0.24117923,-0.6492729,0.089696735,0.89879984,0.40982708,0.012144487,0.81051815,-1.2999693,0.50770324,-0.63894755,0.6122552,-0.4549982,1.6296036,-0.440