16	{"act": "IT_ACT_2000", "title": "Definition - Data", "doc_id": "ITACT_DEF_DATA", "topics": ["definition", "data", "computer_systems"], "entities": [], "keywords": ["data", "information", "knowledge", "computer processing", "storage media", "electronic form"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": [], "clause_text": "\\"data\\" means a representation of information, knowledge, facts, concepts or instructions which are being prepared or have been prepared in a formalised manner, and is intended to be processed, is being processed or has been processed in a computer system or computer network, and may be in any form (including computer printouts magnetic or optical storage media, punched cards, punched tapes) or stored internally in the memory of the computer.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 2(1)(o) of the Information Technology Act 2000 defines data broadly as any formalised representation of information, knowledge, facts, concepts or instructions intended to be, being, or already processed in a computer system or network. It includes computer printouts, magnetic or optical storage media, punched cards, punched tapes, and internal computer memory.", "section_number": "2", "subsection_number": "1(o)", "validation_status": "validated", "plain_english_summary": "Data is any formalised representation of information, knowledge, facts, concepts, or instructions intended for processing in a computer system or network, in any physical or internal storage form."}	[0.6974396,0.6427597,-3.2835357,-1.2076902,0.8004326,0.5845411,0.22740623,0.039329313,-0.6569149,-0.95206803,0.49221233,0.86585414,1.446556,-0.42055959,0.039754067,-0.38357905,-1.0965781,-0.46476772,0.5433498,1.1001563,0.81141746,0.03234082,-0.9990325,-0.35282513,0.52828276,0.28633776,0.6154319,-0.7012827,-0.9934006,-0.9067437,0.51401174,-0.44457394,0.62255734,-0.32025346,-1.1850479,-1.525284,-0.37748227,-0.2002189,0.3161175,