17	{"act": "IT_ACT_2000", "title": "Definition - Digital Signature", "doc_id": "ITACT_DEF_DIGITAL_SIGNATURE", "topics": ["definition", "digital_signature", "authentication"], "entities": ["subscriber"], "keywords": ["digital signature", "authentication", "electronic record", "subscriber", "section 3"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": ["ITACT_SEC_3"], "clause_text": "\\"digital signature\\" means authentication of any electronic record by a subscriber by means of an electronic method or procedure in accordance with the provisions of section 3.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 2(1)(p) of the Information Technology Act 2000 defines digital signature as authentication of any electronic record by a subscriber by means of an electronic method or procedure in accordance with section 3, which requires use of an asymmetric crypto system and hash function.", "section_number": "2", "subsection_number": "1(p)", "validation_status": "validated", "plain_english_summary": "A digital signature is a method of authenticating an electronic record by a subscriber using an electronic procedure as provided under section 3."}	[0.08476411,0.5961658,-3.3476326,-0.41644505,0.91249573,0.17722207,0.37904996,0.6307939,-0.0069984235,-0.29632238,-0.6284501,1.4800082,1.3984736,-0.42956027,0.34014872,-0.8242899,-0.012758978,-0.912569,0.6368454,0.620266,0.64660025,-0.20233303,-1.315295,-0.04077337,1.1434785,-0.67366976,1.480914,-0.4118236,-1.1498961,-1.0080006,0.34707692,-0.31076583,0.8436855,0.15598579,-1.2820086,-0.9095286,0.33575654,0.09254134,-0.57050526,0.121373974,0.6594218,0.45200962,-0.35448918,0.7562904,0.64211476,0.8439236,-0.22818582,0.5149263,-0.04112817,-0.16046098,0.1595218,-0.6433481,0.529624,-0.018570833,1.2810649,0.8392524,-0.4817663,0.22503042,-0.13185017,-0.122729294,0.72736025,2.0417058,-0.74133253,1.0600468,0.58205956,-0.328488,0.27853274,0.7535228,0.04048344,-0.7532559,1.5517997,-0.2