18	{"act": "IT_ACT_2000", "title": "Definition - Electronic Form", "doc_id": "ITACT_DEF_ELECTRONIC_FORM", "topics": ["definition", "electronic_records"], "entities": [], "keywords": ["electronic form", "magnetic", "optical", "computer memory", "microfilm", "information storage"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": [], "clause_text": "\\"electronic form\\" with reference to information, means any information generated, sent, received or stored in media, magnetic, optical, computer memory, micro film, computer generated micro fiche or similar device.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 2(1)(r) of the Information Technology Act 2000 defines electronic form as any information generated, sent, received or stored in magnetic, optical, computer memory, microfilm, computer-generated microfiche or similar media. This definition establishes the scope of electronic records and electronic transactions under the Act.", "section_number": "2", "subsection_number": "1(r)", "validation_status": "validated", "plain_english_summary": "Electronic form means information generated, sent, received, or stored in any magnetic, optical, computer memory, microfilm, or similar medium."}	[0.4948309,0.4673763,-3.2178843,-0.9393627,0.898822,0.14328657,0.26104704,0.29374358,0.3327318,-0.7619622,-0.18859775,0.8991814,1.0204937,-0.25417697,0.5710086,-0.32168752,-0.11982246,-0.9805501,0.031248251,0.9730004,0.48887187,-0.517653,-1.1178896,0.1413829,0.9657792,0.088749476,1.1092632,-0.9179441,-1.0064485,-1.0317471,0.7708368,-0.42727715,1.3383231,-0.035138458,-0.59323794,-1.6016463,0.044532347,0.28347117,-0.6001148,1.148169,0.53417724,0.27041727,-1.2102562,-0.25200343,0.8711554,0.83382034,0.25076872,-0.31465816,0.07073796,-0.9707173,0.057519563,-0.20255062,0.25613812,-0.12921914,1.4989526,-0.2753227,-0.71136177,0.50282997,0.9532204,0.21224925,1.3727628,1.3937495,-0.7535589,1.5633253,1.3169748,-0.31072518,-0.2753082,