19	{"act": "IT_ACT_2000", "title": "Definition - Electronic Record", "doc_id": "ITACT_DEF_ELECTRONIC_RECORD", "topics": ["definition", "electronic_records"], "entities": [], "keywords": ["electronic record", "data", "image", "sound", "electronic form", "microfilm"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": [], "clause_text": "\\"electronic record\\" means data, record or data generated, image or sound stored, received or sent in an electronic form or micro film or computer generated micro fiche.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 2(1)(t) of the Information Technology Act 2000 defines electronic record as data, records, images or sounds stored, received or sent in electronic form or microfilm or computer-generated microfiche. Electronic records have legal recognition under the Act as equivalent to paper records.", "section_number": "2", "subsection_number": "1(t)", "validation_status": "validated", "plain_english_summary": "An electronic record is any data, record, image, or sound stored, received, or sent in electronic form or on microfilm or computer-generated microfiche."}	[0.58340335,0.22730212,-3.3850057,-1.1434228,0.81561774,0.26154152,-0.25729704,0.70956635,-0.13347863,-0.40828168,-0.058477595,1.0916901,0.85621923,-0.050696045,0.2594242,-0.68334675,-0.30706528,-1.1597011,-0.1087716,0.6185593,1.0268894,-0.23718193,-1.5883008,0.18412383,1.018735,-0.07781335,1.3178847,-0.74803734,-1.1768563,-0.7107468,0.76621443,-0.5658122,1.0979695,0.06579352,-0.60707563,-1.6103271,0.14306511,0.07531012,0.08361082,0.77773935,0.8709767,-0.06602461,-0.9746549,0.06597683,0.77870655,0.47457114,-0.12228406,0.013880771,0.31468174,-0.547637,0.1633053,-0.58203393,0.026546888,0.31500018,1.4434334,-0.013037782,-0.80625355,0.2877261,0.5673189,-0.03141647,1.1461253,1.1560324,-1.0038956,1.569114,1.2753619,-0.1741097,0.10396277,0.9523521,0.3353079,-0.6512039,1.1255326,-0.06286684,0.0419068,0.1716204,0.3556873