20	{"act": "IT_ACT_2000", "title": "Definition - Electronic Signature", "doc_id": "ITACT_DEF_ELECTRONIC_SIGNATURE", "topics": ["definition", "electronic_signature", "authentication"], "entities": ["subscriber"], "keywords": ["electronic signature", "authentication", "electronic record", "subscriber", "Second Schedule", "digital signature"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": ["ITACT_SECOND_SCHEDULE"], "clause_text": "\\"electronic signature\\" means authentication of any electronic record by a subscriber by means of the electronic technique specified in the Second Schedule and includes digital signature.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 2(1)(ta) of the Information Technology Act 2000 defines electronic signature as authentication of any electronic record by a subscriber using an electronic technique specified in the Second Schedule, and includes digital signatures. Electronic signatures are legally recognised under section 5 as equivalent to handwritten signatures.", "section_number": "2", "subsection_number": "1(ta)", "validation_status": "validated", "plain_english_summary": "An electronic signature is authentication of an electronic record using techniques specified in the Second Schedule, and includes digital signatures."}	[0.018364165,0.6285988,-3.3702893,-0.65686995,0.7312808,0.35774222,-0.06506331,1.0964271,0.05489517,-0.054925013,-0.65613467,1.0358868,1.0337301,-0.33325624,0.40379462,-0.5634306,0.49910447,-1.0919179,0.7235335,0.08527868,0.7487011,-0.54969704,-1.5893174,-0.2547844,0.83495104,-0.8792454,1.7582014,-0.38560882,-1.066552,-1.3766998,0.7194967,-0.21092811,1.6614869,-0.26843768,-1.2128077,-1.468657,0.22888163,0.51803255,-0.7924398,0.6485138,1.087232,0.4512241,-0.4439756,0.5142094,0.69506687,0.11613955,0.051499512,0.29872942,-0.0543052,-0.7164489,0.2384171,-0.8565705,0.025524648,-0.20382065,1.4258275,0.88419485,-0.54055107,0.46992564,-0.06558235,0.1267557,1.3