21	{"act": "IT_ACT_2000", "title": "Definition - Indian Computer Emergency Response Team", "doc_id": "ITACT_DEF_ICERT", "topics": ["definition", "cyber_security", "governance"], "entities": ["Indian Computer Emergency Response Team", "CERT-In"], "keywords": ["CERT-In", "Indian Computer Emergency Response Team", "cyber security", "incident response", "section 70B"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": ["ITACT_SEC_70B"], "clause_text": "\\"Indian Computer Emergency Response Team\\" means an agency established under sub-section (1) of Section 70B.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 2(1)(ua) of the Information Technology Act 2000 defines the Indian Computer Emergency Response Team (CERT-In) as the agency established under section 70B(1) to serve as the national agency for cyber security incident response, analysis, and coordination.", "section_number": "2", "subsection_number": "1(ua)", "validation_status": "validated", "plain_english_summary": "The Indian Computer Emergency Response Team (CERT-In) is the agency established under section 70B(1) as the national agency for cyber security incident response."}	[-0.011984071,0.3770398,-3.437029,0.5795787,2.2503765,0.48235115,0.6094554,0.6277603,-0.047416996,-0.49599057,0.011508678,0.68562907,1.2570868,-0.7187453,0.05323243,-1.4657776,-0.023303596,-0.5971667,-1.0200869,0.15999676,0.7609778,-1.4838263,-0.69427246,0.03845658,1.8014733,0.40749556,1.2746134,0.4011798,-0.9755784,-1.2879256,1.0655645,0.025982616,0.48721787,-0.9277367,-0.39107975,-0.472138,0.315665,0.24430661,-1.2296247,-0.07593635,0.33161303,0.01643116,0.36435312,-0.7353055,0.061080523,0.937423,0.3807582,0.03415701,1.0643876,-0.82750905,0.053459693,-1.0137999,0.2025912,-0.36914566,0.7417547,0.1613371,-1.1953069,0.101338275,-0.41480002,-0.48907825,1.2301764,1.4611483,-1.0673828,0.3013871,0.92965573,-1.3912623,-0.18749984,1.1528355,-0.3816968,-0.25013405,0.6635109,-1.103956,0.42