22	{"act": "IT_ACT_2000", "title": "Definition - Information", "doc_id": "ITACT_DEF_INFORMATION", "topics": ["definition", "information", "electronic_records"], "entities": [], "keywords": ["information", "data", "message", "text", "image", "sound", "software", "database", "computer programme"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": [], "clause_text": "\\"information\\" includes data, message, text, images, sound, voice, codes, computer programmes, software and data bases or micro film or computer generated micro fiche.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 2(1)(v) of the Information Technology Act 2000 defines information broadly to include data, messages, text, images, sound, voice, codes, computer programmes, software, databases, microfilm and computer-generated microfiche. This expansive definition is central to the Act's coverage of digital content and cyber offences.", "section_number": "2", "subsection_number": "1(v)", "validation_status": "validated", "plain_english_summary": "Information includes data, messages, text, images, sound, voice, codes, computer programs, software, databases, microfilm, or computer-generated microfiche."}	[0.72800374,0.8318385,-3.1863828,-0.7788712,0.7118274,0.5161887,0.09344481,0.40257028,-0.23322907,-0.71582144,-0.072407655,0.7920108,1.0207257,0.30351856,-0.61176306,-0.8652841,-0.9713375,-0.31809324,-0.063977525,1.3006439,0.7637184,-0.12849313,-0.83167875,-0.6020035,0.7185323,0.28531367,1.0132686,-0.4174721,-0.9705037,-0.9880994,0.25406373,-0.7706627,-0.033846438,-0.30403712,-0.61304295,-1.3751849,0.016795993,-0.008709919,-1.0403157,0.793831,0.28842035,0.17027558,-0.6786195,-0.5392193,0.43817106,0.32093802,-0.29192552,0.035823133,0.1743579,-1.1498897,0.30693918,-0.7102753,0.24964868,0.17250602,1.7173618,0.19295995,-1.1465855,-0.108314805,0.4185452,-0.12402668,1.1423429,1.8532993,-1.0232247,1.074396,0.955732,-0.08050958,-0.5075723,0.87784857,-0.3