23	{"act": "IT_ACT_2000", "title": "Definition - Intermediary", "doc_id": "ITACT_DEF_INTERMEDIARY", "topics": ["definition", "intermediary", "safe_harbour"], "entities": ["intermediary", "telecom service provider", "internet service provider"], "keywords": ["intermediary", "telecom service provider", "internet service provider", "web-hosting", "search engine", "online marketplace", "safe harbour"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": ["ITACT_SEC_79"], "clause_text": "\\"intermediary\\", with respect to any particular electronic records, means any person who on behalf of another person receives, stores or transmits that record or provides any service with respect to that record and includes telecom service providers, network service providers, internet service providers, web-hosting service providers, search engines, online payment sites, online-auction sites, online-market places and cyber cafes.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 2(1)(w) of the Information Technology Act 2000 defines intermediary with respect to electronic records as any person who on behalf of another person receives, stores or transmits electronic records or provides any service with respect to such records. This includes telecom service providers, network service providers, internet service providers, web-hosting service providers, search engines, online payment sites, online-auction sites, online marketplaces and cyber cafes. Intermediaries receive conditional safe harbour under section 79.", "section_number": "2", "subsection_number": "1(w)", "validation_status": "validated", "plain_english_summary": "An intermediary is any person who receives, stores, or transmits electronic records on behalf of another, including telecom providers, ISPs, web hosts, search engines, online payment and auction sites, online marketplaces, and cyber cafes."}	[-0.5150001,0.6401341,-3.634708,-1.3936094,1.1024565,0.004320397,0.