24	{"act": "IT_ACT_2000", "title": "Definition - Originator", "doc_id": "ITACT_DEF_ORIGINATOR", "topics": ["definition", "electronic_records"], "entities": [], "keywords": ["originator", "electronic message", "sends", "generates", "transmits", "intermediary"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": [], "clause_text": "\\"originator\\" means a person who sends, generates, stores or transmits any electronic message or causes any electronic message to be sent, generated, stored or transmitted to any other person but does not include an intermediary.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 2(1)(za) of the Information Technology Act 2000 defines originator as a person who sends, generates, stores or transmits any electronic message or causes such message to be sent, generated, stored or transmitted to any other person, but does not include an intermediary.", "section_number": "2", "subsection_number": "1(za)", "validation_status": "validated", "plain_english_summary": "An originator is a person who sends, generates, stores, or transmits an electronic message, excluding intermediaries."}	[0.10194042,0.68261755,-3.2954323,-0.68267006,0.75061184,-0.08267837,0.2337705,0.78929186,0.0039267954,-0.4139935,-1.1448671,0.78210145,0.8107576,0.3167116,-0.2750036,-0.705121,0.8338391,-1.123312,0.3878793,0.8406516,0.20305572,-1.4808986,0.07609379,0.0788878,1.7610104,-1.0678183,0.9885456,-0.17429774,-0.64746743,-1.2092483,0.44304916,-0.27262905,-0.12323552,-0.6335894,-0.9374086,-0.32041502,-0.8317034,0.3812233,-1.2554697,0.56654614,-0.6654403,-0.3502162,-0.31336534,-1.2500994,-0.30000997,0.54487574,0.47298822,0.5199662,0.20193562,-1.0893766,-0.13392104,-1.2716602,0.32262963,0.20829839,0.9390664,1.2714359,-1.5647153,0.8215459,0.42498073,0.22055468,0.44308925,1.6238432,-0.85625416,1.3585147,0.2116393,-0.6534089,-0.11617969,1.726074,0.30969068,-1.4578613,1.8431209,0.08031536,-0.5095733,0.40285757,1.0171139,-0