25	{"act": "IT_ACT_2000", "title": "Definition - Secure System", "doc_id": "ITACT_DEF_SECURE_SYSTEM", "topics": ["definition", "security", "cyber_security"], "entities": [], "keywords": ["secure system", "unauthorised access", "reliability", "security procedures", "hardware", "software"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": [], "clause_text": "\\"secure system\\" means computer hardware, software, and procedure that— (a) are reasonably secure from unauthorised access and misuse; (b) provide a reasonable level of reliability and correct operation; (c) are reasonably suited to performing the intended functions; and (d) adhere to generally accepted security procedures.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 2(1)(ze) of the Information Technology Act 2000 defines secure system as computer hardware, software and procedures that are reasonably secure from unauthorised access and misuse, provide a reasonable level of reliability and correct operation, are suited to their intended functions, and adhere to generally accepted security procedures.", "section_number": "2", "subsection_number": "1(ze)", "validation_status": "validated", "plain_english_summary": "A secure system is computer hardware, software, and procedures that are reasonably secure from unauthorised access, reliable, suited to their intended functions, and follow generally accepted security procedures."}	[0.19496696,1.3803515,-2.853454,-0.18387112,1.1628631,0.3845403,0.9132062,0.31536022,0.31761518,-0.3511211,-0.010625273,0.88486725,-0.20006096,-0.51268804,0.19454412,0.21142656,0.671897,-0.017057145,0.52085465,-0.11453036,0.39296702,-0.80087554,-0.8758774,-0.6888249,1.6714095,1.1458877,1.1156578,-0.6131804,-0.5551213,-1.3653054,0.8734493,-0.2205853,0.93485636,-0.8659007,-1.1711693,-2.1764216,-0.16530742,0.27712148,-1.0091387,-0.4462022,-0.08275906,0.83017755,-0.22744837,-0.48820284,-0.13585536,0.82137847,0.26709142,-0.4236323