26	{"act": "IT_ACT_2000", "title": "Definition - Subscriber", "doc_id": "ITACT_DEF_SUBSCRIBER", "topics": ["definition", "electronic_signature"], "entities": ["subscriber"], "keywords": ["subscriber", "electronic signature certificate", "certificate holder"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": [], "clause_text": "\\"subscriber\\" means a person in whose name the electronic signature Certificate is issued.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 2(1)(zg) of the Information Technology Act 2000 defines subscriber as a person in whose name an electronic signature certificate is issued. Subscribers have duties under Chapter VIII including maintaining control of private keys and notifying Certifying Authorities of compromise.", "section_number": "2", "subsection_number": "1(zg)", "validation_status": "validated", "plain_english_summary": "A subscriber is the person in whose name an electronic signature certificate has been issued."}	[-0.47489923,0.5675761,-3.1789808,-0.54656017,0.32120895,-0.14336875,-0.06819977,0.327947,0.6431118,0.3395425,-1.2424142,0.99606526,0.62005043,-0.38898897,0.67228967,-1.0286465,0.5803875,-0.90782523,0.23047042,-0.39767924,-0.078272015,-0.9093755,-0.50023687,0.15580282,1.1994483,0.18514575,2.0976384,-0.043101497,-0.13620862,-0.922679,-0.06710158,0.21951528,0.7898344,-0.26238456,-0.92013204,-0.9370729,0.47107947,0.9057986,-1.31626,0.43921745,0.031180432,-0.098128565,-0.47638837,-0.59096664,-0.28612316,-0.12881505,0.15821247,0.051430397,0.67886686,-0.3915677,0.0919925,-1.1988602,0.29086408,0.016723137,1.3286332,0.49743456,-0.7052129,0.6185084,-0.68060714,-0.020625021,1.1584282,1.0258988,-0.33456567,1.0998895,0.6770353,-0.38516408,-0.26653418,1.2576846,0.8544949,-1.2309129,1.034062,0.23694433,0.878985,0.32871637,0.8569853,-1.3648467,-0.5037841,-0.9965582,0.3321737,0.6116183,0.4262059,-0.4909251,2.1849825,0.53502303,0.24576005,0.6099308,-1.1854433,-0.044657208,-0.