28	{"act": "IT_ACT_2000", "title": "Authentication - Asymmetric Crypto System and Hash Function", "doc_id": "ITACT_SEC_3_SUB_2", "topics": ["authentication", "digital_signature", "cryptography"], "entities": [], "keywords": ["asymmetric crypto system", "hash function", "electronic record", "authentication", "cryptography", "key pair"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": [], "clause_text": "The authentication of the electronic record shall be effected by the use of asymmetric crypto system and hash function which envelop and transform the initial electronic record into another electronic record.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 3(2) of the Information Technology Act 2000. Authentication of electronic records must be effected using an asymmetric crypto system and hash function that envelops and transforms the initial electronic record into another electronic record. The hash function produces a unique result for each input record, making it computationally infeasible to reconstruct the original from the hash or for two records to produce the same hash.", "section_number": "3", "subsection_number": "2", "validation_status": "validated", "plain_english_summary": "Authentication of an electronic record is achieved using an asymmetric crypto system and hash function that transforms the original record into a new authenticated electronic record."}	[0.2996977,0.75684476,-3.8118322,-0.6112265,1.6912785,-0.21362056,0.21975064,1.001187,-0.19312562,0.32351226,-0.7232439,1.4806399,0.93302166,-0.9189902,0.052678216,-0.028968345,-0.03405485,-0.63248044,0.17708734,0.5409874,0.38483402,-0.11521533,-1.4005609,0.5328629,1.2100343,-0.65969706,0.8230871,-0.27154225,-0.82441884,-0.37084284,0.41807163,-0.17028436,1.1116879,0.35032576,-1.2727165,-0.99793434,-0.022927923,0.25277576,0.035623852,0.24092557,0.5784964,0.45054182,-0.50065374,0.7007096,0.65420157,0.7964639,0.63174736,0.53791577,0.5701109,