30	{"act": "IT_ACT_2000", "title": "Electronic Signature - Authentication Techniques", "doc_id": "ITACT_SEC_3A_SUB_1", "topics": ["authentication", "electronic_signature", "procedure"], "entities": ["subscriber"], "keywords": ["electronic signature", "authentication technique", "subscriber", "Second Schedule", "reliable", "electronic record"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": ["ITACT_SECOND_SCHEDULE"], "clause_text": "Notwithstanding anything contained in section 3, but subject to the provisions of sub-section (2), a subscriber may authenticate any electronic record by such electronic signature or electronic authentication technique which— (a) is considered reliable; and (b) may be specified in the Second Schedule.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 3A(1) of the Information Technology Act 2000. A subscriber may authenticate any electronic record by an electronic signature or electronic authentication technique that is considered reliable and is specified in the Second Schedule. This provision broadens authentication methods beyond asymmetric cryptography to include other techniques meeting reliability standards.", "section_number": "3A", "subsection_number": "1", "validation_status": "validated", "plain_english_summary": "In addition to digital signatures under section 3, a subscriber may authenticate electronic records using any reliable electronic signature or authentication technique specified in the Second Schedule."}	[0.13944963,0.46788263,-3.7418523,-0.58672714,1.169699,-0.11772641,-0.020478334,0.64809257,0.37795603,0.22981927,-0.2699544,0.760677,0.42641032,-0.64730036,-0.47316128,-0.3476311,0.38610828,-1.4208724,0.5848768,0.12410638,0.4396652,-0.5314994,-1.1595709,0.10467774,0.7575831,-0.23125963,1.1878442,-0.14229593,-0.94809526,-1.2608902,0.7987513,-0.51937515,1.5947089,-0.33793575,-0.35818323,-1.4547455,-0.47739944,0.73151076,-0.89149344,0.3063087,0.8064236,0.19266