31	{"act": "IT_ACT_2000", "title": "Reliability Criteria for Electronic Signature Techniques", "doc_id": "ITACT_SEC_3A_SUB_2", "topics": ["electronic_signature", "authentication", "compliance_requirement"], "entities": ["signatory", "authenticator"], "keywords": ["reliability", "electronic signature", "signature creation data", "signatory", "exclusive control", "alteration detectable", "authentication technique"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": [], "clause_text": "For the purposes of this section any electronic signature or electronic authentication technique shall be considered reliable if— (a) the signature creation data or the authentication data are, within the context in which they are used, linked to the signatory or, as the case may be, the authenticator and to no other person; (b) the signature creation data or the authentication data were, at the time of signing, under the control of the signatory or, as the case may be, the authenticator and of no other person; (c) any alteration to the electronic signature made after affixing such signature is detectable; (d) any alteration to the information made after its authentication by electronic signature is detectable; and (e) it fulfils such other conditions which may be prescribed.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 3A(2) of the Information Technology Act 2000 sets out reliability criteria for electronic signature techniques. A technique is reliable if: the signature creation data is linked exclusively to the signatory; it was under the signatory's exclusive control at the time of signing; any post-signing alteration to the signature is detectable; any post-authentication alteration to the information is detectable; and any other prescribed conditions are fulfilled.", "section_number": "3A", "subsection_number": "2", "validation_status": "validated", "plain_english_summary": "An electronic signature technique is reliable if it uniquely links to the signatory, was under their exclusive control at signing, and any post-signing alterations to the signature or the authenticated information are detectable."}	[0.42592245,0.34293023,-3.8110964,-0.7645588,1.0037335,-0.29943225,0.32036483,0.9297649,0.3890678,-0.12805508,-0.7215963,0.072061494,0.8958272,-0.3411265,-0.48649338,0.1285216,0.70311165,-1.4405004,0.8039882,1.0018308,0.35274512,-0.77608454,-1.3597097,-0.39098373,0.80837196,-1.0101385,0.7286095,-0.32956344,-0.8595043,-1.2345188,1.6744612,-0.45989704,1.2627157,-1.0222611,-1.0230274,-1.4753292,-0.4185803,0.3894375,-0.41116294,0.4704164,0.77772367,0.5747784,0.18163909,-0.061076287,0.49757385,0.073457085,0.7374072,0.21339294,0.029109761,-0.54341406,0.28426883,-0.86851656,-0.29809895,-0.32919216,1.4936262,1.0642102,-1.1819876,0.54210234,-0.8499802,-1.2444268,0.8404986,1.2404059,-1.0551844,0.6874705,0.37893593,-0.30547908,-0.56733114,0.88638836,0.5217629,-0.74100095,0.93738204,-0.3002838,0.25087094,-0.33080232,0.59740585,-0.50635344,-0.52783585,-1.0129095,0.3120799,1.1439335,-0.14690791,-0.94810855,1.5156639,0.095450014,0.7167908,0.11662475,-0.008866368,-0.1635485,-0.34936905,1.9551277,0.56426555,-0.6525986,0.47965688,-0.4234566,-1.2440822,0.6089734,0.8488237,0.036992125,-0.6906623,-0.20565201,-0.63167804,-1.1876619,-0.14176024,-0.15145996,-0.3551038,0.69995517,-0.08028567,-0.32287455,-0.1426092,0.5664267,0.011053667,0.81185687,0.1354829,0.570001,0.031192105,0.09060216,0.7633086,-1.4424844,-0.07230867,0.37136927,-0.8062056,-1.4084833,-0.28559223,0.61582893,-0.31978214,-0.03748706,-0.48186958,0.17636134,0.30389273,-0.67771804,-0.63365674,0.40211356,-1.0939485,-0.20388064,0.723984,1.0586181,0.17394343,-0.15032972,0.0944628,-0.49940157,0.06835617,0.26345733,-0.16417609,-0.5526793,0.77595013,-0.25641227,0.3487958,-0.10773747,-0.4089706,0.39063644,-0.87926126,-0.3383914,0.55110174,0.27195725,-0.19218303,-0.52337897,0.106506124,-0.43545255,0.18037222,1.9505851,1.379166,-0.31214055,-0.58580065