32	{"act": "IT_ACT_2000", "title": "Legal Recognition of Electronic Records", "doc_id": "ITACT_SEC_4", "topics": ["electronic_records", "legal_recognition"], "entities": [], "keywords": ["electronic record", "legal recognition", "written form", "electronic form", "accessible", "subsequent reference"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": [], "clause_text": "Where any law provides that information or any other matter shall be in writing or in the typewritten or printed form, then, notwithstanding anything contained in such law, such requirement shall be deemed to have been satisfied if such information or matter is— (a) rendered or made available in an electronic form; and (b) accessible so as to be usable for a subsequent reference.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 4 of the Information Technology Act 2000. Any legal requirement that information or a matter be in writing, typewritten, or printed form is deemed satisfied if that information is rendered or made available in electronic form and is accessible so as to be usable for subsequent reference. This grants electronic records legal equivalence to paper records.", "section_number": "4", "subsection_number": null, "validation_status": "validated", "plain_english_summary": "Any legal requirement for information to be in writing or printed form is satisfied if the information is in electronic form and accessible for future reference."}	[0.5303248,0.26241854,-2.719676,-1.0657457,0.79978293,0.53229535,-0.39345163,0.6443183,-0.105332114,-0.23702997,0.5911917,-0.31022525,0.46636146,-0.19034056,0.27329573,0.2912539,0.23158126,-1.7569898,0.105529785,0.32596692,0.29201487,-0.10363294,-1.7093433,-0.0628555,0.5406635,-0.3794884,0.3490443,-1.1214107,-1.253851,-0.94978595,0.67008775,-0.32025015,1.2995054,-0.23621586,-0.19774157,-1.673684,0.3809152,-0.022914618,-0.7450017,0.42193773,1.6675943,-0.0065683024,-1.2824721,0.21286105,1.0792059,0