33	{"act": "IT_ACT_2000", "title": "Legal Recognition of Electronic Signatures", "doc_id": "ITACT_SEC_5", "topics": ["electronic_signature", "legal_recognition", "authentication"], "entities": ["Central Government"], "keywords": ["electronic signature", "legal recognition", "handwritten signature", "authentication", "Central Government", "prescribed"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": [], "clause_text": "Where any law provides that information or any other matter shall be authenticated by affixing the signature or any document shall be signed or bear the signature of any person, then, notwithstanding anything contained in such law, such requirement shall be deemed to have been satisfied, if such information or matter is authenticated by means of electronic signature affixed in such manner as may be prescribed by the Central Government.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 5 of the Information Technology Act 2000. Any legal requirement for authentication by affixing a handwritten signature is satisfied if the information or matter is authenticated by means of an electronic signature affixed in the manner prescribed by the Central Government. This gives electronic signatures the same legal standing as handwritten signatures.", "section_number": "5", "subsection_number": null, "validation_status": "validated", "plain_english_summary": "Any legal requirement for a handwritten signature is satisfied if the information or document is authenticated using an electronic signature in the manner prescribed by the Central Government."}	[0.46924412,1.0215036,-2.9389427,-0.767015,0.9939997,0.12101999,-0.19977897,1.3679483,0.43702394,0.13109466,-0.52071095,0.32592922,0.8023374,-0.1397289,0.13935857,0.44750425,0.7781558,-1.1586725,0.8539643,0.6200623,0.4244764,-0.189538,-2.0950303,0.04955098,0.8832046,-1.4463242,1.5808251,-0.4557367,-0.8137083,-1.4267194,0.8549135,-0.16503683,1.4801687,-0.560