34	{"act": "IT_ACT_2000", "title": "Use of Electronic Records in Government - Acceptance", "doc_id": "ITACT_SEC_6_SUB_1", "topics": ["e_governance", "electronic_records", "government_filing"], "entities": ["appropriate Government"], "keywords": ["e-governance", "electronic filing", "government", "licence", "permit", "payment", "electronic form", "appropriate Government"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": [], "clause_text": "Where any law provides for— (a) the filing of any form, application or any other document with any office, authority, body or agency owned or controlled by the appropriate Government in a particular manner; (b) the issue or grant of any licence, permit, sanction or approval by whatever name called in a particular manner; (c) the receipt or payment of money in a particular manner, then, notwithstanding anything contained in any other law for the time being in force, such requirement shall be deemed to have been satisfied if such filing, issue, grant, receipt or payment, as the case may be, is effected by means of such electronic form as may be prescribed by the appropriate Government.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 6(1) of the Information Technology Act 2000. Any legal requirement for filing forms or documents with Government, issuing licences or permits, or making or receiving payments in a particular manner is deemed satisfied if effected in the electronic form prescribed by the appropriate Government. This enables e-governance and paperless interactions with government bodies.", "section_number": "6", "subsection_number": "1", "validation_status": "validated", "plain_english_summary": "Legal requirements for filing documents, issuing licences, or making payments with Government in a particular manner are satisfied if done in the electronic form prescribed by the appropriate Government."}	[-0.30718422,1.1699213,-2.7129855,-0.37841946,0.9965586,0.2898