35	{"act": "IT_ACT_2000", "title": "Delivery of Services by Service Provider - Authorisation", "doc_id": "ITACT_SEC_6A_SUB_1", "topics": ["e_governance", "service_provider", "authorisation"], "entities": ["appropriate Government", "service provider"], "keywords": ["service provider", "authorisation", "electronic service delivery", "appropriate Government", "computerised facilities"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": [], "clause_text": "The appropriate Government may, for the purposes of this Chapter and for efficient delivery of services to the public through electronic means authorise, by order, any service provider to set up, maintain and upgrade the computerised facilities and perform such other services as it may specify, by notification in the Official Gazette.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 6A(1) of the Information Technology Act 2000. The appropriate Government may authorise any service provider by order to set up, maintain and upgrade computerised facilities and perform other specified services for efficient delivery of services to the public through electronic means. Service providers include private agencies, companies, partnership firms and sole proprietors granted permission to offer services through electronic means.", "section_number": "6A", "subsection_number": "1", "validation_status": "validated", "plain_english_summary": "The appropriate Government may authorise service providers by order to set up, maintain, and upgrade computerised facilities for public service delivery through electronic means."}	[-1.2497463,1.3482237,-2.9918773,-0.53928226,0.91825765,0.22007145,-0.30372295,0.65255886,0.8557676,0.05096751,0.42338905,0.31060582,-0.032720648,-0.6202324,-0.059999786,-0.1637839,-0.12792227,-0.3017622,-0.06174675,0.68744457,0.2801159,-1.0387259,-0.3153473,-1.0367993,0.95677376,-0.074764274,0.7979662,-0.23098744,0.21689524,-0.88948154,1.2466955,0.18003844,