37	{"act": "IT_ACT_2000", "title": "Retention of Electronic Records", "doc_id": "ITACT_SEC_7_SUB_1", "topics": ["record_retention", "electronic_records", "compliance_requirement"], "entities": [], "keywords": ["retention", "electronic records", "accessible", "original format", "origin", "destination", "date and time", "compliance"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": [], "clause_text": "Where any law provides that documents, records or information shall be retained for any specific period, then, that requirement shall be deemed to have been satisfied if such documents, records or information are retained in the electronic form, if— (a) the information contained therein remains accessible so as to be usable for a subsequent reference; (b) the electronic record is retained in the format in which it was originally generated, sent or received or in a format which can be demonstrated to represent accurately the information originally generated, sent or received; (c) the details which will facilitate the identification of the origin, destination, date and time of despatch or receipt of such electronic record are available in the electronic record.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 7(1) of the Information Technology Act 2000. A legal requirement to retain documents, records or information for a specific period is satisfied if they are retained in electronic form, subject to three conditions: the information remains accessible for subsequent reference; the electronic record is in its original format or one accurately representing the original; and details of origin, destination, date and time of despatch or receipt are available within the record.", "section_number": "7", "subsection_number": "1", "validation_status": "validated", "plain_english_summary": "A legal retention requirement for documents is satisfied by retaining them in electronic form, provided the records remain accessible, are kept in original or accurately representative format, and include origin, destination, and date/time details."}	[0.8162954,0.2128833,-3.141618,-0.9752095,0.69200796,0.19161776,-0.77271295,0.5008899,0.56425405,-0.26321107,-0.12383913,0.2973004,0.81848043,-0.1426742,0.4238946,-0.14061685,-0.37365356,-1.2369081,0.2511853,0.6227107,0.7570751,-0.34496868,-1.3405598,0.0038731545,0.100828305,-0.24316955,1.0246477,-0.37459812,-0.8932888,-0.8315043,0.9457494,-0.19752194,1.3445841,-0.4258993,-0.4302869,-1.8884736,0.19763887,0.07571306,-0.69416374,0.02935726,1.9017864,-0.24310638,-1.1961488,-0.11850939,1.233621,0.740882,0.37405822,-0.42145154,0.37362185,-0.87026423,0.49667558,-0.49376217,-0.33277062,-0.3894571,0.8823036,0.12279965,-0.8006887,-0.18803594,0.31223813,-0.54980797,1.7353283,0.91076654,-1.1787792,1.5139173,0.35245878,-0.82188004,-0.13086681,0.95613617,-0.025510255,-1.5319215,1.1869676,0.50823915,0.38127863,-0.14828384,0.005910774,0.013897388,-1.2108349,-0.7719254,0.06584693,1.1143789,0.22700885,0.1407082,0.9611038,0.5217091,0.4691147,0.5242219,0.47340688,-0.7005075,0.35136446,1.6902918,0.1029036,-0.3334847,1.1555288,0.120796844,-0.37998584,0.6280784,0.09863991,0.51301646,-0.6237877,0.19416033,-0.83014596,-2.1551528,0.83842087,-0.041887667,0.7910157,0.66608566,-0.52631664,-0.0042265514,-0.7982099,-0.41222286,0.20321943,0.51311153,-0.7331791,0.58248305,0.21184029,0.5538761,0.89467406,-0.40840265,0.15866224,0.20947643,-0.99568844,-0.35925463,0.4296479,1.1197133,0.5771233,-0.3395051,-0.21576014,-0.39702612,1.0493779,-0.7858679,-1.000973,0.3494679,-0.69923085,0.3928411,0.8695463,0.28263012,-0.38395905,-0.10228967,-0.115608476,0.6882353,1.1017866,-0.06572481,-0.24780798,-0.27654585,0.32497448,-0.25487578,0.65803814,-0.15439992,-0.32212964,0.483085,-0.912774,-0.04261715,0.004138293,-0.018942056,0.78918004,-1.3311162,0.47668335,-0.20901302,0.44255245,0.9362089,1.2472883,0.40580058,-1.2543035,1.3724308,-0.61747557,-0.564097,-0.495722,-0.17516115,0.24456057,0.051140