38	{"act": "IT_ACT_2000", "title": "Audit of Documents Maintained in Electronic Form", "doc_id": "ITACT_SEC_7A", "topics": ["audit", "electronic_records", "compliance_requirement"], "entities": [], "keywords": ["audit", "electronic form", "documents", "records", "audit provision", "compliance"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": [], "clause_text": "Where in any law for the time being in force, there is a provision for audit of documents, records or information, that provision shall also be applicable for audit of documents, records or information processed and maintained in the electronic form.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 7A of the Information Technology Act 2000. Any provision in law requiring audit of documents, records or information also applies to documents, records or information that are processed and maintained in electronic form. This ensures audit requirements are technology-neutral.", "section_number": "7A", "subsection_number": null, "validation_status": "validated", "plain_english_summary": "Any statutory audit requirement for documents or records applies equally to documents, records, or information maintained in electronic form."}	[0.58961165,0.4352337,-2.877917,-0.7315209,0.7130908,0.28065223,-0.21572652,1.0312576,0.7161409,-0.2010342,0.66708905,0.5951541,0.4302331,0.2941057,-0.24000621,-0.029218271,-0.29374507,-1.1437149,-0.11561994,0.08723764,0.862444,-0.16403139,-1.0890063,-0.42319626,0.7567049,-0.08875869,0.40262234,-0.29234907,-0.5926162,-2.04733,0.93546945,-0.56623554,0.8149673,-0.84505653,-0.5510926,-1.7927411,0.50084066,0.64305645,-0.5592431,0.59671897,1.133283,0.09047453,-0.95296425,-0.17734976,0.8456177,1.0294011,0.91445816,-0.0049084546,0.50822234,-0.88124734,-0.21417564,-0.9433749,-0.07981151,-0.19591281,0.7292342,0.5306591,-1.5581964,0.2387595,0.37434062,-0.95225376,1.1755005,1.1253823,-0.70812535,1.2365896,0.06624758,-0.82529014,-0.082686,