39	{"act": "IT_ACT_2000", "title": "Publication in Electronic Gazette", "doc_id": "ITACT_SEC_8", "topics": ["e_governance", "official_gazette", "electronic_records"], "entities": [], "keywords": ["Electronic Gazette", "Official Gazette", "publication", "notification", "rules", "regulations"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": [], "clause_text": "Where any law provides that any rule, regulation, order, bye-law, notification or any other matter shall be published in the Official Gazette, then, such requirement shall be deemed to have been satisfied if such rule, regulation, order, bye-law, notification or any other matter is published in the Official Gazette or Electronic Gazette.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 8 of the Information Technology Act 2000. Any legal requirement for publication in the Official Gazette is satisfied if publication is made in either the Official Gazette or the Electronic Gazette. The date of publication is the date of whichever gazette form is published first.", "section_number": "8", "subsection_number": null, "validation_status": "validated", "plain_english_summary": "A legal requirement to publish in the Official Gazette is satisfied if publication occurs in either the printed Official Gazette or the Electronic Gazette."}	[0.106625214,0.025696976,-3.108259,-0.68368787,0.40171105,0.81329376,-0.50741494,0.21710272,0.5203218,-0.4042976,0.7082387,-0.09120816,1.1779584,-0.31643063,0.15088174,-0.21869138,0.16958287,-0.9978415,-0.38329116,0.45615554,-0.32100967,-0.300615,-1.4369863,-0.73824596,1.3561505,-0.01835428,0.4005748,-1.4006935,-1.1854625,0.02387253,0.67043924,0.059528913,0.26556745,-0.5976477,0.09210236,-1.9968444,0.5390856,-0.2863838,-1.3361894,-0.5068294,1.8820391,0.26618397,-0.6743124,0.22730501,0.45097774,0.0065298467,0.095304094,0.382498,0.36532786,-1.2787057,0.6241707,0.16028689,0.0054568606,-0.272614,0.84015363,0.87016314,-0.79374844,0.