40	{"act": "IT_ACT_2000", "title": "No Right to Insist on Electronic Form", "doc_id": "ITACT_SEC_9", "topics": ["restriction", "e_governance", "electronic_records"], "entities": ["Central Government", "State Government"], "keywords": ["no right to insist", "electronic form", "Government", "Ministry", "Department", "electronic transactions"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": ["ITACT_SEC_6", "ITACT_SEC_7", "ITACT_SEC_8"], "clause_text": "Nothing contained in sections 6, 7 and 8 shall confer a right upon any person to insist that any Ministry or Department of the Central Government or the State Government or any authority or body established by or under any law or controlled or funded by the Central or State Government should accept, issue, create, retain and preserve any document in the form of electronic records or effect any monetary transaction in the electronic form.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 9 of the Information Technology Act 2000. Despite sections 6, 7, and 8 enabling electronic records, no person has the right to insist that any Government Ministry, Department, authority or body funded or controlled by Central or State Government must accept, issue, create, retain or preserve documents in electronic form or conduct monetary transactions electronically.", "section_number": "9", "subsection_number": null, "validation_status": "validated", "plain_english_summary": "Sections 6, 7, and 8 do not give any person the right to demand that Government bodies accept, issue, or preserve documents in electronic form or conduct transactions electronically."}	[0.44536662,0.9786691,-2.709655,-0.87863797,0.8363699,0.82518584,-0.60004514,0.44796526,0.5202665,-0.17296658,0.42453906,0.22537023,0.15267539,-0.15978745,0.13332981,-0.026117403,0.18419357,-0.33385387,-0.30915612,1.0189905,0.7536366,-0.40188423,-1.5740151,0.26626906,1.3781927,-0.63585776,1.5696228,-0.9381505,-0.8211198,