41	{"act": "IT_ACT_2000", "title": "Validity of Contracts Formed Through Electronic Means", "doc_id": "ITACT_SEC_10A", "topics": ["electronic_contracts", "legal_recognition", "e_commerce"], "entities": [], "keywords": ["electronic contract", "contract formation", "proposal", "acceptance", "revocation", "electronic form", "enforceability"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": [], "clause_text": "Where in a contract formation, the communication of proposals, the acceptance of proposals, the revocation of proposals and acceptances, as the case may be, are expressed in electronic form or by means of an electronic records, such contract shall not be deemed to be unenforceable solely on the ground that such electronic form or means was used for that purpose.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 10A of the Information Technology Act 2000. A contract is not unenforceable merely because proposals, acceptances, or revocations were communicated in electronic form or through electronic records. This establishes the legal validity of contracts concluded through electronic means, including e-commerce transactions.", "section_number": "10A", "subsection_number": null, "validation_status": "validated", "plain_english_summary": "Contracts formed through electronic means — including proposals, acceptances, and revocations communicated electronically — are not unenforceable solely because they were made electronically."}	[0.70773023,0.8001628,-2.7276518,-0.91570777,1.6796485,0.16618904,-0.22893672,1.0839522,0.72055686,0.33803192,-0.12671237,0.12680204,0.5054897,-0.5214107,-0.17180458,0.20358387,0.31370166,-1.3890815,-0.47016072,0.6661458,0.5854012,-1.1143912,-1.0371971,-0.64849776,0.8977185,-1.0128427,0.8795912,0.26165533,-1.0042228,-1.2302463,0.6455027,0.20994838,1.5564815,-0.64115953,-0.98717237,-1.611522,0.2840507,-0.08693493,-0.72387236,-0.19455115,0.68541044,0.21596925,-0.4896051,0.44993928,1.