42	{"act": "IT_ACT_2000", "title": "Attribution of Electronic Records", "doc_id": "ITACT_SEC_11", "topics": ["electronic_records", "attribution"], "entities": ["originator"], "keywords": ["attribution", "electronic record", "originator", "authorised person", "automated system"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": [], "clause_text": "An electronic record shall be attributed to the originator— (a) if it was sent by the originator himself; (b) by a person who had the authority to act on behalf of the originator in respect of that electronic record; or (c) by an information system programmed by or on behalf of the originator to operate automatically.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 11 of the Information Technology Act 2000. An electronic record is attributed to the originator if it was sent by the originator personally, by a person authorised to act on the originator's behalf, or by an automated information system programmed by or on behalf of the originator.", "section_number": "11", "subsection_number": null, "validation_status": "validated", "plain_english_summary": "An electronic record is attributed to the originator if it was sent by the originator, by an authorised representative, or by an automated system programmed on the originator's behalf."}	[0.7165243,0.45583728,-3.3480613,-0.67044574,1.1767144,-0.26504672,-0.22899847,1.016674,0.1751834,-0.13291186,-0.22942096,0.67951274,1.1669929,-0.028129997,0.13095543,-0.37060657,0.24571133,-1.1338563,0.08358529,0.58032846,1.3302032,-1.1052008,-1.3162053,0.14403506,1.4573706,-0.8406327,0.6228148,-0.77576506,-0.5521884,-1.0534239,1.0449526,0.1617288,1.0578408,-0.31584576,-1.0580983,-1.0004854,-0.46663687,0.23365675,-0.7761038,0.91722035,0.23858312,-0.03142775,-0.80688006,-0.44445047,0.16016515,0.6223672,0.41158292,0.36778316,0.17395113,0.04858284,-0.16366553,-0.7064115,0.022854617,-0.12999363,1.4131174,0.6966643,-1.3065228,0.7167