43	{"act": "IT_ACT_2000", "title": "Acknowledgment of Receipt of Electronic Record", "doc_id": "ITACT_SEC_12_SUB_1", "topics": ["electronic_records", "acknowledgment", "procedure"], "entities": ["originator", "addressee"], "keywords": ["acknowledgment", "receipt", "electronic record", "originator", "addressee", "communication"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": [], "clause_text": "Where the originator has not stipulated that the acknowledgment of receipt of electronic record be given in a particular form or by a particular method, an acknowledgment may be given by— (a) any communication by the addressee, automated or otherwise; or (b) any conduct of the addressee, sufficient to indicate to the originator that the electronic record has been received.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 12(1) of the Information Technology Act 2000. Where the originator has not stipulated a specific form or method for acknowledgment of receipt, acknowledgment may be given by any communication (automated or otherwise) from the addressee or by any conduct of the addressee sufficient to indicate to the originator that the electronic record has been received.", "section_number": "12", "subsection_number": "1", "validation_status": "validated", "plain_english_summary": "Where the originator has not specified how acknowledgment must be given, it may be given by any communication or conduct from the addressee that indicates receipt."}	[0.3568593,0.4907288,-3.2492535,-1.0312134,0.83287853,0.107548185,0.36146212,1.2251745,0.30618766,0.21385194,-0.33553466,0.4317853,1.178287,0.7557364,0.70539385,-0.7055777,0.29564777,-1.4155415,-0.08539334,0.9305271,0.5751549,-0.49194592,-1.6507406,0.004135925,0.9432624,-0.700324,0.45360976,-0.10415349,-0.9789958,-1.5635438,0.5802056,-0.4473719,1.0536528,-0.42088845,-1.0008527,-0.9001188,-0.28159532,-0.83947617,-1.5370685,0.41198018,0.7063108,0.075402424,-0.7833974,0.4906