44	{"act": "IT_ACT_2000", "title": "Binding Effect Conditional on Acknowledgment", "doc_id": "ITACT_SEC_12_SUB_2", "topics": ["electronic_records", "acknowledgment", "binding_effect"], "entities": ["originator"], "keywords": ["binding", "acknowledgment", "electronic record", "originator", "deemed not sent"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": [], "clause_text": "Where the originator has stipulated that the electronic record shall be binding only on receipt of an acknowledgment of such electronic record by him, then unless acknowledgment has been so received, the electronic record shall be deemed to have been never sent by the originator.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 12(2) of the Information Technology Act 2000. Where the originator has stipulated that the electronic record shall be binding only upon receipt of an acknowledgment, the record is deemed never to have been sent unless and until that acknowledgment is received by the originator.", "section_number": "12", "subsection_number": "2", "validation_status": "validated", "plain_english_summary": "If the originator conditions the binding effect of an electronic record on acknowledgment, the record is deemed never sent until such acknowledgment is received."}	[0.81281996,0.34012306,-3.3463616,-1.0729716,1.0932652,0.49914095,-0.08568804,1.220803,-0.11388191,0.12629984,-0.58037835,0.7417555,0.5709573,0.018761571,0.58228886,-0.1820869,0.6151592,-1.1201699,-0.37394872,0.80992925,0.93862915,-0.50136596,-1.1303157,0.41658977,0.3654794,-0.60770345,1.2285428,-0.82722616,-1.1804827,-0.88936025,1.1040002,-0.13632485,1.4113865,-0.594611,-0.6453187,-1.1810294,-0.5652407,-0.3980795,-0.9426075,0.38672277,0.53326195,0.1097027,-0.48936927,-0.0118807405,0.15981348,0.8563829,0.7627772,0.9434696,0.034086496,0.25128216,0.5786899,-1.185582,-0.25013223,0.011890848,0.67609733,0.049061272,-0.63622046,0.6988573,0.16449772,-0.10763673,1.6498929,