47	{"act": "IT_ACT_2000", "title": "Secure Electronic Record", "doc_id": "ITACT_SEC_14", "topics": ["security", "electronic_records", "secure_record"], "entities": [], "keywords": ["secure electronic record", "security procedure", "verification", "electronic record"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": ["ITACT_SEC_16"], "clause_text": "Where any security procedure has been applied to an electronic record at a specific point of time, then such record shall be deemed to be a secure electronic record from such point of time to the time of verification.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 14 of the Information Technology Act 2000. An electronic record to which a security procedure has been applied at a specific point in time is deemed to be a secure electronic record from that point in time until the time of verification. Security procedures are prescribed by the Central Government under section 16.", "section_number": "14", "subsection_number": null, "validation_status": "validated", "plain_english_summary": "An electronic record to which a security procedure has been applied is deemed a secure electronic record from the time of application until the time of verification."}	[0.5885494,0.46957797,-3.5212674,-0.9325915,1.320151,-0.03386352,0.3227157,1.0217687,0.12040877,0.23397642,-0.23528975,0.31384164,0.009736538,-0.460821,0.16333781,-0.9826231,0.86303276,-0.98842764,-0.4220742,-0.27340624,1.0956463,-0.60876274,-1.301007,0.2544611,0.63894457,0.07091146,1.4026595,-0.8901792,-0.7640839,-0.6491295,1.2501076,-0.48686618,1.2941424,-0.09397715,-0.7998611,-2.8773007,-0.3385373,0.030639056,-0.67404187,-0.48715872,1.172673,0.26710054,-0.33310494,-0.2350483,0.29894233,0.6597151,0.7261906,0.3472806,-0.11628928,-0.82220846,-0.05875628,-0.051093012,-0.17300437,-0.8051307,1.5725892,0.51121664,-0.9677231,0.6412987,0.2872158,-0.47930923,2.1534088,1.570826,-0.6061328,0.9689527,0.656194,-0.28358546