48	{"act": "IT_ACT_2000", "title": "Secure Electronic Signature", "doc_id": "ITACT_SEC_15", "topics": ["electronic_signature", "security", "compliance_requirement"], "entities": ["signatory"], "keywords": ["secure electronic signature", "signature creation data", "exclusive control", "signatory", "private key", "prescribed manner"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": ["ITACT_SEC_16"], "clause_text": "An electronic signature shall be deemed to be a secure electronic signature if— (i) the signature creation data, at the time of affixing signature, was under the exclusive control of signatory and no other person; and (ii) the signature creation data was stored and affixed in such exclusive manner as may be prescribed.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 15 of the Information Technology Act 2000. An electronic signature is deemed secure if at the time of affixing, the signature creation data was under the exclusive control of the signatory and no other person, and the signature creation data was stored and affixed in the exclusive manner prescribed by the Central Government. For digital signatures, the signature creation data refers to the subscriber's private key.", "section_number": "15", "subsection_number": null, "validation_status": "validated", "plain_english_summary": "An electronic signature is a secure electronic signature if the signature creation data was under the exclusive control of the signatory at the time of signing and was stored and affixed in the prescribed exclusive manner."}	[-0.061383598,0.93489456,-3.128235,-0.9556466,1.2937149,0.07028371,-0.2520633,0.91069067,0.31984875,-0.35888675,-0.75620604,0.76195925,0.9000218,-0.60278094,0.3507178,0.42319578,0.38179433,-1.0375508,0.71516806,0.4457924,0.4807036,-0.6352235,-1.4245772,0.112609014,0.93113464,-0.76017606,1.7118506,-1.0857432,-0.54959977,-0.7342129,1.1352575,-0.18179914,0.8772878,-0.10582957,-1.2011325,-1.97