49	{"act": "IT_ACT_2000", "title": "Security Procedures and Practices", "doc_id": "ITACT_SEC_16", "topics": ["security", "procedure", "governance"], "entities": ["Central Government"], "keywords": ["security procedures", "security practices", "Central Government", "prescribed", "secure electronic record", "secure electronic signature"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": ["ITACT_SEC_14", "ITACT_SEC_15"], "clause_text": "The Central Government may, for the purposes of sections 14 and 15, prescribe the security procedures and practices: Provided that in prescribing such security procedures and practices, the Central Government shall have regard to the commercial circumstances, nature of transactions and such other related factors as it may consider appropriate.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 16 of the Information Technology Act 2000. The Central Government is empowered to prescribe security procedures and practices for the purposes of sections 14 and 15, relating to secure electronic records and secure electronic signatures. In prescribing such procedures, the Central Government shall consider commercial circumstances, the nature of transactions, and other relevant factors.", "section_number": "16", "subsection_number": null, "validation_status": "validated", "plain_english_summary": "The Central Government may prescribe security procedures and practices for secure electronic records and signatures under sections 14 and 15, considering commercial circumstances and the nature of transactions."}	[0.18371132,1.0394795,-3.119565,-0.70420486,1.1487697,-0.08474301,-0.18776411,0.9744775,0.7481289,-0.0003022648,-0.180839,0.39096445,-0.11510835,-0.7197998,0.7067395,-0.22465864,0.772259,-0.6836176,0.14389159,0.24734873,0.95986,-0.3993952,-1.3857883,0.12262004,1.1873224,-0.22405571,1.527467,-1.0188779,-0.60705066,-1.2291437,1.1821649,-0.1723611,1.0915104,-0.6843773,-0.41183415,-2.37030