50	{"act": "IT_ACT_2000", "title": "Appointment of Controller of Certifying Authorities", "doc_id": "ITACT_SEC_17_SUB_1", "topics": ["governance", "certifying_authority"], "entities": ["Central Government", "Controller of Certifying Authorities"], "keywords": ["Controller of Certifying Authorities", "appointment", "Central Government", "Deputy Controller", "Assistant Controller"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": [], "clause_text": "The Central Government may, by notification in the Official Gazette, appoint a Controller of Certifying Authorities for the purposes of this Act and may also by the same or subsequent notification appoint such number of Deputy Controllers, Assistant Controllers, other officers and employees as it deems fit.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 17(1) of the Information Technology Act 2000. The Central Government may appoint a Controller of Certifying Authorities and any number of Deputy Controllers, Assistant Controllers, other officers and employees as deemed necessary, by notification in the Official Gazette. The Controller regulates and supervises Certifying Authorities under the Act.", "section_number": "17", "subsection_number": "1", "validation_status": "validated", "plain_english_summary": "The Central Government may appoint a Controller of Certifying Authorities and such Deputy Controllers, Assistant Controllers, and other officers as it sees fit, by notification."}	[-0.28932634,0.14577408,-3.4808562,-0.43497676,1.1004416,-0.25918254,-0.13813363,0.9176511,0.3826506,-0.78143847,-0.41994202,-0.1273684,1.4117811,-0.13174,0.8305405,-0.46035025,-0.08366592,-0.8541329,-0.11216962,-0.39131773,1.1645423,-1.0193721,-0.5802435,0.31296116,1.474171,0.7150064,0.84782046,-0.77653646,-0.24138168,-1.09618,0.57361597,0.1851223,1.1342916,-0.43689013,0.51551294,-1.8723388,0.8369434,0.43650684,-1.238461,0.39922732,0.81278455,-0.1594337,-0.44467485,-1.1481582,-0