51	{"act": "IT_ACT_2000", "title": "Functions of Controller", "doc_id": "ITACT_SEC_18", "topics": ["governance", "certifying_authority", "regulation"], "entities": ["Controller", "Certifying Authority", "subscriber"], "keywords": ["Controller", "Certifying Authority", "supervision", "standards", "public key", "disclosure record", "database"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": [], "clause_text": "The Controller may perform all or any of the following functions, namely:— (a) exercising supervision over the activities of the Certifying Authorities; (b) certifying public keys of the Certifying Authorities; (c) laying down the standards to be maintained by the Certifying Authorities; (d) specifying the qualifications and experience which employees of the Certifying Authority should possess; (e) specifying the conditions subject to which the Certifying Authorities shall conduct their business; (f) specifying the contents of written, printed or visual materials and advertisements that may be distributed or used in respect of a electronic signature Certificate and the public key; (g) specifying the form and content of a electronic signature Certificate and the key; (h) specifying the form and manner in which accounts shall be maintained by the Certifying Authorities; (i) specifying the terms and conditions subject to which auditors may be appointed; (j) facilitating the establishment of any electronic system by a Certifying Authority; (k) specifying the manner in which the Certifying Authorities shall conduct their dealings with the subscribers; (l) resolving any conflict of interests between the Certifying Authorities and the subscribers; (m) laying down the duties of the Certifying Authorities; (n) maintaining a data base containing the disclosure record of every Certifying Authority.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 18 of the Information Technology Act 2000. The Controller of Certifying Authorities may supervise Certifying Authorities, certify their public keys, set standards and qualifications, specify business conditions and dealing procedures, resolve conflicts of interest with subscribers, maintain a publicly accessible database of disclosure records for all Certifying Authorities, and perform other regulatory functions.", "section_number": "18", "subsection_number": null, "validation_status": "validated", "plain_english_summary": "The Controller supervises Certifying Authorities, sets standards, certifies public keys, specifies conditions for conducting business, resolves disputes, and maintains a public disclosure database of Certifying Authorities."}	[-0.044979755,0.20154697,-3.4931848,-0.4288952,1.237287,-0.285996,0.12418849,1.0525466,0.41366386,-0.48632437,-0.079949796,-0.23696761,1.1164854,-0.33517054,1.0944028,-0.5421522,0.0011949962,-0.9535059,0.12293403,-0.4906843,0.74744934,-1.062989,-0.5444811,0.22649868,1.6263632,0.74282795,0.822884,-0.6311521,-0.3102063,-0.5672388,0.16273114,-0.03552653,1.4032891,-0.28684747,0.21666831,-1.7580358,0.6228348,0.6405957,-1.1444682,0.2549217,0.36302114,0.10078385,-0.37752318,-1.2420956,-0.36478326,0.6269684,0.49117365,0.2602369,0.13583471,-0.6532542,0.19149083,-0.86841905,0.03855297,0.22129257,1.3077933,-0.093044095,-0.4820254,0.64793,-0.6894204,-1.2038875,0.93003386,1.0126777,0.13064143,0.6061994,1.1787827,-0.60285276,-0.016832067,1.2858398,-0.4609703,-0.10604403,1.176176,-0.09605395,1.2291878,0.2200293,-0.09128478,-1.1954201,-0.015199212,-1.2944214,0.1553838,0.56780034,0.61777955,0.04963835,2.0821846,0.13030171,-0.9309197,0.62258404,-0.9649651,-0.45608035,0.20554781,1.4958276,1.1716586,-0.27759677,1.0411078,0.66230655,-0.29573697,0.009515217,0.42301545,0.34572682,0.40263304,0.062094636,-0.52579856,-0.27914602,0.33156276,-0.08169151,0.25540784,1.6735291,-0.13882656,-0.3646829,-0.15674691,0.49036235,0.12144228,0.7131,-0.82811147,-0.16385552,1.003049,0.33925676,0.46834648,-0.47292817,-0.25586176