52	{"act": "IT_ACT_2000", "title": "Recognition of Foreign Certifying Authorities", "doc_id": "ITACT_SEC_19", "topics": ["certifying_authority", "cross_border", "recognition"], "entities": ["Controller", "Central Government"], "keywords": ["foreign Certifying Authority", "recognition", "Controller", "Central Government", "electronic signature certificate"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": [], "clause_text": "Subject to such conditions and restrictions as may be specified by regulations, the Controller may with the previous approval of the Central Government, and by notification in the Official Gazette, recognise any foreign Certifying Authority as a Certifying Authority for the purposes of this Act.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 19 of the Information Technology Act 2000. The Controller may recognise any foreign Certifying Authority as a Certifying Authority for purposes of the Act, with the prior approval of the Central Government, by notification in the Official Gazette, and subject to conditions and restrictions specified by regulations. Electronic signature certificates issued by such recognised foreign authorities are valid under the Act.", "section_number": "19", "subsection_number": null, "validation_status": "validated", "plain_english_summary": "The Controller may recognise a foreign Certifying Authority as valid under this Act, with prior Central Government approval and subject to prescribed conditions."}	[0.2981382,0.5273059,-3.4061265,-0.5799624,0.9963505,0.45484307,-0.70544666,0.7485112,0.7033078,-0.5589667,-0.26732188,0.27888694,1.2073828,-0.5757566,0.8231594,-0.4034006,0.4390317,-1.1024266,0.07962551,0.00034261993,0.83548355,-0.6795172,-0.96489894,-0.056474444,1.4096819,0.014889774,1.3802896,-0.5084703,-1.0412415,-1.4125,0.69337094,-0.12571707,1.3644805,-0.8005624,0.25304756,-1.7159489,0.28916374,0.39902535,-1.1759682,0.4342774,0.93804854,0.59471923,-0.24