53	{"act": "IT_ACT_2000", "title": "Licence to Issue Electronic Signature Certificates", "doc_id": "ITACT_SEC_21", "topics": ["certifying_authority", "licensing", "procedure"], "entities": ["Controller", "Certifying Authority"], "keywords": ["licence", "electronic signature certificate", "Controller", "application", "qualification", "expertise", "infrastructure"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": [], "clause_text": "Subject to the provisions of sub-section (2), any person may make an application, to the Controller, for a licence to issue electronic signature Certificates. No licence shall be issued under sub-section (1), unless the applicant fulfils such requirements with respect to qualification, expertise, manpower, financial resources and other infrastructure facilities, which are necessary to issue electronic signature Certificates as may be prescribed by the Central Government.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 21 of the Information Technology Act 2000. Any person may apply to the Controller for a licence to issue electronic signature certificates. A licence will only be granted if the applicant satisfies prescribed requirements relating to qualification, expertise, manpower, financial resources and other infrastructure facilities necessary for issuing electronic signature certificates.", "section_number": "21", "subsection_number": null, "validation_status": "validated", "plain_english_summary": "Any person may apply to the Controller for a licence to issue electronic signature certificates, provided they meet prescribed requirements for qualification, expertise, manpower, financial resources, and infrastructure."}	[-0.9500267,0.7960337,-2.9715059,-0.35933548,0.64275306,0.5146762,-0.37486455,1.1046394,0.77294683,-0.55645084,-0.33513936,0.54849225,0.58438694,-0.43410006,0.20434871,0.052877203,0.21032822,-1.5785159,0.3131282,-0.3337829,0.340852,-0.9186582,-1.2399576,-0.