54	{"act": "IT_ACT_2000", "title": "Suspension and Revocation of Certifying Authority Licence", "doc_id": "ITACT_SEC_25", "topics": ["certifying_authority", "licensing", "revocation", "suspension"], "entities": ["Controller", "Certifying Authority"], "keywords": ["revocation", "suspension", "Certifying Authority", "licence", "Controller", "false statement", "contravention"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": ["ITACT_SEC_30"], "clause_text": "The Controller may, if he is satisfied after making such inquiry, as he may think fit, that a Certifying Authority has— (a) made a statement in, or in relation to, the application for the issue or renewal of the licence, which is incorrect or false in material particulars; (b) failed to comply with the terms and conditions subject to which the licence was granted; (c) failed to maintain the procedures and standards specified in section 30; (d) contravened any provisions of this Act, rule, regulation or order made thereunder, revoke the licence.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 25 of the Information Technology Act 2000. The Controller may revoke a Certifying Authority licence after inquiry if the authority made false statements in its licence application, failed to comply with licence conditions, failed to maintain procedures and standards under section 30, or contravened any provision of the Act. A licence may also be suspended for up to ten days pending completion of an inquiry, with opportunity to show cause.", "section_number": "25", "subsection_number": null, "validation_status": "validated", "plain_english_summary": "The Controller may revoke a Certifying Authority's licence if it made false statements in its application, failed to comply with licence conditions, failed to maintain required standards, or violated the Act. The Controller may also suspend a licence pending inquiry."}	[1.355067,-0.28409278,-2.9943898,-0.6294945,0.7571