55	{"act": "IT_ACT_2000", "title": "Certifying Authority - Mandatory Procedures", "doc_id": "ITACT_SEC_30", "topics": ["certifying_authority", "obligation", "security"], "entities": ["Certifying Authority"], "keywords": ["Certifying Authority", "secure hardware", "reliability", "secrecy", "privacy", "certificate repository", "publish", "standards"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": [], "clause_text": "Every Certifying Authority shall,— (a) make use of hardware, software and procedures that are secure from intrusion and misuse; (b) provide a reasonable level of reliability in its services which are reasonably suited to the performance of intended functions; (c) adhere to security procedures to ensure that the secrecy and privacy of the electronic signatures are assured; (ca) be the repository of all electronic signature Certificates issued under this Act; (cb) publish information regarding its practices, electronic signature Certificates and current status of such certificates; and (d) observe such other standards as may be specified by regulations.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 30 of the Information Technology Act 2000. Every Certifying Authority has a mandatory obligation to use hardware, software and procedures that are secure from intrusion and misuse, provide reliable services, ensure secrecy and privacy of electronic signatures, act as a repository for all electronic signature certificates it issues, publish information about its practices and certificate status, and observe standards specified by regulations.", "section_number": "30", "subsection_number": null, "validation_status": "validated", "plain_english_summary": "Every Certifying Authority must use secure hardware and software, provide reliable services, maintain security of electronic signatures, act as a certificate repository, publish certificate status information, and comply with regulatory standards."}	[-0.082513325,0.79337716,-2.9420128,-0.4531278,0.8183655,0.16681819,-0.5036386,1.2584251,0.44667506,0.16499396,0.08026659,0.34920102,0.35781443,-0.2008417,0.12344295,-0.13787717,0.09461527,-1.2489207,0.3472191,0.25317708,0.89694846,-1.2273487,-0.93603367,-0.2089776,1.273572,0.2663267,1.7897009,-0.5786304,-0.6388424,-1.4237093,1.4187962,-0.120122105,1.563008,-0.6983064,-0.3810516,-1.9396044,0.10612169,0.7483977,-1.0110649,0.46278223,1.3703203,0.21143946,0.18331234,-0.18676096,-0.102571204,0.64835495,0.3695551,0.059971597,0.51049584,-1.3353913,0.52132744,-1.0318402,0.32198414,0.049194288,1.3140323,0.6318374,-1.0010324,0.22484529,-0.6714952,-0.9154843,1.3978112,1.5106074,-1.067333,0.9091372,0.81531346,-1.0353353,-0.19991094,1.0449866,-0.13240376,-0.13930745,0.842476,-0.7680116,1.1793317,0.26470906,-0.03248168,-1.1077943,-0.24727014,-1.6202123,-0.22593908,1.1620301,0.12017098,-0.2908278,1.9319184,-0.3452612,-0.77427155,-0.0075790375,-1.1846559,-0.41468412,0.2643978,1.550884,0.78408635,-0.51092356,0.5813814,-0.39773515,-0.06355875,-0.584451,0.7257408,0.5901248,0.0038899095,-0.0025006074,-0.6132792,-0.6964377,0.108158305,-0.7044394,0.7363602,0.9264815,-0.26475126,0.41268644,-0.75112075,0.5945436,0.5451301,0.8479947,-0.37111658,-0.031954456,0.11164004,0.8607012,0.80630976,-0.69324255,-0.3319001,0.47749686,-0.44256535,-0.95095074,0.04549728,0.8146103,0.07650935,0.10555861,-0.64928937,-0.20800741,-0.17546953,-0.99590605,-0.43347356,0.2387997,-0.72516817,-0.06112631,0.7721574,0.63430095,-1.0215653,-0.19367082,0.3102074,-0.2507644,-0.07010289,0.48956272,-0.5865283,0.26599064,1.0053464,-0.64206004,1.2315161,0.047735903,-0.13358295,0.36891904,-0.8166599,-0.23217374,0.48835996,0.0010459224,0.442574,-0.2787924,0.7031919,-0.13028239,0.15676942,1.0511664,1.4260298,0.5586894,-0.9877708,1.1956843,-0.964058,-0.8573396,-0.48545393,1.1081686,0.41133013,0.87264925,-0.49648002,0.15075822,-0.64855564,0.39732325,0.33336723,-0.4145042,0.07987838,-1.4525106,0.9807187,-1.7395723,-0.44304127,-