57	{"act": "IT_ACT_2000", "title": "Certifying Authority - Disclosure Obligations", "doc_id": "ITACT_SEC_34", "topics": ["certifying_authority", "obligation", "disclosure"], "entities": ["Certifying Authority"], "keywords": ["disclosure", "Certifying Authority", "certification practice statement", "revocation", "suspension", "reliability"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": [], "clause_text": "Every Certifying Authority shall disclose in the manner specified by regulations— (a) its electronic signature Certificate; (b) any certification practice statement relevant thereto; (c) notice of the revocation or suspension of its Certifying Authority certificate, if any; and (d) any other fact that materially and adversely affects either the reliability of a electronic signature Certificate, which that Authority has issued, or the Authority's ability to perform its services.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 34 of the Information Technology Act 2000. Every Certifying Authority must disclose its own electronic signature certificate, relevant certification practice statements, notice of revocation or suspension of its certificate, and any fact that materially and adversely affects the reliability of certificates it has issued or its ability to perform services.", "section_number": "34", "subsection_number": null, "validation_status": "validated", "plain_english_summary": "Every Certifying Authority must disclose its electronic signature certificate, certification practice statement, any revocation or suspension of its certificate, and any material facts adversely affecting certificate reliability or service performance."}	[0.041973665,0.7487809,-2.8968248,-0.4561844,0.9538046,0.43781492,-0.6414019,1.2866824,0.7115831,0.042698283,0.14586197,0.47383347,0.53608835,0.1666422,0.26048428,-0.67302406,0.16550793,-1.5000978,0.26512074,0.40104246,0.5841487,-0.89634037,-1.0622778,-0.013370844,1.