59	{"act": "IT_ACT_2000", "title": "Suspension of Digital Signature Certificate", "doc_id": "ITACT_SEC_37", "topics": ["digital_signature", "certifying_authority", "suspension", "procedure"], "entities": ["Certifying Authority", "subscriber"], "keywords": ["suspension", "Digital Signature Certificate", "Certifying Authority", "subscriber", "public interest", "opportunity of hearing"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": [], "clause_text": "Subject to the provisions of sub-section (2), the Certifying Authority which has issued a Digital Signature Certificate may suspend such Digital Signature Certificate,— (a) on receipt of a request to that effect from— (i) the subscriber listed in the Digital Signature Certificate; or (ii) any person duly authorised to act on behalf of that subscriber; (b) if it is of opinion that the Digital Signature Certificate should be suspended in public interest. A Digital Signature Certificate shall not be suspended for a period exceeding fifteen days unless the subscriber has been given an opportunity of being heard in the matter.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 37 of the Information Technology Act 2000. A Certifying Authority may suspend a Digital Signature Certificate on request from the subscriber or their authorised representative, or in the public interest. A suspension cannot exceed fifteen days unless the subscriber has been given an opportunity to be heard.", "section_number": "37", "subsection_number": null, "validation_status": "validated", "plain_english_summary": "A Certifying Authority may suspend a Digital Signature Certificate on the subscriber's request or in the public interest, but not for more than fifteen days unless the subscriber has been given a hearing."}	[0.7736898,1.1826725,-3.1291692,-0.8857414,0.23181467,0.47078642,-0.08816569,0.9936525,0.21624789,-0.28518024,-0.5271015,0.91121703,0.26153386,-0.9218069,1.0129603,-0.77343