60	{"act": "IT_ACT_2000", "title": "Revocation of Digital Signature Certificate", "doc_id": "ITACT_SEC_38", "topics": ["digital_signature", "certifying_authority", "revocation", "procedure"], "entities": ["Certifying Authority", "subscriber"], "keywords": ["revocation", "Digital Signature Certificate", "Certifying Authority", "subscriber", "death", "dissolution", "insolvency", "security compromise"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": [], "clause_text": "A Certifying Authority may revoke a Digital Signature Certificate issued by it— (a) where the subscriber or any other person authorised by him makes a request to that effect; or (b) upon the death of the subscriber; or (c) upon the dissolution of the firm or winding up of the company where the subscriber is a firm or a company. A Certifying Authority may also revoke a certificate if a material fact is false, a requirement for issuance was not satisfied, the Certifying Authority's security was compromised, or the subscriber is declared insolvent or has ceased to exist. A Digital Signature Certificate shall not be revoked unless the subscriber has been given an opportunity of being heard.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 38 of the Information Technology Act 2000. A Certifying Authority may revoke a Digital Signature Certificate on subscriber request, on the death or dissolution of the subscriber, or if a material fact is false or concealed, an issuance requirement was not satisfied, the Certifying Authority's security system was compromised, or the subscriber is insolvent or has ceased to exist. Revocation requires giving the subscriber an opportunity to be heard.", "section_number": "38", "subsection_number": null, "validation_status": "validated", "plain_english_summary": "A Certifying Authority may revoke a Digital Signature Certificate on subscriber request, death, dissolution, falsity of material facts, unmet issuance requirements, security compromise, or insolvency, subject to giving the subscriber an opportunity to be heard."}	[1.4325519,0.2868274,-2.682811,-0.48383933,0.6089043,0.4361146,-0.37220255,2.02623,1.0470991,0.19667459,-0.56594324,0.89903146,0.5701304,-0.61333513,0.24708232,-0.9550386,0.53218305,-1.2085277,-0.52178836,0.5588499,0.7935332,-1.2324798,-1.5952494,-0.28261712,0.9835557,0.21914004,1.4597039,0.34624666,-1.0879384,-0.2769075,0.98495865,0.22048831,0.7609561,-0.07266703,-0.94387794,-1.1597823,0.817378,0.12077507,-0.88625616,0.0556431,1.4233919,0.791224,0.38280547,-0.08731641,0.6777042,0.48093873,0.7399468,0.6729005,0.78672373,-1.232117,1.3618276,-0.6736699,0.32225096,0.3248484,0.3808674,0.8934425,-0.7502238,-0.0062951185,-1.0859208,-1.2676316,0.6267869,1.2522246,-0.26120764,1.1225265,1.0069574,-1.038539,-0.7225593,0.88075846,0.6048453,-1.4160234,1.1428847,0.07969675,1.0538386,0.34949315,-0.089737356,-0.90012157,-0.9535034,-1.815659,-0.43852022,0.7411236,-0.21452288,-0.51678205,2.154085,0.79681695,-0.3681742,0.4949325,-1.2297468,-0.040602416,-0.053232696,1.5671436,0.4193863,-0.65765417,0.6276028,-0.12468948,-0.3321851,-0.065597445,0.79701406,0.6728789,-0.6736827,-0.23819713,-1.0520135,-1.0865352,-0.22037958,-0.59771436,0.10593971,0.69606924,-0.06520594,-0.19242784,0.0745685,0.6708586,0.22907612,-0.42407575,-0.383549,0.38512537,0.90417874,-0.02321517,0.339991,-0.5529628,-0.75698775,0.17287779,-0.5061129,-0.7869018,-0.056794494,1.0879177,0.07532835,0.47239825,-0.5132382,0.2666275,0.61657614,-0.9577437,-0.88421553,0.44734913,-0.6245427,0.35022274,0.27884322,-0.12469591,-1.0083983,-0.7451606,-0.36074397,-0.75639045,0.89168227,0.17713574,0.25120535,0.31551543,0.9118877,-1.1111087,1.5473384,-0.115541644,-0.7905778,0.30181852,-0.5548755,-0.9058691,0.6701668,0.048087895,0.8720397,-0.1509362,0.6784707,0.53062755,-0.072102055,1.0798807,0.8786,-0.027765792,-1.4081261,1.7102867,-1.0078449,-0.51934326,-0.7609561,0.25577843,0.09058819,0.12627362,-1.0464869,0.21688268,-0.6158691,