61	{"act": "IT_ACT_2000", "title": "Subscriber - Duty to Generate Key Pair", "doc_id": "ITACT_SEC_40", "topics": ["digital_signature", "subscriber_duty", "key_pair"], "entities": ["subscriber"], "keywords": ["key pair", "subscriber", "private key", "public key", "security procedure", "Digital Signature Certificate"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": [], "clause_text": "Where any Digital Signature Certificate the public key of which corresponds to the private key of that subscriber which is to be listed in the Digital Signature Certificate has been accepted by a subscriber, the subscriber shall generate that key pair by applying the security procedure.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 40 of the Information Technology Act 2000. Where a subscriber accepts a Digital Signature Certificate, they are obligated to generate the corresponding key pair by applying the prescribed security procedure. The key pair consists of the private key used to create the digital signature and the public key listed in the certificate.", "section_number": "40", "subsection_number": null, "validation_status": "validated", "plain_english_summary": "A subscriber who accepts a Digital Signature Certificate must generate the corresponding key pair using the prescribed security procedure."}	[-0.6374415,1.2570001,-3.049724,-0.7677084,0.38733023,-0.023064453,-0.26166022,0.9166033,0.04327787,-0.0183253,-0.7445943,0.679951,0.47092086,-0.7022111,0.5046242,-0.3050451,0.2606945,-1.1135184,0.064703844,-0.20743513,0.26922283,-0.99249786,-0.55606294,-0.6367908,1.0661808,-0.6739489,1.5368052,0.1746815,-1.0297421,-0.65113866,0.66415936,0.3095833,1.0994396,-0.2765338,-1.324818,-1.369532,-0.07944404,-0.30019233,-1.2120136,-0.13705863,0.61447155,0.85627323,-0.45322275,0.013224559,-0.20375949,-0.033115704,0.5822482,0.23297451,0.6209398,-0.14600319,0.8972517,-0.78149587,1.2617393,-0.59158015,1.2888238,1.5570586,-0.5845182