62	{"act": "IT_ACT_2000", "title": "Subscriber - Control of Private Key", "doc_id": "ITACT_SEC_42_SUB_1", "topics": ["digital_signature", "subscriber_duty", "security"], "entities": ["subscriber"], "keywords": ["private key", "subscriber", "reasonable care", "disclosure", "control", "Digital Signature Certificate"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": [], "clause_text": "Every subscriber shall exercise reasonable care to retain control of the private key corresponding to the public key listed in his Digital Signature Certificate and take all steps to prevent its disclosure.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 42(1) of the Information Technology Act 2000. Every subscriber has a duty to exercise reasonable care to retain control of the private key corresponding to the public key listed in their Digital Signature Certificate and to take all steps to prevent its disclosure. The subscriber remains liable until they have notified the Certifying Authority of a compromise.", "section_number": "42", "subsection_number": "1", "validation_status": "validated", "plain_english_summary": "Every subscriber must take reasonable care to maintain control of their private key and take all steps to prevent its disclosure to unauthorised persons."}	[0.20493326,0.509507,-2.9292552,-0.6858807,0.63107055,-0.1965989,-0.20067453,0.62599385,0.98904413,0.3369933,-0.7497983,1.0100062,-0.3141496,-0.39324993,0.800434,-0.23478182,0.7147475,-0.7982261,0.1920345,-0.056683272,0.3990403,-0.8686751,-0.6669182,0.40241635,0.634233,-0.122330375,1.8624356,-0.15598932,0.031080043,-0.42256626,0.19781707,0.17008618,0.6860381,-0.66548806,-0.9421772,-1.1413486,0.13693246,0.07465276,-1.4020983,0.21034867,0.4382488,0.5380975,-0.24471453,-0.5336818,-0.291309,-0.40683824,-0.18866055,-0.03294416,0.6623928,-0.42313725,0.8704128,-1.1665565,0.01771337,-0.5247965,1.3993094,0.07815098,-0.5297941,-0.00933001,-0.7725111,-0.53092724,1.2