63	{"act": "IT_ACT_2000", "title": "Subscriber - Duty to Report Private Key Compromise", "doc_id": "ITACT_SEC_42_SUB_2", "topics": ["digital_signature", "subscriber_duty", "security", "breach_reporting"], "entities": ["subscriber", "Certifying Authority"], "keywords": ["private key compromise", "subscriber", "Certifying Authority", "notification", "without delay", "liability"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": [], "clause_text": "If the private key corresponding to the public key listed in the Digital Signature Certificate has been compromised, then, the subscriber shall communicate the same without any delay to the Certifying Authority in such manner as may be specified by the regulations.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 42(2) of the Information Technology Act 2000. If a subscriber's private key is compromised, the subscriber must immediately communicate this to the Certifying Authority without any delay, in the manner specified by regulations. The subscriber remains liable for any use of the compromised key until the Certifying Authority is notified.", "section_number": "42", "subsection_number": "2", "validation_status": "validated", "plain_english_summary": "If a subscriber's private key is compromised, they must immediately notify the Certifying Authority in the manner specified by regulations. The subscriber remains liable until such notification is made."}	[0.6416505,0.0969302,-3.2544804,-0.65585166,0.9317977,-0.41472515,-0.68882394,0.5280311,0.85605246,0.37048388,-0.9313484,1.2897004,-0.5551813,-0.6568083,0.66091776,-0.34010437,1.150301,-0.8571023,-0.35780272,-0.17798361,0.20091853,-0.9676042,-0.7926057,0.5082495,0.6911462,0.16188595,1.7310389,-0.5485432,0.2222,-0.46302366,0.18044922,-0.083150655,0.81679523,-0.68574065,-1.0290291,-1.8398682,-0.16898735,-0.2708593,-1.1733314,0.23426679,0.25634184,0.40306157,0.3747234,-0.7781436,-0.1966434,-0.10615765,0.3460756,0.10