64	{"act": "IT_ACT_2000", "title": "Penalty and Compensation for Damage to Computer Systems", "doc_id": "ITACT_SEC_43", "topics": ["cyber_offence", "penalty", "computer_damage", "unauthorised_access"], "entities": [], "keywords": ["unauthorised access", "computer damage", "computer virus", "computer contaminant", "data theft", "disruption", "compensation", "computer system"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": [], "clause_text": "If any person without permission of the owner or any other person who is in charge of a computer, computer system or computer network,— (a) accesses or secures access to such computer, computer system or computer network or computer resource; (b) downloads, copies or extracts any data, computer data base or information; (c) introduces or causes to be introduced any computer contaminant or computer virus; (d) damages or causes to be damaged any computer, computer system or computer network, data, computer data base or any other programmes; (e) disrupts or causes disruption of any computer, computer system or computer network; (f) denies or causes the denial of access to any person authorised to access; (g) provides any assistance to any person to facilitate access in contravention of the provisions of this Act; (h) charges services to the account of another person by tampering; (i) destroys, deletes or alters any information residing in a computer resource or diminishes its value; (j) steal, conceal, destroys or alters any computer source code, he shall be liable to pay damages by way of compensation to the person so affected.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 43 of the Information Technology Act 2000. Any person who without the permission of the owner or person in charge accesses, downloads from, introduces contaminants into, damages, disrupts, denies access to, assists unauthorised access to, manipulates billing, destroys or alters information in, or tampers with computer source code on a computer, computer system or computer network is liable to pay damages by way of compensation to the person affected.", "section_number": "43", "subsection_number": null, "validation_status": "validated", "plain_english_summary": "Any person who, without permission, accesses, damages, disrupts, introduces viruses into, or tampers with a computer system or its data is liable to pay compensation to the affected person."}	[1.2640249,0.8648284,-3.054105,-0.57329845,0.4127981,0.30417478,-0.46957284,0.94927573,1.5395889,-0.26637784,-0.3892027,0.91022754,0.40487757,-0.2683779,0.532501,-0.17315228,-0.33980572,0.1533145,-0.6564935,0.19233973,0.43050748,-1.2882681,-0.91398185,0.3333921,0.79357237,-0.8877897,1.0501829,0.06859392,0.047549076,-0.15253083,0.31261894,0.2867453,-0.30529246,-1.3783735,-1.7281123,-0.8313758,0.8870092,0.21427876,-1.0050764,0.9628741,0.65458417,-0.2316773,0.028665578,-0.99809843,-0.29630014,-0.22207949,0.7814509,1.0950862,0.024147306,-0.34779945,0.023034235,-2.2171597,0.15571395,-0.5246878,1.1027815,0.06016311,-1.017606,-0.3730479,0.014353972,-0.37447998,1.7413095,2.5277834,-0.3140354,0.95870847,0.23366408,-0.22658329,-0.35130468,1.2160861,-0.09220563,-0.91222584,0.9925543,0.62246764,0.9380192,-0.33840168,-0.4617717,-0.42380258,-0.56472176,-0.30086228,0.3711134,1.1914752,0.5847615,-0.15989143,1.4809804,0.35223004,0.81134826,-0.6849898,-0.032401837,-0.12715386,0.03363932,1.2182844,-0.059347726,-0.18037854,0.3515419,-0.4572369,-0.7987445,-0.43662077,-0.3264094,0.032632187,-0.4881888,-0.4611332,-0.67356306,-0.84811485,0.59376186,0.03488716,0.8847202,1.4157661,0.9651513,0.10338747,-0.30062032,0.33449373,0.6900936,0.15090036,-0.09821463,-0.49041566,0.8725904,0.32469735,0.9595262,-0.4624739,-0.60348356,0.99414694,-0.73454416,0.18754849,-0.72255,1.459498,0.4673156,0.5921126,-0.76488936,0.5430094,0.17609593,-0.9985782,-0.8091395,-0.5080618,-0.0784619,0.25839645,0.3189315,-0.12763554,-0.23476453,-0.48388827,-0.78061444,0