65	{"act": "IT_ACT_2000", "title": "Compensation for Failure to Protect Data", "doc_id": "ITACT_SEC_43A", "topics": ["data_protection", "security", "compliance_requirement", "penalty"], "entities": ["body corporate"], "keywords": ["body corporate", "sensitive personal data", "reasonable security practices", "negligence", "wrongful loss", "wrongful gain", "compensation", "data protection"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": [], "clause_text": "Where a body corporate, possessing, dealing or handling any sensitive personal data or information in a computer resource which it owns, controls or operates, is negligent in implementing and maintaining reasonable security practices and procedures and thereby causes wrongful loss or wrongful gain to any person, such body corporate shall be liable to pay damages by way of compensation to the person so affected.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 43A of the Information Technology Act 2000. A body corporate that possesses, deals with or handles sensitive personal data or information in a computer resource and is negligent in implementing and maintaining reasonable security practices and procedures is liable to pay compensation if that negligence causes wrongful loss or wrongful gain to any person. Reasonable security practices means practices designed to protect information from unauthorised access, damage, use, modification, disclosure or impairment as specified by agreement, law, or prescribed by the Central Government.", "section_number": "43A", "subsection_number": null, "validation_status": "validated", "plain_english_summary": "A body corporate that negligently fails to implement reasonable security practices for sensitive personal data and thereby causes wrongful loss or gain to any person is liable to pay compensation to that person."}	[1.3385606,0.9431189,-3.2471037,-0.2367253,0.79858357,0.72815764,0.2849627,0.89666176,1.2814561,0