66	{"act": "IT_ACT_2000", "title": "Penalty for Failure to Furnish Information", "doc_id": "ITACT_SEC_44", "topics": ["penalty", "compliance_requirement", "certifying_authority"], "entities": ["Controller", "Certifying Authority"], "keywords": ["penalty", "failure to furnish", "Controller", "Certifying Authority", "return", "books of account", "records", "one lakh fifty thousand"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": [], "clause_text": "If any person who is required under this Act or any rules or regulations made thereunder to— (a) furnish any document, return or report to the Controller or the Certifying Authority fails to furnish the same, he shall be liable to a penalty not exceeding one lakh and fifty thousand rupees for each such failure; (b) file any return or furnish any information, books or other documents within the time specified therefor in the regulations fails to file return or furnish the same within the time specified, he shall be liable to a penalty not exceeding five thousand rupees for every day during which such failure continues; (c) maintain books of account or records, fails to maintain the same, he shall be liable to a penalty not exceeding ten thousand rupees for every day during which the failure continues.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 44 of the Information Technology Act 2000. Penalties for failure to comply with information furnishing obligations: failure to furnish documents or reports to the Controller or Certifying Authority attracts a penalty of up to Rs 1,50,000 per failure; failure to file returns or furnish information within the prescribed time attracts up to Rs 5,000 per day of continuing failure; failure to maintain required books of account or records attracts up to Rs 10,000 per day of continuing failure.", "section_number": "44", "subsection_number": null, "validation_status": "validated", "plain_english_summary": "Failure to furnish required documents to the Controller or Certifying Authority attracts a penalty up to Rs 1.5 lakh. Failure to file returns within the specified time attracts up to Rs 5,000 per day. Failure to maintain books of account attracts up to Rs 10,000 per day."}	[1.2045386,0.8284283,-3.6213915,-0.55374223,1.0205148,-0.64245516,0.37285417,0.019897757,-0.09979072,-0.25012508,-0.48994324,-0.12837724,0.86141163,0.31355873,0.75386024,0.38013774,0.5149691,-0.46181375,-0.78021705,0.36945337,0.37568137,0.3834351,-1.2663069,0.43845373,0.64242816,-0.0606425,0.8783726,-0.93196416,-0.65198827,-0.08169091,0.39965984,-0.042725787,-0.1448937,-1.4415772,-1.1112156,-0.88945514,0.77138287,-0.2277347,-0.3204974,-1.0097692,1.1380315,-0.29908472,-0.26464313,-0.09291552,-0.11513184,0.18034868,1.5229344,0.5449525,0.7799699,-0.2712314,0.6639894,-1.2485635,0.12834255,-0.5003735,0.6688103,0.7462489,-1.8927039,-1.028904,-0.13511267,0.12499248,2.2234087,1.3396404,-0.35824314,1.570159,0.80117834,-0.68948066,0.28778458,1.4059682,-0.063741624,-0.35473317,1.0221236,0.7081218,0.37306753,-0.74608916,-0.68817854,0.24516867,-0.66173905,-0.54008204,-0.7014247,1.1086363,-0.18418334,-0.29077473,1.8365557,0.39336658,0.6098118,-0.5753663,-0.055014554,0.31975943,-0.47278434,1.4162655,0.3092259,-0.29565468,0.5150045,-0.2373322,-0.86637175,0.29000008,-0.1035478,-0.4721478,-0.9239622,0.4135426,-0.32578072,-1.6004947,0.49107113,-0.5597222,0.2630474,0.5801494,0.273972,0.417284,-0.7461744,-0.4845118,0.56740946,1.3779873,-0.47697735,-0.8491038,0.8941511,0.10441427,0.9304285,-0.7939081,-0.7503219,0.5582691,-0.9255494,-0.583443,0.7146991,0.3041473,0.40966347,-0.45497432,-0.48693407,0.5165773,0.8395529,-0.9531754,-0.4596144,0.12688844,-1.5146754,-0.17743899,0.16893052,0.4749312,-0.6473629,-0.7074015,-0.43021148,-0.3952536,1.0683908,-0.016141996,-0.054593563,0.032366995,0.51909655,-0.115643375,1.23151,-0.1589585,-0.1021703,0.35315353,-1.2065532,0.009222155,0.19440041,0.00965816,0.6122984,-1.1574665,0.23792928,0.2953548,0.5