67	{"act": "IT_ACT_2000", "title": "Residuary Penalty", "doc_id": "ITACT_SEC_45", "topics": ["penalty", "residuary_penalty"], "entities": [], "keywords": ["residuary penalty", "contravention", "rules", "regulations", "twenty-five thousand rupees", "compensation"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": [], "clause_text": "Whoever contravenes any rules or regulations made under this Act, for the contravention of which no penalty has been separately provided, shall be liable to pay a compensation not exceeding twenty-five thousand rupees to the person affected by such contravention or a penalty not exceeding twenty-five thousand rupees.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 45 of the Information Technology Act 2000. A residuary penalty provision: whoever contravenes any rules or regulations made under the Act for which no separate penalty is prescribed shall be liable to pay compensation not exceeding Rs 25,000 to the affected person or a penalty not exceeding Rs 25,000.", "section_number": "45", "subsection_number": null, "validation_status": "validated", "plain_english_summary": "Any contravention of rules or regulations under the Act for which no specific penalty is provided attracts a residual compensation or penalty of up to Rs 25,000."}	[1.4820343,1.0361462,-3.4636922,-0.6429292,0.86082345,0.15619096,0.7802328,0.15665022,0.4514459,0.31739077,-0.12455173,0.23766622,0.3728839,-1.0106328,0.36942863,0.062357377,0.22020422,-0.7596552,-0.7347754,0.55450934,-0.08053381,-0.4487532,-1.4197206,0.4801141,1.1446927,0.3642572,1.7051241,-0.21780208,-0.92802304,-0.3527175,0.5161802,-0.17283066,0.34348568,-0.9833609,-0.73289925,-0.7046743,1.8530304,-0.26440954,-0.69911724,-0.60470587,0.64546394,-0.2421249,-0.19549827,-0.30719867,0.10719871,0.116663784,1.5829636,1.1758603,0.24656734,-0.14669396,0.08389376,-1.2747555,-0.8429923,-0.99506146,0.7567598,0.29709205,-1.8165833,-0.3057239,0.21791434,0.13