68	{"act": "IT_ACT_2000", "title": "Power to Adjudicate - Appointment of Adjudicating Officer", "doc_id": "ITACT_SEC_46_SUB_1", "topics": ["adjudication", "governance", "procedure"], "entities": ["Central Government", "adjudicating officer"], "keywords": ["adjudicating officer", "appointment", "Central Government", "Director rank", "contravention", "penalty", "compensation"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": [], "clause_text": "For the purpose of adjudging under this Chapter whether any person has committed a contravention of any of the provisions of this Act or of any rule, regulation, direction or order made thereunder which renders him liable to pay penalty or compensation, the Central Government shall, subject to the provisions of sub-section (3), appoint any officer not below the rank of a Director to the Government of India or an equivalent officer of a State Government to be an adjudicating officer for holding an inquiry in the manner prescribed by the Central Government.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 46(1) of the Information Technology Act 2000. The Central Government appoints an officer not below the rank of a Director to the Government of India, or an equivalent State Government officer, as adjudicating officer to adjudicate contraventions of the Act and determine liability for penalties or compensation. The adjudicating officer's jurisdiction is limited to claims not exceeding Rs 5 crore, with higher claims going to the competent court.", "section_number": "46", "subsection_number": "1", "validation_status": "validated", "plain_english_summary": "The Central Government appoints an officer of at least Director rank as adjudicating officer to conduct inquiries into contraventions of the Act and determine liability for penalties or compensation."}	[0.81900805,0.7981472,-3.1335013,-0.25882006,1.1421263,0.12918535,-0.37289804,0.646521,0.86369777,-0.37337574,0.1055