69	{"act": "IT_ACT_2000", "title": "Adjudicating Officer - Pecuniary Jurisdiction", "doc_id": "ITACT_SEC_46_SUB_1A", "topics": ["adjudication", "jurisdiction", "procedure"], "entities": ["adjudicating officer"], "keywords": ["pecuniary jurisdiction", "adjudicating officer", "five crore", "competent court", "claim"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": [], "clause_text": "The adjudicating officer appointed under sub-section (1) shall exercise jurisdiction to adjudicate matters in which the claim for injury or damage does not exceed rupees five crore: Provided that the jurisdiction in respect of the claim for injury or damage exceeding rupees five crores shall vest with the competent court.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 46(1A) of the Information Technology Act 2000. The adjudicating officer's jurisdiction is limited to claims for injury or damage not exceeding Rs 5 crore. Claims exceeding Rs 5 crore vest with the competent court. This creates a tiered adjudication framework.", "section_number": "46", "subsection_number": "1A", "validation_status": "validated", "plain_english_summary": "The adjudicating officer has jurisdiction over claims up to Rs 5 crore. Claims exceeding Rs 5 crore are within the jurisdiction of the competent court."}	[1.5335474,0.7275109,-3.3948703,-0.782099,1.1149901,0.0800747,0.01844122,0.61264324,0.8110942,-0.8526529,0.2601886,0.79607755,0.8911185,-1.2774726,0.4004637,-0.8853218,-0.44506755,-1.2477785,-0.34478474,-0.110504955,0.29828975,-0.83549356,-0.8932452,0.11545791,1.1648637,-0.23606426,1.4429542,-0.058759134,-0.4973193,0.50755,0.5416022,0.12908426,0.8604449,-0.6789191,-0.53248835,-0.8474257,1.0977447,0.54149467,-0.8602279,-0.38151368,0.9469925,-0.65717125,0.3778697,-0.07334879,-0.10376183,0.1339562,0.48540786,0.46735993,0.01075926,-0.37958723,-0.5689088,-1.3152801,-0.14622521,-1.1870501,0.22044018,0.22265244,-1.9506079,0.61699516,0.06451099,0.079