70	{"act": "IT_ACT_2000", "title": "Factors for Adjudicating Compensation", "doc_id": "ITACT_SEC_47", "topics": ["adjudication", "compensation", "procedure"], "entities": ["adjudicating officer"], "keywords": ["compensation", "adjudicating officer", "unfair advantage", "loss", "repetitive default", "quantum"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": [], "clause_text": "While adjudging the quantum of compensation under this Chapter, the adjudicating officer shall have due regard to the following factors, namely:— (a) the amount of gain of unfair advantage, wherever quantifiable, made as a result of the default; (b) the amount of loss caused to any person as a result of the default; (c) the repetitive nature of the default.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 47 of the Information Technology Act 2000. When adjudging the quantum of compensation, the adjudicating officer must consider: the amount of unfair advantage gained by the defaulter; the amount of loss caused to any person; and the repetitive nature of the default. These factors guide proportionate compensation awards.", "section_number": "47", "subsection_number": null, "validation_status": "validated", "plain_english_summary": "In determining the quantum of compensation, the adjudicating officer must consider the unfair advantage gained, the loss caused to any person, and whether the default is repetitive."}	[1.4673369,1.0784357,-3.1707237,-1.1770773,1.3762202,0.22836442,0.4053065,0.69309825,1.1140318,0.69821507,-0.28269958,0.8852756,0.9074168,0.20694005,1.0931557,-0.62270457,-0.31665263,-0.9243772,-0.32665426,0.16190061,0.53988844,-0.84260386,-1.3103714,0.056546178,0.5808586,0.62642014,0.66613525,0.09777721,-0.5699671,-0.035929933,-0.087201856,0.82508034,0.5755485,-0.7672262,-0.9550593,-0.30344364,1.5081447,0.78515404,-0.51656777,-0.10311096,-0.101504155,-0.10056879,0.062148184,-0.018984353,-0.04785959,0.018126965,1.3371431,1.