71	{"act": "IT_ACT_2000", "title": "Appellate Tribunal", "doc_id": "ITACT_SEC_48_SUB_1", "topics": ["governance", "appellate_tribunal", "appeals"], "entities": ["Appellate Tribunal", "Telecom Disputes Settlement and Appellate Tribunal"], "keywords": ["Appellate Tribunal", "TDSAT", "Telecom Disputes Settlement", "TRAI Act", "Finance Act 2017", "jurisdiction"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": [], "clause_text": "The Telecom Disputes Settlement and Appellate Tribunal established under section 14 of the Telecom Regulatory Authority of India Act, 1997, shall, on and from the commencement of Part XIV of Chapter VI of the Finance Act, 2017, be the Appellate Tribunal for the purposes of this Act and the said Appellate Tribunal shall exercise the jurisdiction, powers and authority conferred on it by or under this Act.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 48(1) of the Information Technology Act 2000. The Telecom Disputes Settlement and Appellate Tribunal (TDSAT) established under the TRAI Act 1997 functions as the Appellate Tribunal for the IT Act, with effect from the Finance Act 2017. It exercises all jurisdiction, powers and authority conferred on it under the IT Act.", "section_number": "48", "subsection_number": "1", "validation_status": "validated", "plain_english_summary": "The Telecom Disputes Settlement and Appellate Tribunal (TDSAT) serves as the Appellate Tribunal for the purposes of the IT Act, exercising all jurisdiction and powers conferred by the Act."}	[0.5883027,0.55190444,-3.7458289,-1.1024368,1.2030426,0.3453926,-0.03137696,0.24544576,0.43361506,-0.64769477,0.35028496,0.089988574,1.1046782,-1.2331065,-0.54642934,-0.9089786,-0.4819207,0.4591788,-0.8164586,-0.1059482,0.75220937,-1.1651845,-1.5456156,-0.37095627,1.295255,0.22489077,-0.014445528,0.6878617,-0.24077453,-0.7927147,1.4579731,-0.74741936,0.51605374,0.01970865,-1.0346243,-0.8578921,1.7014976,0.74295676,-1.5908