72	{"act": "IT_ACT_2000", "title": "Appeal to Appellate Tribunal", "doc_id": "ITACT_SEC_57_SUB_1", "topics": ["appeals", "procedure", "adjudication"], "entities": ["Appellate Tribunal", "Controller", "adjudicating officer"], "keywords": ["appeal", "Appellate Tribunal", "Controller", "adjudicating officer", "aggrieved person"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": [], "clause_text": "Save as provided in sub-section (2), any person aggrieved by an order made by controller or an adjudicating officer under this Act may prefer an appeal to a Appellate Tribunal having jurisdiction in the matter.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 57(1) of the Information Technology Act 2000. Any person aggrieved by an order made by the Controller or an adjudicating officer under the Act may prefer an appeal to the Appellate Tribunal having jurisdiction. No appeal lies from orders made with the consent of the parties.", "section_number": "57", "subsection_number": "1", "validation_status": "validated", "plain_english_summary": "Any person aggrieved by an order of the Controller or an adjudicating officer under the Act may appeal to the Appellate Tribunal, except where the order was made with the consent of the parties."}	[0.82218564,0.97704095,-2.992595,-0.57149196,1.1981615,0.24802136,-0.7391633,0.15527867,0.46159407,0.10995207,0.5490625,0.8429289,0.9044979,-0.46396258,-0.24887775,-0.38262105,0.21591228,-0.6797613,-0.8014164,-0.46337113,0.60387504,-1.311524,-1.0501864,0.14881353,0.8322584,-0.26220697,1.1653444,-0.4258733,-1.102277,-0.23799127,0.7801112,0.30323777,1.1433032,-0.88417006,-1.0810791,-1.0438598,0.90948796,-0.04344079,-1.4049662,0.011764137,0.663129,0.020504212,-0.23272283,-1.0997313,0.35215297,-0.21737124,0.7998132,0.8284425,-0.2667549,-0.703344,0.2910863,-1.2735039,-0.37995178,-1.2885754,0.18909033,0.32581723,-0.9377799,0.9371781,0.5298846,0.20281965,0.64609367,0.91191894,0.068596095,0.68