73	{"act": "IT_ACT_2000", "title": "Appeal - Limitation Period", "doc_id": "ITACT_SEC_57_SUB_3", "topics": ["appeals", "procedure", "limitation"], "entities": ["Appellate Tribunal"], "keywords": ["limitation period", "forty-five days", "appeal", "Appellate Tribunal", "condone delay", "prescribed form"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": [], "clause_text": "Every appeal under sub-section (1) shall be filed within a period of forty-five days from the date on which a copy of the order made by the Controller or the adjudicating officer is received by the person aggrieved and it shall be in such form and be accompanied by such fee as may be prescribed: Provided that the Appellate Tribunal may entertain an appeal after the expiry of the said period of forty-five days if it is satisfied that there was sufficient cause for not filing it within that period.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 57(3) of the Information Technology Act 2000. An appeal to the Appellate Tribunal must be filed within 45 days of receiving a copy of the Controller's or adjudicating officer's order, in the prescribed form and accompanied by the prescribed fee. The Appellate Tribunal may condone delay beyond the 45-day period if there was sufficient cause.", "section_number": "57", "subsection_number": "3", "validation_status": "validated", "plain_english_summary": "Appeals must be filed within 45 days of receiving the Controller's or adjudicating officer's order, in the prescribed form with prescribed fee. The Appellate Tribunal may condone delay for sufficient cause."}	[1.0772556,0.6233274,-3.525949,-1.0418185,0.77988976,-0.12756859,0.22815472,0.53286296,0.5220721,0.12747101,0.23471819,1.0796381,1.0012543,-0.36373907,0.01858947,-0.4504751,0.18333513,-0.7673692,-1.479555,-0.36983305,1.1133852,-1.1479734,-1.4972394,-0.071481496,0.63873667,-0.110584944,0.9015105,-0.31549042,-0.6695316,0.44858575,0.95895845,-0.3393