75	{"act": "IT_ACT_2000", "title": "Civil Court - Bar on Jurisdiction", "doc_id": "ITACT_SEC_61", "topics": ["restriction", "jurisdiction", "adjudication"], "entities": ["adjudicating officer", "Appellate Tribunal"], "keywords": ["bar on jurisdiction", "civil court", "adjudicating officer", "Appellate Tribunal", "injunction"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": [], "clause_text": "No court shall have jurisdiction to entertain any suit or proceeding in respect of any matter which an adjudicating officer appointed under this Act or the Appellate Tribunal constituted under this Act is empowered by or under this Act to determine and no injunction shall be granted by any court or other authority in respect of any action taken or to be taken in pursuance of any power conferred by or under this Act.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 61 of the Information Technology Act 2000. No civil court shall have jurisdiction to entertain any suit or proceeding in respect of any matter that the adjudicating officer or Appellate Tribunal is empowered to determine. No injunction may be granted by any court or authority in respect of any action taken or to be taken under powers conferred by the Act.", "section_number": "61", "subsection_number": null, "validation_status": "validated", "plain_english_summary": "Civil courts have no jurisdiction over matters within the jurisdiction of the adjudicating officer or Appellate Tribunal under this Act, and no court may grant an injunction against actions taken under the Act."}	[1.0936698,0.67308754,-2.6200693,-0.2132093,0.7509716,0.9888116,-0.18882006,0.60727453,0.10294223,-0.98927784,1.140961,1.0900406,0.33253255,-0.9234313,-0.6664221,-0.38105512,-0.06510864,-0.6363639,-0.70479876,-0.24120146,0.55697984,-1.234676,-0.79409987,-0.024331875,0.9901872,-0.112109676,2.073171,-0.14680515,-1.2947227,-0.565661,0.39171878,0.40180966,1.2867585,-0.93143874,-0.7413304