76	{"act": "IT_ACT_2000", "title": "Appeal to High Court", "doc_id": "ITACT_SEC_62", "topics": ["appeals", "procedure"], "entities": ["Appellate Tribunal", "High Court"], "keywords": ["High Court", "appeal", "sixty days", "Appellate Tribunal", "question of law", "question of fact"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": [], "clause_text": "Any person aggrieved by any decision or order of the Appellate Tribunal may file an appeal to the High Court within sixty days from the date of communication of the decision or order of the Appellate Tribunal to him on any question of fact or law arising out of such order.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 62 of the Information Technology Act 2000. Any person aggrieved by a decision or order of the Appellate Tribunal may file an appeal to the High Court within sixty days from the date of communication of the decision or order, on any question of fact or law. The High Court may allow an appeal filed after sixty days if the appellant demonstrates sufficient cause for the delay.", "section_number": "62", "subsection_number": null, "validation_status": "validated", "plain_english_summary": "Any person aggrieved by an order of the Appellate Tribunal may appeal to the High Court within 60 days on any question of fact or law, with provision for condonation of delay."}	[1.4264092,0.9167679,-3.3864079,-0.3781618,0.9014316,0.37672606,-0.09717977,0.77684367,0.23036286,0.23130946,0.21447653,1.3978487,0.9817085,-0.095814474,-0.061104797,-0.35748577,0.43387172,-1.0553882,-1.6819707,-0.18340744,0.35904396,-0.5931723,-1.0864985,0.16450107,0.46583354,-0.1890822,1.3132981,-0.69419837,-0.3610212,0.64735335,0.7463353,-0.3971126,0.71840304,-0.5122144,-0.6558513,-0.8172861,0.6068875,-0.73215955,-0.75893396,-1.0505037,0.9227652,-1.2486196,0.4826185,-0.84743327,0.6994926,-0.20831315,1.5951949,0.72167563,-0.817473,-1.2386518,0.5969466,-1.2342813,-0.5357902,-0.42619577