77	{"act": "IT_ACT_2000", "title": "Tampering with Computer Source Documents", "doc_id": "ITACT_SEC_65", "topics": ["cyber_offence", "penalty", "computer_source_code"], "entities": [], "keywords": ["computer source code", "tampering", "concealment", "destruction", "alteration", "imprisonment", "two lakh rupees"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": [], "clause_text": "Whoever knowingly or intentionally conceals, destroys or alters or intentionally or knowingly causes another to conceal, destroy, or alter any computer source code used for a computer, computer programme, computer system or computer network, when the computer source code is required to be kept or maintained by law for the time being in force, shall be punishable with imprisonment up to three years, or with fine which may extend up to two lakh rupees, or with both.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 65 of the Information Technology Act 2000. Whoever knowingly or intentionally conceals, destroys or alters computer source code required to be kept or maintained by law, or causes another to do so, shall be punished with imprisonment for up to three years or a fine up to Rs 2 lakh or both. Computer source code means the listing of programmes, computer commands, design, layout, and programme analysis of a computer resource.", "section_number": "65", "subsection_number": null, "validation_status": "validated", "plain_english_summary": "Knowingly concealing, destroying, or altering computer source code that is required to be maintained by law is punishable with imprisonment up to three years or a fine up to Rs 2 lakh, or both."}	[1.3966137,0.82640743,-2.7706635,-0.56494063,0.9672748,0.060344342,-0.16357407,1.2000506,-0.70233876,0.13483799,-0.16340622,0.8220584,0.76103824,0.0582042,-0.015501194,-0.6382847,-0.06891804,-0.44590142,-0.540264,0.74053234,0.31069332,-1.278834,-0.6949369,-0.44936225,1.098295,-0.2698139,1.0443274,-