78	{"act": "IT_ACT_2000", "title": "Computer Related Offences", "doc_id": "ITACT_SEC_66", "topics": ["cyber_offence", "penalty", "unauthorised_access"], "entities": [], "keywords": ["computer related offence", "dishonestly", "fraudulently", "section 43", "imprisonment", "five lakh rupees"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": ["ITACT_SEC_43"], "clause_text": "If any person, dishonestly or fraudulently, does any act referred to in section 43, he shall be punishable with imprisonment for a term which may extend to three years or with fine which may extend to five lakh rupees or with both.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 66 of the Information Technology Act 2000. Whoever dishonestly or fraudulently commits any act described in section 43 — including unauthorised access, downloading or extracting data, introducing computer contaminants or viruses, damaging, disrupting, or denying access to computer systems — shall be punished with imprisonment for up to three years or a fine up to Rs 5 lakh or both.", "section_number": "66", "subsection_number": null, "validation_status": "validated", "plain_english_summary": "Any person who dishonestly or fraudulently commits any of the acts listed in section 43 (such as unauthorised access, data theft, introducing viruses) is punishable with imprisonment up to three years or a fine up to Rs 5 lakh, or both."}	[1.417245,1.3975028,-3.482584,-0.091386706,1.0218171,-0.0065929457,-0.02051956,0.96940506,0.6719803,0.24333906,-0.3190907,1.3089283,0.3885134,-0.52246773,-0.11214055,-0.5578563,0.14598702,-0.81353104,-0.5654896,0.22439225,0.52115107,-0.2040621,-1.1534745,-0.59263515,1.0916897,-0.31713656,0.95783603,-0.1569585,-0.32251313,0.22953202,1.0154151,-0.1764043,-0.19305672,-0.6161492,-1.187284,-1.2256109,0.58421886,-0.057118043,-0.461544,-0.5178524,0.567453,0.29308167,-0.5241465,-0.65890855,-0.10906946,0.10731103,0.6211498,-0.018522412,0.6173624,-