84	{"act": "IT_ACT_2000", "title": "Punishment for Publishing Obscene Material in Electronic Form", "doc_id": "ITACT_SEC_67", "topics": ["cyber_offence", "obscene_content", "penalty"], "entities": [], "keywords": ["obscene material", "electronic form", "lascivious", "prurient interest", "deprave", "corrupt", "publish", "transmit", "imprisonment"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": [], "clause_text": "Whoever publishes or transmits or causes to be published or transmitted in the electronic form, any material which is lascivious or appeals to the prurient interest or if its effect is such as to tend to deprave and corrupt persons who are likely, having regard to all relevant circumstances, to read, see or hear the matter contained or embodied in it, shall be punished on first conviction with imprisonment of either description for a term which may extend to three years and with fine which may extend to five lakh rupees and in the event of second or subsequent conviction with imprisonment of either description for a term which may extend to five years and also with fine which may extend to ten lakh rupees.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 67 of the Information Technology Act 2000. Whoever publishes or transmits or causes to be published or transmitted in electronic form any lascivious material or material that appeals to the prurient interest or tends to deprave and corrupt persons shall be punished on first conviction with imprisonment up to three years and a fine up to Rs 5 lakh, and on second or subsequent conviction with imprisonment up to five years and a fine up to Rs 10 lakh.", "section_number": "67", "subsection_number": null, "validation_status": "validated", "plain_english_summary": "Publishing or transmitting obscene material in electronic form is punishable with imprisonment up to 3 years and a fine up to Rs 5 lakh on first conviction, and up to 5 years and Rs 10 lakh on subsequent conviction."}	[1.5405235,1.2154337,-3.4641242,-0.4024665,0.856833,-0.28690448,-0.4563864,0.5918855,-0.24240321,0.2731209,0.35418594,1.0728134,0.856233,-0.08311134,-0.0828045,-0.33839792,0.490656,-0.83659416,-0.54306203,0.19285029,-0.3217213,-0.48977843,-1.1624367,-0.5777485,0.28453904,-0.14370719,1.0591931,-0.43642113,-0.5273753,0.23047486,0.5485764,-0.5661965,-0.3831984,-0.28751045,-0.76560986,-1.0407181,0.8972704,-0.2927926,-0.6584362,-0.057542577,1.2998852,0.06716374,-0.94636935,-0.6805515,0.23353973,-0.49122003,0.30403137,-0.13166991,0.619682,-1.1779482,0.018040698,-1.3324068,0.23458537,-0.8166823,1.2862183,0.5278857,-2.2032382,-0.68760836,0.110235505,-0.13365725,1.1754704,0.8027843,-0.9634866,1.6545821,0.95600694,-0.875926,0.12048139,1.727634,-0.15676224,-0.498951,1.0808688,-0.28174037,0.68353957,-0.06513326,0.10730938,-0.66556305,-0.60021317,-0.48819292,0.08547132,1.0933291,0.0764628,-0.52195495,1.153557,0.19129282,0.6294326,-0.7495452,0.14297898,-0.21754873,-0.5976548,1.0476999,0.6491255,-0.29288983,0.59339136,-0.1182197,-0.51733035,-0.39309594,0.38404474,0.27149838,-0.86993706,-0.1925488,-0.24083146,-0.9171179,1.2229278,-0.08330415,0.33600187,1.0784622,0.14095108,-0.2740025,-0.46223766,-0.37211755,0.65380853,0.640875,-0.5411348,-0.6366966,0.6510521,0.64047384,1.2351407,-0.79852194,-0.27845135,0.68120015,-0.45902437,-0.07734743,0.22207199,0.9704751,0.6181292,-0.41753474,-0.2254065,0.1721961,-0.19237314,-1.6098253,-0.48622864,0.31728426,-0.3455739,-0.3556119,0.08525895,1.0008953,0.025215985,-0.64532197,-0.33025625,-0.16966817,1.1396395,-0.4775394,0.022516515,0.5329752,0.12506504,-0.23109867,0.72815925,-0.14561354,-0.24690378,0.6794133,-0.9968091,0.4012545,0.6179575,-0.03918699,0.4802584,-1.0615282,0.5284894,0.53760356,0.5678427,-0.059504654,0.5151709,0.89973587,-0.30419397,1.5239924,-1.344962,0.1636283,-0.9683357,1.3973051,-0.0906212,0.19797854,-1.5640155,0.35736707,-0.5629884,-0.081010774,0.51793075,-0.51886374,-0.067635454,-1.2752621,-0.0823