79	{"act": "IT_ACT_2000", "title": "Punishment for Dishonestly Receiving Stolen Computer Resource", "doc_id": "ITACT_SEC_66B", "topics": ["cyber_offence", "penalty"], "entities": [], "keywords": ["stolen computer resource", "communication device", "dishonestly", "receiving", "imprisonment", "one lakh rupees"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": [], "clause_text": "Whoever dishonestly receive or retains any stolen computer resource or communication device knowing or having reason to believe the same to be stolen computer resource or communication device, shall be punished with imprisonment of either description for a term which may extend to three years or with fine which may extend to rupees one lakh or with both.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 66B of the Information Technology Act 2000. Whoever dishonestly receives or retains any stolen computer resource or communication device, knowing or having reason to believe it is stolen, shall be punished with imprisonment for up to three years or a fine up to Rs 1 lakh or both.", "section_number": "66B", "subsection_number": null, "validation_status": "validated", "plain_english_summary": "Dishonestly receiving or retaining a stolen computer resource or communication device is punishable with imprisonment up to three years or a fine up to Rs 1 lakh, or both."}	[1.6280218,1.0559556,-3.279015,-0.062164664,1.3341352,-0.0047505177,-0.07350596,0.8250102,0.39422223,0.561346,-0.5818953,0.8400283,0.0910287,-1.024887,-0.14498565,-0.31736276,0.27489147,-0.6360968,-0.53864056,0.52513963,0.39638442,0.12648977,-1.3445526,-0.62984025,0.7657174,-0.37999856,1.1733181,-0.03921484,-0.2069482,-0.2336997,1.018834,-0.672497,-0.7233139,-0.26161423,-1.4756113,-0.7569728,0.5373499,-0.7810365,-0.7638496,-0.11140296,0.37168196,0.2398016,-0.80321985,-0.24430296,0.706617,0.38380456,0.59393483,-0.5528848,1.0522763,-0.74350816,0.25233823,-1.1822634,0.24801949,