80	{"act": "IT_ACT_2000", "title": "Punishment for Identity Theft", "doc_id": "ITACT_SEC_66C", "topics": ["cyber_offence", "identity_theft", "penalty"], "entities": [], "keywords": ["identity theft", "electronic signature", "password", "unique identification", "fraudulently", "dishonestly", "imprisonment"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": [], "clause_text": "Whoever, fraudulently or dishonestly make use of the electronic signature, password or any other unique identification feature of any other person, shall be punished with imprisonment of either description for a term which may extend to three years and shall also be liable to fine which may extend to rupees one lakh.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 66C of the Information Technology Act 2000. Whoever fraudulently or dishonestly uses the electronic signature, password or any other unique identification feature of any other person is guilty of identity theft and shall be punished with imprisonment for up to three years and also a fine up to Rs 1 lakh.", "section_number": "66C", "subsection_number": null, "validation_status": "validated", "plain_english_summary": "Fraudulently or dishonestly using another person's electronic signature, password, or unique identification feature constitutes identity theft, punishable with imprisonment up to three years and a fine up to Rs 1 lakh."}	[0.9350407,0.85552967,-3.2404199,0.15458104,1.3484771,-0.07825792,-0.12392315,0.9166472,0.47528517,0.56406635,-1.3637408,0.6860455,0.6429723,-1.0909444,-0.042042434,-0.32822567,0.6353964,-0.7975125,0.015645478,0.31633392,0.04009336,0.22779386,-1.2947905,-0.36325967,1.1789913,-1.0431155,1.5977519,-0.13183717,-0.4098803,-0.31897292,1.0555896,0.045503184,-0.11430311,-0.35413477,-1.2917342,-0.6586146,0.48209426,0.16673464,-0.49278817,-0.10593163,0.42003715,0.5724307,-0.7391747,-0.3502222,0.13083856,0.4920895,0.6011987,-0.2255118,0.967715,-0.4153137