81	{"act": "IT_ACT_2000", "title": "Punishment for Cheating by Personation Using Computer Resource", "doc_id": "ITACT_SEC_66D", "topics": ["cyber_offence", "personation", "fraud", "penalty"], "entities": [], "keywords": ["cheating by personation", "computer resource", "communication device", "impersonation", "fraud", "imprisonment"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": [], "clause_text": "Whoever, by means of any communication device or computer resource cheats by personation, shall be punished with imprisonment of either description for a term which may extend to three years and shall also be liable to fine which may extend to one lakh rupees.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 66D of the Information Technology Act 2000. Whoever cheats by personation using any communication device or computer resource shall be punished with imprisonment for up to three years and a fine up to Rs 1 lakh. This covers online impersonation fraud conducted through computers or mobile devices.", "section_number": "66D", "subsection_number": null, "validation_status": "validated", "plain_english_summary": "Cheating by impersonating another person using a computer resource or communication device is punishable with imprisonment up to three years and a fine up to Rs 1 lakh."}	[1.1140181,1.1387092,-3.489286,0.12949432,1.0817496,0.12809727,0.35688207,0.8166946,0.45321125,0.7593713,-0.6919724,0.5898709,0.120131075,-0.73645234,-0.57430094,-0.4605971,0.68454623,-1.6260281,-0.83579725,0.7256447,-0.18496494,-0.24632592,-1.5168827,-0.36973697,0.84906745,-0.23614565,1.2184714,-0.068655424,-0.49050435,-0.08591555,0.9059142,-0.21592999,-0.26903144,-0.024538526,-1.1393851,-0.3808423,0.3141851,-0.32880086,-0.17477898,-0.5112236,0.54153645,0.24071927,-0.6623664,-0.022926439,0.50192726,0.19555748,0.7339876,-0.2172356,0.7583899,-1.06145,-0.09823853,-1.411681,0.26617345,-0.88875794,1.064018,0.3292834,-1.9487389,-0.21981