82	{"act": "IT_ACT_2000", "title": "Punishment for Violation of Privacy", "doc_id": "ITACT_SEC_66E", "topics": ["cyber_offence", "privacy_violation", "penalty"], "entities": [], "keywords": ["privacy violation", "private area", "image", "without consent", "capture", "publish", "transmit", "imprisonment"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": [], "clause_text": "Whoever, intentionally or knowingly captures, publishes or transmits the image of a private area of any person without his or her consent, under circumstances violating the privacy of that person, shall be punished with imprisonment which may extend to three years or with fine not exceeding two lakh rupees, or with both.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 66E of the Information Technology Act 2000. Whoever intentionally or knowingly captures, publishes or transmits images of a private area of any person without their consent, under circumstances violating that person's privacy, shall be punished with imprisonment for up to three years or a fine not exceeding Rs 2 lakh or both. Private area means the naked or undergarment-clad genitals, pubic area, buttocks or female breast.", "section_number": "66E", "subsection_number": null, "validation_status": "validated", "plain_english_summary": "Intentionally capturing, publishing, or transmitting images of a person's private areas without consent, in circumstances violating their privacy, is punishable with imprisonment up to three years or a fine up to Rs 2 lakh, or both."}	[0.9284325,1.3204743,-3.1291404,-0.5131166,0.46668693,0.4320365,-0.13703544,0.47573367,0.31559005,0.28529394,-0.17127545,1.1751775,1.1175597,-0.6204129,-0.1048206,-0.95934135,-0.024960909,-1.1423275,-0.28574306,-0.009790075,-0.718789,0.6310839,-0.68867075,0.19460799,1.0378898,-0.66572416,2.0379941,-0.029073058,0.13628969,0.25285727,0.57284456,-0.1786486,-0.26617277,-0.3440837,-0.7416146,-1.687905,0.3592676,-0.