83	{"act": "IT_ACT_2000", "title": "Punishment for Cyber Terrorism", "doc_id": "ITACT_SEC_66F", "topics": ["cyber_offence", "cyber_terrorism", "national_security", "penalty"], "entities": [], "keywords": ["cyber terrorism", "critical information infrastructure", "sovereignty", "unauthorised access", "computer contaminant", "imprisonment for life", "national security"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": ["ITACT_SEC_70"], "clause_text": "Whoever with intent to threaten the unity, integrity, security or sovereignty of India or to strike terror in the people by denying or causing denial of access to any authorised person, attempting to penetrate or access a computer resource without authorisation, or introducing computer contaminants, and by means of such conduct causes or is likely to cause death or injuries to persons or damage to property or disrupts supplies or services essential to the community or adversely affects the critical information infrastructure; or knowingly or intentionally penetrates or accesses a computer resource without authorisation and obtains restricted information that may be used to cause injury to the sovereignty and integrity of India, commits the offence of cyber terrorism. Whoever commits or conspires to commit cyber terrorism shall be punishable with imprisonment which may extend to imprisonment for life.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 66F of the Information Technology Act 2000. Cyber terrorism is committed by anyone who with intent to threaten India's unity, integrity, security or sovereignty, or to strike terror, denies access to authorised users, penetrates computer resources without authorisation, or introduces contaminants causing or likely to cause death, injury, property damage, disruption of essential services, or affecting critical information infrastructure. Also covers unauthorised access to restricted State information that may harm India's sovereignty, security or foreign relations. Punishment is imprisonment for life.", "section_number": "66F", "subsection_number": null, "validation_status": "validated", "plain_english_summary": "Cyber terrorism — attacking computer systems to threaten national security, sovereignty, public order, or critical infrastructure, or obtaining restricted government information through unauthorised access — is punishable with imprisonment for life."}	[1.4682547,1.6188059,-3.3582215,0.3684599,2.1312907,0.354144,0.026949061,0.78806895,0.40249264,-0.26181674,-0.024202304,0.7099672,0.918495,-1.0464389,-0.23643908,-1.1528133,0.3630666,0.1561567,-0.42968777,0.7268962,0.047120053,-0.35672823,-0.5740937,-0.4977726,1.0928127,-0.28926814,1.6120219,-0.103210256,-0.7908734,0.30561358,1.3127402,-0.36811137,-0.46978843,-0.0564509,-0.8139027,-1.3848987,0.28927127,0.16940252,-1.1403316,-0.5200834,0.52153474,0.40807113,-0.17977127,-0.79242694,-0.45786116,0.58727765,0.40329418,-0.2124832,0.5120105,-1.4175694,-0.26090497,-1.5797763,0.25226805,-1.6835456,0.50541604,0.2088821,-1.8609273,-0.07183022,0.096668586,-0.14152032,1.9290102,1.364068,-0.51449555,0.86367685,0.4968018,-0.88773954,-0.87492925,1.0493474,0.058018733,-0.47571355,1.4243153,-0.47348526,0.323012,0.37648875,-0.3287487,-0.7875346,-0.57899994,-0.96600217,0.17884105,1.2703158,-0.06569096,-0.66272783,1.4018168,-0.34228313,0.7204973,0.06787583,-0.75420773,-0.11200143,-0.19142407,1.571973,0.41391578,0.04693188,0.59631103,-0.038196467,-0.42201614,0.026497208,0.08710555,0.23044556,-0.4393601,-0.51911485,0.15180752,-0.6059989,0.6449929,-0.7807012,0.27942306,0.6509658,0.45066044,-0.7174784,-0.39147192,0.04951508,0.72109,0.19367093,-0.5742852,-0.3316247,1.3038824,0.4816975,0.78714687,-1.254432,-0.040833604,0.2534669,-0.15186447,-0.31911755,-0.26032504,1.0644807,1.1224625,-0.73196906,-0.5824791,0.7321216,0.3242106,-1.4857328,-0.71984994,0.43055812,-0.6772745,-0.37614128,-0.3325505,0.47841582,-0.54936486,-1.1985619,-0.36517057,0.341750