85	{"act": "IT_ACT_2000", "title": "Punishment for Publishing Sexually Explicit Material in Electronic Form", "doc_id": "ITACT_SEC_67A", "topics": ["cyber_offence", "sexually_explicit_content", "penalty"], "entities": [], "keywords": ["sexually explicit", "electronic form", "publish", "transmit", "imprisonment", "ten lakh rupees"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": [], "clause_text": "Whoever publishes or transmits or causes to be published or transmitted in the electronic form any material which contains sexually explicit act or conduct shall be punished on first conviction with imprisonment of either description for a term which may extend to five years and with fine which may extend to ten lakh rupees and in the event of second or subsequent conviction with imprisonment of either description for a term which may extend to seven years and also with fine which may extend to ten lakh rupees.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 67A of the Information Technology Act 2000. Whoever publishes or transmits or causes to be published or transmitted in electronic form any material containing sexually explicit acts or conduct shall be punished on first conviction with imprisonment for up to five years and a fine up to Rs 10 lakh, and on second or subsequent conviction with imprisonment for up to seven years and a fine up to Rs 10 lakh.", "section_number": "67A", "subsection_number": null, "validation_status": "validated", "plain_english_summary": "Publishing or transmitting sexually explicit material in electronic form attracts imprisonment up to 5 years and a fine up to Rs 10 lakh on first conviction, and up to 7 years and Rs 10 lakh on subsequent conviction."}	[1.6219321,1.2782863,-3.439028,-0.05835875,0.45806885,-0.059444062,-0.16693197,0.42995757,-0.19618197,0.36039212,0.22186245,0.791097,0.80606186,-0.22992,-0.36782825,-0.75464875,0.6683231,-1.2093165,-1.1094004,0.055467285,-0.1199