86	{"act": "IT_ACT_2000", "title": "Punishment for Publishing Child Sexually Explicit Material in Electronic Form", "doc_id": "ITACT_SEC_67B", "topics": ["cyber_offence", "child_protection", "sexually_explicit_content", "penalty"], "entities": [], "keywords": ["child sexually explicit material", "CSAM", "children", "electronic form", "publish", "download", "imprisonment", "child abuse"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": [], "clause_text": "Whoever publishes or transmits or causes to be published or transmitted material in any electronic form which depicts children engaged in sexually explicit act or conduct; or creates text or digital images, collects, seeks, browses, downloads, advertises, promotes, exchanges or distributes material depicting children in obscene or indecent or sexually explicit manner; or cultivates, entices or induces children to online relationship for sexually explicit purposes; or facilitates abusing children online; or records own abuse or that of others pertaining to sexually explicit act with children, shall be punished on first conviction with imprisonment for a term which may extend to five years and with fine which may extend to ten lakh rupees and in the event of second or subsequent conviction with imprisonment which may extend to seven years and fine up to ten lakh rupees.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 67B of the Information Technology Act 2000. Offences relating to child sexually explicit material in electronic form include publishing, transmitting, creating, collecting, downloading, advertising, promoting, exchanging or distributing such material, cultivating or enticing children for online sexual relationships, facilitating child abuse online, and recording sexual abuse of children. Punishment on first conviction is imprisonment up to five years and a fine up to Rs 10 lakh; on subsequent conviction, up to seven years and Rs 10 lakh. Children means persons under 18 years.", "section_number": "67B", "subsection_number": null, "validation_status": "validated", "plain_english_summary": "Publishing, distributing, creating, browsing, or downloading child sexually explicit material in electronic form, or facilitating or recording child sexual abuse online, is punishable with imprisonment up to 5 years and a fine up to Rs 10 lakh on first conviction, and up to 7 years on subsequent conviction."}	[1.3956525,1.4107769,-3.1659055,-0.42188773,0.2770574,0.56755596,0.062238317,0.42697594,-0.15535629,0.25296682,-0.6347625,0.5060637,1.100508,-0.13161749,-0.92576504,-0.8464759,0.039667103,-1.135727,-0.8920368,0.5027345,0.001877553,-0.4043667,-0.7749564,0.075805314,0.9289047,-0.21756668,1.1410581,-0.33630204,-0.53889614,0.1355993,1.2997612,0.05004618,-0.2227246,0.17718223,-1.3554415,-0.9969963,0.27593872,-0.60239977,-0.98289627,-0.45732832,1.160473,0.28362685,-0.6299265,-0.19151461,-0.14103499,-0.6526878,0.2651151,-0.10079814,0.9752779,-0.8434943,0.37640592,-1.3888905,0.8908455,-1.0671489,1.6981455,0.5762606,-1.815303,-0.6568223,-0.21650779,-0.025648545,1.8545417,1.4177101,-1.0240275,1.5911996,0.863668,-0.7565291,-0.10290658,1.5181693,-0.078114614,0.011701012,1.3106093,-0.752203,0.7120369,-0.17507602,0.1575098,-1.1624954,-0.61252046,-0.6747241,0.49371815,1.561439,0.6565042,-0.14517687,0.5683765,0.50003314,0.7504882,-0.34550655,0.027500829,0.4515285,-0.65224123,0.8692467,0.39695552,0.19467449,0.24225698,-0.13026768,-0.38325053,-0.5606106,0.4547087,0.51824117,-0.47961298,0.107505985,-0.22660908,-0.7623625,1.1973038,0.37635148,0.6988513,0.8344744,0.28202838,0.11187477,-0.41648352,-0.042391874,0.6933534,0.46041286,-0.18095425,-0.6989122,0.8493365,0.8308384,0.6639004,-0.8587718,0.36117965,0.09187755,-0.5229042,-0.34025896,0.42151684,0.70699954,0.61805123,-0.45478964,-0.3458608,0.1959803,-0.60316324,-1.835778,-0.031324357,0.44672608,-0.3525323,-1.1699656,0.62961394,1.0343462,0.4902996,-1.0165542,-0.28529987,0.3774659,0.4