87	{"act": "IT_ACT_2000", "title": "Preservation and Retention of Information by Intermediaries", "doc_id": "ITACT_SEC_67C", "topics": ["intermediary", "obligation", "data_retention", "penalty"], "entities": ["intermediary", "Central Government"], "keywords": ["intermediary", "data retention", "preservation", "information retention", "Central Government", "prescribed", "imprisonment"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": [], "clause_text": "Intermediary shall preserve and retain such information as may be specified for such duration and in such manner and format as the Central Government may prescribe. Any intermediary who intentionally or knowingly contravenes the provisions of sub-section (1) shall be punished with an imprisonment for a term which may extend to three years and also be liable to fine.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 67C of the Information Technology Act 2000. Intermediaries are obligated to preserve and retain information as specified by the Central Government in terms of duration, manner and format. Intentional or knowing contravention of this preservation and retention obligation is punishable with imprisonment for up to three years and a fine.", "section_number": "67C", "subsection_number": null, "validation_status": "validated", "plain_english_summary": "Intermediaries must preserve and retain specified information for the duration, manner, and format prescribed by the Central Government. Intentional contravention is punishable with imprisonment up to three years and a fine."}	[1.300768,0.6104766,-3.3026068,-1.2789717,1.4475615,-0.41635844,-0.34277984,0.8569351,0.36580902,0.5176109,-0.6316555,0.2714644,-0.19546616,-0.8015761,0.23297049,-0.6322748,0.9214496,-0.6765278,-0.2054463,0.3643497,-0.21713851,-0.6797284,-0.28523013,0.2936028,0.47629467,-0.06685661,1.4679263,-0.36447608,-0.3351834,-0.2656666,0.76549155,-0.052625846,0.5193677,-0.32777718,-1.2675571