88	{"act": "IT_ACT_2000", "title": "Power to Issue Directions for Interception, Monitoring or Decryption", "doc_id": "ITACT_SEC_69_SUB_1", "topics": ["surveillance", "national_security", "interception", "procedure"], "entities": ["Central Government", "State Government"], "keywords": ["interception", "monitoring", "decryption", "computer resource", "national security", "sovereignty", "cognizable offence", "government direction"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": [], "clause_text": "Where the Central Government or a State Government or any of its officers specially authorised by the Central Government or the State Government, as the case may be, in this behalf may, if satisfied that it is necessary or expedient so to do, in the interest of the sovereignty or integrity of India, defence of India, security of the State, friendly relations with foreign States or public order or for preventing incitement to the commission of any cognizable offence relating to above or for investigation of any offence, it may subject to the provisions of sub-section (2), for reasons to be recorded in writing, by order, direct any agency of the appropriate Government to intercept, monitor or decrypt or cause to be intercepted or monitored or decrypted any information generated, transmitted, received or stored in any computer resource.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 69(1) of the Information Technology Act 2000. The Central or State Government may, for reasons recorded in writing, direct any government agency to intercept, monitor or decrypt information in any computer resource when necessary in the interest of the sovereignty or integrity of India, defence, State security, friendly relations with foreign States, public order, or for preventing incitement to or investigation of cognizable offences, subject to prescribed procedures and safeguards.", "section_number": "69", "subsection_number": "1", "validation_status": "validated", "plain_english_summary": "The Central Government or State Government may direct interception, monitoring, or decryption of any information in a computer resource in the interest of national security, public order, or for preventing or investigating cognizable offences, subject to safeguards and written reasons."}	[0.29369104,0.500002,-3.0454412,-0.29171506,1.6217059,0.14094678,-0.06928118,0.8147388,0.5109563,-0.3393399,0.4536263,1.1051924,0.66558236,-0.5727075,-0.110491455,-0.20051943,0.86418766,-0.51819223,-0.332175,0.916929,0.7519696,-0.15878889,-0.86403286,0.45030326,1.0613493,-0.27017087,1.6061368,-0.19766967,-0.5303158,-0.6014865,0.61487466,-0.44262087,0.13202648,-0.8241997,-0.35826156,-1.8699782,0.19859718,-0.46038112,-1.3241854,-0.2447147,0.7722782,0.4124656,-0.43567836,-1.2520149,0.3740605,0.25824082,0.72188634,-0.53648335,1.0574119,-1.2072669,0.14513598,-1.3230501,-0.074959904,-1.3651892,0.5720447,0.58221763,-1.2498235,-0.2996713,0.67554593,-0.57084966,1.8439436,0.8136963,-0.6275112,0.41961232,0.24563316,-0.43132213,-0.45428237,1.2377752,-0.3268198,-0.16512163,1.1971414,-0.53048694,1.1184832,-0.021617623,0.1391652,-0.4290706,-0.48183525,-0.8257559,0.36334476,0.70693,0.42868805,-0.7531786,1.2286288,-0.32269123,0.7318161,0.003180298,-0.7445522,-0.32252583,-0.32507315,1.5330372,0.25136814,-0.46063083,0.9731793,-0.14860895,0.19655544,0.46285298,0.2407182,-0.33783317,-0.16595368,-0.02297549,-0.29767472,-0.39911214,0.7893423,-0.8084201,0.8207069,0.22352692,-0.5357632,-0.4067549,-0.50772417,-0.39261997,0.6287776,0.655564,-1.0032283,-0.52945197,1.2627085,0.6717078,1.7274851,-1.3496604,0.105471276,0.463321,-0.6724831,0.12352958,-0.31232587,0.37153965,0.61237854,-0.6788569,-1.0461915,0.24144368,-0.22897801,-1.0523406,-0.32037622,0.38612348,-1.0528073,0.11494364,0.05642205,0.41122726,-0.8195155,-0.81174177,0.59293383,0.17116664,0.65746886,0.32435352,-0.41804406,-0.054686524,1.2144313,-0.5566858,1.041352,0.2512848,-0.32654762,0.06033