93	{"act": "IT_ACT_2000", "title": "Protected System - Unauthorised Access Penalty", "doc_id": "ITACT_SEC_70_SUB_3", "topics": ["penalty", "protected_system", "unauthorised_access", "critical_information_infrastructure"], "entities": [], "keywords": ["protected system", "unauthorised access", "imprisonment", "ten years", "fine", "Critical Information Infrastructure"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": ["ITACT_SEC_70_SUB_1"], "clause_text": "Any person who secures access or attempts to secure access to a protected system in contravention of the provisions of this section shall be punished with imprisonment of either description for a term which may extend to ten years and shall also be liable to fine.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 70(3) of the Information Technology Act 2000. Any person who secures or attempts to secure access to a protected system (a computer resource affecting Critical Information Infrastructure declared by the appropriate Government) in contravention of the Act shall be punished with imprisonment for up to ten years and a fine.", "section_number": "70", "subsection_number": "3", "validation_status": "validated", "plain_english_summary": "Unauthorised access or attempted access to a protected system is punishable with imprisonment up to ten years and a fine."}	[1.1681062,1.388044,-2.9111288,-0.43944857,0.70436823,0.51205105,-0.27134115,1.1282233,0.5542897,0.09310026,-0.24789107,0.71285,-0.4203353,-1.0014364,0.22732523,-0.32046372,0.49682656,-0.5446335,-0.5726439,-0.6772339,0.34967294,-1.3031433,-1.3895855,-0.13003674,0.85669434,0.6744361,1.5855786,-0.41512015,-0.9806568,-0.095873356,0.8646409,-0.2426138,-0.07965356,-0.5465421,-1.2433815,-1.4324319,0.2329602,0.05897344,-0.50710285,-0.05073525,0.91632056,0.4368548,-0.2847015,-0.29773477,0.15295388,-0.047150195,0.69650424,0.2688541,0.15127668,-0.7058416,0.686052,-1.028221,0.1100316,-0.844935,0.8952836,0.38