89	{"act": "IT_ACT_2000", "title": "Subscriber and Intermediary Obligation to Assist Interception", "doc_id": "ITACT_SEC_69_SUB_3", "topics": ["obligation", "intermediary", "surveillance", "compliance_requirement"], "entities": ["subscriber", "intermediary"], "keywords": ["technical assistance", "subscriber", "intermediary", "computer resource", "interception", "monitoring", "decryption", "government agency"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": ["ITACT_SEC_69_SUB_1"], "clause_text": "The subscriber or intermediary or any person in-charge of the computer resource shall, when called upon by any agency referred to in sub-section (1), extend all facilities and technical assistance to— (a) provide access to or secure access to the computer resource generating, transmitting, receiving or storing such information; or (b) intercept, monitor, or decrypt the information, as the case may be; or (c) provide information stored in computer resource.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 69(3) of the Information Technology Act 2000. Subscribers, intermediaries and persons in charge of computer resources are obligated to extend all facilities and technical assistance to government agencies directed under section 69(1), including providing or securing access to the computer resource, assisting with interception, monitoring or decryption, and providing stored information. Failure to assist is punishable with imprisonment for up to seven years and fine.", "section_number": "69", "subsection_number": "3", "validation_status": "validated", "plain_english_summary": "Subscribers, intermediaries, and persons in charge of computer resources must provide all technical assistance to government agencies for interception, monitoring, or decryption when directed."}	[0.5869633,1.1852539,-3.2166538,-0.8594001,0.74341637,0.35485876,-0.09053587,1.0170108,0.49029326,-0.015386962,-0.29977,0.2557226,-0.24182494,-0.4