90	{"act": "IT_ACT_2000", "title": "Power to Block Public Access to Information", "doc_id": "ITACT_SEC_69A_SUB_1", "topics": ["content_blocking", "national_security", "intermediary", "procedure"], "entities": ["Central Government", "intermediary"], "keywords": ["blocking", "public access", "information", "computer resource", "Central Government", "intermediary", "sovereignty", "public order"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": [], "clause_text": "Where the Central Government or any of its officers specially authorised by it in this behalf is satisfied that it is necessary or expedient so to do, in the interest of sovereignty and integrity of India, defence of India, security of the State, friendly relations with foreign States or public order or for preventing incitement to the commission of any cognizable offence relating to above, it may subject to the provisions of sub-section (2), for reasons to be recorded in writing, by order, direct any agency of the Government or intermediary to block for access by the public or cause to be blocked for access by the public any information generated, transmitted, received, stored or hosted in any computer resource.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 69A(1) of the Information Technology Act 2000. The Central Government may direct any government agency or intermediary to block public access to any information generated, transmitted, received, stored or hosted in a computer resource when satisfied it is necessary in the interest of sovereignty, integrity or defence of India, State security, friendly relations with foreign States, public order, or for preventing incitement to cognizable offences. Directions must be in writing with recorded reasons.", "section_number": "69A", "subsection_number": "1", "validation_status": "validated", "plain_english_summary": "The Central Government may direct government agencies or intermediaries to block public access to information in a computer resource in the interest of national security, public order, or to prevent cognizable offences."}	[0.18114585,1.2203016,-2.7166772,-0.3725825,1.1547148,0.5652322,0.06648935,0.76110184,0.15634724,-0.0639586,0.81885034,0.8403124,0.44158894,-0.58251184,0.395151,0.050956875,0.51267004,-0.54296756,-0.53405905,0.86104697,0.50498056,-0.40234104,-1.0182498,0.3539235,1.0080639,-0.46509078,1.9199027,-0.74604464,-0.4494403,-0.15096018,0.64289767,-0.526475,0.24138932,-0.37713322,-0.60169923,-1.3082234,0.25801978,-0.2777437,-1.4663345,-0.15048476,0.97547716,0.46007517,-0.5931139,-1.0607524,0.23728617,-0.2539009,0.7512091,-0.5142829,0.6950028,-1.2418553,0.4996262,-1.5614762,-0.37692785,-1.1013014,0.37900987,0.3970406,-0.887355,-0.39616656,0.822666,-0.3854931,1.7961311,0.9840663,-0.72032565,0.8622089,0.5516979,-0.5754459,-0.47887328,1.4470073,-0.3825112,0.03509679,1.405085,-0.035569247,1.1546687,-0.50016993,0.115437336,-0.13163392,-0.6119929,-1.0027103,0.24943887,0.70337933,0.30730346,-0.72202367,1.382342,-0.54698265,0.85712665,0.40728396,-0.46748427,-0.5299338,-0.26222274,1.4914445,-0.15291147,-0.2107581,1.0732858,-0.09747421,0.37348598,0.371218,-0.019419221,-0.4310861,-0.66793144,-0.17282456,-0.34685248,-0.5893508,0.5548019,-0.25066045,0.47647443,0.12743369,-0.07414216,-0.49396926,-0.30191866,-0.058665194,0.35011363,0.30582067,-0.95183545,-0.5675088,0.9027869,0.3903124,1.9518894,-1.4051505,0.51542455,0.3479967,-0.8934904,0.2700285,-0.31838977,0.19349086,0.68215233,-0.7509866,-1.3815696,-0.10899982,-0.20741695,-1.2677966,-0.6480171,-0.09208812,-0.7688734,0.28800908,-0.14432834,0.2126444,-0.6487806,-1.0739492,0.6052577,0.19975933,0.9272841,0.043750565,-0.40358132,0.017233966,1.5839577,-0.78567517,0.82671016,0.1854351,-0.03814288,0.5895077,-0.51662755,0.67632145,0.080422334,-0.37075093,0.5088642,-0.98944074,0.7623391,0.8022601,0.47916925,0.7318026,1.3121458,0.7699486,-1.1392769,1.6214943,-0.7985981,-0.55151385,-0.24424385,0.9624113,0.69374