91	{"act": "IT_ACT_2000", "title": "Power to Monitor Traffic Data for Cyber Security", "doc_id": "ITACT_SEC_69B", "topics": ["cyber_security", "surveillance", "monitoring", "procedure"], "entities": ["Central Government"], "keywords": ["traffic data", "cyber security", "monitoring", "computer resource", "Central Government", "intrusion", "computer contaminant"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": [], "clause_text": "The Central Government may, to enhance cyber security and for identification, analysis and prevention of intrusion or spread of computer contaminant in the country, by notification in the Official Gazette, authorise any agency of the Government to monitor and collect traffic data or information generated, transmitted, received or stored in any computer resource.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 69B of the Information Technology Act 2000. The Central Government may authorise a government agency by notification to monitor and collect traffic data or information in any computer resource for the purpose of enhancing cyber security, identifying and analysing intrusions, and preventing the spread of computer contaminants. Intermediaries and persons in charge of computer resources must provide technical assistance to such authorised agencies.", "section_number": "69B", "subsection_number": null, "validation_status": "validated", "plain_english_summary": "The Central Government may authorise a government agency to monitor and collect traffic data from computer resources to enhance cyber security and prevent intrusions or computer contaminants."}	[0.08460415,1.1010913,-3.486581,-0.70691144,1.1401929,0.37359932,0.4346488,1.228238,0.7195822,-0.43455127,0.21119682,0.80252296,0.32320645,-0.5060292,-0.16144204,-0.5103317,0.061623443,-0.23411112,-0.43384588,0.84535193,0.93609995,-0.8150608,-0.32402274,-0.24256487,1.1089445,-0.09172643,1.2874287,-0.26588982,-0.11980542,-0.708091