92	{"act": "IT_ACT_2000", "title": "Protected System - Declaration", "doc_id": "ITACT_SEC_70_SUB_1", "topics": ["critical_information_infrastructure", "protected_system", "national_security"], "entities": ["appropriate Government"], "keywords": ["protected system", "Critical Information Infrastructure", "appropriate Government", "notification", "computer resource", "national security"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": [], "clause_text": "The appropriate Government may, by notification in the Official Gazette, declare any computer resource which directly or indirectly affects the facility of Critical Information Infrastructure, to be a protected system.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 70(1) of the Information Technology Act 2000. The appropriate Government may by notification declare any computer resource that directly or indirectly affects Critical Information Infrastructure to be a protected system. Critical Information Infrastructure means computer resources whose incapacitation or destruction would have a debilitating impact on national security, economy, public health or safety. Unauthorised access to a protected system is punishable with imprisonment for up to ten years.", "section_number": "70", "subsection_number": "1", "validation_status": "validated", "plain_english_summary": "The appropriate Government may declare any computer resource affecting Critical Information Infrastructure as a protected system by notification."}	[1.0247355,1.3625996,-3.0632415,-0.3712823,1.0814885,1.0300101,-0.36756766,1.4116479,0.7081122,-0.101227164,0.44670215,0.44352195,0.09489333,-0.86536974,0.53910065,-0.41486466,-0.10320353,-0.2593447,-0.42321578,-0.25621182,0.00861368,-1.4688802,-1.2138253,-0.050215587,0.85941553,0.9093666,1.9138792,-0.4707717,-0.8688072,-0.05625221,0.7264646,-0.35561135,0.32137963,-0.236359,-1.0627524,-1.4674877,-0.1275991,-0.1560433,-0.39269614,-0.055962503,0.