94	{"act": "IT_ACT_2000", "title": "National Nodal Agency for Critical Information Infrastructure Protection", "doc_id": "ITACT_SEC_70A", "topics": ["governance", "critical_information_infrastructure", "national_security"], "entities": ["Central Government"], "keywords": ["national nodal agency", "Critical Information Infrastructure Protection", "Central Government", "research and development", "designation"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": [], "clause_text": "The Central Government may, by notification published in the Official Gazette, designate any organisation of the Government as the national nodal agency in respect of Critical Information Infrastructure Protection. The national nodal agency designated under sub-section (1) shall be responsible for all measures including Research and Development relating to protection of Critical Information Infrastructure.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 70A of the Information Technology Act 2000. The Central Government may designate any government organisation as the national nodal agency for Critical Information Infrastructure Protection. That agency is responsible for all protection measures, including research and development, relating to Critical Information Infrastructure.", "section_number": "70A", "subsection_number": null, "validation_status": "validated", "plain_english_summary": "The Central Government may designate a government organisation as the national nodal agency for Critical Information Infrastructure Protection, responsible for all protection measures including R&D."}	[0.50841236,0.32317984,-3.0892663,-0.21397264,1.0464717,0.14369285,-0.56788987,1.3631532,0.76254314,-0.18824972,0.38815972,0.120073944,0.59193087,-1.0440372,0.9139033,-0.4375635,0.08966074,-0.005338066,-0.08553335,0.21509854,0.30477136,-0.8655373,-0.7325644,-0.15690444,1.4611762,0.52852106,1.7201111,-0.562263,-1.0503991,-0.58734465,1.2054964,0.224