95	{"act": "IT_ACT_2000", "title": "Indian Computer Emergency Response Team (CERT-In)", "doc_id": "ITACT_SEC_70B", "topics": ["governance", "cyber_security", "incident_response"], "entities": ["Central Government", "Indian Computer Emergency Response Team", "CERT-In"], "keywords": ["CERT-In", "Indian Computer Emergency Response Team", "cyber security", "cyber incident", "alerts", "guidelines", "vulnerability", "incident response"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": [], "clause_text": "The Central Government shall, by notification in the Official Gazette, appoint an agency of the Government to be called the Indian Computer Emergency Response Team. The Indian Computer Emergency Response Team shall serve as the national agency for performing the following functions in the area of cyber security,— (a) collection, analysis and dissemination of information on cyber incidents; (b) forecast and alerts of cyber security incidents; (c) emergency measures for handling cyber security incidents; (d) coordination of cyber incidents response activities; (e) issue guidelines, advisories, vulnerability notes and white papers relating to information security practices, procedures, prevention, response and reporting of cyber incidents; (f) such other functions relating to cyber security as may be prescribed.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 70B of the Information Technology Act 2000. The Central Government establishes the Indian Computer Emergency Response Team (CERT-In) as the national agency for cyber security. CERT-In's functions include collection, analysis and dissemination of cyber incident information, issuing forecasts and alerts, emergency response measures, coordinating cyber incident response, and issuing guidelines, advisories, vulnerability notes and white papers on information security practices. Service providers, intermediaries, data centres and body corporates must comply with CERT-In directions.", "section_number": "70B", "subsection_number": null, "validation_status": "validated", "plain_english_summary": "The Central Government establishes CERT-In as the national cyber security agency responsible for collecting and analysing cyber incident information, issuing alerts, handling emergencies, coordinating responses, and issuing cyber security guidelines."}	[0.018777305,0.5817093,-3.6110666,0.20171534,2.161052,0.351602,0.57073694,0.7578647,0.20513956,-0.46476758,-0.3102161,0.28996202,1.2295669,-0.44449624,0.1994074,-1.0188469,-0.19957425,-0.46336198,-1.1991903,0.10808411,0.71220046,-1.5830711,-0.6933032,0.16854893,1.3619436,0.52241325,1.2494572,0.17653999,-0.5803504,-0.64111626,1.3520035,0.13169937,0.30516756,-0.77645475,-0.34152284,-0.7618507,-0.031139094,-0.13212249,-1.4640771,0.10445648,0.55838585,-0.052805617,0.2395708,-0.752462,0.3600145,0.9923412,0.74682367,-0.08141962,1.1763515,-0.94627416,0.1700982,-1.1789782,0.37905648,-0.28370747,1.1411175,-0.06827559,-0.9134561,0.116441905,-0.2643558,-0.81060565,1.8970052,1.420724,-0.9853859,0.23728862,0.9186009,-1.3535867,-0.44751936,1.2048136,-0.20496556,0.07993185,0.67700344,-0.8745167,0.48441678,0.42974374,-0.5777616,-1.1460469,-0.78074336,-1.325492,-0.48716053,1.3580309,0.3944802,-0.03363022,1.2120864,-0.14602898,0.411823,0.50853777,-0.32938787,-0.11855633,-0.6077995,1.6429676,0.94213736,0.67244923,0.13470462,-0.14748791,-0.41050473,0.6518937,0.039234545,-0.2545302,-0.07985525,0.12924917,0.1788324,-0.5471129,0.2150984,-0.8988284,0.39369026,0.9434552,-0.14832097,0.03683084,-0.6858121,0.2717076,-0.17391777,0.38161042,-0.6135057,-0.25304216,0.7989214,0.9413373,1.1242287,-1.0178844,0.063420504,0.858669,0.206499,-0.43799195,-0.25943726,0.3425477,0.9609956,-0.037209123,-0.9225825,0.5463667,0.17572723,-1.2378583,-0.54008114,0.553431,-1.247401,-0.27010098,0.3483574,0.69022065,-0.89245987,-1.0093333,0.70020574,0.5457038,0.33165914,0.6002591,0.027997976,-0.26631957,0.94846505,0.12626654,1.1872038,0