96	{"act": "IT_ACT_2000", "title": "Penalty for Misrepresentation to Controller or Certifying Authority", "doc_id": "ITACT_SEC_71", "topics": ["penalty", "certifying_authority", "misrepresentation"], "entities": ["Controller", "Certifying Authority"], "keywords": ["misrepresentation", "suppression of material facts", "Controller", "Certifying Authority", "licence", "electronic signature certificate", "imprisonment"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": [], "clause_text": "Whoever makes any misrepresentation to, or suppresses any material fact from the Controller or the Certifying Authority for obtaining any licence or electronic signature Certificate, as the case may be, shall be punished with imprisonment for a term which may extend to two years, or with fine which may extend to one lakh rupees, or with both.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 71 of the Information Technology Act 2000. Whoever makes any misrepresentation to, or suppresses any material fact from, the Controller or a Certifying Authority for the purpose of obtaining a licence or electronic signature certificate shall be punished with imprisonment for up to two years or a fine up to Rs 1 lakh or both.", "section_number": "71", "subsection_number": null, "validation_status": "validated", "plain_english_summary": "Making a misrepresentation or suppressing material facts when obtaining a licence or electronic signature certificate from the Controller or Certifying Authority is punishable with imprisonment up to two years or a fine up to Rs 1 lakh, or both."}	[1.2903525,0.65790486,-2.9959064,0.2961283,0.9109286,0.10829988,-0.44309017,0.95325094,0.31041485,-0.10058692,0.3720931,0.8752542,0.9944463,-0.48272556,0.37053767,-0.72403765,0.23445185,-1.3066856,-0.18920283,0.025654748,0.46923232,-0.38389415,-1.4518727,-0.5318589,1.1504048,-0.49815178,1.3843136,-0.5984931,-0.6948427,0.19981106,0.99375623,-0.5883572,0.21224277,