97	{"act": "IT_ACT_2000", "title": "Penalty for Breach of Confidentiality and Privacy", "doc_id": "ITACT_SEC_72", "topics": ["privacy", "confidentiality", "penalty", "data_protection"], "entities": [], "keywords": ["confidentiality", "privacy", "disclosure", "electronic record", "without consent", "imprisonment", "one lakh rupees"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": [], "clause_text": "Save as otherwise provided in this Act or any other law for the time being in force, if any person who, in pursuance of any of the powers conferred under this Act, rules or regulations made thereunder, has secured access to any electronic record, book, register, correspondence, information, document or other material without the consent of the person concerned discloses such electronic record, book, register, correspondence, information, document or other material to any other person shall be punished with imprisonment for a term which may extend to two years, or with fine which may extend to one lakh rupees, or with both.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 72 of the Information Technology Act 2000. Any person who, while exercising powers conferred under the Act, secures access to electronic records, books, registers, correspondence, information, documents or other material without the consent of the person concerned and discloses such material to any other person shall be punished with imprisonment for up to two years or a fine up to Rs 1 lakh or both. This protects confidentiality of information accessed in exercise of official powers.", "section_number": "72", "subsection_number": null, "validation_status": "validated", "plain_english_summary": "Any person who, while exercising powers under the Act, obtains access to electronic records or information without the concerned person's consent and then discloses it to another person is punishable with imprisonment up to two years or a fine up to Rs 1 lakh, or both."}	[1.1417897,1.112957,-3.194807,-0.039612684,0.6346034,-0.051276967,-0.83500725,0.93072164,-0.017525224,0.032144897,-0.14226867,0.59922147,0.367824,-0.7202641,0.3920841,-0.23129301,0.51006967,-1.5729142,-0.49706626,-0.60718477,0.17660475,-0.3769215,-1.2632258,0.35068414,0.91512835,-0.41395363,1.5921286,-0.77166426,-0.5833494,-0.36343724,0.6427126,-0.68373185,0.36404186,-0.0791411,-0.8475111,-1.4828991,0.86525804,-0.36994997,-0.71287364,0.006628813,1.1292133,0.40042046,-0.6280645,-0.8917583,0.23294304,-0.19540332,0.45836285,-0.17127459,0.13948068,-0.9951981,0.004536101,-1.4172931,0.27173108,-0.76135665,1.2206011,0.60376805,-1.55005,-0.61697924,0.53966534,-0.440765,1.956492,1.2193383,-0.72197115,1.4715803,0.922763,-0.4044337,-0.362209,1.6408781,0.3667638,-0.6316663,1.5803301,-0.10674158,0.5272127,-0.3071608,0.49785408,-0.33507913,-0.15056843,-0.8646024,0.37601852,1.4267219,0.15320764,-0.0606043,1.3924811,0.31866235,1.0966071,0.025646526,0.053193253,-0.124471925,-0.031449843,1.3593646,0.28916308,-0.57604057,0.87888086,-0.088553205,-0.28902754,0.34665772,0.57129747,-0.2394598,-0.73805887,-0.0022201466,-0.10497189,-1.1455605,0.635237,0.16018231,0.391805,0.6505681,-0.25020626,-0.25111237,-0.8876362,0.37152195,0.5286301,0.6461752,-0.40615493,-0.175504,0.76445013,0.59170735,1.1952395,-1.2419062,-0.1868894,-0.0043836213,-0.29629368,0.16806386,0.053175863,0.89455885,0.6863899,-0.09674046,-0.5002392,-0.014387314,0.44674972,-1.5579867,-0.87987524,0.28901747,-0.59086454,0.1610077,0.23828007,0.7643224,-0.613135,-0.58951366,-0.14701375,-0.39590806,0.583339,0.13750014,-0.057153787,-0.061547626,0.8648289,-0.99694943,0.82383513,-0.21009898,-0.9757363,1.0656118,-1.130062,0.22559527,0.5697994,-0.026570613,0.19141774,-0.79159325,0.7451005,0.2923356,0.47532475,0.69546264,1.3450109,1.3318914,-0.73580587,1.3414904,-1.3690797,-0.41215843,-0.47344276,1.1207056,0.23365971,0.28549647,-0.69124496,0.19675168,-0.45186493,-0.029017912,0.06584806,-0.5115986,0.17496452,-1.307127,