98	{"act": "IT_ACT_2000", "title": "Punishment for Disclosure of Information in Breach of Lawful Contract", "doc_id": "ITACT_SEC_72A", "topics": ["privacy", "data_protection", "penalty", "intermediary"], "entities": ["intermediary"], "keywords": ["personal information", "disclosure", "lawful contract", "wrongful loss", "wrongful gain", "intermediary", "without consent", "imprisonment"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": [], "clause_text": "Save as otherwise provided in this Act or any other law for the time being in force, any person including an intermediary who, while providing services under the terms of lawful contract, has secured access to any material containing personal information about another person, with the intent to cause or knowing that he is likely to cause wrongful loss or wrongful gain discloses, without the consent of the person concerned, or in breach of a lawful contract, such material to any other person, shall be punished with imprisonment for a term which may extend to three years, or with fine which may extend to five lakh rupees, or with both.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 72A of the Information Technology Act 2000. Any person including an intermediary who, while providing services under a lawful contract, accesses material containing personal information about another person and discloses it without consent or in breach of the contract, with intent to cause or knowing it is likely to cause wrongful loss or wrongful gain, shall be punished with imprisonment for up to three years or a fine up to Rs 5 lakh or both. This protects personal information shared with service providers and intermediaries.", "section_number": "72A", "subsection_number": null, "validation_status": "validated", "plain_english_summary": "Any person, including an intermediary, who discloses personal information accessed under a lawful contract without consent and with intent to cause wrongful loss or gain is punishable with imprisonment up to three years or a fine up to Rs 5 lakh, or both."}	[1.3783997,0.91406935,-2.8273413,-0.2294182,0.6599094,-0.29760322,-0.35559753,0.56406194,0.30235636,0.31532308,-0.58639246,0.5792144,0.5002254,-0.93127596,-0.0053457543,-0.23700644,0.7359131,-1.0537059,-0.5299823,0.1904074,-0.52557933,-0.62640595,-0.7163036,0.11878386,0.67598546,-0.83881706,1.3615654,-0.17014925,-0.09072938,-0.22032364,0.5922927,-0.6444444,0.02398448,-0.49642676,-1.6646918,-0.9706853,0.6554762,0.13680092,-0.8898117,-0.11700755,0.7686515,0.31415546,-0.47369698,-0.60110414,0.36086074,-0.3439604,0.7593048,0.058705803,0.38069138,-0.5826796,0.1358038,-1.2930964,0.22299524,-0.7386275,1.3146529,0.3665199,-1.4633095,-0.19803466,-0.07419531,-0.1741134,1.5330608,1.4476975,-0.584897,1.3639257,0.9003657,-0.34068477,-0.50529724,1.4542152,0.34849685,-0.46374422,1.3581469,0.24351007,0.77886885,0.039307725,0.58264524,-0.24492724,-0.25992173,-0.26255658,0.3576186,0.9680541,0.267494,0.09930047,0.858312,0.3263149,0.41043612,-0.43791494,0.43175125,-0.23973075,-0.19302754,1.4352797,0.079782635,-0.32857063,0.693343,0.05267724,-0.75206053,0.12415074,0.009260936,0.0682921,-0.65110934,-0.07916838,-0.2983608,-1.16474,0.5826512,0.59374726,-0.03185456,0.81333905,0.4592764,0.19672833,-0.46946722,0.09104776,0.3511338,0.7094011,-0.23087165,-0.6546912,0.7582912,0.107736096,0.76099634,-0.6575892,-0.3298794,0.21695168,-0.24672602,-0.055154264,0.51589656,1.2378699,0.88524705,-0.2262125,-0.47748536,0.37954777,0.44636294,-1.525756,-0.7943372,-0.1101016,-0.6265061,0.02452192,-0.123395555,0.33151415,-0.3559893,-0.4579825,-0.4447186,0.1039575,0.7995621,0.5005695,0.08785417,-0.06281977,0.5611874,-1.1369793,0.795689,-0.53074235,-0.6503658,0.92901284,-0.6180694,0.6144829,0.24282853,0.15974624,0.44910228,-0.89587855,0.17630921,-0.021242844,0.5957712,0.18952304,1.0607193,1.1767783,-0.8146701,1.6213305,-1.1768216,-0.36561105,-0.55103135,1.0650945,0.20922858,0.19740005,-0.525666