99	{"act": "IT_ACT_2000", "title": "Extra-Territorial Application for Offences Outside India", "doc_id": "ITACT_SEC_75", "topics": ["jurisdiction", "extra_territorial_application"], "entities": [], "keywords": ["extra-territorial", "outside India", "offence", "computer system", "nationality", "jurisdiction"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": [], "clause_text": "Subject to the provisions of sub-section (2), the provisions of this Act shall apply also to any offence or contravention committed outside India by any person irrespective of his nationality. For the purposes of sub-section (1), this Act shall apply to an offence or contravention committed outside India by any person if the act or conduct constituting the offence or contravention involves a computer, computer system or computer network located in India.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 75 of the Information Technology Act 2000. The Act has extra-territorial application and applies to any offence or contravention committed outside India by any person irrespective of nationality, provided the act involves a computer, computer system or computer network located in India.", "section_number": "75", "subsection_number": null, "validation_status": "validated", "plain_english_summary": "The Act applies to offences committed outside India by any person, regardless of nationality, if the act involves a computer, computer system, or computer network located in India."}	[0.9004993,0.9664975,-3.443444,-0.25992772,0.66862494,0.52662355,0.08179077,0.3164579,0.36695865,-0.8155564,-0.3491078,0.9841499,1.1680523,-0.62642443,-0.73855895,-0.97932917,-0.035175625,-0.68725556,-0.4730667,0.7621476,-0.06021902,-0.063018605,-0.36562037,0.15445933,1.1724378,-0.016308814,1.5735626,-0.48578274,-0.6297389,-0.86019886,0.53517085,-0.8287729,0.585754,-0.7966673,-1.0005747,-1.1530915,0.15162344,-0.28506052,-1.3636049,-0.021327512,0.5159468,0.37262