100	{"act": "IT_ACT_2000", "title": "Safe Harbour - Intermediary Exemption from Liability", "doc_id": "ITACT_SEC_79_SUB_1", "topics": ["safe_harbour", "intermediary", "exemption"], "entities": ["intermediary"], "keywords": ["safe harbour", "intermediary", "third-party information", "liability exemption", "hosting", "conduit"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": ["ITACT_SEC_79_SUB_2", "ITACT_SEC_79_SUB_3"], "clause_text": "Notwithstanding anything contained in any law for the time being in force but subject to the provisions of sub-sections (2) and (3), an intermediary shall not be liable for any third party information, data, or communication link made available or hosted by him.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 79(1) of the Information Technology Act 2000. An intermediary shall not be liable for any third-party information, data or communication link made available or hosted by it, subject to compliance with the conditions set out in sections 79(2) and 79(3). This creates a conditional safe harbour from liability for intermediaries acting as mere conduits.", "section_number": "79", "subsection_number": "1", "validation_status": "validated", "plain_english_summary": "An intermediary is not liable for third-party information, data, or communication links it makes available or hosts, subject to conditions in subsections (2) and (3)."}	[0.8742889,0.46871296,-2.9309723,-1.3718978,0.88739026,0.73772514,0.23107332,0.68149894,0.2655854,-0.4168079,-0.29348484,0.035026774,-0.025559299,-0.57985055,-0.5522941,-0.17113322,0.4022654,-0.21840186,-0.22613916,0.16758989,-0.6311169,-0.90426296,-0.45066383,-0.037368268,0.71252257,-0.4765055,0.9649272,-0.36165845,-0.47861686,-0.8085125,0.7369993,-0.21329232,1.0535562,-0.56092983,-1.7367182,-0.85705316,0.031671178,1.0741165,-1.2771832,-0.16858193,0.27574807,0.5385284,-0.13029939,-0.38540953,0.19967993,-0.42948225,0.9814325,0.70090425,0.44243613