101	{"act": "IT_ACT_2000", "title": "Safe Harbour - Conditions for Exemption", "doc_id": "ITACT_SEC_79_SUB_2", "topics": ["safe_harbour", "intermediary", "due_diligence", "compliance_requirement"], "entities": ["intermediary", "Central Government"], "keywords": ["safe harbour conditions", "due diligence", "intermediary", "conduit", "no modification", "transmission", "Central Government guidelines"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": ["ITACT_SEC_79_SUB_1"], "clause_text": "The provisions of sub-section (1) shall apply if— (a) the function of the intermediary is limited to providing access to a communication system over which information made available by third parties is transmitted or temporarily stored or hosted; or (b) the intermediary does not— (i) initiate the transmission, (ii) select the receiver of the transmission, and (iii) select or modify the information contained in the transmission; (c) the intermediary observes due diligence while discharging his duties under this Act and also observes such other guidelines as the Central Government may prescribe in this behalf.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 79(2) of the Information Technology Act 2000. The safe harbour from liability under section 79(1) applies if the intermediary's function is limited to providing access to a communication system for third-party information, it does not initiate the transmission, select the receiver, or select or modify the content, and it observes due diligence and guidelines prescribed by the Central Government.", "section_number": "79", "subsection_number": "2", "validation_status": "validated", "plain_english_summary": "An intermediary qualifies for safe harbour if it acts only as a conduit, does not initiate or modify transmissions, does not select recipients, and observes due diligence and prescribed guidelines."}	[0.6225127,0.32706895,-2.9768045,-1.4751215,0.91231257,0.8907521,0.69