102	{"act": "IT_ACT_2000", "title": "Safe Harbour - When Exemption Ceases", "doc_id": "ITACT_SEC_79_SUB_3", "topics": ["safe_harbour", "intermediary", "obligation", "take_down"], "entities": ["intermediary", "appropriate Government"], "keywords": ["safe harbour loss", "intermediary", "unlawful act", "actual knowledge", "government notification", "remove", "disable access", "expeditiously"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": ["ITACT_SEC_79_SUB_1"], "clause_text": "The provisions of sub-section (1) shall not apply if— (a) the intermediary has conspired or abetted or aided or induced, whether by threats or promise or otherwise in the commission of the unlawful act; (b) upon receiving actual knowledge, or on being notified by the appropriate Government or its agency that any information, data or communication link residing in or connected to a computer resource controlled by the intermediary is being used to commit the unlawful act, the intermediary fails to expeditiously remove or disable access to that material on that resource without vitiating the evidence in any manner.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 79(3) of the Information Technology Act 2000. An intermediary loses safe harbour protection if it conspires in, abets, aids or induces the commission of an unlawful act, or if, upon receiving actual knowledge or government notification that information on its platform is being used to commit an unlawful act, it fails to expeditiously remove or disable access to that material without vitiating evidence.", "section_number": "79", "subsection_number": "3", "validation_status": "validated", "plain_english_summary": "The safe harbour does not apply if the intermediary conspired in or induced the unlawful act, or if, after receiving actual knowledge or government notification that content is being used unlawfully, the intermediary fails to expeditiously remove or disable access to that content."}	[0.83715314,0.56059545,-3.0371819,-0.86363524,1.5160611,0.86983365,0.4345309,0.9081085,0.6229432,-0.4500801,-0.5232328,0.19614743,0.28998962,-0.52927804,0.05449231,-0.74284756,0.5727647,-0.5362949,-0.40895268,-0.2881833,-0.50834984,-0.9724487,-0.8949887,0.3124144,1.030268,-0.3267743,1.3383238,-0.4622254,0.042054668,-0.30969986,0.50627685,-0.41810563,0.5980179,-0.41191503,-1.4684323,-1.3675258,0.5628114,0.8424907,-1.6700788,-0.18272746,0.50006986,0.7624192,-0.4892003,-0.507324,-0.04462084,-0.35913974,0.86526203,0.15140617,0.3323126,-1.6360421,1.2628626,-0.63882434,-0.0739461,-0.52535987,0.6832094,0.342294,-0.9918286,0.13929532,-0.45092598,-0.68728876,0.92827827,1.525245,-0.5228574,1.0367973,0.77121663,-0.27225634,-0.9686977,0.8206725,0.23141925,-1.299494,0.86804634,0.7784287,0.43189105,-0.5877444,0.45109355,0.16676033,-0.49687177,-0.13306226,-0.5820059,0.7609257,0.36613783,-0.89835405,0.4925871,0.43846536,0.15284023,0.26488858,-0.47423443,-0.86497694,-0.62765193,1.3860967,0.4511522,-0.6633536,1.006991,0.2694963,-0.38476434,0.24691479,0.2013287,-0.13113652,-0.9595286,-0.089872725,-0.29408422,-0.93662256,0.23113403,0.4425713,0.6339263,0.9940492,1.3543307,-0.32772428,-0.09072177,0.4180217,0.23813708,0.26013675,-0.5688693,-1.1662731,0.80875194,-0.20625155,0.86225337,-0.02615182,0.12147983,-0.13183917,-1.0251583,-0.42447475,-0.12399625,0.8965233,0.79361624,-0.598491,-1.2015642,0.9369693,-0.44242683,-1.5535736,-0.64894664,0.1318047,-0.2330599,0.22309417,0.27951524,0.5930277,-0.44143975,-0.71262664,-0.09996528,1.363409,0.8595923,0.32864752,0.06724964,-0.6430196,0.56872416,-0.8689845,1.310319,-0.1787331,-0.5618025,-0.48598608,-0.5702563,1.0863079,0.4356065,-0.0894869,0.879319,-1.0607743,0.5341658,0.3770422,0.6468902,-0.10585804,1.2375236,0.77689654,-0.6176367,1.3931558,-1.6407307,0.031867053,-0.57193583,0.78870285,-0.16823798,0.16524202,-0.78440636,-0.06454006,-0.61180836,0.83959264,0.10832863,-0.07435529,0.31707236,-1.5217067,0.5207759,-0.353051,-0.3832131,