103	{"act": "IT_ACT_2000", "title": "Examiner of Electronic Evidence", "doc_id": "ITACT_SEC_79A", "topics": ["governance", "electronic_evidence", "expert_opinion"], "entities": ["Central Government"], "keywords": ["Examiner of Electronic Evidence", "electronic evidence", "expert opinion", "Central Government", "court", "digital evidence"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": [], "clause_text": "The Central Government may, for the purposes of providing expert opinion on electronic form evidence before any court or other authority specify, by notification in the Official Gazette, any Department, body or agency of the Central Government or a State Government as an Examiner of Electronic Evidence.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 79A of the Information Technology Act 2000. The Central Government may designate, by notification, any Central or State Government department, body or agency as an Examiner of Electronic Evidence for the purpose of providing expert opinions on electronic evidence before courts or other authorities. Electronic form evidence includes computer evidence, digital audio, digital video, cell phones and digital fax machines.", "section_number": "79A", "subsection_number": null, "validation_status": "validated", "plain_english_summary": "The Central Government may designate a government department, body, or agency as an Examiner of Electronic Evidence to provide expert opinions on electronic evidence before courts or other authorities."}	[0.14409398,0.7055483,-3.1733384,-1.31385,1.0972098,0.4772407,-0.13674459,1.0592754,0.8152862,-0.34239995,0.6243293,0.57199854,0.9457457,0.28764743,-0.15546846,-0.66274625,-0.22484536,-1.0270205,-0.3766983,-0.004312426,0.496155,-0.9253094,-1.694758,0.17527214,1.2231121,-0.40515414,0.981329,-0.19850782,-0.44564876,-0.4869286,0.7943034,-0.008882163,1.3504577,-0.07536278,-0.46272758,-1.641505,0.7589457,0.78778577,-1.0979849,0.835301