104	{"act": "IT_ACT_2000", "title": "Power of Police Officer to Enter, Search and Arrest", "doc_id": "ITACT_SEC_80", "topics": ["enforcement", "procedure", "search_and_arrest"], "entities": ["Central Government", "State Government"], "keywords": ["police officer", "Inspector", "search", "arrest without warrant", "public place", "offence", "Central Government", "State Government"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": [], "clause_text": "Notwithstanding anything contained in the Code of Criminal Procedure, 1973, any police officer, not below the rank of a Inspector, or any other officer of the Central Government or a State Government authorised by the Central Government in this behalf may enter any public place and search and arrest without warrant any person found therein who is reasonably suspected of having committed or of committing or of being about to commit any offence under this Act.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 80 of the Information Technology Act 2000. A police officer not below the rank of Inspector, or an authorised Central or State Government officer, may enter any public place and search and arrest without warrant any person reasonably suspected of having committed, committing, or being about to commit an offence under the Act. This power operates notwithstanding the Code of Criminal Procedure 1973.", "section_number": "80", "subsection_number": null, "validation_status": "validated", "plain_english_summary": "A police officer of Inspector rank or above, or an authorised Central or State Government officer, may enter any public place and arrest without warrant any person reasonably suspected of committing an offence under the Act."}	[0.5473939,0.47604734,-2.9068122,-0.106442004,0.8821649,0.7907752,-0.027481295,0.75723404,0.19363444,-0.3531841,0.22466196,0.28528935,-0.25206855,-0.9617918,-0.5076475,-0.40060818,0.52147937,-1.2510312,-0.20152123,-0.97667325,0.367