105	{"act": "IT_ACT_2000", "title": "Overriding Effect of the Act", "doc_id": "ITACT_SEC_81", "topics": ["overriding_effect", "legislation"], "entities": [], "keywords": ["overriding effect", "inconsistent law", "Copyright Act", "Patents Act", "prevails"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": [], "clause_text": "The provisions of this Act shall have effect notwithstanding anything inconsistent therewith contained in any other law for the time being in force. Provided that nothing contained in this Act shall restrict any person from exercising any right conferred under the Copyright Act, 1957 or the Patents Act, 1970.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 81 of the Information Technology Act 2000. The Act has overriding effect and prevails over any inconsistent provision in any other law currently in force. However, this override does not restrict any person from exercising rights conferred by the Copyright Act 1957 or the Patents Act 1970.", "section_number": "81", "subsection_number": null, "validation_status": "validated", "plain_english_summary": "This Act overrides any inconsistent provisions in other laws, but does not restrict rights under the Copyright Act, 1957 or the Patents Act, 1970."}	[0.39789793,0.66464597,-2.9700198,-0.40103728,0.009060832,1.1498271,-0.20420355,0.5677182,0.5358768,-0.5201718,0.9534797,0.4551346,0.18684469,-0.53872025,0.43390673,0.0009254819,0.23459294,-0.6473336,-0.012597376,0.22378641,0.24597104,-0.8857396,-1.758769,0.017348282,0.8688469,-0.3348044,1.4143182,-0.84232366,-0.8396335,-0.73347116,0.55310243,-0.085041426,0.89825094,-0.8706653,-0.786649,-1.1520553,1.2118696,0.05942164,-0.7641285,0.7193043,0.72229403,0.20425549,0.16670002,-0.04766992,0.8877982,-0.5428769,0.22587594,-0.13938852,0.27923444,-0.33924076,0.43958098,-1.3545666,0.30464914,-0.79367715,0.9366964,0.48573163,-1.2354451,0.65173835,0.66766167,-0.6439343,-0.022307571,1.80835,-0.8419918,1