106	{"act": "IT_ACT_2000", "title": "Protection of Action Taken in Good Faith", "doc_id": "ITACT_SEC_84", "topics": ["good_faith_protection", "exemption", "governance"], "entities": ["Central Government", "State Government", "Controller", "adjudicating officer"], "keywords": ["good faith", "protection", "legal proceedings", "Controller", "adjudicating officer", "Central Government", "State Government"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": [], "clause_text": "No suit, prosecution or other legal proceeding shall lie against the Central Government, the State Government, the Controller or any person acting on behalf of him, and adjudicating officers for anything which is in good faith done or intended to be done in pursuance of this Act or any rule, regulation or order made thereunder.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 84 of the Information Technology Act 2000. The Central Government, State Government, the Controller, adjudicating officers, and any person acting on behalf of the Controller are protected from suits, prosecutions or other legal proceedings for anything done or intended to be done in good faith in pursuance of the Act or rules, regulations or orders made thereunder.", "section_number": "84", "subsection_number": null, "validation_status": "validated", "plain_english_summary": "No legal action lies against the Central Government, State Government, Controller, adjudicating officers, or persons acting on their behalf for anything done in good faith under the Act."}	[0.6845711,1.0051209,-3.2192664,-0.70928633,0.84889024,0.5989384,-0.19078322,0.44742697,1.0758122,-0.62067896,-0.24989906,0.42922345,0.43945846,-0.6170832,0.44637835,-0.55317676,0.51902896,-0.25068462,-0.29237366,-0.1984919,0.64200664,-0.66900057,-1.2653916,0.07630261,1.444946,0.019204805,1.1072667,-0.72486067,-0.57764596,-0.72012526,0.53013325,0.48791853,1.2050691,-1.3526816,-0.2750194,-1.3933094,0.7375109,0