108	{"act": "IT_ACT_2000", "title": "Punishment for Abetment of Offences", "doc_id": "ITACT_SEC_84B", "topics": ["penalty", "abetment", "cyber_offence"], "entities": [], "keywords": ["abetment", "abets", "punishment", "offence", "consequence"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": [], "clause_text": "Whoever abets any offence shall, if the act abetted is committed in consequence of the abetment, and no express provision is made by this Act for the punishment of such abetment, be punished with the punishment provided for the offence under this Act.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 84B of the Information Technology Act 2000. Whoever abets any offence under the Act is, if the abetted act is committed in consequence of the abetment and no express provision is made for the punishment of such abetment, punishable with the same punishment provided for the principal offence.", "section_number": "84B", "subsection_number": null, "validation_status": "validated", "plain_english_summary": "Whoever abets an offence under the Act, where the abetted act is actually committed and no separate abetment penalty is provided, shall be punished with the same punishment as the principal offence."}	[1.0459514,1.1838567,-2.9865773,-0.83134395,1.001446,0.56617194,0.7016089,0.6612335,0.7990851,0.19379205,-0.8901864,1.1544696,0.47418815,-0.368914,-0.302592,-0.2627447,0.3549795,-0.28643256,0.40316114,-0.056570496,0.49695316,-0.35087228,-0.8108402,-0.52975374,1.3991797,-0.039247088,0.76343113,-0.12178603,-0.9719395,-0.4813216,0.5471087,0.20873092,0.28989917,-0.68024594,-0.1907247,-1.2141725,0.3692136,0.26448956,-1.0338216,-0.553053,0.08129363,0.47047538,-0.32411265,-0.3008395,-0.004060819,-0.09534965,1.2206777,0.8629457,0.5055261,0.09452402,0.4606695,-1.4587462,0.68882203,-1.7923797,1.3069096,0.28272936,-1.3206656,0.3431615,0.14814785,-0.082571186,0.48285046,1.4285059,-0.17253552,0.92050916,0.7216659,-0.2