109	{"act": "IT_ACT_2000", "title": "Punishment for Attempt to Commit Offences", "doc_id": "ITACT_SEC_84C", "topics": ["penalty", "attempt", "cyber_offence"], "entities": [], "keywords": ["attempt", "punishment", "half the term", "imprisonment", "fine", "offence"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": [], "clause_text": "Whoever attempts to commit an offence punishable by this Act or causes such an offence to be committed, and in such an attempt does any act towards the commission of the offence, shall, where no express provision is made for the punishment of such attempt, be punished with imprisonment of any description provided for the offence, for a term which may extend to one-half of the longest term of imprisonment provided for that offence, or with such fine as is provided for the offence, or with both.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 84C of the Information Technology Act 2000. Whoever attempts to commit an offence under the Act and does any act towards its commission shall, where no express provision covers such attempt, be punished with imprisonment for up to half the longest term provided for the offence, or with the fine provided, or both.", "section_number": "84C", "subsection_number": null, "validation_status": "validated", "plain_english_summary": "Attempting to commit an offence under the Act carries a maximum penalty of half the term of imprisonment or fine prescribed for the completed offence, where no separate provision exists for the attempt."}	[1.2396795,1.4628099,-2.9716985,-0.6453213,1.2585405,0.4939539,0.0061472096,0.48362148,-0.19250703,-0.041861054,-0.7915548,0.7494483,0.05218584,-0.66378516,-0.32745853,-0.22011153,0.71114916,-0.71113807,-0.02236819,0.100651085,0.47593462,-0.7585053,-0.7406323,-0.7517711,1.0659178,-0.020414565,1.2527514,-0.2922199,-1.2074405,0.31577867,0.68138045,0.2062959,0.15627198,-0.671363,-0.6475938,-1.2387726,0.40491545,0.005381