110	{"act": "IT_ACT_2000", "title": "Offences by Companies - Corporate Liability", "doc_id": "ITACT_SEC_85", "topics": ["corporate_liability", "obligation", "penalty"], "entities": [], "keywords": ["company", "corporate liability", "director", "manager", "officer", "contravention", "due diligence", "in charge"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": [], "clause_text": "Where a person committing a contravention of any of the provisions of this Act or of any rule, direction or order made thereunder is a company, every person who, at the time the contravention was committed, was in charge of, and was responsible to, the company for the conduct of business of the company as well as the company, shall be guilty of the contravention and shall be liable to be proceeded against and punished accordingly. Notwithstanding the foregoing, where a contravention has been committed by a company and it is proved that the contravention has taken place with the consent or connivance of, or is attributable to any neglect on the part of, any director, manager, secretary or other officer of the company, such director, manager, secretary or other officer shall also be deemed to be guilty.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 85 of the Information Technology Act 2000. Corporate liability: where a company commits a contravention, every person in charge of the company's conduct at the time of the contravention is guilty and liable along with the company, unless they prove the contravention occurred without their knowledge and despite due diligence. Directors, managers, secretaries or other officers who consent, connive in, or whose neglect causes a contravention are also personally liable.", "section_number": "85", "subsection_number": null, "validation_status": "validated", "plain_english_summary": "When a company violates the Act, both the company and persons in charge of its conduct are liable. Directors, managers, secretaries, or other officers who consent, connive in, or neglect to prevent the contravention are also personally liable."}	[1.8059579,0.7693283,-3.5750656,-0.16004762,0.7468516,0.5887021,0.47013983,-0.0017282689,0.61098486,0.5530922,-0.34708306,0.5059457,0.59111685,-0.32634363,-0.14372523,-0.27950177,0.55942374,-0.27689257,-0.6514468,0.080110565,0.48578855,-0.7199152,-1.051829,-0.27605236,1.3494695,0.3322038,0.15416895,-0.34948334,0.114120126,-0.6411089,0.7281697,1.014977,0.92589754,-1.8225858,-1.5046118,-1.1295176,0.584189,1.1146177,-0.64867204,0.25805426,-0.08714712,0.8829282,-0.25036108,-1.5067481,0.06422571,-0.35008362,0.6896401,0.7266234,0.8972551,-0.4279718,0.79845935,-0.9554567,0.50190616,-0.5824718,0.6007261,0.3821623,-0.83319044,0.32592988,-0.38107175,-0.6131299,1.1717778,1.6433904,0.26185772,0.7834918,0.3981568,-0.6882321,-0.9010067,1.876109,-0.1684956,-0.8937441,0.66453904,0.47102463,0.79785216,0.44377136,-0.53600633,-0.7326507,-0.049634177,0.08645317,-0.37478128,0.34738842,1.0847602,-0.20862925,1.5601497,0.25152987,0.4959884,-0.27823046,0.04721651,-0.595455,-0.12714693,2.1274347,0.5637105,-0.35361573,1.5371621,0.19177985,-0.38406134,-0.77442867,0.45687273,-0.43354654,-0.77294594,0.39049855,-0.3239039,-0.93547994,0.2273982,0.75703573,0.43061697,1.2529668,1.3481938,-0.16398138,0.041027922,-0.058665656,0.3441124,0.33974937,-0.20193343,-0.19843581,1.5736151,1.2189184,1.0529227,-1.3367964,-0.6527031,1.4836336,-1.3002161,-1.065428,-0.6546992,0.19844644,0.35054848,3.1306132e-05,-0.6114894,0.4035174,0.7698538,-1.1448005,-0.61363447,0.45672002,-0.39251292,-0.39803752,0.21919516,0.3254967,-0.13845655,-0.27097192,-0.22818087,0.15111144,0.38073555,0.29497126,0.3669566,0.90106016,0.82345873,-1.4345977,0.93978053,0.18341406,-0.7053918,0.5876849,-0.7617071,-0.29746157,-0.0621196,-0.23668104,0.4698385,-1.4529634,-0.5726325,0.48020858,0.14412011,-0.06980754,1.3450644,0.41984802,-0.61645263,1.2354698,-1.032689,-0.4902859,-0.08966016,1.7489115,0.09008964,0.1