112	{"act": "IT_ACT_2000", "title": "Cyber Regulations Advisory Committee", "doc_id": "ITACT_SEC_88", "topics": ["governance", "advisory_committee"], "entities": ["Central Government", "Controller", "Cyber Regulations Advisory Committee"], "keywords": ["Cyber Regulations Advisory Committee", "Chairperson", "Central Government", "Controller", "advisory", "regulations"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": [], "clause_text": "The Central Government shall, as soon as may be after the commencement of this Act, constitute a Committee called the Cyber Regulations Advisory Committee. The Cyber Regulations Advisory Committee shall consist of a Chairperson and such number of other official and non-official members representing the interests principally affected or having special knowledge of the subject-matter as the Central Government may deem fit. The Cyber Regulations Advisory Committee shall advise— (a) the Central Government either generally as regards any rules or for any other purpose connected with this Act; (b) the Controller in framing the regulations under this Act.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 88 of the Information Technology Act 2000. The Central Government is required to constitute the Cyber Regulations Advisory Committee, consisting of a Chairperson and official and non-official members with relevant expertise. The Committee advises the Central Government on rules under the Act and the Controller in framing regulations.", "section_number": "88", "subsection_number": null, "validation_status": "validated", "plain_english_summary": "The Central Government must constitute the Cyber Regulations Advisory Committee to advise the Central Government on rules under the Act and the Controller on framing regulations."}	[0.025042627,1.4767532,-3.2562883,-1.446661,1.5193323,0.5683984,0.49559206,0.8596051,0.3093546,-0.13299157,-0.41314366,0.21794617,0.2722054,-0.07493622,-0.31549