114	{"act": "IT_ACT_2000", "title": "Compounding of Offences", "doc_id": "ITACT_SEC_77A", "topics": ["procedure", "compounding_of_offences"], "entities": [], "keywords": ["compounding", "offences", "court", "life imprisonment", "three years", "child", "woman", "socio-economic", "prior conviction"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": [], "clause_text": "A court of competent jurisdiction may compound offences, other than offences for which the punishment for life or imprisonment for a term exceeding three years has been provided, under this Act: Provided that the court shall not compound such offence where the accused is, by reason of his previous conviction, liable to either enhanced punishment or to a punishment of a different kind: Provided further that the court shall not compound any offence where such offence affects the socio economic conditions of the country or has been committed against a child below the age of 18 years or a woman.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 77A of the Information Technology Act 2000. Courts of competent jurisdiction may compound IT Act offences, except those punishable with life imprisonment or imprisonment exceeding three years. Compounding is not permitted where the accused faces enhanced punishment due to prior conviction, or where the offence affects the socio-economic conditions of the country or was committed against a child below 18 years or a woman.", "section_number": "77A", "subsection_number": null, "validation_status": "validated", "plain_english_summary": "A court may compound offences under the Act except those carrying life imprisonment or imprisonment exceeding three years, or where the accused has a prior conviction attracting enhanced punishment, or the offence affects socio-economic conditions or is against a child or woman."}	[1.9921353,1.1459333,-2.925317,-0.81447154,0.6271817,0.49217504,0.18549646,0.7140978,0.7521483,-0.1