115	{"act": "IT_ACT_2000", "title": "Bailable and Cognizable Offences", "doc_id": "ITACT_SEC_77B", "topics": ["procedure", "cognizable_offence", "bailable_offence"], "entities": [], "keywords": ["cognizable", "bailable", "imprisonment", "three years", "CrPC"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": [], "clause_text": "Notwithstanding anything contained in the Code of Criminal Procedure, 1973, the offence punishable with imprisonment of three years and above shall be cognizable and the offence punishable with imprisonment of three years shall be bailable.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 77B of the Information Technology Act 2000. Notwithstanding the Code of Criminal Procedure 1973, offences under the Act punishable with imprisonment of three years and above are cognizable (police can arrest without warrant), and offences punishable with imprisonment of three years are bailable.", "section_number": "77B", "subsection_number": null, "validation_status": "validated", "plain_english_summary": "Offences punishable with imprisonment of three years or more are cognizable. Offences punishable with exactly three years are bailable, notwithstanding the CrPC."}	[1.775493,0.5664303,-3.262075,-0.13909233,0.9596333,0.7223593,-0.076784655,0.82034296,-0.28047255,0.34666923,0.0031811069,0.40787795,0.1637937,-0.8295666,-0.3570856,-0.52113485,0.49714473,-0.74115276,-0.011040289,-0.39745548,0.51046795,-0.51552844,-1.057285,-0.8223766,1.2652847,-0.5635211,0.7698608,-0.17318277,-0.6878077,-0.14859664,1.0966424,-0.28947502,0.49538118,-0.9830817,-0.5922424,-1.5259718,0.54124206,0.07349135,-0.4600413,-0.51790583,0.51615334,0.43618253,-0.45889294,-0.15467064,0.6540112,-0.37610352,1.003357,0.0966947,0.28445882,-0.13781044,-0.07354005,-0.88510513,0.37835994,-0.6560402,1.0219599,1.0328449,-1.4302192,-0.6003488,-0.25608695,0.05275556,1.3740965,0.88216406,-0.6374232,1.2511481,0.4659795,0.107364215,-0.21019304