116	{"act": "IT_ACT_2000", "title": "Power to Investigate Offences", "doc_id": "ITACT_SEC_78", "topics": ["procedure", "investigation", "enforcement"], "entities": [], "keywords": ["investigation", "police officer", "Inspector rank", "offence", "CrPC"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": [], "clause_text": "Notwithstanding anything contained in the Code of Criminal Procedure, 1973, a police officer not below the rank of Inspector shall investigate any offence under this Act.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 78 of the Information Technology Act 2000. Notwithstanding the Code of Criminal Procedure 1973, only a police officer of Inspector rank or above may investigate any offence under the IT Act. This ensures cyber offences are investigated by officers with appropriate rank and expertise.", "section_number": "78", "subsection_number": null, "validation_status": "validated", "plain_english_summary": "Only a police officer of Inspector rank or above may investigate offences under the Act, notwithstanding the CrPC."}	[0.8908977,0.9090659,-3.1394994,-0.2378053,1.6113453,0.85689163,0.3565288,0.75491595,0.35463926,-0.33888176,0.22458372,0.52355176,0.028834498,-1.1550575,-1.0758896,-0.9962399,0.4170396,-1.1761496,-0.62362766,-0.37996614,0.33981177,-0.84424716,-0.5563671,-0.43845287,1.3416014,-0.4528512,0.8964483,-0.39528686,-0.4081685,-0.3903582,0.98676294,0.05258109,0.34518668,-0.6078902,-0.5710033,-1.5984235,0.5100051,0.22517985,-1.1748487,0.4521968,0.5880192,0.07790001,-0.72926843,-0.8918743,0.39605525,-0.00028129749,0.28649884,0.25727922,0.43222377,-0.3188146,-0.07611553,-0.65474486,0.19384009,-0.49333274,0.806473,0.95699596,-0.75283766,0.30172053,0.5028606,-0.72644687,1.5420142,1.2176809,-0.52545756,0.7772118,-0.5475907,-0.40998322,-0.043549094,0.6254899,0.04348295,-0.75593424,0.6416488,-0.86765116,0.7706338,0.23678882,-0.46555465,-0.058180682,-0.4981788,-1.2541921,0.2044705,0.8