117	{"act": "IT_ACT_2000", "title": "Compounding of Contraventions", "doc_id": "ITACT_SEC_63", "topics": ["procedure", "compounding", "adjudication"], "entities": ["Controller", "adjudicating officer"], "keywords": ["compounding", "contraventions", "Controller", "adjudicating officer", "maximum penalty", "conditions", "three years"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": [], "clause_text": "Any contravention under this Act may, either before or after the institution of adjudication proceedings, be compounded by the Controller or such other officer as may be specially authorised by him in this behalf or by the adjudicating officer, as the case may be, subject to such conditions as the Controller or such other officer or the adjudicating officer may specify: Provided that such sum shall not, in any case, exceed the maximum amount of the penalty which may be imposed under this Act for the contravention so compounded.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 63 of the Information Technology Act 2000. Any contravention under the Act may be compounded by the Controller or adjudicating officer, before or after adjudication proceedings are instituted, subject to conditions and a cap not exceeding the maximum penalty for that contravention. A person who commits the same or similar contravention within three years of a previous compounded contravention cannot benefit from compounding again.", "section_number": "63", "subsection_number": null, "validation_status": "validated", "plain_english_summary": "Contraventions under the Act may be compounded by the Controller or adjudicating officer before or after adjudication proceedings begin, subject to conditions and a cap at the maximum penalty for the contravention. A person cannot have a contravention compounded twice within three years."}	[1.5086452,0.8556774,-3.216481,-0.3172948,0.7943118,-0.43029833,0.48671558,0.054874044,1.5783659,-0.11348808,-