118	{"act": "IT_ACT_2000", "title": "Recovery of Penalty or Compensation", "doc_id": "ITACT_SEC_64", "topics": ["procedure", "penalty", "recovery"], "entities": [], "keywords": ["recovery", "penalty", "compensation", "arrear of land revenue", "licence suspension", "electronic signature certificate"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": [], "clause_text": "A penalty imposed or compensation awarded under this Act, if it is not paid, shall be recovered as an arrear of land revenue and the licence or the electronic signature Certificate, as the case may be, shall be suspended till the penalty is paid.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 64 of the Information Technology Act 2000. Any penalty imposed or compensation awarded under the Act that remains unpaid shall be recovered as an arrear of land revenue. Additionally, the relevant licence or electronic signature certificate shall be suspended until the outstanding penalty or compensation is paid.", "section_number": "64", "subsection_number": null, "validation_status": "validated", "plain_english_summary": "Unpaid penalties or compensation under the Act are recoverable as arrears of land revenue, and the relevant licence or electronic signature certificate is suspended until payment is made."}	[1.3025427,0.44963714,-3.3391929,0.02446313,1.0220197,0.3400347,-0.08385422,1.2431012,1.0350636,0.007720001,0.36619553,0.36901733,0.7080975,-0.99024457,0.79939085,-0.07812824,0.3151404,-0.5865564,-0.25753868,-0.11056354,0.6964483,-0.19528477,-1.0098382,-0.67831975,1.0223751,-0.23498487,1.5707885,-0.2149694,-0.4036857,-0.49671838,0.5340988,0.24541597,0.2979325,-0.98207253,-1.0781232,-0.11173468,0.86788476,0.32680196,-1.1705015,-0.16234842,1.0300899,-1.1755416,-0.8249851,0.738523,0.5478321,-0.30804437,1.2459702,0.8401057,0.12021962,-0.29281926,0.37915075,-0.32171658,-0.41652396,-0.2226103,0.74702626,0.3874265,-1.1260991,-0.0136992615,-0.33300042,