120	{"act": "IT_ACT_2000", "title": "Definition - Appropriate Government", "doc_id": "ITACT_DEF_APPROPRIATE_GOVERNMENT", "topics": ["definition", "governance"], "entities": ["Central Government", "State Government"], "keywords": ["appropriate Government", "State Government", "Central Government", "Seventh Schedule", "List II", "List III"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": [], "clause_text": "\\"appropriate Government\\" means as respects any matter,— (i) enumerated in List II of the Seventh Schedule to the Constitution; (ii) relating to any State law enacted under List III of the Seventh Schedule to the Constitution, the State Government and in any other case, the Central Government.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 2(1)(e) of the Information Technology Act 2000 defines appropriate Government as the State Government for matters in List II (State List) or List III (Concurrent List) of the Seventh Schedule to the Constitution, and the Central Government for all other matters.", "section_number": "2", "subsection_number": "1(e)", "validation_status": "validated", "plain_english_summary": "Appropriate Government means the State Government for matters under List II (State List) or List III (Concurrent List) of the Constitution, and the Central Government in all other cases."}	[-0.25226483,1.1164786,-2.9576058,-0.93291867,0.5245358,0.7705105,-0.69355214,0.21400458,1.4577708,-0.010607069,0.14895068,0.46140522,0.44296965,0.25483036,0.09088681,-0.9764099,0.62274647,0.17737716,0.026579646,0.68481904,0.47573102,-0.109204255,-0.95750767,0.109498836,1.5708376,0.42503086,0.9585243,-0.26921967,-0.49902958,-1.4835521,0.033880644,0.06939415,0.9219894,-0.9685077,0.43428767,-1.6521955,0.6210505,-0.28126097,-0.4106363,-0.59469664,0.23715611,0.0793971,-0.33340108,-1.2650268,0.6589235,0.09380398,0.9541823,0.4647297,0.034988016,-0.9779205,0.42397797,-0.47172728,0.33949456,-0.56297815,0.44346592,