121	{"act": "IT_ACT_2000", "title": "Definition - Asymmetric Crypto System", "doc_id": "ITACT_DEF_ASYMMETRIC_CRYPTO_SYSTEM", "topics": ["definition", "cryptography", "digital_signature"], "entities": [], "keywords": ["asymmetric crypto system", "private key", "public key", "digital signature", "key pair", "cryptography"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": ["ITACT_SEC_3"], "clause_text": "\\"asymmetric crypto system\\" means a system of a secure key pair consisting of a private key for creating a digital signature and a public key to verify the digital signature.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 2(1)(f) of the Information Technology Act 2000 defines asymmetric crypto system as a system of a secure key pair consisting of a private key for creating a digital signature and a public key to verify that digital signature. This underpins the digital signature framework under section 3.", "section_number": "2", "subsection_number": "1(f)", "validation_status": "validated", "plain_english_summary": "An asymmetric crypto system is a cryptographic key pair where a private key creates a digital signature and the corresponding public key verifies it."}	[-0.10311957,1.2971616,-3.3697903,-0.48453185,1.281173,0.26251185,0.4065034,0.0607084,-0.15557773,-0.06242195,-0.007987292,1.4198701,1.0714712,-0.6509584,0.35750756,-0.18339105,0.45347542,-0.29719663,0.9059982,0.44392204,-0.14103091,-0.42148483,-0.74411106,-0.3257829,1.6169991,0.1091685,1.1375579,-0.27258942,-1.3960444,-1.1269183,0.020290084,-0.06855364,0.62890124,0.031830184,-1.31822,-1.0487418,0.5683677,-0.0059239445,-0.9482512,-0.008380908,0.59877694,0.73680145,-0.2701818,0.49337474,0.31015083,0.3192375,-0.33118984,0.312168,-0.009902312,-0.49866042,0.46646068,-0.08677697,0.8695501,0.101367585,1.1994748,0.5821611,0.07287811,-0.00064795447,0.19773357,-0.46059066,0.25074828,2.4854777,-0.27164423,0.8348769,0.41041234,-0.2794566,0.48374608,0