122	{"act": "IT_ACT_2000", "title": "Definition - Certification Practice Statement", "doc_id": "ITACT_DEF_CERTIFICATION_PRACTICE_STATEMENT", "topics": ["definition", "certifying_authority", "electronic_signature"], "entities": ["Certifying Authority"], "keywords": ["certification practice statement", "Certifying Authority", "electronic signature certificate", "practices"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": ["ITACT_SEC_22", "ITACT_SEC_35"], "clause_text": "\\"certification practice statement\\" means a statement issued by a Certifying Authority to specify the practices that the Certifying Authority employs in issuing electronic signature Certificates.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 2(1)(h) of the Information Technology Act 2000 defines certification practice statement as a statement issued by a Certifying Authority specifying the practices it employs in issuing electronic signature certificates. It is a required document accompanying licence applications and certificate issuance under sections 22 and 35.", "section_number": "2", "subsection_number": "1(h)", "validation_status": "validated", "plain_english_summary": "A certification practice statement is a document issued by a Certifying Authority setting out the practices it uses when issuing electronic signature certificates."}	[0.02429078,-0.340384,-2.992123,-0.5887606,0.93206745,-0.094616,-0.07992937,0.67512405,0.64485896,-0.10575654,0.18469143,0.018317426,0.53645986,-0.34450796,0.46850315,-0.84280705,-0.12264252,-2.0131023,-0.20621935,-0.24742883,0.2759619,-0.73615056,-0.9680642,-0.8326545,1.3025666,0.6845677,0.531927,-0.7611729,-1.1693915,-1.4522836,0.55165225,0.15803777,1.4673505,-0.514601,-0.58010954,-1.8066888,0.83066016,0.51029795,-0.7254526,-0.410783,1.4696964,-0.05267635,-0.20172411,0.11196863,0.42225292,-0.16242853,-0.34659317,0.23832068,-0.51816916,-0.70597553,0.3697894,-0.6355169,0.8441421,0.5386774,1.3889617