123	{"act": "IT_ACT_2000", "title": "Definition - Computer System", "doc_id": "ITACT_DEF_COMPUTER_SYSTEM", "topics": ["definition", "computer_systems"], "entities": [], "keywords": ["computer system", "device", "programmable", "logic", "arithmetic", "data storage", "retrieval"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": [], "clause_text": "\\"computer system\\" means a device or collection of devices, including input and output support devices and excluding calculators which are not programmable and capable of being used in conjunction with external files, which contain computer programmes, electronic instructions, input data and output data, that performs logic, arithmetic, data storage and retrieval, communication control and other functions.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 2(1)(l) of the Information Technology Act 2000 defines computer system as a device or collection of devices containing computer programmes, electronic instructions, and data that performs logic, arithmetic, data storage and retrieval, and communication functions. Non-programmable calculators are excluded.", "section_number": "2", "subsection_number": "1(l)", "validation_status": "validated", "plain_english_summary": "A computer system is a programmable device or collection of devices that processes logic, arithmetic, data storage, retrieval, and communication functions, including input/output devices but excluding non-programmable calculators."}	[0.507736,1.5969344,-2.8297658,-1.0319173,0.4238066,0.7871481,0.79024273,-0.7650756,-0.4734827,-0.96534044,-0.13556278,1.1402017,0.70336336,0.32858342,-0.1847577,-0.481921,-0.8070486,-0.038382,0.42316133,1.160209,1.3347688,-0.5704196,-0.9004957,-0.46270964,1.3960721,1.159317,0.6497376,-0.073303066,-1.1670724,-0.8260718,0.6656452,-0.5527051,1.154107,-0.58202714,-1.4266757,-1.1430403,0.62603486,-0.5649547,-0.33784643,0.24851502,-0.1869231,0.022991626,-0.16145968,-0.1620