124	{"act": "IT_ACT_2000", "title": "Definition - Digital Signature Certificate", "doc_id": "ITACT_DEF_DIGITAL_SIGNATURE_CERTIFICATE", "topics": ["definition", "digital_signature", "certifying_authority"], "entities": ["Certifying Authority"], "keywords": ["Digital Signature Certificate", "Certifying Authority", "public key", "section 35", "subscriber"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": ["ITACT_SEC_35"], "clause_text": "\\"Digital Signature Certificate\\" means a Digital Signature Certificate issued under sub-section (4) of section 35.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 2(1)(q) of the Information Technology Act 2000 defines Digital Signature Certificate as a certificate issued under section 35(4) by a Certifying Authority. It certifies the subscriber's public key and its relationship with the private key used to create digital signatures.", "section_number": "2", "subsection_number": "1(q)", "validation_status": "validated", "plain_english_summary": "A Digital Signature Certificate is a certificate issued by a Certifying Authority under section 35(4) that validates the subscriber's public key."}	[-0.06769182,0.7829393,-2.9634674,-0.65423495,0.34788704,0.3485148,-0.12954934,0.7978502,0.06938816,-0.5713275,-0.6166953,1.439212,1.0391355,-0.7726158,0.6281969,-0.9918796,-0.06821404,-1.3149642,0.44212466,0.19244827,0.7723318,-0.7591976,-0.7449122,-0.3303539,1.1534481,-0.34472117,1.6653023,-0.04357623,-1.2682537,-1.1154691,0.21786313,-0.144657,1.1695725,-0.3417973,-0.7664708,-1.2926979,0.46587536,0.10216797,-0.85614574,0.27172232,1.0375997,0.5820837,-0.270775,-0.19542004,0.10893499,0.3087843,-0.30789977,0.41132185,0.1489187,-0.46143246,0.36526534,-0.85784656,0.99607027,0.16667438,0.61853117,1.3437777,-0.84471697,-0.0067990418,-0.914691,-0.25222492,0.8271207,1.6830392,-0.36947545,1.1921463,1.1706173,-0.5139294,-0.3640434,0.4965862,0.66097414,-0.9014709,0.9070753,-0.5152876,1.1398954