127	{"act": "IT_ACT_2000", "title": "Definition - Key Pair", "doc_id": "ITACT_DEF_KEY_PAIR", "topics": ["definition", "cryptography", "digital_signature"], "entities": [], "keywords": ["key pair", "private key", "public key", "asymmetric crypto system", "digital signature", "verification"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": [], "clause_text": "\\"key pair\\", in an asymmetric crypto system, means a private key and its mathematically related public key, which are so related that the public key can verify a digital signature created by the private key.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 2(1)(x) of the Information Technology Act 2000 defines key pair in an asymmetric crypto system as a private key and its mathematically related public key, structured so that the public key can verify any digital signature created by the corresponding private key.", "section_number": "2", "subsection_number": "1(x)", "validation_status": "validated", "plain_english_summary": "A key pair consists of a mathematically related private key and public key, where the public key can verify digital signatures created by the private key."}	[-0.12954114,1.1782256,-3.372991,-0.38310263,1.1821148,-0.3540151,-0.1726711,-0.112638794,-0.09740877,0.315737,0.13392106,1.6591817,0.4485834,-0.8963661,0.20558219,-0.11245001,0.6268266,-0.07484506,0.8009122,0.29415655,-0.53087187,-0.34534535,-0.26574808,-0.21827091,1.5195961,-0.22682263,1.4839191,-0.4074409,-0.8725121,-1.2650999,0.16492175,-0.15573594,1.1022508,-0.554359,-1.7459279,-1.1265558,0.5909584,-0.45208046,-0.6179711,-0.22330545,0.48015004,0.7273009,-0.7247035,0.16654989,0.05102666,-0.010390059,-0.4635061,-0.056100708,0.39895344,-0.31683365,0.74465525,0.11731339,1.3839123,-0.17043,1.6033999,0.9650368,0.4284749,0.006250773,0.4363519,-0.26589364,0.3900321,2.022781,0.093877845,0.9167412,0.67998666,-0.32578313,0.32079694,0.64924794,0.24384698,-0.9700186,0.798127,0.0