129	{"act": "IT_ACT_2000", "title": "Definition - Public Key", "doc_id": "ITACT_DEF_PUBLIC_KEY", "topics": ["definition", "cryptography", "digital_signature"], "entities": [], "keywords": ["public key", "key pair", "verify", "digital signature", "Digital Signature Certificate"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": [], "clause_text": "\\"public key\\" means the key of a key pair used to verify a digital signature and listed in the Digital Signature Certificate.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 2(1)(zd) of the Information Technology Act 2000 defines public key as the key of a key pair used to verify a digital signature, which is listed in the subscriber's Digital Signature Certificate. Any person may use the public key to verify digital signatures created by the corresponding private key.", "section_number": "2", "subsection_number": "1(zd)", "validation_status": "validated", "plain_english_summary": "A public key is the key in a key pair used to verify a digital signature, and it is listed in the Digital Signature Certificate."}	[-0.10884826,0.95190704,-3.234055,-0.96366584,0.7707256,0.12903644,0.12316941,0.50289655,-0.025414348,0.06901711,-0.4897538,1.4734304,-0.011034526,-0.68602765,0.33710852,-0.5984971,0.096312866,-1.0233351,0.7086076,0.26916626,0.55162597,-0.8455996,-0.74447286,-0.12445854,0.9285909,-0.69764304,1.7684468,-0.013121191,-0.9030504,-1.2474726,0.05215787,-0.3896454,1.2543391,-0.8811778,-1.3414532,-1.3002288,0.7558975,-0.20124952,-0.34091094,0.012306243,0.5790749,0.53063875,-0.09219019,-0.45193735,-0.08538736,0.05031758,-0.7038336,-0.032917436,0.5273167,-0.47842726,0.5144947,-0.7789809,1.0500512,-0.35508436,1.0711441,0.868051,-0.3438397,-0.26373282,-0.5511941,-0.049873084,1.2347881,1.6400903,-0.30182123,0.7064598,0.771259,-0.38661736,-0.42180145,0.7409273,0.46703947,-0.96114534,0.72354317,0.083042204,1.3624871,-0.2109193,0.51154244,-1.113729,-0.5199255,-0.90624