130	{"act": "IT_ACT_2000", "title": "Definition - Security Procedure", "doc_id": "ITACT_DEF_SECURITY_PROCEDURE", "topics": ["definition", "security"], "entities": ["Central Government"], "keywords": ["security procedure", "Central Government", "section 16", "prescribed"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": ["ITACT_SEC_16"], "clause_text": "\\"security procedure\\" means the security procedure prescribed under section 16 by the Central Government.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 2(1)(zf) of the Information Technology Act 2000 defines security procedure as the procedure prescribed by the Central Government under section 16. These procedures govern what constitutes a secure electronic record and a secure electronic signature.", "section_number": "2", "subsection_number": "1(zf)", "validation_status": "validated", "plain_english_summary": "Security procedure means the procedure prescribed by the Central Government under section 16 for securing electronic records and signatures."}	[0.54293054,0.59651,-3.303155,-0.55834633,1.0090201,-0.016481327,0.7248636,1.0046549,0.37131152,-0.08962183,-0.40636632,0.24815334,0.22973737,-0.8628839,0.1257863,-0.725321,0.9413008,-0.74416906,-0.1693915,-0.3987652,0.84925985,-0.4966658,-1.3506782,0.12989229,1.4366257,0.10487969,1.084595,-1.0581912,-0.78792673,-1.2398535,1.1239667,-0.08250379,1.5432616,-0.38771096,-0.7393853,-2.589173,0.37446415,0.3213912,-1.1284204,-0.43954992,0.7178058,0.12374336,0.14918241,-0.53841394,0.0972061,0.7462497,0.70836097,0.069598235,-0.42803234,-0.7916882,0.13888097,-0.19201936,-0.05526549,-0.72522056,1.4172251,0.66317725,-0.56480443,0.80564934,0.14664494,-0.052743625,1.900707,1.7978187,-0.8106379,0.63063604,0.57421553,-0.05389513,-0.41600457,1.0406791,0.24381277,-0.2953253,0.75807273,0.04367114,0.40364796,-0.72539777,0.016053945,-1.062563,-0.39185774,-1.0334337,0.14336173,1.1335709,0.08176169,-0.6943255,1.0999452,-0.08