131	{"act": "IT_ACT_2000", "title": "Definition - Verify", "doc_id": "ITACT_DEF_VERIFY", "topics": ["definition", "digital_signature", "verification"], "entities": ["subscriber"], "keywords": ["verify", "digital signature", "electronic record", "public key", "private key", "intact", "altered", "subscriber"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": [], "clause_text": "\\"verify\\", in relation to a digital signature, electronic record or public key, with its grammatical variations and cognate expressions, means to determine whether— (a) the initial electronic record was affixed with the digital signature by the use of private key corresponding to the public key of the subscriber; (b) the initial electronic record is retained intact or has been altered since such electronic record was so affixed with the digital signature.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 2(1)(zh) of the Information Technology Act 2000 defines verify as the process of determining, in relation to a digital signature, electronic record or public key, whether the initial electronic record was affixed with a digital signature using the private key corresponding to the subscriber's public key, and whether the record remains intact or has been altered since signing.", "section_number": "2", "subsection_number": "1(zh)", "validation_status": "validated", "plain_english_summary": "To verify a digital signature means to determine that the electronic record was signed using the subscriber's private key and that the record has not been altered since it was signed."}	[1.1843795,0.07696136,-3.4717464,-0.70607275,1.622109,-0.2596406,0.70649034,0.8562556,0.23218402,-0.011332733,-0.8675722,0.9837552,-0.21732046,-0.115540884,0.30688205,-0.46603072,0.49295616,-1.6650085,0.68403095,0.45090514,0.7134611,-0.5625687,-1.630605,0.47918212,1.0436625,-0.5448641,1.114639,-0.3148711,-0.81333613,-1.4324319,0.26300526,-0.3176487,1.5855252,-1.13