132	{"act": "IT_ACT_2000", "title": "Cross-Reference Interpretation", "doc_id": "ITACT_SEC_2_SUB_2", "topics": ["interpretation", "legislation"], "entities": [], "keywords": ["cross-reference", "enactment", "corresponding law", "interpretation", "in force", "area"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": [], "clause_text": "Any reference in this Act to any enactment or any provision thereof shall, in relation to an area in which such enactment or such provision is not in force, be construed as a reference to the corresponding law or the relevant provision of the corresponding law, if any, in force in that area.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 2(2) of the Information Technology Act 2000. Where the Act refers to any enactment or provision that is not in force in a particular area, that reference shall be construed as a reference to the corresponding law or provision in force in that area. This ensures the Act operates uniformly across all territories of India regardless of local variations in applicable law.", "section_number": "2", "subsection_number": "2", "validation_status": "validated", "plain_english_summary": "Any reference in the Act to a law or provision not in force in a particular area shall be read as a reference to the corresponding law or provision that is in force in that area."}	[0.34730315,-0.21549831,-3.3126843,-0.30065423,1.36298,0.9580094,0.28465655,0.23609957,0.1873204,-0.38223675,0.6062256,0.6606996,0.9255263,-0.48874122,0.017026622,-0.45348534,0.30858195,-0.58221626,0.2250964,0.7261771,0.38372466,0.2901688,-0.36248162,-0.34023884,0.89239734,0.36283278,1.8080729,-0.18659668,-1.3571135,-1.7520823,0.8056749,-0.39812684,1.0169106,-1.8259224,-0.6736271,-1.1627017,0.6141562,-0.17364961,-1.0527437,0.01460621,0.7770592,0.36414325,-0.2993192,-0.33813524,1.2123631,-0.3758255,0.93353474,0.13628444,-0.035227243,-0.9168467,-0.17918746,-0.66366637,-0.18412685,-0.41373804