133	{"act": "IT_ACT_2000", "title": "Use of Electronic Records in Government - Rule-Making", "doc_id": "ITACT_SEC_6_SUB_2", "topics": ["e_governance", "procedure", "rule_making"], "entities": ["appropriate Government"], "keywords": ["electronic records", "manner and format", "payment", "fees", "appropriate Government", "rules"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": ["ITACT_SEC_6_SUB_1"], "clause_text": "The appropriate Government may, for the purposes of sub-section (1), by rules, prescribe— (a) the manner and format in which such electronic records shall be filed, created or issued; (b) the manner or method of payment of any fee or charges for filing, creation or issue any electronic record under clause (a).", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 6(2) of the Information Technology Act 2000. The appropriate Government may make rules to prescribe the manner and format for filing, creating or issuing electronic records with Government, and the manner or method of payment of fees or charges for such electronic filings under section 6(1).", "section_number": "6", "subsection_number": "2", "validation_status": "validated", "plain_english_summary": "The appropriate Government may make rules prescribing the manner, format, and method of payment for electronic filing, creation, or issuance of records under section 6(1)."}	[0.031313714,1.0288445,-3.1208453,-0.7348414,0.5802983,0.14632511,-0.4791605,0.031708155,0.4454454,-0.4225881,0.21996747,0.3752878,0.60164344,0.20459639,0.4941072,-0.59618384,0.5230653,-0.7267257,0.26534516,1.0300133,0.72479534,-0.5635073,-1.4415134,-0.29495975,0.86826897,-0.6320268,1.3429712,-0.037105996,-0.5289873,-1.0172558,0.92233986,0.41516438,0.97767717,-0.45654744,-0.759089,-1.5083337,0.19295721,-0.039694615,-1.0485706,-0.057298686,1.2017726,-0.6220961,-0.8390402,-0.0032168534,0.47581747,0.16299164,0.9696128,0.17411302,0.05111759,-0.26093078,0.32779613,-1.1299969,-0