134	{"act": "IT_ACT_2000", "title": "Power to Make Rules on Electronic Signature", "doc_id": "ITACT_SEC_10", "topics": ["electronic_signature", "rule_making", "procedure"], "entities": ["Central Government"], "keywords": ["electronic signature", "Central Government", "rules", "manner and format", "integrity", "security", "confidentiality"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": [], "clause_text": "The Central Government may, for the purposes of this Act, by rules, prescribe— (a) the type of electronic signature; (b) the manner and format in which the electronic signature shall be affixed; (c) the manner or procedure which facilitates identification of the person affixing the electronic signature; (d) control processes and procedures to ensure adequate integrity, security and confidentiality of electronic records or payments; and (e) any other matter which is necessary to give legal effect to electronic signatures.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 10 of the Information Technology Act 2000. The Central Government may make rules prescribing the type of electronic signature, the manner and format in which it shall be affixed, procedures for identifying the signatory, and control processes to ensure integrity, security and confidentiality of electronic records or payments, and any other matter necessary to give legal effect to electronic signatures.", "section_number": "10", "subsection_number": null, "validation_status": "validated", "plain_english_summary": "The Central Government may make rules covering the type, manner, and format of electronic signatures, procedures for identifying the signatory, and controls to ensure integrity and security of electronic records."}	[0.12742706,0.9253746,-2.9062476,-1.0578395,1.1875614,-0.07005849,-0.20207348,1.3576206,0.49736768,-0.28024125,-0.24315245,0.5590302,0.869651,0.04881822,0.56604856,-0.22533134,0.46400997,-1.0810945,0.7073493,0.75058