135	{"act": "IT_ACT_2000", "title": "Acknowledgment - No Stipulation and Reasonable Time", "doc_id": "ITACT_SEC_12_SUB_3", "topics": ["electronic_records", "acknowledgment", "procedure"], "entities": ["originator", "addressee"], "keywords": ["acknowledgment", "reasonable time", "originator", "addressee", "notice", "deemed not sent"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": ["ITACT_SEC_12_SUB_1"], "clause_text": "Where the originator has not stipulated that the electronic record shall be binding only on receipt of such acknowledgment, and the acknowledgment has not been received by the originator within the time specified or agreed or, if no time has been specified or agreed to within a reasonable time, then the originator may give notice to the addressee stating that no acknowledgment has been received by him and specifying a reasonable time by which the acknowledgment must be received by him and if no acknowledgment is received within the aforesaid time limit he may after giving notice to the addressee, treat the electronic record as though it has never been sent.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 12(3) of the Information Technology Act 2000. Where the originator has not made the electronic record's binding effect conditional on acknowledgment, but acknowledgment has not been received within the specified or reasonable time, the originator may give notice specifying a reasonable deadline. If acknowledgment is still not received by that deadline, the originator may treat the electronic record as though it was never sent.", "section_number": "12", "subsection_number": "3", "validation_status": "validated", "plain_english_summary": "Where the originator has not made binding effect conditional on acknowledgment but none has arrived within the stipulated or reasonable time, the originator may give notice and, if still no acknowledgment is received, treat the record as never sent."}	[0