136	{"act": "IT_ACT_2000", "title": "Place of Despatch and Receipt of Electronic Record", "doc_id": "ITACT_SEC_13_SUB_3", "topics": ["electronic_records", "despatch", "receipt", "procedure"], "entities": ["originator", "addressee"], "keywords": ["place of despatch", "place of receipt", "originator", "addressee", "place of business"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": [], "clause_text": "Save as otherwise agreed to between the originator and the addressee, an electronic record is deemed to be despatched at the place where the originator has his place of business, and is deemed to be received at the place where the addressee has his place of business.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 13(3) of the Information Technology Act 2000. Unless otherwise agreed, an electronic record is deemed to be dispatched at the originator's place of business and received at the addressee's place of business, regardless of where the computer resource processing the record is located.", "section_number": "13", "subsection_number": "3", "validation_status": "validated", "plain_english_summary": "Unless agreed otherwise, an electronic record is deemed dispatched from the originator's place of business and received at the addressee's place of business."}	[0.059284948,0.401256,-3.266005,-0.789994,0.878755,0.37053442,0.020313779,1.35351,-0.028506717,0.15858209,-0.37341222,0.441717,0.5347161,-0.6012764,-0.2472842,-0.8197994,0.3691444,-0.6003424,0.3776439,0.794672,0.8212052,-0.5368839,-1.3099205,0.18243636,0.84896773,-0.5697168,0.986381,-0.51913965,-0.6530316,-1.1313406,0.67051053,-0.30668378,0.8557466,-0.66069144,-1.0590807,-1.0398132,-0.69816333,-0.4170294,-0.5348881,0.4132413,0.8833837,-0.46143022,-1.2291808,-0.29278734,0.48835862,0.7767226,-0.10169236,0.7252083,0.6490518,0.17532662,-0.06599606,-0.6849596,-0.54544073,-0.0046364525,0.9809414,0.15211596,-0.90631706,0.706393,0.20187908,-0.06721302,2.28213