137	{"act": "IT_ACT_2000", "title": "Application for Certifying Authority Licence", "doc_id": "ITACT_SEC_22", "topics": ["certifying_authority", "licensing", "procedure"], "entities": ["Central Government", "Certifying Authority"], "keywords": ["licence application", "Certifying Authority", "certification practice statement", "identification procedures", "fees", "twenty-five thousand"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": ["ITACT_SEC_21"], "clause_text": "Every application for issue of a licence shall be in such form as may be prescribed by the Central Government. Every application for issue of a licence shall be accompanied by— (a) a certification practice statement; (b) a statement including the procedures with respect to identification of the applicant; (c) payment of such fees, not exceeding twenty-five thousand rupees as may be prescribed by the Central Government; (d) such other documents, as may be prescribed by the Central Government.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 22 of the Information Technology Act 2000. Every application for a Certifying Authority licence must be in the prescribed form and accompanied by a certification practice statement, a statement of identification procedures, payment of prescribed fees not exceeding Rs 25,000, and other prescribed documents.", "section_number": "22", "subsection_number": null, "validation_status": "validated", "plain_english_summary": "An application for a Certifying Authority licence must be in the prescribed form, accompanied by a certification practice statement, identification procedures, a fee not exceeding Rs 25,000, and other prescribed documents."}	[-0.33434904,-0.15012982,-2.7850916,-0.36989358,0.47331285,-0.49672723,-0.4495052,0.93402016,0.4552591,-0.13664034,0.3993687,-0.11395212,1.4351001,-0.41235632,0.51283044,-0.6218188,0.3240607,-1.9380405,-0.40559828,-0.025657607,0.14960483,-0.77705,-1.0752445,-0.39954495,1.