138	{"act": "IT_ACT_2000", "title": "Renewal of Certifying Authority Licence", "doc_id": "ITACT_SEC_23", "topics": ["certifying_authority", "licensing", "procedure"], "entities": ["Central Government"], "keywords": ["licence renewal", "forty-five days", "Certifying Authority", "fees", "five thousand rupees", "expiry"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": ["ITACT_SEC_21"], "clause_text": "An application for renewal of a licence shall be— (a) in such form; (b) accompanied by such fees, not exceeding five thousand rupees, as may be prescribed by the Central Government and shall be made not less than forty-five days before the date of expiry of the period of validity of the licence.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 23 of the Information Technology Act 2000. An application for renewal of a Certifying Authority licence must be made in the prescribed form at least 45 days before expiry, accompanied by prescribed fees not exceeding Rs 5,000.", "section_number": "23", "subsection_number": null, "validation_status": "validated", "plain_english_summary": "A licence renewal application must be submitted at least 45 days before expiry, in the prescribed form, with a fee not exceeding Rs 5,000."}	[0.41528234,-0.26102224,-3.0799508,-0.38255355,-0.10467608,-0.79964006,-0.52325577,0.89695287,0.84419423,-0.020219948,0.024872301,0.45266554,0.9127118,-0.51709116,0.6199487,-0.38895622,0.19633187,-1.7078741,-0.649636,0.2132439,0.2535499,-1.1302366,-1.1120622,-0.54491323,1.0904421,0.157032,1.2564739,-0.29046005,-0.020678699,-0.47635368,1.2255682,-0.2982986,1.2018846,-0.9600759,0.04229206,-1.401546,1.0383556,0.43907183,-0.8867824,-0.646008,2.047354,-0.4862661,0.73413783,-0.14248317,1.1426767,-0.52934635,0.8260083,-0.023494283,0.270781,-1.0931386,-0.023558408,-0.31381965,-0.582532,-0.0124372,0.5264312,1.5488468,-1.6146594,-0.042442273,-0.88475543,-0.4780782,1.8643852,0.55862594,-0.50640374,1.8354691,