139	{"act": "IT_ACT_2000", "title": "Procedure for Grant or Rejection of Licence", "doc_id": "ITACT_SEC_24", "topics": ["certifying_authority", "licensing", "procedure"], "entities": ["Controller"], "keywords": ["grant", "rejection", "licence", "Controller", "reasonable opportunity", "application"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": ["ITACT_SEC_21"], "clause_text": "The Controller may, on receipt of an application under sub-section (1) of section 21, after considering the documents accompanying the application and such other factors, as he deems fit, grant the licence or reject the application: Provided that no application shall be rejected under this section unless the applicant has been given a reasonable opportunity of presenting his case.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 24 of the Information Technology Act 2000. The Controller may grant or reject a licence application under section 21 after considering the accompanying documents and such other factors as deemed fit. No application may be rejected without first giving the applicant a reasonable opportunity to present their case.", "section_number": "24", "subsection_number": null, "validation_status": "validated", "plain_english_summary": "The Controller may grant or reject a Certifying Authority licence after considering accompanying documents and other relevant factors, but must give the applicant a reasonable opportunity to present their case before rejection."}	[0.1672761,-0.12731425,-2.7716324,-0.23918866,0.035586182,0.64059037,-0.048198603,1.2195644,0.22055636,-0.51767164,0.32337344,0.18112709,0.90997773,-0.13874203,0.21448335,-0.048616413,0.32910922,-1.2811947,-0.14378762,-0.5447141,0.14041068,-0.35659584,-1.9081656,-0.72772646,1.226266,-0.27406132,0.91685,-1.0712185,-0.3641945,0.018965451,0.19045553,-0.2839856,1.4380066,-1.4627055,-0.8126957,-0.9483321,0.39647457,0.2594545,-2.2476993,0.4717328,0.8240086,-0.16907