140	{"act": "IT_ACT_2000", "title": "Notice of Suspension or Revocation of Certifying Authority Licence", "doc_id": "ITACT_SEC_26", "topics": ["certifying_authority", "obligation", "disclosure"], "entities": ["Controller", "Certifying Authority"], "keywords": ["suspension", "revocation", "notice", "Controller", "database", "repository", "accessible"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": ["ITACT_SEC_25"], "clause_text": "Where the licence of the Certifying Authority is suspended or revoked, the Controller shall publish notice of such suspension or revocation, as the case may be, in the data base maintained by him. Where one or more repositories are specified, the Controller shall publish notices of such suspension or revocation, as the case may be, in all such repositories: Provided that the data base containing the notice of such suspension or revocation, as the case may be, shall be made available through a web site which shall be accessible round the clock.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 26 of the Information Technology Act 2000. The Controller is obligated to publish notice of any suspension or revocation of a Certifying Authority licence in the Controller's database and all specified repositories. The database must be accessible round the clock through a website.", "section_number": "26", "subsection_number": null, "validation_status": "validated", "plain_english_summary": "When a Certifying Authority licence is suspended or revoked, the Controller must publish notice in the relevant database and all specified repositories, accessible round the clock via a website."}	[0.5289759,-0.2210225,-3.288609,-1.0261713,0.90173084,-0.6396663,0.14376302,0.94647497,0.8725596,-0.52248824,0.49576288,-0.33363,0.8865327,-0.47069278,0.9927771,-0.54182357,-0.28739816,-0.9600371,-0.5317687,-0.29667056,0.858695,-1.4757205,-1.6017919,-0.06920512,1.3305845,0.7100341,0.5891049,-0.6512514,-0.22