142	{"act": "IT_ACT_2000", "title": "Power to Investigate Contraventions", "doc_id": "ITACT_SEC_28", "topics": ["investigation", "enforcement", "procedure"], "entities": ["Controller"], "keywords": ["investigation", "contravention", "Controller", "Income Tax Act", "powers", "authorised officer"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": [], "clause_text": "The Controller or any officer authorised by him in this behalf shall take up for investigation any contravention of the provisions of this Act, rules or regulations made thereunder. The Controller or any officer authorised by him in this behalf shall exercise the like powers which are conferred on Income-tax authorities under Chapter XIII of the Income-tax Act, 1961, and shall exercise such powers, subject to such limitations laid down under that Act.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 28 of the Information Technology Act 2000. The Controller or any authorised officer may investigate contraventions of the Act and rules and regulations thereunder. For investigations, they have the same powers as Income Tax authorities under Chapter XIII of the Income Tax Act 1961, subject to the limitations of that Act.", "section_number": "28", "subsection_number": null, "validation_status": "validated", "plain_english_summary": "The Controller or an authorised officer may investigate contraventions of the Act and its rules, with powers equivalent to Income Tax authorities under Chapter XIII of the Income Tax Act, 1961."}	[0.774815,0.1960904,-3.2145367,-0.41643268,1.3805727,0.20776528,-0.052320763,0.60528535,0.73474365,-0.65254474,0.26569468,-0.14074463,0.46189722,-0.5498891,0.093817115,-0.6672968,0.23082702,-0.8740133,0.11143409,-0.29269955,0.96280974,-0.82321644,-0.8765677,0.18459716,1.7223874,0.04857678,0.67834944,-0.45954874,-0.3718439,-0.9308152,0.7465862,-0.41705385,1.2098074,-0.738466,-0.5340288,-1.2109557,1.1043143,0.46435708,-1.3934335,0.