143	{"act": "IT_ACT_2000", "title": "Access to Computers and Data for Investigation", "doc_id": "ITACT_SEC_29", "topics": ["investigation", "enforcement", "procedure"], "entities": ["Controller"], "keywords": ["access", "computer system", "data", "Controller", "reasonable cause", "search", "investigation"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": ["ITACT_SEC_69"], "clause_text": "Without prejudice to the provisions of sub-section (1) of section 69, the Controller or any person authorised by him shall, if he has reasonable cause to suspect that any contravention of the provisions of this Chapter has been committed, have access to any computer system, any apparatus, data or any other material connected with such system, for the purpose of searching or causing a search to be made for obtaining any information or data contained in or available to such computer system.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 29 of the Information Technology Act 2000. The Controller or any authorised person may, on reasonable suspicion of a contravention of Chapter VI, access any computer system, apparatus, data or related material for the purpose of searching for information or data. They may also direct persons in charge of such systems to provide technical assistance.", "section_number": "29", "subsection_number": null, "validation_status": "validated", "plain_english_summary": "The Controller or an authorised person may access any computer system and data when there is reasonable cause to suspect a contravention of the Act, for the purpose of searching for relevant information."}	[0.5627233,0.5542359,-3.1484106,-0.66695803,0.6065993,0.14061783,0.1624855,-0.046375316,0.16901387,-0.5327017,0.5574606,0.037549052,0.47026092,-0.3346414,0.28842813,0.02116592,0.015627548,-0.33900082,-0.24156046,-0.4409914,1.3122044,-1.175697,-0.6419721,0.17013575,1.0133959,0.4473028,1.4437717,-0.27854598,-0.5298137,-0.6990252,0.