145	{"act": "IT_ACT_2000", "title": "Certifying Authority - Surrender of Licence", "doc_id": "ITACT_SEC_33", "topics": ["certifying_authority", "obligation", "penalty"], "entities": ["Certifying Authority", "Controller"], "keywords": ["surrender", "licence", "Certifying Authority", "Controller", "suspended", "revoked", "imprisonment", "ten thousand rupees"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": ["ITACT_SEC_25"], "clause_text": "Every Certifying Authority whose licence is suspended or revoked shall immediately after such suspension or revocation, surrender the licence to the Controller. Where any Certifying Authority fails to surrender a licence under sub-section (1), the person in whose favour a licence is issued, shall be guilty of an offence and shall be punished with imprisonment which may extend up to six months or a fine which may extend up to ten thousand rupees or with both.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 33 of the Information Technology Act 2000. A Certifying Authority whose licence is suspended or revoked must immediately surrender the licence to the Controller. Failure to surrender is an offence punishable with imprisonment for up to six months or a fine up to Rs 10,000 or both.", "section_number": "33", "subsection_number": null, "validation_status": "validated", "plain_english_summary": "A Certifying Authority whose licence is suspended or revoked must immediately surrender the licence to the Controller. Failure to do so is an offence punishable with imprisonment up to six months or a fine up to Rs 10,000, or both."}	[1.2532469,0.12232547,-3.2646878,-0.3413113,1.2925035,0.22717384,-0.47006226,0.4969568,0.3967683,-0.1177642,-0.30025938,-0.012708663,0.6718778,-0.3572638,1.4460052,-0.38627055,0.64233047,-1.5753181,-0.5620025,-0.04144662,0.2963044,-0.6563016,-1.5369309,-0.05618911,1.6141027,0.3331163,1.5159329,-0.7653122,-0.18868476,0.39054298,0.6293404,-0.2490997,0.