146	{"act": "IT_ACT_2000", "title": "Representations Upon Issuance of Digital Signature Certificate", "doc_id": "ITACT_SEC_36", "topics": ["certifying_authority", "obligation", "digital_signature"], "entities": ["Certifying Authority", "subscriber"], "keywords": ["representations", "Digital Signature Certificate", "Certifying Authority", "subscriber", "private key", "public key", "accuracy", "compliance"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": [], "clause_text": "A Certifying Authority while issuing a Digital Signature Certificate shall certify that— (a) it has complied with the provisions of this Act and the rules and regulations made thereunder; (b) it has published the Digital Signature Certificate or otherwise made it available to such person relying on it and the subscriber has accepted it; (c) the subscriber holds the private key corresponding to the public key, listed in the Digital Signature Certificate; (ca) the subscriber holds a private key which is capable of creating a digital signature; (cb) the public key to be listed in the certificate can be used to verify a digital signature affixed by the private key held by the subscriber; (d) the subscriber's public key and private key constitute a functioning key pair; (e) the information contained in the Digital Signature Certificate is accurate; and (f) it has no knowledge of any material fact, which if included in the Digital Signature Certificate would adversely affect the reliability of the representations.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 36 of the Information Technology Act 2000. A Certifying Authority issuing a Digital Signature Certificate must certify: its own compliance with the Act; publication and subscriber acceptance of the certificate; that the subscriber holds the corresponding private key capable of creating digital signatures; that the public key can verify those signatures; that the key pair is functional; that the certificate information is accurate; and that no adverse material fact is known.", "section_number": "36", "subsection_number": null, "validation_status": "validated", "plain_english_summary": "When issuing a Digital Signature Certificate, a Certifying Authority must certify compliance with the Act, accuracy of information, that the subscriber holds the correct private key capable of creating digital signatures, that the key pair functions correctly, and absence of knowledge of any adverse material fact."}	[-0.08098287,0.89847654,-3.1210685,-0.36021635,0.7263174,0.16486707,-0.56801134,1.1384646,0.2592032,-0.20554014,-0.20536992,1.0036479,0.7572943,-0.45589763,0.49422127,-0.38612726,0.057998095,-1.653566,0.40101454,0.5481894,0.69931674,-0.6549531,-0.97609687,-0.3593684,1.1449481,-0.34714833,1.5023509,-0.15510547,-0.8134099,-0.93472296,0.64914745,-0.093834855,1.0420213,-0.7318167,-0.26695958,-1.6661514,0.39889264,0.52305883,-0.6123828,0.39941832,1.2156327,0.5369407,-0.40421057,-0.072618134,0.10130819,0.30760172,0.11475247,0.47843084,0.46766627,-0.5996746,0.3022048,-1.0924996,0.9684744,0.4608513,0.5951788,1.5822841,-1.330586,0.19002454,-1.1079235,-1.1768254,0.6247093,1.6502893,-0.40183586,1.0833308,1.2091506,-0.8433583,-0.5207338,0.6682591,0.40403003,-0.6579022,0.8973788,-0.60716736,1.2465955,0.22193933,0.42352885,-1.6357421,-0.39584053,-1.5943007,0.1469116,0.73558396,0.44443014,-0.30447963,2.2537334,0.12903614,0.3338055,0.52393943,-1.4039818,-0.42095634,0.10150199,1.673026,0.9213501,-0.3687825,0.49566877,-0.16980475,0.011918054,-0.10009989,0.5832775,1.0187745,-0.045996398,-0.42388192,-0.65633065,-0.4331501,0.044162568,-0.64508075,0.29899532,0.69983387,-0.29706657,0.19441134,0.012876506,0.23232986,0.096946426,0.49259523,-0.25450966,0.052638896,0.6073072,0.33826956,0.6411129,-0.8255157,-0.250971,0.20707542,-0.5160703,-0.7886451,0.23216096,1.2610027,-0.0051889853,-0.043903165,-0.7137252,-0.08160253,0.23220989,-0.78389084,-0.19858044,0.59588,-0.6565264,0.1938