147	{"act": "IT_ACT_2000", "title": "Notice of Suspension or Revocation of Digital Signature Certificate", "doc_id": "ITACT_SEC_39", "topics": ["certifying_authority", "obligation", "digital_signature"], "entities": ["Certifying Authority"], "keywords": ["notice", "suspension", "revocation", "Digital Signature Certificate", "repository", "Certifying Authority", "publication"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": ["ITACT_SEC_37", "ITACT_SEC_38"], "clause_text": "Where a Digital Signature Certificate is suspended or revoked under section 37 or section 38, the Certifying Authority shall publish a notice of such suspension or revocation, as the case may be, in the repository specified in the Digital Signature Certificate for publication of such notice. Where one or more repositories are specified, the Certifying Authority shall publish notices of such suspension or revocation, as the case may be, in all such repositories.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 39 of the Information Technology Act 2000. When a Digital Signature Certificate is suspended under section 37 or revoked under section 38, the Certifying Authority must promptly publish notice of the suspension or revocation in the repository or repositories specified in the certificate.", "section_number": "39", "subsection_number": null, "validation_status": "validated", "plain_english_summary": "When a Digital Signature Certificate is suspended or revoked, the Certifying Authority must publish notice of the suspension or revocation in all repositories specified in the certificate."}	[0.82670915,0.433787,-2.9832041,-0.82938766,0.48997635,0.1868146,0.00024352325,1.3052027,0.7079828,-0.5758726,-0.3407603,0.8350665,0.5660124,-0.6406669,0.5120597,-0.619528,0.6102656,-1.2269537,-0.6373927,0.08796701,0.7586111,-1.0923305,-1.4771105,-0.0013442232,1.1957195,0.6263243,1.242089,0.029244773,-1.3389536,-0.34363177,0.95044273,0.23516423,0.2