148	{"act": "IT_ACT_2000", "title": "Duties of Subscriber of Electronic Signature Certificate", "doc_id": "ITACT_SEC_40A", "topics": ["electronic_signature", "duty", "subscriber_duty"], "entities": ["subscriber"], "keywords": ["Electronic Signature Certificate", "subscriber", "duties", "prescribed"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": [], "clause_text": "In respect of Electronic Signature Certificate the subscriber shall perform such duties as may be prescribed.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 40A of the Information Technology Act 2000. A subscriber of an Electronic Signature Certificate must perform such duties as are prescribed. This provision enables the Central Government to prescribe specific obligations on subscribers of electronic signature certificates beyond those relating to Digital Signature Certificates.", "section_number": "40A", "subsection_number": null, "validation_status": "validated", "plain_english_summary": "A subscriber holding an Electronic Signature Certificate must perform such duties as are prescribed by the Central Government."}	[-0.6618346,0.751575,-2.9631295,-0.9843987,0.26598832,0.30723825,-0.2992423,0.7857184,0.5182384,0.42099208,-0.8688353,0.8332155,0.37441728,-0.32863766,0.517338,-0.39288846,0.402575,-0.9703354,0.16894016,0.2917723,0.5677973,-0.7028252,-0.8810077,0.15043789,0.9244453,-0.18517461,2.0690007,-0.1525836,-0.5670468,-1.3880334,0.6196025,0.019604793,1.1210282,-0.55796784,-0.79500383,-1.048242,0.42874303,0.8477605,-1.3489866,0.40606105,0.78812385,0.08833776,-0.37077925,0.11630457,0.14748754,-0.367191,0.9941303,0.4772589,0.52819836,-0.64554006,0.25241205,-1.2437079,0.07913916,0.03004179,1.162507,0.80119133,-0.7988534,0.21091673,-0.30757385,-0.09532666,1.6045592,1.6675657,-0.7994436,1.2856699,0.7834547,-0.65576255,-0.1863439,0.7388858,0.22235142,-0.29793125,0.82249457,-0.0013236662,0.85675484,-0.3215357,0.495263,-1.3724377,-0.6938765,-