149	{"act": "IT_ACT_2000", "title": "Acceptance of Digital Signature Certificate", "doc_id": "ITACT_SEC_41", "topics": ["digital_signature", "duty", "subscriber_duty"], "entities": ["subscriber", "Certifying Authority"], "keywords": ["acceptance", "Digital Signature Certificate", "subscriber", "private key", "certifies", "relying party", "truth"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": [], "clause_text": "A subscriber shall be deemed to have accepted a Digital Signature Certificate if he publishes or authorises the publication of a Digital Signature Certificate— (a) to one or more persons; (b) in a repository; or otherwise demonstrates his approval of the Digital Signature Certificate in any manner. By accepting a Digital Signature Certificate the subscriber certifies to all who reasonably rely on the information contained in the Digital Signature Certificate that— (a) the subscriber holds the private key corresponding to the public key listed in the Digital Signature Certificate and is entitled to hold the same; (b) all representations made by the subscriber to the Certifying Authority and all material relevant to the information contained in the Digital Signature Certificate are true; (c) all information in the Digital Signature Certificate that is within the knowledge of the subscriber is true.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 41 of the Information Technology Act 2000. A subscriber who publishes, authorises publication of, or otherwise demonstrates approval of a Digital Signature Certificate is deemed to have accepted it. By accepting, the subscriber certifies to relying parties that the private key information is accurate, all representations to the Certifying Authority are true, and all certificate information within the subscriber's knowledge is accurate.", "section_number": "41", "subsection_number": null, "validation_status": "validated", "plain_english_summary": "A subscriber is deemed to have accepted a Digital Signature Certificate by publishing it or otherwise demonstrating approval, and in doing so certifies the accuracy of all information in it to anyone relying on it."}	[-0.06529506,0.81467015,-3.0599084,-0.8138063,0.35527664,0.37958208,-0.3260477,0.8419465,0.19233792,0.38094342,-0.28036672,0.87254566,0.7234084,-0.41210207,0.32588506,-0.5947886,0.629139,-1.8646969,0.14480485,0.0132635,-0.076849274,-0.4323147,-1.3026149,-0.033616327,1.0138601,-0.3525555,1.0370617,-0.10063436,-0.41889754,-0.7807938,0.13222197,0.023159742,0.88047606,0.059416838,-0.552913,-1.4589726,0.17999569,0.28658238,-0.7770173,0.16330223,0.23918372,0.9849762,-0.5820194,0.07811388,0.16748425,-0.05194135,-0.010709371,0.4202983,0.73784006,-0.86529607,0.11948584,-0.9454061,0.5257417,0.6356377,1.2091073,1.4766934,-1.1829842,0.3696259,-1.0203326,-0.92982924,0.76793647,1.2631842,-0.16247025,1.023763,1.4576827,-0.25553033,-0.6393897,0.85951596,0.94026476,-0.7881744,1.0075151,-0.36507672,0.7859818,0.28234512,0.45046818,-1.5560687,-0.2823531,-1.5124772,-0.30433038,0.7202585,0.3164854,-0.5625595,1.8940425,-0.049994133,0.54441255,0.66154534,-0.558931,-0.100236624,-0.35410994,1.4277244,0.86692417,-0.2745212,0.42956766,0.15790276,-0.3543112,0.4053536,0.19495456,0.37486768,-0.48261824,-0.58821154,-0.8289535,-0.25355747,0.0016825019,0.3112862,0.34321707,1.2991401,-0.54521453,0.040368333,0.05002378,-0.25369042,-0.06874008,-0.11058654,-0.116149604,-0.45377514,0.88823426,-0.08103731,0.47617477,-0.74561393,-0.098389655,0.27042705,-0.7242724,-0.7136495,0.07718604,1.670761,0.042967625,-0.0703984,-1.2419931,-0.1275122,0.35336423,-0.8237881,-0.2798806,0.30698952,-0.35984516,0.089179285,0.16260675,0.60783434,-0.6354844,-0.36121297,-0.13982855,-0.623979,0.2906736,0.9336311,0.050807998,0.4519776,0.7265956,-0.37929988,0.82935745,-0.10652152,-0.1856452,0.19315054,-0.39630267,0.4825011,0.74624705,0.59278315,0.20952235,-0.4194456,0.43942693,-0.3436957,0.7499669,1.479441,1.0171497,-0.0134