151	{"act": "IT_ACT_2000", "title": "Adjudicating Officer - Civil Court Powers", "doc_id": "ITACT_SEC_46_SUB_5", "topics": ["adjudication", "procedure"], "entities": ["adjudicating officer"], "keywords": ["adjudicating officer", "civil court powers", "judicial proceedings", "IPC", "CrPC", "CPC"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": ["ITACT_SEC_58_SUB_2"], "clause_text": "Every adjudicating officer shall have the powers of a civil court which are conferred on the Appellate Tribunal under sub-section (2) of section 58, and— (a) all proceedings before it shall be deemed to be judicial proceedings within the meaning of sections 193 and 228 of the Indian Penal Code; (b) shall be deemed to be a civil court for the purposes of sections 345 and 346 of the Code of Criminal Procedure, 1973; (c) shall be deemed to be a civil court for purposes of Order XXI of the Civil Procedure Code, 1908.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 46(5) of the Information Technology Act 2000. Every adjudicating officer has the civil court powers conferred on the Appellate Tribunal under section 58(2). Proceedings before adjudicating officers are deemed judicial proceedings under sections 193 and 228 of the IPC, and the officer is deemed a civil court under the CrPC and CPC.", "section_number": "46", "subsection_number": "5", "validation_status": "validated", "plain_english_summary": "An adjudicating officer has civil court powers including those under the CPC, and proceedings before them are deemed judicial proceedings under the IPC and CrPC."}	[0.96352607,0.2021671,-2.8924239,-0.72146493,1.5253961,0.26181412,0.21902348,0.5703241,0.103013426,-0.42632905,0.016780743,0.9314456,0.10341916,-0.45557916,-0.20032088,-0.9917987,-0.33247632,-0.887107,-0.92017967,-0.78237706,0.56361526,-1.2384819,-0.44827753,-0.60915095,1.538262,-0.09004929,0.96825904,-0.56649625,-1.2658061,-0.7068479,0.6967131,0.57516223,1.2444957,-0.54