152	{"act": "IT_ACT_2000", "title": "Decision by Majority in Appellate Tribunal", "doc_id": "ITACT_SEC_52D", "topics": ["appellate_tribunal", "procedure", "governance"], "entities": ["Appellate Tribunal"], "keywords": ["majority decision", "Appellate Tribunal", "bench", "Chairperson", "difference of opinion"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": [], "clause_text": "If the Members of a Bench consisting of two Members differ in opinion on any point, they shall state the point or points on which they differ, and make a reference to the Chairperson of the Appellate Tribunal who shall hear the point or points himself and such point or points shall be decided according to the opinion of the majority of the Members who have heard the case, including those who first heard it.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 52D of the Information Technology Act 2000. Where members of a two-member bench of the Appellate Tribunal differ in opinion, the disputed point is referred to the Chairperson who hears it, and the matter is decided by the majority opinion of all members who heard the case, including those who first heard it.", "section_number": "52D", "subsection_number": null, "validation_status": "validated", "plain_english_summary": "Where two members of a bench disagree, the disputed point is referred to the Chairperson and decided by the majority of all members who have heard the case."}	[1.1270494,0.08646383,-3.0034664,-0.6492859,1.1531947,0.9411025,-0.012136018,0.029083401,-0.005738954,0.55595624,0.73348826,0.64036685,0.37615073,-0.25142753,-0.24182928,-0.9946836,-0.6322245,-1.2421027,-0.30936453,0.29719156,0.020107796,-0.39365065,-1.5235261,0.3724704,1.2955744,0.45738047,-0.1914328,0.17789236,-0.8838982,-0.6205973,0.18876107,-0.26708236,0.7050628,-0.8478583,-0.9216472,-0.5757538,1.5654545,0.134191,-1.3173487,-0.09530542,0.48848674,-0.67575395,-0.3172691,-1.0939355,0.9199262,-0.5477613,0.5