153	{"act": "IT_ACT_2000", "title": "Orders Constituting Appellate Tribunal - Finality", "doc_id": "ITACT_SEC_55", "topics": ["appellate_tribunal", "governance", "procedure"], "entities": ["Appellate Tribunal", "Central Government"], "keywords": ["finality", "appointment", "Appellate Tribunal", "Chairperson", "Member", "defect in constitution"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": [], "clause_text": "No order of the Central Government appointing any person as the Chairperson or the Member of a Appellate Tribunal shall be called in question in any manner and no act or proceeding before a Appellate Tribunal shall be called in question in any manner on the ground merely of any defect in the constitution of a Appellate Tribunal.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 55 of the Information Technology Act 2000. Central Government orders appointing Chairpersons or Members of the Appellate Tribunal cannot be challenged in any manner. No act or proceeding of the Appellate Tribunal can be called into question merely on the ground of any defect in the constitution of the Tribunal.", "section_number": "55", "subsection_number": null, "validation_status": "validated", "plain_english_summary": "Appointments to the Appellate Tribunal cannot be challenged, and acts or proceedings of the Tribunal cannot be invalidated merely due to a defect in its constitution."}	[0.71108943,0.60361004,-3.0348182,-1.0789299,0.99593085,0.84469306,-0.060872674,0.6702391,0.6412627,-0.16799739,0.26881886,0.68878615,0.5596713,-0.5256608,-0.68028,-0.8087658,-0.11224812,-1.1681461,-0.58865815,0.2725379,0.6912076,-0.51860636,-1.1797011,0.28520024,1.4595495,0.15907638,0.7654107,-0.52999115,-0.41997695,-0.9780309,1.2316827,-0.10082655,1.1875037,-1.3998673,0.07485355,-0.9936659,2.0583367,0.3275361,-1.4531232,-0.22391386,0.5628633,-0.46792132,-0.53580683,-1.2257099,0.09430921,-0.2521771,1.134552,0.6181666,-0.029148947,-1.29509