154	{"act": "IT_ACT_2000", "title": "Appeal - Powers of Appellate Tribunal on Hearing", "doc_id": "ITACT_SEC_57_SUB_4", "topics": ["appeals", "procedure"], "entities": ["Appellate Tribunal"], "keywords": ["Appellate Tribunal", "confirm", "modify", "set aside", "order", "hearing"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": ["ITACT_SEC_57_SUB_1"], "clause_text": "On receipt of an appeal under sub-section (1), the Appellate Tribunal may, after giving the parties to the appeal, an opportunity of being heard, pass such orders thereon as it thinks fit, confirming, modifying or setting aside the order appealed against.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 57(4) of the Information Technology Act 2000. After receiving an appeal and giving parties an opportunity to be heard, the Appellate Tribunal may confirm, modify or set aside the order appealed against.", "section_number": "57", "subsection_number": "4", "validation_status": "validated", "plain_english_summary": "On receiving an appeal, the Appellate Tribunal may, after hearing the parties, confirm, modify, or set aside the order under appeal."}	[0.5360269,0.49039933,-2.8797174,-0.98402494,1.178633,0.29860914,-0.41092673,0.70688957,0.45587444,0.09290465,0.13649863,1.0681324,0.73400295,-0.38475597,-0.60781014,-0.20551446,0.08888162,-0.62017787,-0.906588,-0.123158775,0.80407214,-1.1132439,-1.0340213,0.036744382,0.53610647,-0.18292376,1.1045446,0.48204255,-1.2878635,-0.3614151,0.94174606,-0.051206447,1.1211536,-1.0310588,-0.90981364,-0.6359358,1.4873035,0.07124163,-1.9499323,-0.49592045,0.8652322,-0.33822286,-0.16972683,-0.7072594,0.9137304,-0.32948443,1.3561462,0.34934762,-0.44052252,-0.8833975,0.58155847,-0.79220426,-0.23523472,-0.98530954,0.1984546,0.5195215,-1.2781711,0.9871143,0.795344,0.60082334,0.6131504,0.89453405,-0.32383075,0.9830323,0.6858807,-0.8372917,-0.69303733,0.9744925,-0.44509026,-1.5211316,1.1116331,0.24291185,-0.16055724,-0.