155	{"act": "IT_ACT_2000", "title": "Appeal - Expeditious Disposal", "doc_id": "ITACT_SEC_57_SUB_6", "topics": ["appeals", "procedure"], "entities": ["Appellate Tribunal"], "keywords": ["expeditious disposal", "six months", "Appellate Tribunal", "appeal"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": [], "clause_text": "The appeal filed before the Appellate Tribunal under sub-section (1) shall be dealt with by it as expeditiously as possible and endeavour shall be made by it to dispose of the appeal finally within six months from the date of receipt of the appeal.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 57(6) of the Information Technology Act 2000. The Appellate Tribunal must deal with appeals as expeditiously as possible and endeavour to dispose of each appeal within six months of receiving it.", "section_number": "57", "subsection_number": "6", "validation_status": "validated", "plain_english_summary": "The Appellate Tribunal must deal with appeals as expeditiously as possible and endeavour to dispose of them within six months of receipt."}	[0.9202285,0.72449166,-3.351898,-1.2234998,0.8782203,0.036315273,0.37626144,0.7283063,0.43119365,0.24586958,0.09586458,1.1467956,1.0323398,-0.42846367,-0.7895108,-0.6299449,0.13137457,-0.36499816,-0.6142241,0.31093273,1.0137284,-1.3400387,-0.8777132,-0.2174902,0.5458532,0.099610955,0.72301555,0.5898748,-0.39946854,-0.06896768,0.7992892,-0.4265419,0.40619743,-0.9932811,-0.8354724,-0.795974,0.9489254,0.12697218,-1.432184,-0.9363814,0.7478989,-0.7177884,0.17392218,-0.3149483,0.7453307,-0.08036105,1.3499749,0.7045246,-0.9283994,-1.5358535,0.21391456,-1.3071579,-0.43200472,-0.26173994,0.023219593,0.13668565,-1.3740859,0.55147105,0.66299427,0.109374754,1.1671398,0.64135325,-0.82228065,1.3306347,1.0072072,-0.5018597,-0.04140094,1.0678877,-0.26360387,-1.1204966,0.96647364,-0.21513708,0.27076307,-0.80968463,-0.41406345,-0.07731939,-0.1398338,-1.5920261,-0.209544