156	{"act": "IT_ACT_2000", "title": "Appellate Tribunal - Procedure and Natural Justice", "doc_id": "ITACT_SEC_58_SUB_1", "topics": ["appellate_tribunal", "procedure", "natural_justice"], "entities": ["Appellate Tribunal"], "keywords": ["natural justice", "Appellate Tribunal", "procedure", "CPC", "own procedure", "sittings"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": [], "clause_text": "The Appellate Tribunal shall not be bound by the procedure laid down by the Code of Civil Procedure, 1908 but shall be guided by the principles of natural justice and, subject to the other provisions of this Act and of any rules, the Appellate Tribunal shall have powers to regulate its own procedure including the place at which it shall have its sittings.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 58(1) of the Information Technology Act 2000. The Appellate Tribunal is not bound by the Code of Civil Procedure 1908 but must be guided by the principles of natural justice. It may regulate its own procedure, including determining the place of its sittings, subject to the Act and applicable rules.", "section_number": "58", "subsection_number": "1", "validation_status": "validated", "plain_english_summary": "The Appellate Tribunal is not bound by the CPC but must be guided by the principles of natural justice and may regulate its own procedure, including the place of sittings."}	[1.0829713,0.9961476,-2.821041,-1.3602022,1.0355437,0.77209854,0.5347273,0.686528,0.4930648,0.0986187,0.4860003,0.5082347,0.93137515,-0.3461593,-1.1660886,-0.83754605,-0.1708784,-0.026897406,-0.20043263,-0.08911295,0.5249848,-0.9823666,-1.3440263,-0.3259479,1.2071902,-0.21262482,0.6845292,0.32864225,-0.91516435,-0.834421,0.5397398,-0.27300608,0.9602919,-0.9072825,-0.2951911,-0.3788318,2.0229666,0.8064556,-1.341876,-0.44669506,0.7492868,-0.70161355,-0.5706744,-0.26994076,0.31519523,-0.13094172,1.1539526,0.41362104,-0.2502823,-0.6780469,0.3285