158	{"act": "IT_ACT_2000", "title": "Limitation for Appeals to Appellate Tribunal", "doc_id": "ITACT_SEC_60", "topics": ["procedure", "limitation", "appellate_tribunal"], "entities": ["Appellate Tribunal"], "keywords": ["Limitation Act", "limitation period", "Appellate Tribunal", "appeals"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": ["ITACT_SEC_57_SUB_3"], "clause_text": "The provisions of the Limitation Act, 1963, shall, as far as may be, apply to an appeal made to the Appellate Tribunal.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 60 of the Information Technology Act 2000. The Limitation Act 1963 applies, as far as practicable, to appeals made to the Appellate Tribunal, supplementing the specific 45-day limitation period for appeals under section 57(3).", "section_number": "60", "subsection_number": null, "validation_status": "validated", "plain_english_summary": "The Limitation Act, 1963 applies, as far as practicable, to appeals made to the Appellate Tribunal."}	[1.1262753,1.265931,-3.0860538,-1.1117246,0.134292,1.2763708,0.29774103,0.33709145,0.5526341,0.12674832,0.3613613,0.83844405,0.48225555,-0.64025927,0.0007469387,-0.5371011,-0.17002569,-0.92668915,-0.7257556,0.54977185,1.0561444,-0.82603204,-1.2087504,-0.15740396,0.70942205,-0.036614213,1.3021109,0.38253137,-0.84627974,-0.27941814,0.54678077,-0.29204157,0.59874934,-0.75180286,-0.52732146,-0.74524355,0.98220843,0.09613373,-1.4841202,-0.11170144,0.9658897,-0.534782,0.2959049,-0.1534274,0.3730167,-0.592834,0.92356646,0.8410282,0.08963278,-1.0581273,0.4359861,-1.123815,-0.18051745,-0.693553,0.18333557,-0.12217209,-1.6866065,0.21026336,0.8300837,0.288686,1.405679,1.1133579,-0.3828667,1.2742344,0.9833666,-0.6891957,-0.19956674,1.117241,-0.7122112,-0.9065443,1.2753445,-0.36580127,0.117130086,-0.70458823,-0.46036562,0.23203832,-0.689351,-1.0328269,-0.34307006,1.2483169,0.08639898,-0.40034214,0.6766343,-0.4291019,-0.1849055,0.46293986,-0.01