160	{"act": "IT_ACT_2000", "title": "Power of Controller to Give Directions", "doc_id": "ITACT_SEC_68", "topics": ["certifying_authority", "enforcement", "penalty", "procedure"], "entities": ["Controller", "Certifying Authority"], "keywords": ["Controller", "directions", "Certifying Authority", "compliance", "imprisonment", "one lakh rupees", "non-compliance"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": [], "clause_text": "The Controller may, by order, direct a Certifying Authority or any employee of such Authority to take such measures or cease carrying on such activities as specified in the order if those are necessary to ensure compliance with the provisions of this Act, rules or any regulations made thereunder. Any person who intentionally or knowingly fails to comply with any order under sub-section (1) shall be guilty of an offence and shall be liable on conviction to imprisonment for a term not exceeding two years or a fine not exceeding one lakh rupees or with both.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 68 of the Information Technology Act 2000. The Controller may by order direct a Certifying Authority or any of its employees to take specified measures or cease specified activities to ensure compliance with the Act and regulations. Intentional or knowing failure to comply with such an order is an offence punishable with imprisonment not exceeding two years or a fine not exceeding Rs 1 lakh or both.", "section_number": "68", "subsection_number": null, "validation_status": "validated", "plain_english_summary": "The Controller may direct a Certifying Authority or its employees to take action or stop activities to ensure compliance. Intentional non-compliance is an offence punishable with imprisonment up to two years or a fine up to Rs 1 lakh, or both."}	[1.1574415,0.37627763,-3.0275378,0.12344471,1.1082268,0.16315109,0.5021902,0.25678542,0.16466773,0.08601854,-0.009576414,0.06696135