161	{"act": "IT_ACT_2000", "title": "Interception and Monitoring - Safeguards", "doc_id": "ITACT_SEC_69_SUB_2", "topics": ["surveillance", "procedure", "safeguards"], "entities": ["Central Government"], "keywords": ["interception", "monitoring", "decryption", "safeguards", "prescribed", "procedure"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": ["ITACT_SEC_69_SUB_1"], "clause_text": "The procedure and safeguards subject to which such interception or monitoring or decryption may be carried out, shall be such as may be prescribed.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 69(2) of the Information Technology Act 2000. The procedures and safeguards governing interception, monitoring, or decryption of information in computer resources under section 69(1) shall be as prescribed by the Central Government. These safeguards are intended to prevent misuse of surveillance powers.", "section_number": "69", "subsection_number": "2", "validation_status": "validated", "plain_english_summary": "The procedure and safeguards for interception, monitoring, or decryption of information must be prescribed by the Central Government."}	[0.8090296,0.2830394,-3.485883,-0.30446103,1.0860907,0.59196115,0.33431697,0.63686574,0.58876234,-0.27912575,-0.11187196,0.30658576,0.30648735,-0.19736262,-0.1398459,-0.23830543,0.706143,-0.47007653,-0.23618339,0.30883646,0.7870271,-0.82230705,-0.90690804,-0.2681139,0.8890309,0.2956575,1.3356282,0.08665697,-0.7047209,-0.6994354,0.9485768,-0.42013353,0.33906978,-0.53868383,-0.7958319,-1.7714993,0.3540382,-0.15461199,-1.6901839,0.2114367,0.6801473,0.6421926,-0.4540971,-0.7744304,0.38131878,0.87799376,0.7236568,-0.36913958,0.5769463,-0.9289737,0.7329949,-0.73206055,-0.21536328,-0.8441947,1.2311921,0.059854817,-0.37974387,-0.24600028,0.5284287,-1.409928,1.8342004,1.7044095,-1.0591843,0.20775709,0.30975837,-0.18208407,-0.46866232,0.9889142,-0.2038701,-0.7364776,1.2236683,-0.5069261,0.476090