162	{"act": "IT_ACT_2000", "title": "Failure to Assist Interception - Penalty", "doc_id": "ITACT_SEC_69_SUB_4", "topics": ["penalty", "surveillance", "intermediary"], "entities": ["subscriber", "intermediary"], "keywords": ["failure to assist", "subscriber", "intermediary", "imprisonment", "seven years", "interception", "monitoring", "decryption"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": ["ITACT_SEC_69_SUB_3"], "clause_text": "The subscriber or intermediary or any person who fails to assist the agency referred to in sub-section (3) shall be punished with imprisonment for a term which may extend to seven years and shall also be liable to fine.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 69(4) of the Information Technology Act 2000. A subscriber, intermediary, or any person who fails to assist a government agency authorised under section 69(1) to intercept, monitor, or decrypt information shall be punished with imprisonment for up to seven years and also liable to a fine.", "section_number": "69", "subsection_number": "4", "validation_status": "validated", "plain_english_summary": "Any subscriber, intermediary, or person who fails to assist an authorised government agency with interception, monitoring, or decryption is punishable with imprisonment up to seven years and a fine."}	[1.0064075,0.80660355,-3.2724307,-0.6836654,0.7980921,0.24452983,-0.056542717,0.7522154,0.7297774,0.03381751,-0.77543205,0.9541585,-0.38223472,-0.9439192,0.107999064,-0.47819003,1.1637398,-0.5228176,-0.45920458,-0.033681467,0.37684798,-0.7187015,-0.7225533,-0.03976129,0.6581086,0.01803902,1.0788412,-0.09012831,-0.60267544,0.09114703,0.51546997,-0.17175342,-0.15650249,-0.48144436,-0.9004694,-0.91892093,0.47606054,0.40182403,-1.0694014,-0.064052016,0.34101516,-0.16294949,-0.99760425,-0.65630585,0.40558192,-0.36768624,0.87898844,0.30160442,0.52247065,-1.0511153,0.2867354,-0.82819915,-0.20855111,-0.38466218,0.87434256,0.7