164	{"act": "IT_ACT_2000", "title": "Blocking of Information - Penalty for Non-Compliance", "doc_id": "ITACT_SEC_69A_SUB_3", "topics": ["content_blocking", "penalty", "intermediary"], "entities": ["intermediary"], "keywords": ["intermediary", "non-compliance", "blocking", "imprisonment", "seven years", "fine"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": ["ITACT_SEC_69A_SUB_1"], "clause_text": "The intermediary who fails to comply with the direction issued under sub-section (1) shall be punished with an imprisonment for a term which may extend to seven years and also be liable to fine.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 69A(3) of the Information Technology Act 2000. An intermediary that fails to comply with a Central Government direction to block public access to information under section 69A(1) shall be punished with imprisonment for up to seven years and also liable to a fine.", "section_number": "69A", "subsection_number": "3", "validation_status": "validated", "plain_english_summary": "An intermediary that fails to comply with a blocking direction under section 69A(1) is punishable with imprisonment up to seven years and a fine."}	[0.89756423,1.1918752,-2.9862921,-0.7299967,0.6051056,0.645935,0.038295828,0.8212615,0.5119215,0.43300036,-0.35835662,0.65568984,-0.40565768,-1.041447,0.26039368,-0.5348717,1.2026894,-0.65866673,-0.5676301,0.12288475,0.18256074,-0.68851435,-0.8620339,-0.16674195,0.6947884,-0.11309115,1.336936,-0.2785016,-0.686528,0.07821167,0.50176746,-0.41846988,-0.18754245,-0.6406065,-1.1887835,-0.81019735,0.70239097,0.6061686,-0.82477236,-0.33735698,0.5376422,0.073033616,-0.8205886,-0.6832985,0.54561675,-0.48816282,0.91729045,0.5859971,0.09908257,-0.9965926,0.6103606,-0.969709,-0.4370882,-0.37445626,0.40505177,0.5802802,-1.0139451,-0.4502546,-0.021253116,-0.29920113,1.3557179,0.903337,-0.7920291,0.8688757,0.655449,-0.05483957,-0.39255935,1.4760257,-0.020537045,-0.48013