165	{"act": "IT_ACT_2000", "title": "Traffic Data Monitoring - Penalty for Non-Compliance", "doc_id": "ITACT_SEC_69B_SUB_4", "topics": ["penalty", "intermediary", "cyber_security"], "entities": ["intermediary"], "keywords": ["intermediary", "traffic data", "non-compliance", "imprisonment", "three years", "fine"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": ["ITACT_SEC_69B"], "clause_text": "Any intermediary who intentionally or knowingly contravenes the provisions of sub-section (2) shall be punished with an imprisonment for a term which may extend to three years and shall also be liable to fine.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 69B(4) of the Information Technology Act 2000. An intermediary that intentionally or knowingly fails to provide technical assistance to an authorised government agency for monitoring and collecting traffic data under section 69B(2) shall be punished with imprisonment for up to three years and also be liable to a fine.", "section_number": "69B", "subsection_number": "4", "validation_status": "validated", "plain_english_summary": "An intermediary that intentionally or knowingly fails to provide technical assistance for traffic data monitoring under section 69B(2) is punishable with imprisonment up to three years and a fine."}	[0.7580265,0.7357299,-3.3579466,-0.6705929,1.0865659,0.54013926,0.34303057,0.9777422,0.44067422,0.35060748,-0.51203233,0.40718412,-0.16297784,-1.0644742,-0.07138387,-0.31450742,1.0535052,-0.4752789,-0.59555113,0.086218186,0.31125396,-0.719151,-0.5703848,-0.35008222,1.0859823,-0.48804888,0.9854271,-0.3440612,-0.33943602,0.039478157,0.74916905,-0.41900265,-0.16407941,-0.6672806,-1.2984887,-0.8522149,0.23391777,0.5546953,-0.6801061,0.0024785418,-0.08114941,-0.48342913,-0.8529158,-0.5969,0.47011116,-0.64004946,0.8448106,0.6937295,0.3392007,-0.5470472,0.5517554,-0.5333222,-0.22748792,-0.34963498,0.6976146,0.38106722,-1.171733,-0.016204596,-0.47