171	{"act": "IT_ACT_2000", "title": "Penalty for Publishing False Electronic Signature Certificate", "doc_id": "ITACT_SEC_73", "topics": ["penalty", "electronic_signature", "certifying_authority"], "entities": ["Certifying Authority", "subscriber"], "keywords": ["false certificate", "electronic signature certificate", "revoked", "suspended", "not accepted", "imprisonment", "one lakh rupees"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": [], "clause_text": "No person shall publish a electronic signature Certificate or otherwise make it available to any other person with the knowledge that— (a) the Certifying Authority listed in the certificate has not issued it; or (b) the subscriber listed in the certificate has not accepted it; or (c) the certificate has been revoked or suspended, unless such publication is for the purpose of verifying a electronic signature created prior to such suspension or revocation. Any person who contravenes the provisions of sub-section (1) shall be punished with imprisonment for a term which may extend to two years, or with fine which may extend to one lakh rupees, or with both.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 73 of the Information Technology Act 2000. It is an offence to publish or make available an electronic signature certificate knowing that the listed Certifying Authority did not issue it, the subscriber has not accepted it, or the certificate has been revoked or suspended, unless the purpose is to verify a signature created before suspension or revocation. The punishment is imprisonment up to two years or a fine up to Rs 1 lakh or both.", "section_number": "73", "subsection_number": null, "validation_status": "validated", "plain_english_summary": "Publishing or sharing an electronic signature certificate knowing it was not issued by the listed Certifying Authority, not accepted by the subscriber, or is revoked or suspended, is punishable with imprison