166	{"act": "IT_ACT_2000", "title": "Protected System - Authorisation of Access", "doc_id": "ITACT_SEC_70_SUB_2", "topics": ["protected_system", "authorisation", "procedure"], "entities": ["appropriate Government"], "keywords": ["protected system", "authorisation", "appropriate Government", "written order", "access"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": ["ITACT_SEC_70_SUB_1"], "clause_text": "The appropriate Government may, by order in writing, authorise the persons who are authorised to access protected systems notified under sub-section (1).", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 70(2) of the Information Technology Act 2000. The appropriate Government may by written order specify and authorise the persons who are permitted to access protected systems declared under section 70(1). Any access to a protected system by an unauthorised person is an offence.", "section_number": "70", "subsection_number": "2", "validation_status": "validated", "plain_english_summary": "The appropriate Government may by written order authorise specific persons to access protected computer systems."}	[0.24104135,1.2484701,-3.060897,-0.5845237,0.7681113,1.353562,-0.781755,0.8108777,0.7278782,-0.3936655,0.14568074,0.77387655,0.13396002,-0.45158628,-0.23802319,-0.062105533,0.7400273,-0.6459428,-0.58703095,-0.8692259,0.3927267,-1.2157687,-1.3558242,-0.1118397,1.151927,-0.2717203,1.5894668,-0.5448362,-0.76533216,-0.6928569,0.9467755,0.34758458,0.54719484,-0.15955584,-0.71767634,-1.3734959,0.3020862,-0.034858022,-1.1319038,0.41498616,0.80912215,0.86175156,-0.34466484,-0.4998075,-0.25320306,0.067872636,0.63598263,0.68336296,0.22534648,-0.59955823,0.9909733,-1.2817421,0.22469942,-0.45467043,1.2646145,-0.2085265,-0.9859869,-0.4900824,0.5589751,-0.44656554,1.8130901,2.1326118,-0.48933887,0.5745169,-0.024731325,0.30850393,-0.4115467,0.98564106,0.23173584,-1.2340599,0.6275115,-0.26016742,0.47784954,-0.4408396,0.23416