167	{"act": "IT_ACT_2000", "title": "Protected System - Information Security Practices", "doc_id": "ITACT_SEC_70_SUB_4", "topics": ["protected_system", "security", "compliance_requirement"], "entities": ["Central Government"], "keywords": ["information security practices", "protected system", "Central Government", "procedures", "prescribed"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": ["ITACT_SEC_70_SUB_1"], "clause_text": "The Central Government shall prescribe the information security practices and procedures for such protected system.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 70(4) of the Information Technology Act 2000. The Central Government is required to prescribe information security practices and procedures applicable to protected computer systems. These standards govern how operators of critical infrastructure must secure their systems.", "section_number": "70", "subsection_number": "4", "validation_status": "validated", "plain_english_summary": "The Central Government must prescribe information security practices and procedures specifically applicable to protected systems."}	[0.14068396,0.76823825,-2.9939663,-0.35941428,1.373012,0.95490277,-0.058148194,1.1610572,0.46841457,-0.20451012,-0.05441431,0.06857921,-0.30715212,-0.7367089,0.8038816,-0.14410035,0.15850481,-0.21825682,0.004326981,-0.046308443,0.19065757,-1.240082,-1.0225674,-0.3908665,1.2074952,0.8709278,1.3468028,-0.6623373,-0.6124891,-1.1880902,0.983,-0.37738642,0.71889293,-0.9402043,-0.37825507,-2.0738192,0.26828396,-0.29544935,-1.0333035,-0.20625618,0.96108264,0.30337983,-0.33867294,-0.33318195,0.26431364,0.4985911,0.59515274,-0.15719597,0.18196824,-0.43723553,0.7895449,-0.8598567,0.006997705,-0.5987218,0.9959873,0.20722334,-0.73944014,0.41175938,0.2054639,-0.23347978,2.3505235,2.1039977,-0.7908138,0.18054743,0.29928765,-0.048147008,0.023388753,1.100073,-0.31141385,-0.22621247,0.33573157,0.105645575,0.55488515,-0.2124017