168	{"act": "IT_ACT_2000", "title": "CERT-In Functions", "doc_id": "ITACT_SEC_70B_SUB_4", "topics": ["cyber_security", "incident_response", "governance"], "entities": ["Indian Computer Emergency Response Team", "CERT-In"], "keywords": ["CERT-In", "cyber incidents", "alerts", "forecasts", "guidelines", "advisories", "vulnerability", "incident response", "emergency measures"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": [], "clause_text": "The Indian Computer Emergency Response Team shall serve as the national agency for performing the following functions in the area of cyber security,— (a) collection, analysis and dissemination of information on cyber incidents; (b) forecast and alerts of cyber security incidents; (c) emergency measures for handling cyber security incidents; (d) coordination of cyber incidents response activities; (e) issue guidelines, advisories, vulnerability notes and white papers relating to information security practices, procedures, prevention, response and reporting of cyber incidents; (f) such other functions relating to cyber security as may be prescribed.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 70B(4) of the Information Technology Act 2000. CERT-In's national cyber security functions are: collection, analysis and dissemination of information on cyber incidents; forecast and alerts on cyber security incidents; emergency measures for handling incidents; coordination of response activities; and issuing guidelines, advisories, vulnerability notes and white papers on information security practices, prevention, response and reporting.", "section_number": "70B", "subsection_number": "4", "validation_status": "validated", "plain_english_summary": "CERT-In's statutory functions include collecting and analysing cyber incident data, issuing alerts and forecasts, handling cyber emergencies, coordinating incident response, and issuing information security guidelines and advisor