169	{"act": "IT_ACT_2000", "title": "CERT-In - Power to Call for Information and Give Directions", "doc_id": "ITACT_SEC_70B_SUB_6", "topics": ["cyber_security", "obligation", "enforcement"], "entities": ["Indian Computer Emergency Response Team", "CERT-In"], "keywords": ["CERT-In", "directions", "service provider", "intermediary", "data centre", "body corporate", "information"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": ["ITACT_SEC_70B_SUB_4"], "clause_text": "For carrying out the provisions of sub-section (4), the agency referred to in sub-section (1) may call for information and give direction to the service providers, intermediaries, data centres, body corporate and any other person.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 70B(6) of the Information Technology Act 2000. CERT-In may call for information and issue directions to service providers, intermediaries, data centres, body corporates and any other person for carrying out its cyber security functions under section 70B(4). Failure to comply is punishable with imprisonment up to one year or a fine up to Rs 1 lakh or both.", "section_number": "70B", "subsection_number": "6", "validation_status": "validated", "plain_english_summary": "CERT-In may call for information and give directions to service providers, intermediaries, data centres, body corporates, and any other persons for carrying out its cyber security functions."}	[0.41183373,0.6585168,-2.9215245,0.2436676,1.0547898,0.61944866,0.27046794,0.57603604,0.044285715,0.24113546,-0.54117954,0.37806866,0.759771,-0.47213274,-0.15642518,-0.8270239,0.42675212,-1.2469555,-0.71106565,-0.3474761,0.5118862,-1.1130142,-0.44736284,-0.52413464,0.6891844,0.13630508,1.7531972,-0.14297609,-0.742736,-0.27655178,0.7905538,0.113761894,0.40293252,-0.6501227,-1.2694103,-0.7566336,0.4927575,-0.27892923,-1.2663192,0.21002373,0.89889723,-0.28088543,-0.13655657,-0.7349597,0.740545,0.031264808,1.0517465,0.0