170	{"act": "IT_ACT_2000", "title": "CERT-In - Penalty for Non-Compliance with Directions", "doc_id": "ITACT_SEC_70B_SUB_7", "topics": ["penalty", "cyber_security", "enforcement"], "entities": ["Indian Computer Emergency Response Team", "CERT-In"], "keywords": ["CERT-In", "non-compliance", "service provider", "intermediary", "data centre", "body corporate", "imprisonment", "one lakh rupees"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": ["ITACT_SEC_70B_SUB_6"], "clause_text": "Any service provider, intermediaries, data centres, body corporate or person who fails to provide the information called for or comply with the direction under sub-section (6), shall be punishable with imprisonment for a term which may extend to one year or with fine which may extend to one lakh rupees or with both.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 70B(7) of the Information Technology Act 2000. Any service provider, intermediary, data centre, body corporate or person who fails to provide information called for or comply with directions given by CERT-In under section 70B(6) shall be punished with imprisonment for up to one year or a fine up to Rs 1 lakh or both.", "section_number": "70B", "subsection_number": "7", "validation_status": "validated", "plain_english_summary": "Failure to provide information or comply with CERT-In directions is punishable with imprisonment up to one year or a fine up to Rs 1 lakh, or both."}	[0.7700998,0.7138211,-2.89934,0.0626857,1.0175358,0.52912056,-0.073243596,0.7955719,-0.041134197,0.09533716,-0.08341107,0.55580425,0.75867754,-0.64154965,-0.09306578,-0.6398581,0.48328102,-1.0353637,-0.7217994,-0.23708516,0.3620015,-0.8007007,-0.8754058,-0.43369186,0.56043744,0.031684585,1.3927605,-0.33399564,-1.055003,-0.16081323,0.72682434,0.007122736,0.31872118,-0.8119726,-1.2185261,-0.6544583,0.8186202,-0.073829666,-0.48224697,0.19796918,1.1398995,-0.2625835,-0.5295339,-0.8162596,0.45653078,-0