198	{"act": "SPDI_RULES_2011", "title": "Collection of Information - Right to Review and Correct", "doc_id": "SPDI_RULE_5_SUB_6", "topics": ["correction", "sensitive_personal_data", "privacy_policy"], "entities": ["body corporate"], "keywords": ["right to review", "correction", "amendment", "inaccurate", "deficient", "body corporate", "authenticity", "provider of information"], "metadata": {"act": "SPDI_RULES_2011", "year": 2011, "jurisdiction": "India"}, "references": [], "clause_text": "Body corporate or any person on its behalf permit the providers of information, as and when requested by them, to review the information they had provided and ensure that any personal information or sensitive personal data or information found to be inaccurate or deficient shall be corrected or amended as feasible: Provided that a body corporate shall not be responsible for the authenticity of the personal information or sensitive personal data or information supplied by the provider of information to such body corporate or any other person acting on behalf of such body corporate.", "source_files": [2], "conflict_notes": [], "retrieval_text": "Rule 5(6) of the SPDI Rules 2011 grants information providers the right to review their personal information or sensitive personal data held by a body corporate upon request, and requires the body corporate to correct or amend any inaccurate or deficient information as feasible. However, the body corporate is not responsible for the authenticity of information originally supplied by the provider.", "section_number": "5", "subsection_number": "6", "validation_status": "validated", "plain_english_summary": "Information providers have the right to review their data held by a body corporate and have inaccurate or deficient information corrected or amended. However, the body corporate is not responsible for the authenticity of information originally supplied by the provider."}	[0.7181801,0.6807531,-3.1721199,0.19822341,0.13183391,0.05159771,-0.341