172	{"act": "IT_ACT_2000", "title": "Publication of Electronic Signature Certificate for Fraudulent Purpose", "doc_id": "ITACT_SEC_74", "topics": ["penalty", "electronic_signature", "fraud"], "entities": [], "keywords": ["fraudulent purpose", "electronic signature certificate", "unlawful", "publish", "imprisonment", "one lakh rupees"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": [], "clause_text": "Whoever knowingly creates, publishes or otherwise makes available a electronic signature Certificate for any fraudulent or unlawful purpose shall be punished with imprisonment for a term which may extend to two years, or with fine which may extend to one lakh rupees, or with both.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 74 of the Information Technology Act 2000. Whoever knowingly creates, publishes or makes available an electronic signature certificate for any fraudulent or unlawful purpose shall be punished with imprisonment for up to two years or a fine up to Rs 1 lakh or both.", "section_number": "74", "subsection_number": null, "validation_status": "validated", "plain_english_summary": "Knowingly creating, publishing, or making available an electronic signature certificate for a fraudulent or unlawful purpose is punishable with imprisonment up to two years or a fine up to Rs 1 lakh, or both."}	[0.8034008,1.2849225,-3.1513886,0.048330065,0.7681308,-0.2611032,-0.34233308,1.1616077,-0.0023449953,-0.048513517,-0.48736125,1.0100832,0.9250669,-0.6256598,-0.058406338,-0.49152806,0.8411237,-1.3894995,-0.33236143,0.099255666,0.30111298,-0.33214012,-1.2978027,-0.2635999,1.0302274,-0.52222216,1.793579,0.01309432,-0.70562726,-0.085071556,0.95225435,-0.26665437,0.22970118,-0.3553225,-0.8973606,-1.1871365,0.27230063,-0.1684886,-0.42998758,-0.21839793,1.322265,0.4780939,-0.81146747,-0.39188164,-0.05548872,0.06838023,0.5529982,0.37036815,0.7038619,-0.8750569,0.19482407,-1.5093368,0.67489135,-0.56757414,0.927