173	{"act": "IT_ACT_2000", "title": "Confiscation", "doc_id": "ITACT_SEC_76", "topics": ["penalty", "confiscation", "enforcement"], "entities": [], "keywords": ["confiscation", "computer", "storage media", "floppy", "compact disk", "tape drive", "contravention"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": [], "clause_text": "Any computer, computer system, floppies, compact disks, tape drives or any other accessories related thereto, in respect of which any provision of this Act, rules, orders or regulations made thereunder has been or is being contravened, shall be liable to confiscation: Provided that where it is established to the satisfaction of the court adjudicating the confiscation that the person in whose possession, power or control of any such computer, computer system, floppies, compact disks, tape drives or any other accessories relating thereto is found is not responsible for the contravention of the provisions of this Act, the court may, instead of making an order for confiscation, make such other order authorised by this Act against the person contravening.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 76 of the Information Technology Act 2000. Any computer, computer system, storage media, or accessories in respect of which a contravention of the Act has occurred or is occurring are liable to confiscation. A court may make an alternative order if the possessor is found not responsible for the contravention.", "section_number": "76", "subsection_number": null, "validation_status": "validated", "plain_english_summary": "Computers, storage devices, and related accessories used in contravention of the Act are liable to confiscation, unless the possessor proves they were not responsible for the contravention."}	[1.5253907,0.73975945,-2.8126292,-0.29049808,0.11291587,0.1429132,-0.16574341,0.38864657,0.710774,0.34344834,-0.30021593,0.46469095,0.4811502,0.019923078,-0.11186284,0.19966796,0