174	{"act": "IT_ACT_2000", "title": "Compensation, Penalties and Confiscation Not to Interfere with Other Punishment", "doc_id": "ITACT_SEC_77", "topics": ["penalty", "procedure"], "entities": [], "keywords": ["compensation", "penalty", "confiscation", "other laws", "concurrent liability", "punishment"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": [], "clause_text": "No compensation awarded, penalty imposed or confiscation made under this Act shall prevent the award of compensation or imposition of any other penalty or punishment under any other law for the time being in force.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 77 of the Information Technology Act 2000. Compensation, penalties and confiscations under this Act are in addition to and do not bar compensation, penalties or punishment under any other law. This preserves the concurrent applicability of other penal laws.", "section_number": "77", "subsection_number": null, "validation_status": "validated", "plain_english_summary": "Awards of compensation, penalties, or confiscations under this Act do not preclude other punishments or compensation under any other applicable law."}	[2.2979665,1.1140888,-2.9809713,-0.5027562,0.9782023,0.2775878,0.20035496,0.88728887,0.752366,0.13894658,-0.0076020383,0.47634327,0.6670056,-0.31650493,0.237833,-0.5333393,0.038591925,0.09953186,-0.33043683,-0.10878309,0.4981144,-0.42322397,-1.00607,-0.37629518,1.1539005,0.3557483,1.1325742,-0.54592973,-1.1049793,-0.34824142,0.24653773,-0.23647217,0.44790316,-0.78604823,-0.81588954,-0.6225608,1.7192465,0.08365971,-1.6103625,-0.27847442,0.9041935,0.038393542,-0.67762965,-0.5391729,0.88419044,-0.012267257,1.5892719,0.4093837,0.007149352,0.037220232,0.1580494,-0.7875394,-0.6394749,-0.353463,1.5360054,-0.013210048,-0.6550204,-0.28441378,-0.06653379,-0.3548157,0.9645365,1.7087222,-0.86927754,1.0888613,0.5383739,-0.50936186,0.3602776,0.96320206,-0.4115865,-0.08065984,0.81