175	{"act": "IT_ACT_2000", "title": "Application of the Act to Electronic Cheque and Truncated Cheque", "doc_id": "ITACT_SEC_81A", "topics": ["e_commerce", "procedure", "electronic_records"], "entities": ["Central Government", "Reserve Bank of India"], "keywords": ["electronic cheque", "truncated cheque", "Negotiable Instruments Act", "Reserve Bank of India", "Central Government"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": [], "clause_text": "The provisions of this Act, for the time being in force, shall apply to, or in relation to, electronic cheques and the truncated cheques subject to such modifications and amendments as may be necessary for carrying out the purposes of the Negotiable Instruments Act, 1881 by the Central Government, in consultation with the Reserve Bank of India, by notification in the Official Gazette.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 81A of the Information Technology Act 2000. The provisions of the IT Act apply to electronic cheques and truncated cheques with modifications and amendments the Central Government may prescribe by notification in consultation with the Reserve Bank of India, to carry out the purposes of the Negotiable Instruments Act 1881.", "section_number": "81A", "subsection_number": null, "validation_status": "validated", "plain_english_summary": "The Act applies to electronic cheques and truncated cheques with such modifications as the Central Government may notify in consultation with the Reserve Bank of India."}	[0.47575003,0.08604032,-2.741437,-0.68445843,1.1434366,0.2070723,-0.4144721,0.63094825,0.7400764,0.22883931,-0.07508645,0.794335,0.7644942,-0.5889671,-0.042828035,-0.468767,0.19940966,-0.6591917,-0.71547055,1.2926027,0.8230287,-0.61128056,-1.0177186,-0.7486712,0.95653623,-0.7567589,0.76738346,0.18532924,-0.91128355,-0.6437324,0.66639465,-0.27297154,1.3251113,-0.3945827,-0.6535254,-0.9529173,1.1478404,0.83137196,-0.8270494,-0.03371275