176	{"act": "IT_ACT_2000", "title": "Controller and Deputy Controller as Public Servants", "doc_id": "ITACT_SEC_82", "topics": ["governance", "procedure"], "entities": ["Controller", "Deputy Controller", "Assistant Controller"], "keywords": ["public servant", "Controller", "Deputy Controller", "Assistant Controller", "Indian Penal Code"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": [], "clause_text": "The Controller, the Deputy Controller and the Assistant Controllers shall be deemed to be public servants within the meaning of section 21 of the Indian Penal Code.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 82 of the Information Technology Act 2000. The Controller, Deputy Controller and Assistant Controllers are deemed to be public servants within the meaning of section 21 of the Indian Penal Code 1860, making them subject to penal provisions applicable to public servants.", "section_number": "82", "subsection_number": null, "validation_status": "validated", "plain_english_summary": "The Controller, Deputy Controller, and Assistant Controllers are deemed public servants under section 21 of the Indian Penal Code."}	[0.60961145,0.48608956,-3.5147762,-0.9603724,0.914189,0.36018258,0.20475236,-0.9238129,0.3567686,-0.04233036,-0.49701908,0.86412907,0.90574807,-0.3556281,0.30641764,-0.7693324,0.7471347,-1.1582793,-0.24599716,-0.4544143,0.890845,-0.48651168,-0.369389,0.0021441593,2.172776,0.22170736,0.49055967,-1.0447862,-0.20477943,-0.93653286,0.25598308,-0.21989724,0.83552706,-0.68914294,0.34867662,-1.3026372,1.6451035,0.07666535,-1.1771988,0.28793722,0.28812435,0.0713286,-0.4798035,-1.4075085,-0.0032649906,0.18710257,0.6184026,0.38992435,0.29772386,0.5375127,-0.006312822,-1.7024391,-0.6669436,-0.2613072,0.45353374,0.28316194,-0.6585205,0.6054593,-0.14960973,-0.68712425,1.5062308,1.0472333,-0.21642387,1.324496,0.30816802,-0.00719566,0.9361757,1.6444433,-0.23738512,-0.26006943,0.5439024,-0.19701529,0.