178	{"act": "IT_ACT_2000", "title": "Removal of Difficulties", "doc_id": "ITACT_SEC_86", "topics": ["governance", "procedure"], "entities": ["Central Government"], "keywords": ["removal of difficulties", "Central Government", "order", "Official Gazette", "two years"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": [], "clause_text": "If any difficulty arises in giving effect to the provisions of this Act, the Central Government may, by order published in the Official Gazette, make such provisions not inconsistent with the provisions of this Act as appear to it to be necessary or expedient for removing the difficulty: Provided that no order shall be made under this section after the expiry of a period of two years from the commencement of this Act.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 86 of the Information Technology Act 2000. The Central Government may by order in the Official Gazette make provisions consistent with the Act to remove any difficulties arising in its implementation. Such orders may not be made after two years from commencement of the Act.", "section_number": "86", "subsection_number": null, "validation_status": "validated", "plain_english_summary": "The Central Government may make provisions to remove difficulties in implementing the Act by order published in the Official Gazette, but only within two years of the Act's commencement."}	[0.42951143,0.61510056,-2.9973297,-1.0251561,0.30469623,0.7288853,-0.13885023,1.1459388,0.9586521,-0.27634558,0.47901225,0.16189331,-0.17402606,-0.39606884,0.10221877,0.053795654,0.7222309,-0.493511,-0.5386285,0.784658,1.3324093,0.032697685,-1.1934242,-0.8968244,0.7785661,0.3865084,0.9927766,-0.6667114,-0.5830745,-0.5742553,1.178494,0.108439855,0.4491243,-1.1035669,-0.0051913257,-1.7527646,0.8834032,-0.6193937,-0.94316685,-0.33699322,0.6370612,0.19668175,0.3376569,-0.27619773,0.57823294,-0.31665748,0.46743953,0.2829859,-0.020131808,-0.72847724,0