179	{"act": "IT_ACT_2000", "title": "Power of Controller to Make Regulations", "doc_id": "ITACT_SEC_89", "topics": ["governance", "certifying_authority", "rule_making"], "entities": ["Controller", "Central Government", "Cyber Regulations Advisory Committee"], "keywords": ["Controller", "regulations", "Certifying Authority", "Advisory Committee", "Central Government", "private key", "disclosure"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": ["ITACT_SEC_88"], "clause_text": "The Controller may, after consultation with the Cyber Regulations Advisory Committee and with the previous approval of the Central Government, by notification in the Official Gazette, make regulations consistent with this Act and the rules made thereunder to carry out the purposes of this Act. Such regulations may provide for: maintenance of data base records of Certifying Authorities; conditions for recognition of foreign Certifying Authorities; terms and conditions for licence; standards to be observed by Certifying Authorities; manner of disclosure by Certifying Authorities; particulars for electronic signature certificate applications; and manner in which subscribers shall communicate private key compromise.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 89 of the Information Technology Act 2000. The Controller may make regulations, after consulting the Cyber Regulations Advisory Committee and with Central Government approval, covering: disclosure records of Certifying Authorities; conditions for recognising foreign Certifying Authorities; licence terms and conditions; standards for Certifying Authorities; manner of disclosure; particulars required for electronic signature certificate applications; and manner of notifying private key compromise.", "section_number": "89", "subsection_number": null, "validation_status": "validated", "plain_english_summary": "The Controller may make regulations covering Certifying Authority databases, foreign authority recognition, licensing conditions, disclosure standards, certificate application particulars, and private key compromise notification, after consulting the Advisory Committee and with Central Government approval."}	[0.2259819,1.0750637,-3.2649677,-0.8377329,0.9386485,0.09701858,0.40972754,0.70190185,0.41641387,-0.2726386,-0.21547233,-0.00093940675,0.8666767,-0.090698116,0.5172635,-0.88781685,-0.06985326,-0.8368999,-0.3616394,-0.058041167,0.960835,-1.2310379,-1.0361283,-0.029233664,1.0492586,0.12611707,1.5031261,-0.53975606,-0.72977656,-0.70436645,0.6138888,-0.52795964,0.66441065,-0.3135656,-0.3304155,-1.9260871,0.008520192,0.7233514,-1.9568999,0.3722,0.51455605,0.10356431,-0.22805639,-0.8272581,-0.09015312,0.39688313,0.5210261,0.24119522,0.20103294,-0.7154388,0.9418814,-0.77579683,-0.49332586,-0.7963131,1.057097,-0.17382726,-0.59800184,0.9618406,0.08880374,-1.6466779,1.0351665,1.0410538,-0.34915435,0.7466608,0.9877904,-0.44967005,-0.048307415,1.3672771,-0.29644826,-0.1893238,1.1742367,-0.2847213,0.99825484,0.13698533,0.027571913,-1.0079058,-0.3297973,-1.2718285,0.3958034,0.85694873,0.043667883,0.05341791,1.5494747,0.18213215,-0.35065624,1.0785447,-0.8316681,-0.39132595,0.7332167,1.3825986,0.8463862,-0.62813324,1.2498235,0.3777347,0.05903761,-0.05246037,0.53571403,0.3570718,-0.23250788,0.09846779,-0.33368438,-0.15316135,-0.12916456,-0.09355988,0.13460116,1.539216,-0.13692015,-0.36987174,0.051857196,-0.13048314,0.029508714,0.7602644,-0.61390275,-0.16111828,1.0666811,-0.10128536,0.7056941,-0.39769346,0.6596023,1.4121015,-0.6629209,-0.983714,0.02276608,0.9194549,0.70299196,-0.20101693,-0.49651623,-0.0022304736,0.13552755,-1.1599392,-0.22788194,0.30245247,-0.5926389,0.17871194,-0.076517165,0.24531147,-0.5449917,-0.109310426,-0.32192743,0.069444925,0.5506797,0.1768951,-0.67575765,-0.35171878,1.0032287,-0.095989384,1.5650626,0.16247474,-0.3552035,-0.33418545,-0.71076185,-0.05144123,0.3389203,0.08343352,0.7474795,-0.5525872,0.6234948,0.47109747,-0.