180	{"act": "IT_ACT_2000", "title": "Power of State Government to Make Rules", "doc_id": "ITACT_SEC_90", "topics": ["governance", "rule_making", "e_governance"], "entities": ["State Government"], "keywords": ["State Government", "rules", "electronic form", "government filings", "grant", "payment", "Official Gazette"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": ["ITACT_SEC_6_SUB_1"], "clause_text": "The State Government may, by notification in the Official Gazette, make rules to carry out the provisions of this Act. In particular, and without prejudice to the generality of the foregoing power, such rules may provide for all or any of the following matters, namely:— (a) the electronic form in which filing, issue, grant, receipt or payment shall be effected under sub-section (1) of section 6; (b) for matters specified in sub-section (2) of section 6.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Section 90 of the Information Technology Act 2000. State Governments may make rules by notification in the Official Gazette for carrying out the Act's provisions, particularly prescribing the electronic form for Government filings, issue, grant, receipt or payment under section 6(1) and related matters under section 6(2).", "section_number": "90", "subsection_number": null, "validation_status": "validated", "plain_english_summary": "State Governments may make rules to carry out the provisions of the Act, particularly for prescribing electronic forms for filings, grant of licences, and payments under section 6."}	[-0.052167635,0.94378555,-2.977345,-0.83587116,0.44447634,0.3890023,-0.28661427,0.71231425,1.3549495,-0.5980366,0.58498293,0.45075417,1.3452011,0.25748226,0.060729012,-0.3405901,0.58843404,-0.76666886,-0.20631945,0.659729,0.7510205,-0.56490016,-1.4870567,-0.03327724,1.1976414,-0.110534236,1.1579946,-0.32965404,-0.833864,-1.234276,0.39567846,0.21313836,0.16749607,-0.7397292,-0.5798473,-1.9086859,0.59809154,-