181	{"act": "IT_ACT_2000", "title": "Electronic Signature or Electronic Authentication Techniques and Procedures", "doc_id": "ITACT_SECOND_SCHEDULE", "topics": ["electronic_signature", "authentication", "procedure"], "entities": ["Central Government"], "keywords": ["Second Schedule", "electronic signature", "authentication technique", "procedure", "section 3A", "reliable", "Central Government"], "metadata": {"act": "IT_ACT_2000", "year": 2000, "jurisdiction": "India"}, "references": ["ITACT_SEC_3A_SUB_1"], "clause_text": "The Second Schedule specifies the electronic signature or electronic authentication technique and procedure for the purposes of section 3A. The Central Government may by notification add to or omit any electronic signature or electronic authentication technique from the Second Schedule, provided that no technique shall be specified unless it is reliable.", "source_files": [1], "conflict_notes": [], "retrieval_text": "Second Schedule to the Information Technology Act 2000. The Second Schedule specifies approved electronic signature and electronic authentication techniques and procedures under section 3A. The Central Government may by notification amend the Schedule by adding or omitting techniques, but only reliable techniques may be included.", "section_number": "Second Schedule", "subsection_number": null, "validation_status": "validated", "plain_english_summary": "The Second Schedule lists the approved electronic signature and authentication techniques for the purposes of section 3A. The Central Government may add or remove techniques from the Schedule by notification, subject to a reliability requirement."}	[-0.20312911,0.14003819,-3.4964602,-0.1975849,0.7553435,0.098907016,-0.30500865,0.496084,0.80489033,-0.56190777,-0.44324026,0.6727479,0.9601561,-0.12423396,-0.43775386,-0.0739341,0.87797415,-0.95426375,-0.29703435,0.6366673,0.8671076,-0.6430052,-1.2487199,-0.3941345,0.6055743,0.16286096,1.7994074,0.14255175,-0.86326736,-1.2302818,0.60461825,-