185	{"act": "SPDI_RULES_2011", "title": "Definition - Biometrics", "doc_id": "SPDI_DEF_BIOMETRICS", "topics": ["sensitive_personal_data", "definition"], "entities": [], "keywords": ["biometrics", "fingerprints", "iris", "voice patterns", "facial patterns", "DNA", "authentication", "sensitive personal data"], "metadata": {"act": "SPDI_RULES_2011", "year": 2011, "jurisdiction": "India"}, "references": ["SPDI_RULE_3"], "clause_text": "\\"Biometrics\\" means the technologies that measure and analyse human body characteristics, such as 'fingerprints', 'eye retinas and irises', 'voice patterns', 'facial patterns', 'hand measurements' and 'DNA' for authentication purposes.", "source_files": [2], "conflict_notes": [], "retrieval_text": "Rule 2(1)(b) of the SPDI Rules 2011 defines biometrics as technologies that measure and analyse human body characteristics including fingerprints, eye retinas and irises, voice patterns, facial patterns, hand measurements and DNA for authentication purposes. Biometric information is classified as sensitive personal data or information under Rule 3.", "section_number": "2", "subsection_number": "1(b)", "validation_status": "validated", "plain_english_summary": "Biometrics refers to technologies that measure and analyse human body characteristics such as fingerprints, iris scans, voice patterns, facial patterns, hand measurements, and DNA for authentication purposes."}	[0.7551706,0.8334898,-3.2610729,0.3039365,0.30228874,0.24607602,0.74655336,0.31964388,-0.26322472,-0.116547674,0.5983646,0.8034738,1.4007676,-0.25419334,-0.099345736,-0.6580241,-0.29592833,-1.5543907,0.67003036,0.90879935,-0.8279843,-0.19267483,-1.7230765,0.6076484,1.5259577,-0.12897274,1.0587683,-0.11754034,-0.5380039,-1.4446594,0.3261076,0.22101665,0.86208725,-0.10134966,0.23389752,-1.7974634,0.9396176,0.68091667,-0.20029123,2.034951,0.30437317,-0.26188725,-0.1333767,-0.84618706,0.8292174,-0.13087822,0.85869724,-0.012411116,1.0018853,-0.24417487,-0.3345649,-0.65670776,-0.28545