186	{"act": "SPDI_RULES_2011", "title": "Definition - Body Corporate", "doc_id": "SPDI_DEF_BODY_CORPORATE", "topics": ["definition", "compliance"], "entities": ["body corporate"], "keywords": ["body corporate", "company", "firm", "sole proprietorship", "commercial activities", "section 43A"], "metadata": {"act": "SPDI_RULES_2011", "year": 2011, "jurisdiction": "India"}, "references": ["ITACT_SEC_43A"], "clause_text": "\\"Body corporate\\" means the body corporate as defined in clause (i) of explanation to section 43A of the Act.", "source_files": [2], "conflict_notes": [], "retrieval_text": "Rule 2(1)(c) of the SPDI Rules 2011 defines body corporate by reference to clause (i) of the explanation to section 43A of the IT Act 2000, which covers any company, firm, sole proprietorship or other association of individuals engaged in commercial or professional activities. Body corporates are the primary duty-bearers under these Rules.", "section_number": "2", "subsection_number": "1(c)", "validation_status": "validated", "plain_english_summary": "Body corporate has the same meaning as in the explanation to section 43A of the IT Act 2000, which includes any company, firm, sole proprietorship or other association of individuals engaged in commercial or professional activities."}	[-0.08121707,0.5292529,-3.1432095,0.3429441,-0.027980346,0.62568504,0.101982795,0.26805595,-0.1579845,-0.020225875,0.5291917,1.2071128,0.7981623,-0.56128037,0.4967074,-1.1454827,-0.36400077,-0.8851536,-0.40681818,1.1380943,-0.25115925,0.2806838,-0.5246544,-0.48029733,1.6615766,1.0512942,0.4710658,-0.31078947,-0.33454874,-1.9028834,0.017642543,1.4786199,1.556576,-0.961976,-0.34015062,-1.1022543,0.98544,1.1718354,-1.0968101,0.47231087,0.036012318,-0.03384174,-0.8463422,-1.3022069,0.32244942,-1.0953573,1.032403,-0.51132125,0.57309103,-0.8048467,-0.06040115,-1.3833058,0.32952133,-0.35453445,0.55919874,-0.5046813,0.28526554,0.39912757,-0.6631932,-0.7628781,0.9020896,1.0459483,0.040306635,1.5281254,0.882629