187	{"act": "SPDI_RULES_2011", "title": "Definition - Cyber Incidents", "doc_id": "SPDI_DEF_CYBER_INCIDENTS", "topics": ["definition", "security"], "entities": [], "keywords": ["cyber incident", "unauthorised access", "denial of service", "disruption", "security policy", "computer resource"], "metadata": {"act": "SPDI_RULES_2011", "year": 2011, "jurisdiction": "India"}, "references": [], "clause_text": "\\"Cyber incidents\\" means any real or suspected adverse event in relation to cyber security that violates an explicitly or implicitly applicable security policy resulting in unauthorised access, denial of service or disruption, unauthorised use of a computer resource for processing or storage of information or changes to data, information without authorisation.", "source_files": [2], "conflict_notes": [], "retrieval_text": "Rule 2(1)(d) of the SPDI Rules 2011 defines cyber incidents as any real or suspected adverse event relating to cyber security that violates an explicitly or implicitly applicable security policy, resulting in unauthorised access, denial of service or disruption, unauthorised use of a computer resource, or unauthorised changes to data or information.", "section_number": "2", "subsection_number": "1(d)", "validation_status": "validated", "plain_english_summary": "A cyber incident is any real or suspected adverse event that violates a security policy, resulting in unauthorised access, denial of service, disruption, unauthorised use of computer resources, or unauthorised data changes."}	[1.4865382,1.2450866,-3.5408235,0.109755546,0.93399364,0.5028964,0.922264,0.27228507,0.8190246,-0.6100774,0.1566028,0.47397742,0.7167528,-0.08453433,-0.4397765,-1.1548395,0.36991403,0.18623962,-1.7732478,0.6047954,-0.13600624,-0.9651232,-0.9141132,-0.8190805,1.6781769,0.3086925,0.9777747,0.048896387,-0.4379218,-0.5786263,-0.03470337,0.05127033,-0.22573897,-0.67389035,-1.3536013,-1.9329176,-0.012395806,-0.42691866,-1.3016698,0.43514052,0.65424824,-0.009301346,0.306993