188	{"act": "SPDI_RULES_2011", "title": "Definition - Password", "doc_id": "SPDI_DEF_PASSWORD", "topics": ["definition", "sensitive_personal_data"], "entities": [], "keywords": ["password", "passphrase", "secret key", "encryption key", "decryption key", "access", "sensitive personal data"], "metadata": {"act": "SPDI_RULES_2011", "year": 2011, "jurisdiction": "India"}, "references": ["SPDI_RULE_3"], "clause_text": "\\"Password\\" means a secret word or phrase or code or passphrase or secret key, or encryption or decryption keys that one uses to gain admittance or access to information.", "source_files": [2], "conflict_notes": [], "retrieval_text": "Rule 2(1)(h) of the SPDI Rules 2011 defines password as a secret word, phrase, code, passphrase, secret key, or encryption or decryption keys used to gain access to information. Passwords are classified as sensitive personal data or information under Rule 3.", "section_number": "2", "subsection_number": "1(h)", "validation_status": "validated", "plain_english_summary": "A password is any secret word, phrase, code, passphrase, secret key, or encryption or decryption key used to gain access to information."}	[0.43983343,0.38176492,-2.825289,0.11409918,0.26159146,-0.21770199,-0.4464732,0.35077724,-0.19004028,0.057586398,-0.6595297,0.8316027,0.42957956,-0.4109997,0.2923321,-0.27637884,0.5729435,-0.6199113,0.093058534,-0.6265058,-0.4371982,-0.49677917,-1.0531472,0.0015719283,1.799056,0.28782097,0.9204358,-0.9495936,-0.554119,-0.47571626,0.11983658,0.07817848,0.66797554,-0.52664846,-1.1759704,-2.2542546,0.18118785,0.34724337,-0.90453124,0.34250236,0.3486731,0.80026156,-0.2765884,-0.5991959,0.58524996,-0.63616496,-0.0034889497,-0.51287,0.7905769,-1.5194479,0.37257022,-1.213272,1.0178534,-0.40764302,1.7177504,0.19321617,0.41666177,-0.8672104,0.56579256,-0.36949176,1.0043784,1.2965947,-0.29777652,0.95873415,0.9491884,0.34151423,-0.63974035,0.8518318,-0.18975861,-0.4098569,1.0551904,-0.5736396,0.5586444,-0.4047069,0.14041507,-0.3345