189	{"act": "SPDI_RULES_2011", "title": "Definition - Personal Information", "doc_id": "SPDI_DEF_PERSONAL_INFORMATION", "topics": ["definition", "sensitive_personal_data"], "entities": ["body corporate"], "keywords": ["personal information", "natural person", "identifiable", "body corporate", "indirect identification"], "metadata": {"act": "SPDI_RULES_2011", "year": 2011, "jurisdiction": "India"}, "references": [], "clause_text": "\\"Personal information\\" means any information that relates to a natural person, which, either directly or indirectly, in combination with other information available or likely to be available with a body corporate, is capable of identifying such person.", "source_files": [2], "conflict_notes": [], "retrieval_text": "Rule 2(1)(i) of the SPDI Rules 2011 defines personal information as any information relating to a natural person that, either directly or indirectly, or in combination with other information available or likely to be available with a body corporate, is capable of identifying that person. This definition covers both directly identifying information and information that becomes identifying when combined with other data.", "section_number": "2", "subsection_number": "1(i)", "validation_status": "validated", "plain_english_summary": "Personal information is any information relating to a natural person that can directly or indirectly identify that person, including when combined with other information available to a body corporate."}	[0.43658698,0.57631826,-3.5358698,0.004206245,-0.17710494,0.13179165,-0.052884836,-0.30301416,-0.5108788,0.0063995793,0.3127263,0.6900965,1.4123032,-0.38625243,-0.09642598,-1.0904331,-0.3347845,-1.4221032,0.35612786,1.1429799,-0.5456569,0.056517147,-1.1062626,0.68365973,1.6692265,-0.18150628,0.88269854,-0.5675954,-0.19880097,-1.3280191,-0.26238355,0.7477023,0.38829115,0.17611845,-1.0464753,-1.6165752,0.9480004,0.37722275,-0.24694687,1.2582524,0.17037736,-0.090816185,-0.3085676,-1.3412056,0.20398942,-