191	{"act": "SPDI_RULES_2011", "title": "Sensitive Personal Data or Information - Definition", "doc_id": "SPDI_RULE_3", "topics": ["sensitive_personal_data", "definition"], "entities": ["body corporate"], "keywords": ["sensitive personal data", "SPDI", "password", "financial information", "bank account", "credit card", "health condition", "sexual orientation", "medical records", "biometrics", "public domain", "RTI Act"], "metadata": {"act": "SPDI_RULES_2011", "year": 2011, "jurisdiction": "India"}, "references": ["SPDI_DEF_BIOMETRICS", "SPDI_DEF_PASSWORD"], "clause_text": "Sensitive personal data or information of a person means such personal information which consists of information relating to;— (i) password; (ii) financial information such as Bank account or credit card or debit card or other payment instrument details; (iii) physical, physiological and mental health condition; (iv) sexual orientation; (v) medical records and history; (vi) Biometric information; (vii) any detail relating to the above clauses as provided to body corporate for providing service; and (viii) any of the information received under above clauses by body corporate for processing, stored or processed under lawful contract or otherwise: provided that, any information that is freely available or accessible in public domain or furnished under the Right to Information Act, 2005 or any other law for the time being in force shall not be regarded as sensitive personal data or information for the purposes of these rules.", "source_files": [2], "conflict_notes": [], "retrieval_text": "Rule 3 of the SPDI Rules 2011 defines sensitive personal data or information as personal information consisting of passwords, financial information such as bank account, credit card or debit card details, physical, physiological and mental health conditions, sexual orientation, medical records and history, biometric information, and any related details provided to a body corporate for providing services or processing under a lawful contract. Information freely available in the public domain or furnished under the Right to Information Act 2005 is expressly excluded from this definition.", "section_number": "3", "subsection_number": null, "validation_status": "validated", "plain_english_summary": "Sensitive personal data or information includes passwords, financial details, health conditions, sexual orientation, medical records, biometric information, and any related details provided to a body corporate. Publicly available information or information disclosed under the RTI Act is excluded."}	[1.0851673,1.259946,-3.2972517,-0.31414002,0.012342777,0.48856962,-0.52085245,-0.23459595,-0.12319336,0.19657275,-0.016681286,0.7636812,0.6186672,-0.8704181,-0.25484627,-0.188985,0.02953783,-0.72419816,0.006483719,0.6491591,-0.56731766,0.106455654,-1.5199072,0.59694517,1.6201915,-0.22400722,1.5742345,-1.1746734,-0.2537151,-0.51335484,-0.33176225,0.5121985,0.15962659,-0.04904122,-0.78320765,-1.856259,0.27119538,0.7539773,-0.79683775,0.9918287,0.6645183,-0.024811452,-0.03813582,-1.5820807,0.11461907,-0.073510855,0.23751646,0.3620391,1.1766369,-0.7181401,0.24700187,-0.6267699,0.078709625,-0.040294435,1.0907385,-0.7004744,-0.23826347,-0.041267514,-0.27592757,-1.1435168,1.5571874,1.4704766,-0.77232605,0.9555838,1.6680224,0.099352695,-0.6118623,1.0032163,-0.17006242,-0.4462237,2.0825298,0.081301555,0.6955308,-0.23101518,0.0070318165,-0.27984497,-0.8647895,-0.84578025,0.3226772,0.54819125,0.9517368,-0.16308078,0.7117745,0.3102337,1.2808808,0.4873951,-0.41466168,-0.41347694,0.3577121,1.4226074,-0.19200204,-0.12610976,1.1456102,0.2379755,-0.36431345,1.415421,0.27859047,-0.05731559,-0.76295036,-0.095514975,-0.4641387,-1.0482465,1.0629683,0.51629555,-0.6494151,0.24562046,0.041529346,0.20464107,0.45678046,-0.039833684,0.2577219,1.8483412,-0.037687145,0.4893229,0.6834541,0.028852126,1.4548484,-1.1144898,-0.7919145,0.61591446,-0.7613399,-0.3484702,1.0165552,1.789243,-0.18869935,-0.18573333,-0.6926959,0.099