193	{"act": "SPDI_RULES_2011", "title": "Collection of Information - Written Consent Requirement", "doc_id": "SPDI_RULE_5_SUB_1", "topics": ["consent", "collection_of_information", "sensitive_personal_data"], "entities": ["body corporate"], "keywords": ["written consent", "sensitive personal data", "body corporate", "purpose of usage", "letter", "fax", "email", "before collection"], "metadata": {"act": "SPDI_RULES_2011", "year": 2011, "jurisdiction": "India"}, "references": ["SPDI_RULE_3"], "clause_text": "Body corporate or any person on its behalf shall obtain consent in writing through letter or Fax or email from the provider of the sensitive personal data or information regarding purpose of usage before collection of such information.", "source_files": [2], "conflict_notes": [], "retrieval_text": "Rule 5(1) of the SPDI Rules 2011 requires a body corporate or any person acting on its behalf to obtain written consent from the provider of sensitive personal data or information before collecting such information. The consent must specify the purpose of usage and may be obtained through letter, fax or email.", "section_number": "5", "subsection_number": "1", "validation_status": "validated", "plain_english_summary": "A body corporate must obtain written consent — by letter, fax, or email — from the person providing sensitive personal data or information, regarding the purpose of use, before collecting it."}	[0.7421605,0.8765941,-2.6375248,0.25846845,0.12533265,-0.3812239,-0.45064375,0.41839418,0.23718016,0.56004286,0.26470163,0.3339899,0.49306926,-0.47196826,0.31811085,0.17596,0.32083637,-1.6320567,-0.7063358,0.50405204,-0.51157165,-0.39411786,-1.62614,0.20058915,1.3921473,-0.3275204,1.20184,-0.70062935,-0.4122013,-1.1675582,0.64756495,1.1690704,0.5839761,-0.3787267,-0.91799366,-2.3206112,0.13627684,-0.3038955,-1.539411,1.0703421,1.150093,0.4160759,-0.12112859,-0.86679983,0.9823549,-0.93936896,1.1044327,-0.4687667,1.1981846,-0.8538703,0.4542508,-0.78498715,-0.34636682