194	{"act": "SPDI_RULES_2011", "title": "Collection of Information - Lawful Purpose and Necessity", "doc_id": "SPDI_RULE_5_SUB_2", "topics": ["collection_of_information", "lawful_processing", "sensitive_personal_data"], "entities": ["body corporate"], "keywords": ["lawful purpose", "necessity", "body corporate", "sensitive personal data", "function or activity", "collection prohibition"], "metadata": {"act": "SPDI_RULES_2011", "year": 2011, "jurisdiction": "India"}, "references": [], "clause_text": "Body corporate or any person on its behalf shall not collect sensitive personal data or information unless — (a) the information is collected for a lawful purpose connected with a function or activity of the body corporate or any person on its behalf; and (b) the collection of the sensitive personal data or information is considered necessary for that purpose.", "source_files": [2], "conflict_notes": [], "retrieval_text": "Rule 5(2) of the SPDI Rules 2011 prohibits a body corporate or any person acting on its behalf from collecting sensitive personal data or information unless two conditions are met: the information is collected for a lawful purpose connected with the body corporate's functions or activities, and the collection is necessary for that purpose. This establishes a necessity and lawful purpose test for collection.", "section_number": "5", "subsection_number": "2", "validation_status": "validated", "plain_english_summary": "A body corporate may only collect sensitive personal data or information if the collection is for a lawful purpose connected with its functions or activities and is considered necessary for that purpose."}	[1.0365325,1.1879991,-3.3276327,-0.060431138,0.19746257,0.20727427,-0.2730413,-0.30169013,-0.07737168,0.5931084,0.24053653,0.5602813,0.7635216,-0.47554988,-0.05723614,-0.41025615,-0.33059466,-1.1717988,-0.41088536,0.8263761,-0.012040245,0.32492283,-1.0417805,0.099013016,1.3346286,0.004959544,1.3543881,-0.3736506,-0.38346466,-0.538334,0.14