195	{"act": "SPDI_RULES_2011", "title": "Collection of Information - Notice Requirements", "doc_id": "SPDI_RULE_5_SUB_3", "topics": ["collection_of_information", "consent", "sensitive_personal_data"], "entities": ["body corporate"], "keywords": ["notice", "direct collection", "purpose of collection", "intended recipients", "collecting agency", "retaining agency", "body corporate"], "metadata": {"act": "SPDI_RULES_2011", "year": 2011, "jurisdiction": "India"}, "references": [], "clause_text": "While collecting information directly from the person concerned, the body corporate or any person on its behalf shall take such steps as are, in the circumstances, reasonable to ensure that the person concerned is having the knowledge of — (a) the fact that the information is being collected; (b) the purpose for which the information is being collected; (c) the intended recipients of the information; and (d) the name and address of — (i) the agency that is collecting the information; and (ii) the agency that will retain the information.", "source_files": [2], "conflict_notes": [], "retrieval_text": "Rule 5(3) of the SPDI Rules 2011 requires a body corporate or person acting on its behalf, when collecting information directly from the person concerned, to take reasonable steps to ensure that the person knows: that the information is being collected; the purpose of collection; the intended recipients; and the name and address of the agency collecting the information and the agency that will retain it.", "section_number": "5", "subsection_number": "3", "validation_status": "validated", "plain_english_summary": "When collecting information directly from a person, the body corporate must take reasonable steps to ensure the person knows that their data is being collected, the purpose, the intended recipients, and the identity and address of both the collecting and retaining agencies."}	[0.38599655,0.6262411,-3.2380948,0.0042172642,0.51364034,-0.10247728,0.012856676,0.1655201,-0.03872