196	{"act": "SPDI_RULES_2011", "title": "Collection of Information - Retention Limitation", "doc_id": "SPDI_RULE_5_SUB_4", "topics": ["data_retention", "sensitive_personal_data", "compliance"], "entities": ["body corporate"], "keywords": ["retention", "data retention", "sensitive personal data", "lawful purpose", "body corporate", "retention limitation"], "metadata": {"act": "SPDI_RULES_2011", "year": 2011, "jurisdiction": "India"}, "references": [], "clause_text": "Body corporate or any person on its behalf holding sensitive personal data or information shall not retain that information for longer than is required for the purposes for which the information may lawfully be used or is otherwise required under any other law for the time being in force.", "source_files": [2], "conflict_notes": [], "retrieval_text": "Rule 5(4) of the SPDI Rules 2011 imposes a data retention limitation on body corporates. Sensitive personal data or information must not be retained longer than is required for the purposes for which it may lawfully be used or as required under any other applicable law. This establishes a purpose-linked retention obligation.", "section_number": "5", "subsection_number": "4", "validation_status": "validated", "plain_english_summary": "A body corporate must not retain sensitive personal data or information for longer than is required for the lawful purposes for which it was collected, unless another law requires retention."}	[0.9694446,1.1636277,-3.3801124,-0.3926743,0.48244855,0.14241754,-0.10834913,0.06406591,-0.22154088,0.16428806,0.08761989,0.5987901,0.5695006,-0.54731613,0.56524736,-0.28422508,-0.16814655,-0.97056603,-0.6433128,0.68532366,0.24588728,0.15863441,-0.97454774,-0.11861732,0.81896454,0.6646044,1.3106937,-0.9028109,-0.533569,-0.6362321,0.8303689,0.8669378,0.69138044,-0.47557634,-0.8045755,-2.135183,0.86225414,-0.16895534,-0.6055915,0.78077996,0.89056945,-0.10573813,0.0138832405,-0.59048253,1.4299376,-0.3075872,1.18514,-0.05323277,1.4564109,-1.1