197	{"act": "SPDI_RULES_2011", "title": "Collection of Information - Purpose Limitation", "doc_id": "SPDI_RULE_5_SUB_5", "topics": ["collection_of_information", "lawful_processing", "compliance"], "entities": ["body corporate"], "keywords": ["purpose limitation", "use limitation", "body corporate", "information collected", "specified purpose"], "metadata": {"act": "SPDI_RULES_2011", "year": 2011, "jurisdiction": "India"}, "references": [], "clause_text": "The information collected shall be used for the purpose for which it has been collected.", "source_files": [2], "conflict_notes": [], "retrieval_text": "Rule 5(5) of the SPDI Rules 2011 establishes a purpose limitation principle: information collected by a body corporate must be used only for the specific purpose for which it was collected and not for any other purpose.", "section_number": "5", "subsection_number": "5", "validation_status": "validated", "plain_english_summary": "Information collected by a body corporate must only be used for the purpose for which it was collected."}	[0.7905169,1.2878786,-2.8607862,-0.24852042,0.00010984532,0.21976697,0.23532014,0.1255166,-0.5718448,0.1114481,0.856913,0.33141768,0.7965063,-0.3195004,0.46928436,-0.36602512,-0.30642077,-0.87338614,-0.34273648,1.0433438,0.12602682,-0.072082445,-0.761226,-0.18061337,1.2779849,0.24780592,1.3133059,-0.58777463,-0.90291643,-0.58854437,0.06568096,0.63796556,0.8512778,0.0311279,-0.5248871,-1.8300979,1.1733856,0.108239785,-0.9376847,0.98314327,0.31769663,0.1473252,-0.22280711,-1.1744816,0.85360503,-0.6442072,1.315106,0.31374004,1.2982382,-1.6118727,0.77408546,-0.6063496,-0.4355397,-0.40544695,0.9739909,-0.30181023,-0.5804675,-0.38604033,-0.46478695,-0.96211284,1.4141765,1.2370213,-0.4903922,1.7081765,1.038746,-0.7492466,-0.76489747,-0.27112716,-0.7276735,-0.26589563,1.518976,-0.2102357,0.8597753,-0.6064967,-0.42012534,0.48774815,-0.97092885,-0.21880442,0.14278509,0.89493066,1.1012876,-0.388596,0.9104821,0.7325903,1.1409807,1.1940529,-0.241245