201	{"act": "SPDI_RULES_2011", "title": "Collection of Information - Grievance Officer", "doc_id": "SPDI_RULE_5_SUB_9", "topics": ["grievance_redressal", "compliance"], "entities": ["body corporate", "Grievance Officer"], "keywords": ["Grievance Officer", "body corporate", "grievances", "one month", "website", "contact details", "discrepancies"], "metadata": {"act": "SPDI_RULES_2011", "year": 2011, "jurisdiction": "India"}, "references": [], "clause_text": "Body corporate shall address any discrepancies and grievances of their provider of the information with respect to processing of information in a time bound manner. For this purpose, the body corporate shall designate a Grievance Officer and publish his name and contact details on its website. The Grievance Officer shall redress the grievances of provider of information expeditiously but within one month from the date of receipt of grievance.", "source_files": [2], "conflict_notes": [], "retrieval_text": "Rule 5(9) of the SPDI Rules 2011 requires every body corporate to designate a Grievance Officer and publish their name and contact details on its website to address discrepancies and grievances relating to the processing of information. The Grievance Officer must redress grievances expeditiously and within one month from the date of receipt.", "section_number": "5", "subsection_number": "9", "validation_status": "validated", "plain_english_summary": "Every body corporate must designate a Grievance Officer and publish their name and contact details on its website. The Grievance Officer must resolve grievances relating to processing of information within one month of receipt."}	[1.0817285,0.27075985,-3.6823523,-0.2869719,0.714489,-0.6974397,0.017868787,0.49070027,0.5522943,0.088423945,0.60323316,0.7372776,0.49042377,0.052007616,0.60464823,-0.53500754,0.5408545,-0.6530442,-1.5463716,0.2174069,0.34220105,-0.7886122,-0.98239577,-0.73108846,1.6015689,0.35556573,0.3672441,-0.47657016,0.2724444,0.10479106,0.22194566,0.9