203	{"act": "SPDI_RULES_2011", "title": "Disclosure of Information - Disclosure by Court Order", "doc_id": "SPDI_RULE_6_SUB_2", "topics": ["disclosure", "sensitive_personal_data"], "entities": [], "keywords": ["court order", "legal order", "disclosure", "sensitive personal data", "third party", "law in force"], "metadata": {"act": "SPDI_RULES_2011", "year": 2011, "jurisdiction": "India"}, "references": ["SPDI_RULE_6_SUB_1"], "clause_text": "Notwithstanding anything contain in sub-rule (1), any sensitive personal data or information shall be disclosed to any third party by an order under the law for the time being in force.", "source_files": [2], "conflict_notes": [], "retrieval_text": "Rule 6(2) of the SPDI Rules 2011 provides that notwithstanding the prior consent requirement in Rule 6(1), sensitive personal data or information must be disclosed to any third party pursuant to an order made under any applicable law. This covers disclosures required by court orders or other legal orders.", "section_number": "6", "subsection_number": "2", "validation_status": "validated", "plain_english_summary": "Sensitive personal data or information may be disclosed to a third party pursuant to an order made under any law in force, overriding the consent requirement in sub-rule (1)."}	[0.81708425,0.75453234,-2.9684741,0.21678984,-0.41352051,0.060273837,-0.6395082,0.10128274,0.17554435,0.6225475,0.31050408,0.4868809,0.7464404,-0.23962101,-0.029467093,-0.08039445,0.841683,-1.179847,-0.59081405,0.5275368,-0.87530726,-0.10541617,-1.5802243,-0.037200525,1.2615287,-0.07623525,1.3278345,-0.6317743,-0.42236957,-0.8264594,0.695688,0.9224027,0.60007566,-0.43492916,-0.7254691,-2.1067812,0.44822904,-0.2721105,-1.5067562,0.3572833,0.8017506,0.671679,-0.17950338,-1.417487,0.5131048,-0.8897265,0.8371266,-0.042299904,0.36927488,-1.2753212,0.48824525,-0.27369344,-0.14830847,-0.419117,0.77814263,0.0051704342,-0.24606965,-0.23049328,0.5736578,-1.1346966,1.3956363,1.2740622,-0.6134528,0.95188296,0.892