205	{"act": "SPDI_RULES_2011", "title": "Disclosure of Information - Onward Disclosure Prohibition", "doc_id": "SPDI_RULE_6_SUB_4", "topics": ["disclosure", "sensitive_personal_data", "restriction"], "entities": [], "keywords": ["onward disclosure", "third party", "sensitive personal data", "prohibition", "further disclosure"], "metadata": {"act": "SPDI_RULES_2011", "year": 2011, "jurisdiction": "India"}, "references": ["SPDI_RULE_6_SUB_1"], "clause_text": "The third party receiving the sensitive personal data or information from body corporate or any person on its behalf under sub-rule (1) shall not disclose it further.", "source_files": [2], "conflict_notes": [], "retrieval_text": "Rule 6(4) of the SPDI Rules 2011 prohibits any third party that receives sensitive personal data or information from a body corporate under Rule 6(1) from further disclosing that information to any other person.", "section_number": "6", "subsection_number": "4", "validation_status": "validated", "plain_english_summary": "A third party that receives sensitive personal data from a body corporate is prohibited from disclosing it to any other party."}	[0.8270376,0.95231175,-3.0672865,0.3428306,-0.079839066,0.37605458,-0.58205414,0.02513009,-0.03305142,0.6419107,0.3057895,0.7968617,0.33522058,-0.6011918,0.2793936,-0.33963773,0.28264746,-1.1183057,-0.74178845,0.7387035,-0.60557663,0.27902046,-1.3354275,-0.3183212,1.3022897,-0.14123504,1.0644628,-0.7180589,0.1416112,-0.80912656,0.15660177,1.179331,0.4754921,-0.11576718,-0.8166284,-1.3691721,0.31726342,-0.14110996,-1.7166158,1.22086,0.120473266,0.9330601,-0.58373904,-1.2056917,0.2998093,-0.8433973,0.8046725,0.27553245,0.7676128,-1.1527286,0.3975583,-0.59076345,-0.120869264,-0.50529224,0.36288255,-0.5386324,-0.48302618,-0.10950862,0.36168715,-1.3002138,1.1287117,1.4143811,-0.45348832,1.0856719,1.1160158,-0.050264034,-1.092857,0.5270265,-0.5373785,-0.64611554,1.3619266,0.4438913,0.7946075,-0.45279297,0.31532583,-0.14728847,-0.35188484,-0.58044916