207	{"act": "SPDI_RULES_2011", "title": "Reasonable Security Practices - Compliance Standard", "doc_id": "SPDI_RULE_8_SUB_1", "topics": ["security", "compliance", "iso_27001"], "entities": ["body corporate"], "keywords": ["reasonable security practices", "documented information security programme", "managerial controls", "technical controls", "operational controls", "physical controls", "information assets", "security breach", "body corporate"], "metadata": {"act": "SPDI_RULES_2011", "year": 2011, "jurisdiction": "India"}, "references": ["ITACT_SEC_43A"], "clause_text": "A body corporate or a person on its behalf shall be considered to have complied with reasonable security practices and procedures, if they have implemented such security practices and standards and have a comprehensive documented information security programme and information security policies that contain managerial, technical, operational and physical security control measures that are commensurate with the information assets being protected with the nature of business. In the event of an information security breach, the body corporate or a person on its behalf shall be required to demonstrate, as and when called upon to do so by the agency mandated under the law, that they have implemented security control measures as per their documented information security programme and information security policies.", "source_files": [2], "conflict_notes": [], "retrieval_text": "Rule 8(1) of the SPDI Rules 2011 sets out the standard for compliance with reasonable security practices and procedures. A body corporate is considered compliant if it has implemented a comprehensive documented information security programme and policies containing managerial, technical, operational and physical security controls commensurate with the nature of its business and the information assets being protected. In the event of an information security breach, the body corporate must demonstrate to the mandated agency that it implemented the documented security controls.", "section_number": "8", "subsection_number": "1", "validation_status": "validated", "plain_english_summary": "A body corporate complies with reasonable security practices by implementing a comprehensive documented information security programme with managerial, technical, operational and physical controls appropriate to the information assets and nature of business. In the event of a breach, the body corporate must be able to demonstrate implementation of these controls to the mandated agency."}	[0.5130302,0.58900774,-3.2013838,0.7295916,0.5645963,-0.13544028,0.050919358,0.9211129,0.61585945,0.20549978,0.2578425,-0.12474806,0.053836998,-0.46323237,0.38259348,-0.4027585,0.3185241,-0.9598063,-0.68627846,0.3339774,-0.32207578,0.017982204,-1.3504812,-0.74925363,1.9829634,0.8044129,0.9089957,-0.84560376,-0.05008158,-1.020612,0.53159827,0.95705694,1.0684477,-1.4548321,0.07997938,-2.0209086,0.24672316,0.6447365,-1.0244962,0.52039266,0.32000703,0.12716778,-0.9187612,-0.78715885,0.380683,-0.21626781,1.1409447,-0.59922993,1.0467796,-0.9130209,-0.17059153,-0.62983245,-0.23210241,-0.70767856,1.3762264,0.044262495,-0.15739077,0.30669436,-1.1388813,-1.6203082,1.5327395,1.4426823,-0.16344987,0.67582303,0.8583356,-0.049401738,-0.77629393,0.36281604,-0.5132196,-0.519589,0.7382443,-0.030202638,0.9219166,-0.43220922,-0.024401154,-1.1504824,-0.6449736,-0.7189211,0.20644572,0.75125754,0.80410135,-0.6131744,1.1953518,0.82573414,0.93027693,0.379734,-0.36223826,-0.66119164,-0.15705048,1.391494,1.420841,-0.17043144,0.3493172,-0.1839954,-0.7899716,0.7164675,0.8731303,0.18599965,-0.55962646,-0.025983084,-0.718015,-1.1866469,0.6887128,0.9613862,-0.44813937,0.5580444,0.18417378,-0.27821374,0.26599684,-0.17989588,0.09609541,1.6626269,0.25489998,-0.24815203,0.59328043,-0.49109602,1.490884,-0.68299794,-0.48476824,1.0653033,-1.1954122,-1.6223261,0.34358916,0.591506,0.5891367,-0.6808332,-1.1928902,0.44574517,0.35113576,-0.7316101,-0.19488326,0.019413156,-1.