208	{"act": "SPDI_RULES_2011", "title": "Reasonable Security Practices - ISO/IEC 27001 Standard", "doc_id": "SPDI_RULE_8_SUB_2", "topics": ["security", "iso_27001", "compliance"], "entities": [], "keywords": ["ISO 27001", "IS/ISO/IEC 27001", "Information Security Management System", "ISMS", "reasonable security practices", "international standard"], "metadata": {"act": "SPDI_RULES_2011", "year": 2011, "jurisdiction": "India"}, "references": ["SPDI_RULE_8_SUB_1"], "clause_text": "The international Standard IS/ISO/IEC 27001 on \\"Information Technology - Security Techniques - Information Security Management System - Requirements\\" is one such standard referred to in sub-rule (1).", "source_files": [2], "conflict_notes": [], "retrieval_text": "Rule 8(2) of the SPDI Rules 2011 recognises the international standard IS/ISO/IEC 27001 on Information Technology Security Techniques — Information Security Management System Requirements as a standard that satisfies the reasonable security practices and procedures requirement under Rule 8(1).", "section_number": "8", "subsection_number": "2", "validation_status": "validated", "plain_english_summary": "The international standard IS/ISO/IEC 27001 on Information Security Management Systems is recognised as one of the standards satisfying the reasonable security practices requirement under Rule 8(1)."}	[-0.15770537,0.2862715,-3.1230793,0.7560317,0.71877384,-0.07696391,-0.20308939,0.83090204,-0.097827315,-0.28065264,0.443719,0.025262466,0.36677134,-1.1398615,-0.29173195,-0.4081424,-0.2846286,-0.5473261,-0.62950253,0.19284317,-0.30320188,-0.88419396,-1.4768322,-1.0843345,1.8848317,0.5875439,0.5943218,-0.25688753,-0.68943244,-0.59391296,0.7239317,-0.21130936,0.79120815,-0.43643674,-0.2270088,-2.263888,0.16603434,0.10845332,-1.3838574,0.89058334,0.78361183,-0.14023513,-0.42972118,0.033560544,1.0508249,-0.13607243,1.4332888,-0.6478582,0.24347991,-0.71716964,0.00470375,-0.35203308,0.367416,-0.5413162,1.1385014,0.12781617,-0.5720104,0.606