209	{"act": "SPDI_RULES_2011", "title": "Reasonable Security Practices - Industry Self-Regulation Approval", "doc_id": "SPDI_RULE_8_SUB_3", "topics": ["security", "compliance", "access_control"], "entities": ["Central Government"], "keywords": ["industry association", "self-regulation", "codes of best practices", "Central Government approval", "notification", "data protection"], "metadata": {"act": "SPDI_RULES_2011", "year": 2011, "jurisdiction": "India"}, "references": ["SPDI_RULE_8_SUB_1"], "clause_text": "Any industry association or an entity formed by such an association, whose members are self-regulating by following other than IS/ISO/IEC codes of best practices for data protection as per sub-rule(1), shall get its codes of best practices duly approved and notified by the Central Government for effective implementation.", "source_files": [2], "conflict_notes": [], "retrieval_text": "Rule 8(3) of the SPDI Rules 2011 requires any industry association or entity whose members follow codes of best practices for data protection other than IS/ISO/IEC standards to obtain approval and notification from the Central Government for those codes to be recognised as satisfying the reasonable security practices requirement under Rule 8(1).", "section_number": "8", "subsection_number": "3", "validation_status": "validated", "plain_english_summary": "Industry associations or entities using self-regulatory codes of best practices for data protection that are different from ISO/IEC standards must get their codes approved and notified by the Central Government."}	[0.16356638,0.432466,-2.7312696,0.37989616,0.8867434,-0.171799,-0.709166,0.32014877,0.42903215,-0.040007677,0.60957307,0.5813654,0.77827656,-0.6929737,0.1804468,-0.24967678,-0.41557866,-0.4522309,-0.6875551,0.3456836,-0.020975886,-0.6581984,-1.2582489,-0.95204395,1.7109933,0.43077418,1.3085175,-0.8728937,-0.56070167,-0.682681,0.42521736,0.39378145,0.3474923,-1.1055719,-0.008581645,-2.2140782,0.15438665,0.27682817,-0.824653