210	{"act": "SPDI_RULES_2011", "title": "Reasonable Security Practices - Audit Requirement", "doc_id": "SPDI_RULE_8_SUB_4", "topics": ["security", "iso_27001", "compliance", "access_control"], "entities": ["body corporate", "Central Government"], "keywords": ["audit", "independent auditor", "ISO 27001", "annual audit", "significant upgrade", "Central Government approval", "certified", "deemed compliant", "body corporate"], "metadata": {"act": "SPDI_RULES_2011", "year": 2011, "jurisdiction": "India"}, "references": ["SPDI_RULE_8_SUB_1", "SPDI_RULE_8_SUB_2", "SPDI_RULE_8_SUB_3"], "clause_text": "The body corporate or a person on its behalf who have implemented either IS/ISO/IEC 27001 standard or the codes of best practices for data protection as approved and notified under sub-rule (3) shall be deemed to have complied with reasonable security practices and procedures provided that such standard or the codes of best practices have been certified or audited on a regular basis by entities through independent auditor, duly approved by the Central Government. The audit of reasonable security practices and procedures shall be carried out by an auditor at least once a year or as and when the body corporate or a person on its behalf undertake significant upgradation of its process and computer resource.", "source_files": [2], "conflict_notes": [], "retrieval_text": "Rule 8(4) of the SPDI Rules 2011 provides that a body corporate implementing IS/ISO/IEC 27001 or Central Government-approved industry codes of best practices is deemed compliant with reasonable security practices and procedures, provided the implementation is certified or audited on a regular basis by an independent auditor approved by the Central Government. Audits must be conducted at least annually or whenever significant upgrades to processes or computer resources are undertaken.", "section_number": "8", "subsection_number": "4", "validation_status": "validated", "plain_english_summary": "A body corporate that implements ISO/IEC 27001 or approved industry codes of best practices is deemed compliant with reasonable security practices, provided the standard or code is regularly certified or audited by an independent auditor approved by the Central Government. The audit must be conducted at least once a year or whenever a significant upgrade of processes or computer resources takes place."}	[0.057797845,0.309683,-2.9176497,0.40364683,0.31089017,-0.29046327,-0.16849352,1.0672256,0.20591535,-0.033482797,0.6423981,0.18480054,-0.21340418,-0.3911057,0.26373318,-0.45132506,0.11267804,-0.7635604,-0.6600998,-0.023801675,0.083733864,-0.33184746,-1.2361194,-0.9362719,2.2363067,0.5692352,0.7001747,-0.5214844,-0.07322315,-1.324438,0.6984912,0.2717577,0.9517923,-0.9376215,-0.09264136,-2.1397681,0.6448636,0.40356135,-0.0973121,0.27090472,0.1267936,0.102787375,-0.25703064,-0.22728376,0.97984505,0.0063134343,1.2045473,-0.9513819,0.72268665,-0.9115419,-0.2035472,-0.11964368,0.5802967,-0.1427197,0.18842722,0.28482816,-0.7028301,0.76743186,-0.70282674,-1.2881761,1.2918617,1.3087168,0.098095894,0.130204,0.64079744,0.2815806,-0.5761208,-0.30225882,0.057728153,0.090997115,0.94046247,-0.6395117,1.2784532,-0.33036557,-0.09942104,-0.80748147,-0.63478154,-1.2218391,0.09770413,0.7495756,0.515191,0.008710806,1.289552,-0.0035219805,0.4769215,0.5943274,-0.16857314,-0.22291154,-0.3910927,1.4247252,0.7651626,-0.13506816,0.14700913,0.12413471,-1.2745875,0.09754074,0.23192061,0.57103556,-0.71744746,0.04135683,-0.4843384,-0.5678455,0.29883698,0.3093519,-0.42413437,0.81685716,0.105262674,-0.23251186,0.1378013,-0.04913414,-0.2129816,1.7812179,0.13897127,-0.2798985,0.42994258,0.12129018,1.2175314,-0.4715518,-0.44226843,1.6719772,-0.8254324,-1.4760529,0.7682229,0.54370284,0.5184566,0.076629624,-1.0133382,0.3679237,-0.41759446,-1.0993818,0.4838024,-0.11425982,-0.954273,-0.027836936,-0.14710988,1.3886526,0.30669266,-0.18380313,-0.13848312,0.025953531,0.21946985,0.64981943,-0.6174888,-0.29347497,0.69347584,-0.86535