211	{"act": "CERTIN_DIRECTIONS_2022", "title": "CERT-In Directions 2022 - Legal Basis and Authority", "doc_id": "CERTIN_DIR_PREAMBLE", "topics": ["cybersecurity", "compliance", "regulatory_reporting"], "entities": ["CERT-In", "Central Government", "service provider", "intermediary", "data centre", "body corporate", "Government organisation"], "keywords": ["CERT-In Directions 2022", "section 70B", "IT Act 2000", "cyber security", "28 April 2022", "60 days", "effective date", "punitive action"], "metadata": {"act": "CERTIN_DIRECTIONS_2022", "year": 2022, "jurisdiction": "India"}, "references": ["ITACT_SEC_70B"], "clause_text": "Directions under sub-section (6) of section 70B of the Information Technology Act, 2000 relating to information security practices, procedure, prevention, response and reporting of cyber incidents for Safe & Trusted Internet. Issued on 28 April 2022. These directions are issued in the interest of the sovereignty or integrity of India, defence of India, security of the state, friendly relations with foreign states or public order or for preventing incitement to the commission of any cognizable offence using computer resource or for handling of any cyber incident, to augment and strengthen cyber security in the country.", "source_files": [3], "conflict_notes": [], "retrieval_text": "The CERT-In Directions issued on 28 April 2022 under sub-section (6) of section 70B of the Information Technology Act 2000 are binding directions relating to information security practices, procedure, prevention, response and reporting of cyber incidents for safe and trusted internet. CERT-In is empowered under section 70B(6) to call for information and give directions to service providers, intermediaries, data centres, body corporates and government organisations. These directions came into effect 60 days from 28 April 2022 and non-compliance may invite punitive action under section 70B(7) of the IT Act 2000.", "section_number": "Preamble", "subsection_number": null, "validation_status": "validated", "plain_english_summary": "These directions are issued by CERT-In on 28 April 2022 under section 70B(6) of the IT Act 2000, to strengthen cyber security in India. They are binding on service providers, intermediaries, data centres, body corporates, and government organisations and became effective 60 days from the date of issue."}	[-0.056506775,-0.07157936,-3.6893213,-0.083628625,0.9361479,0.8528,0.7549014,1.1331832,0.08220336,-0.62582767,-0.1968878,0.48623472,0.9879756,-0.87013614,0.1396909,-0.6962527,0.24675879,-0.8778346,-0.82700205,-0.44484824,0.65279865,-1.8535203,-0.84245944,-0.45859885,0.90230894,0.3690341,0.99072576,-0.44261867,-0.47470728,-0.6876535,0.993229,0.19017231,0.5206089,-0.6613673,-0.8296557,-1.251128,0.5143914,-0.04104691,-1.6545186,0.4700086,0.9215098,0.081248164,0.02365405,-0.6313664,0.35298842,-0.12623973,0.7790377,0.05675122,0.9922806,-0.94206876,0.3649709,-0.888533,0.7935455,-0.059169464,1.3391156,0.017212924,-0.5552266,0.20146044,-0.08734486,-1.4813116,1.8427644,1.0407506,-0.5350053,0.7995263,1.1023636,-1.243583,-1.2499772,0.78821087,0.0397943,-0.1446988,1.2174155,-0.58169925,0.70684004,-0.48227268,-0.5093562,-0.6614952,-0.5306159,-1.5815105,-0.20486243,1.4043603,-0.1996189,-0.37455064,0.9561053,-0.44675106,0.100974515,0.68362486,-0.037700247,0.04159164,-0.45639634,1.1543826,0.57791877,0.24284068,-0.06530917,0.088281065,-0.5540831,0.20597863,-0.07822488,0.08082974,-0.11185706,0.18009616,-0.32042855,-0.6276608,0.01782376,0.024514724,-0.0918708,1.344552,0.6103686,-0.17249212,-0.30303565,0.08160715,-0.23275203,0.38869697,-0.045051903,0.07904159,0.88052857,1.2230343,1.2991796,-0.6570493,0.26479447,0.7251977,0.1115638,-0.72752786,-0.21984918,1.1096189,1.1221044,0.5012539,-0.74006224,0.106700435,-0.15513127,-1.0919001,-0.34660798,0.45160925,-0.9983307,-0.03524261,0.2295818,0.5815024,-0.29026967,-0.9128948,0.4417221,0.06911919,0.670468,0.59593153,0.47938016,-0.45248312,0.9656043,-0.524256,1.1491855,0.30667204,0.457