212	{"act": "CERTIN_DIRECTIONS_2022", "title": "NTP Server Synchronisation", "doc_id": "CERTIN_DIR_1", "topics": ["ntp_synchronization", "cybersecurity", "compliance"], "entities": ["CERT-In", "service provider", "intermediary", "data centre", "body corporate", "Government organisation", "National Informatics Centre", "National Physical Laboratory"], "keywords": ["NTP", "Network Time Protocol", "NIC", "NPL", "National Informatics Centre", "National Physical Laboratory", "clock synchronisation", "ICT systems", "time source"], "metadata": {"act": "CERTIN_DIRECTIONS_2022", "year": 2022, "jurisdiction": "India"}, "references": ["ITACT_SEC_70B"], "clause_text": "All service providers, intermediaries, data centres, body corporate and Government organisations shall connect to the Network Time Protocol (NTP) Server of National Informatics Centre (NIC) or National Physical Laboratory (NPL) or with NTP servers traceable to these NTP servers, for synchronisation of all their ICT systems clocks. Entities having ICT infrastructure spanning multiple geographies may also use accurate and standard time source other than NPL and NIC, however it is to be ensured that their time source shall not deviate from NPL and NIC.", "source_files": [3], "conflict_notes": [], "retrieval_text": "Direction (i) of the CERT-In Directions 2022 requires all service providers, intermediaries, data centres, body corporates and government organisations to synchronise all ICT system clocks with the NTP Server of the National Informatics Centre (NIC) or National Physical Laboratory (NPL), or NTP servers traceable to these. Entities with ICT infrastructure spanning multiple geographies may use other accurate and standard time sources, but such sources must not deviate from NIC and NPL. This obligation ensures accurate and consistent time-stamping across all systems for cyber incident investigation.", "section_number": "i", "subsection_number": null, "validation_status": "validated", "plain_english_summary": "All covered entities must synchronise all their ICT system clocks with the NTP servers of NIC or NPL, or NTP servers traceable to these. Entities with multi-geography infrastructure may use other accurate time sources provided they do not deviate from NIC and NPL."}	[0.08151471,0.6914556,-3.8313243,-0.81663525,1.2349586,0.45012227,0.63398176,-0.16520073,-0.51883245,-0.10209349,-0.4685074,0.101686396,0.80470663,-0.1259397,-0.32648504,-0.96841997,0.41340962,0.02241404,-1.0265867,0.7279347,1.1455646,-1.3364044,-0.3669945,-1.1796738,0.7901534,0.37810546,1.1573194,-0.5657627,-1.4391494,-0.09843789,1.5701092,-0.2591413,0.10201622,-1.3120911,-0.019208824,-1.4844155,-0.34076595,-1.1224889,-0.9601286,0.7022315,0.8788351,-0.28197908,0.37843677,-0.8497539,0.97411877,0.32683182,0.39890394,-0.19982795,0.41108716,-0.6907426,-0.41970882,-0.2702213,0.18976635,0.46770215,1.0152818,0.47494853,0.083240494,0.52639574,0.06863677,-0.44259354,2.298245,1.4295424,-0.22941232,0.90208733,1.1177784,0.025099251,-1.1561581,0.6734133,0.42883417,-0.57210237,-0.49277312,-0.24244101,0.72547543,0.5078969,0.5079037,-0.5143199,-0.092579454,-1.2751546,-0.63122094,1.3509502,-0.159228,0.033069134,1.1213144,-0.61207414,0.8877884,0.56338745,0.13021135,0.054968856,-0.5102068,2.0518467,0.46833444,0.54289013,1.4936758,0.03261651,-0.66580784,0.6164454,0.5558029,1.0749836,-0.16786985,0.42140567,-0.32046217,-0.14410828,-0.6406405,-0.30195242,0.49675503,0.49293795,0.52384025,-0.16387713,0.28128162,-0.5059859,-0.41790625,0.06670958,-0.2523573,0.45670438,0.6154296,0.31047,0.895978,-0.21217142,0.36812627,0.99639606,0.2690208,-1.2741497,-0.15004022,1.4252784,0.2973391,0.013321714,-0.7957211,0.2275787,-0.2513511,-1.1023365,-0.15824276,0.43601856,-1.010986,0.30522344,-0.37338442,0.2339615,-0.14210701,-0.9768452,0.32521936,0.51755816,0.1764824,-0.26293167,-0.18331361,-0.08551301,0.7511474,-0.20103696,0.13104962,0.03180736,0.08646952,0.30179098,-0.3166742,0.09166362,-0.027999848,0.0720778,0.68910813,-0.91198677,-1.12231