213	{"act": "CERTIN_DIRECTIONS_2022", "title": "Mandatory Cyber Incident Reporting Within 6 Hours", "doc_id": "CERTIN_DIR_2", "topics": ["incident_reporting", "breach_reporting", "cybersecurity", "regulatory_reporting", "cyber_incidents"], "entities": ["CERT-In", "service provider", "intermediary", "data centre", "body corporate", "Government organisation"], "keywords": ["6 hours", "mandatory reporting", "cyber incident", "CERT-In", "Annexure I", "incident@cert-in.org.in", "1800-11-4949", "fax", "report"], "metadata": {"act": "CERTIN_DIRECTIONS_2022", "year": 2022, "jurisdiction": "India"}, "references": ["CERTIN_ANNEXURE_1", "ITACT_SEC_70B"], "clause_text": "Any service provider, intermediary, data centre, body corporate and Government organisation shall mandatorily report cyber incidents as mentioned in Annexure I to CERT-In within 6 hours of noticing such incidents or being brought to notice about such incidents. The incidents can be reported to CERT-In via email (incident@cert-in.org.in), Phone (1800-11-4949) and Fax (1800-11-6969). The details regarding methods and formats of reporting cyber security incidents is also published on the website of CERT-In www.cert-in.org.in and will be updated from time to time.", "source_files": [3], "conflict_notes": [], "retrieval_text": "Direction (ii) of the CERT-In Directions 2022 requires all service providers, intermediaries, data centres, body corporates and government organisations to mandatorily report cyber incidents specified in Annexure I to CERT-In within 6 hours of noticing such incidents or being brought to notice of them. Incidents can be reported via email at incident@cert-in.org.in, by phone at 1800-11-4949, or by fax at 1800-11-6969. Reporting formats are published on the CERT-In website and updated from time to time.", "section_number": "ii", "subsection_number": null, "validation_status": "validated", "plain_english_summary": "All covered entities must mandatorily report cyber incidents listed in Annexure I to CERT-In within 6 hours of noticing or being informed of such incidents. Reports may be submitted via email, phone, or fax."}	[0.28570947,0.2693819,-3.965057,-0.607486,1.2766594,0.108060084,1.234594,0.9026379,0.16383392,-0.7517096,-0.78330576,0.8861689,0.91810745,-0.32838762,-0.030056749,-1.2485579,0.45969328,-0.8824694,-2.186816,0.10846913,0.73836684,-1.8379977,-0.54807764,-0.3967011,1.235616,0.9951604,1.1480963,-0.08077275,-0.57214016,-0.22311315,0.602431,0.15059046,-0.5797834,-0.58619744,-0.83028996,-1.3751147,-0.6396497,-1.059782,-1.5886935,0.5425206,1.3125057,-0.46535233,0.3028704,-0.58302444,0.06875045,0.2607764,0.820238,0.51027936,1.5591296,-0.7667059,0.2881422,-0.6435763,0.20448671,0.47925726,1.1277786,-0.08798186,-0.5805007,0.21724801,0.24563015,-2.0646417,2.1428251,1.2804742,-0.44444367,0.41746065,1.2524358,-0.6179522,-1.0277958,1.12341,0.04256184,-0.40291518,0.4314613,-0.8533848,0.22473909,0.14223412,-0.4495229,-0.6416406,-0.4716964,-1.4793965,-0.06838171,1.5199157,0.039806284,0.2480207,1.3669769,-0.8185387,0.5365827,0.41508168,0.1016955,0.36053228,-0.542891,1.1672857,0.7059767,0.51265246,0.050628368,-0.48619807,-0.6425461,0.1384477,0.07179345,0.18053971,-0.45726144,0.038120456,0.09561729,-0.35856968,-0.58580023,-0.44489595,0.19159482,1.236944,0.7304254,0.022451408,0.35366663,-0.64828205,-0.41336715,0.37581232,-0.30019525,0.41365898,1.1690089,0.70634633,1.0700597,-0.69015324,0.18804769,1.1757581,0.011680977,-1.3308752,-0.16146892,0.9848516,1.3214858,0.04845002,-0.49532333,0.18423592,0.19622672,-1.2247812,-0.28899685,0.1536355,-0.6363162,-0.03945282,-0.09664043,1.2440878,0.08271566,-0.9396401,0.20067063,0.05578418,0.39934686,0.9347876,0.3703409,-0.08906566,0.6384131,-0.3394637,0.9890191,0.40847602,0.5182676,-0.4043497,-0.84082586,0.2563438,0.032732554,0.16743489,0.75545985,-0.61266655,-0.65082604,0.28633973,0.5620993,0.79952204,0.5781223,0.06404926,-1.3236432,1.1737198,-0.2657502,-1.0883955,-0.7449848,0.85747707,-0.07204974,0.5885834,-0.86870563,-0.2356