214	{"act": "CERTIN_DIRECTIONS_2022", "title": "Compliance with CERT-In Orders and Point of Contact Designation", "doc_id": "CERTIN_DIR_3", "topics": ["incident_reporting", "compliance", "cybersecurity", "contact_management"], "entities": ["CERT-In", "service provider", "intermediary", "data centre", "body corporate", "Government organisation"], "keywords": ["Point of Contact", "PoC", "CERT-In order", "direction", "cyber incident response", "mitigation", "real-time", "non-compliance", "Annexure II"], "metadata": {"act": "CERTIN_DIRECTIONS_2022", "year": 2022, "jurisdiction": "India"}, "references": ["CERTIN_ANNEXURE_2", "ITACT_SEC_70B"], "clause_text": "When required by order/direction of CERT-In, for the purposes of cyber incident response, protective and preventive actions related to cyber incidents, the service provider/intermediary/data centre/body corporate is mandated to take action or provide information or any such assistance to CERT-In, which may contribute towards cyber security mitigation actions and enhanced cyber security situational awareness. The order/direction may include the format of the information that is required (up to and including near real-time), and a specified timeframe in which it is required, which should be adhered to and compliance provided to CERT-In, else it would be treated as non-compliance of this direction. The service providers, intermediaries, data centres, body corporate and Government organisations shall designate a Point of Contact to interface with CERT-In. The Information relating to a Point of Contact shall be sent to CERT-In in the format specified at Annexure II and shall be updated from time to time. All communications from CERT-In seeking information and providing directions for compliance shall be sent to the said Point of Contact.", "source_files": [3], "conflict_notes": [], "retrieval_text": "Direction (iii) of the CERT-In Directions 2022 mandates that service providers, intermediaries, data centres, body corporates and government organisations comply with CERT-In orders and directions for cyber incident response and preventive actions, including providing information or assistance in specified formats and timeframes. Failure to comply within the specified timeframe constitutes non-compliance. Each covered entity must designate a Point of Contact to interface with CERT-In and submit their details in the format specified in Annexure II, keeping it updated. All CERT-In communications will be directed to the designated Point of Contact.", "section_number": "iii", "subsection_number": null, "validation_status": "validated", "plain_english_summary": "Covered entities must comply with CERT-In orders and directions for cyber incident response, including providing information in specified formats and timeframes. Each entity must designate a Point of Contact (PoC) to interface with CERT-In and submit PoC details in the Annexure II format. All CERT-In communications will be sent to the designated PoC."}	[0.18420133,-0.2250772,-3.3349764,-0.5380948,1.0619087,0.6928205,1.0345671,0.631003,0.08623916,-0.03952812,-0.4820877,0.21319085,0.7564679,-0.4478459,0.26716292,-0.7391565,0.350908,-0.50948566,-1.7110096,0.15189818,0.80156314,-1.1217625,-0.37774906,-0.42249054,0.82825935,0.51683044,1.5519086,-0.23095483,-0.6716492,-0.8314483,0.78227335,0.4729473,0.37692794,-1.199439,-0.5896508,-1.125096,0.08944835,-0.2777196,-1.253412,0.6491979,0.7304302,-0.022032391,0.12338773,-0.8703703,0.35264716,-0.093712665,1.1547824,0.2403206,1.3903137,-1.0717431,0.48136663,-0.5343382,-0.0019695489,0.062062062,1.0408317,0.23455967,-0.24314794,0.11550512,-0.5082604,-1.9555482,1.8645036,1.1819594,-0.36494347,0.788701,1.2293091,-1.0250008,-1.8324205,1.001668,-0.30098727,-0.34484342,0.83338016,-0.07537454,0.52390385,-0.06616214,-0.33099726,-0.84982,-0.9128836,-1.2999697,-0.1386632,1.3153538,-0.124891505,-0.17364854,1.1146982,-0.65319246,1.1734957,0.83060247,0.034866873,0.05543953,-0.439195,1.5308844,-0.05835735,0.618