215	{"act": "CERTIN_DIRECTIONS_2022", "title": "ICT Log Retention for 180 Days Within Indian Jurisdiction", "doc_id": "CERTIN_DIR_4", "topics": ["log_retention", "audit_logs", "compliance", "cybersecurity", "monitoring"], "entities": ["CERT-In", "service provider", "intermediary", "data centre", "body corporate", "Government organisation"], "keywords": ["logs", "ICT logs", "180 days", "rolling period", "Indian jurisdiction", "log retention", "enable logs", "securely maintained", "CERT-In"], "metadata": {"act": "CERTIN_DIRECTIONS_2022", "year": 2022, "jurisdiction": "India"}, "references": ["ITACT_SEC_70B"], "clause_text": "All service providers, intermediaries, data centres, body corporate and Government organisations shall mandatorily enable logs of all their ICT systems and maintain them securely for a rolling period of 180 days and the same shall be maintained within the Indian jurisdiction. These should be provided to CERT-In along with reporting of any incident or when ordered/directed by CERT-In.", "source_files": [3], "conflict_notes": [], "retrieval_text": "Direction (iv) of the CERT-In Directions 2022 requires all service providers, intermediaries, data centres, body corporates and government organisations to mandatorily enable and securely maintain logs of all ICT systems for a rolling period of 180 days. The logs must be maintained within Indian jurisdiction and must be provided to CERT-In when reporting any incident or when ordered or directed by CERT-In to do so.", "section_number": "iv", "subsection_number": null, "validation_status": "validated", "plain_english_summary": "All covered entities must enable and securely maintain logs of all ICT systems for a rolling period of 180 days. Logs must be stored within India and must be provided to CERT-In when reporting an incident or when directed by CERT-In."}	[-0.10199638,0.09009757,-3.6820512,-0.89814216,1.1688967,-0.6205204,0.8548352,0.6872828,-0.21962698,-0.9206903,-0.2171634,0.3116405,1.5491083,-0.83609