216	{"act": "CERTIN_DIRECTIONS_2022", "title": "Data Centre, VPS, Cloud and VPN Provider - Subscriber Registration and Record Retention", "doc_id": "CERTIN_DIR_5", "topics": ["record_retention", "compliance", "cybersecurity", "vpn", "cloud_services"], "entities": ["CERT-In", "data centre", "VPS provider", "cloud service provider", "VPN service provider"], "keywords": ["data centre", "VPS", "cloud service provider", "VPN", "subscriber registration", "5 years", "record retention", "IP address", "timestamp", "KYC", "ownership pattern", "validated names"], "metadata": {"act": "CERTIN_DIRECTIONS_2022", "year": 2022, "jurisdiction": "India"}, "references": ["ITACT_SEC_70B"], "clause_text": "Data Centres, Virtual Private Server (VPS) providers, Cloud Service providers and Virtual Private Network Service (VPN Service) providers, shall be required to register the following accurate information which must be maintained by them for a period of 5 years or longer duration as mandated by the law after any cancellation or withdrawal of the registration as the case may be: a. Validated names of subscribers/customers hiring the services; b. Period of hire including dates; c. IPs allotted to / being used by the members; d. Email address and IP address and time stamp used at the time of registration / on-boarding; e. Purpose for hiring services; f. Validated address and contact numbers; g. Ownership pattern of the subscribers / customers hiring services.", "source_files": [3], "conflict_notes": [], "retrieval_text": "Direction (v) of the CERT-In Directions 2022 requires data centres, Virtual Private Server providers, cloud service providers and VPN service providers to register and maintain accurate subscriber and customer information. The information to be maintained includes validated names of subscribers, period of hire, IPs allotted or used, email address and IP address with timestamp at registration or on-boarding, purpose for hiring services, validated address and contact numbers, and ownership pattern of subscribers. This information must be maintained for a period of five years or longer as mandated by law, calculated from the date of any cancellation or withdrawal of registration.", "section_number": "v", "subsection_number": null, "validation_status": "validated", "plain_english_summary": "Data centres, VPS providers, cloud service providers, and VPN service providers must register and maintain accurate subscriber information — including names, hire period, IP addresses, email addresses, registration timestamps, purpose, address, contact numbers, and ownership pattern — for at least 5 years after cancellation or withdrawal of registration."}	[-0.646992,0.009549181,-3.8362172,-0.6305985,1.0242345,-0.26229423,0.68539,0.7583026,0.35125077,-0.34938592,-0.57848316,0.8459145,1.0942422,-0.9077639,0.60577077,-0.2343978,-0.38918355,-1.2023462,-0.7503573,-0.18996342,0.28453392,-1.4031488,-0.628939,-0.4147791,0.7343398,0.5243613,0.9852718,-0.8280883,0.10388882,-0.7051023,0.76291776,0.48732492,0.77930284,-0.5459291,-0.87663084,-1.3400851,0.0048036953,-0.16027743,-0.62186295,0.27457368,1.2196223,-0.55296046,-0.33859032,-0.7031093,0.32545343,-0.33560178,0.9536764,-0.59475535,1.5270323,-0.74190086,-0.05189962,-0.85486424,0.102852605,1.1490693,0.63982356,-0.004577347,-0.2972282,0.86150324,-0.7748989,-1.3900262,1.7972504,0.74441504,-0.41489574,1.5199249,1.2268126,-1.3818014,-1.1044688,0.79170096,-0.10454173,-0.3218066,0.9306818,0.065803334,0.9162489,0.4879583,0.32175195,-0.3348813,-0.5929982,-1.274337,-0.16046683,0.7871535,0.5953668,-0.22832432,1.4109883,-0.446153,0.8655871,0.36127084,0.039087612,0.15523842,-0.4827032,1.5657723,-0.23801523,0.49603188,0.9737339,0.5683422,-0.60690194,0.106965125,0.005932509,0.39899036,-0.6217126,0.31745988,-0.14596276,-0.9527402,-0.21827938,0.14813305,0.09031656,1.5851988,0.5012792,-0.019640507,0.35301206,-1.0065792,-1.0044836,0.06938262,-0.6236704,1.1277312,0.6303106,0.116071545,1.3377523,-0.23118994,0.5145589,0.7575962