220	{"act": "CERTIN_DIRECTIONS_2022", "title": "KYC Requirements - Officially Valid Documents and Business Entity Due Diligence", "doc_id": "CERTIN_ANNEXURE_3", "topics": ["kyc", "virtual_assets", "compliance", "record_retention"], "entities": ["CERT-In", "virtual asset service provider", "virtual asset exchange provider", "custodian wallet provider", "Reserve Bank of India", "SEBI", "Department of Telecom", "Election Commission of India"], "keywords": ["KYC", "Officially Valid Document", "OVD", "passport", "Aadhaar", "voter ID", "driving licence", "NREGA", "National Population Register", "RBI KYC Directions 2016", "SEBI", "DoT", "B2B", "Customer Due Diligence", "CDD", "Annexure III"], "metadata": {"act": "CERTIN_DIRECTIONS_2022", "year": 2022, "jurisdiction": "India"}, "references": ["CERTIN_DIR_6", "ITACT_SEC_70B"], "clause_text": "For the purpose of KYC, any of following Officially Valid Document (OVD) as a measure of identification procedure prescribed by the Reserve Bank of India (Know Your Customer (KYC)) Directions, 2016 / Securities and Exchange Board of India Clarification on Know Your Client (KYC) Process and Use of Technology for KYC vide Circular SEBI/HO/MIRSD/DOP/CIR/P/2020/73 dated April 24, 2020 / The Department of Telecom File No: 800-12/2021-AS.II dated September 21, 2021 on Self-KYC (S-KYC) as an alternate process for issuing of new mobile connections to Local and Outstation category customers, shall be used and maintained: a. The passport; b. The driving license; c. Proof of possession of Aadhaar number; d. The Voter's Identity Card issued by the Election Commission of India; e. Job card issued by NREGA duly signed by an officer of the State Government; f. Letter issued by the National Population Register containing details of name and address; g. Validated phone number; h. Trading account number and details, Bank account number and bank details. For the purpose of KYC for business entities (B2B), documents mentioned in the Customer Due Diligence (CDD) process prescribed in Reserve Bank of India Master Direction - Know Your Customer (KYC) Direction, 2016 as updated from time to time shall be used and maintained.", "source_files": [3], "conflict_notes": [], "retrieval_text": "Annexure III to the CERT-In Directions 2022 specifies the KYC requirements applicable to virtual asset service providers, virtual asset exchange providers and custodian wallet providers under Direction (vi). For individual customers, Officially Valid Documents include a passport, driving licence, proof of Aadhaar, Voter Identity Card issued by the Election Commission of India, NREGA job card signed by a State Government officer, National Population Register letter, validated phone number, and trading account or bank account details. KYC procedures must follow the RBI KYC Directions 2016, SEBI circular dated April 24 2020, or DoT S-KYC notice dated September 21 2021. For business entity customers, the Customer Due Diligence process under the RBI Master Direction on KYC 2016 must be followed and maintained.", "section_number": "Annexure III", "subsection_number": null, "validation_status": "validated", "plain_english_summary": "Annexure III specifies the Officially Valid Documents (OVDs) required for KYC under Direction (vi). For individual customers these include passport, driving licence, Aadhaar, voter ID, NREGA job card, National Population Register letter, validated phone number, and bank or trading account details. For B2B entities, the RBI Master Direction on KYC 2016 Customer Due Diligence process must be followed."}	[-0.2401191,0.59617,-3.1850278,-0.6869532,0.9909862,0.039885048,0.32519633,0.70461565,0.25802267,0.58426225,-0.5616787,0.18606539,1.2599683,-0.49102238,0.67682654,-0.04353367,0.10509892,-0.46499667,-1.1370499,0.082659476,-0.7747903,-0.63468826,-1.2333463,-0.08991152,1.8341241,-0.69809705,1.0595721,0.30651456,-0.37246495,-0.56149125,1.2992839,-0.35643324,1.5085396,-0.90919435,-0.10711932,-1.1361192,1.2703872,-0.04686618