224	{"act": "DPDP", "title": "Definition - Consent Manager", "doc_id": "DPDP_SEC_2_SUB_g", "topics": ["compliance", "consent"], "entities": ["Consent Manager", "Data Principal", "Board"], "keywords": ["Consent Manager", "consent", "Data Principal", "platform", "interoperable"], "metadata": {"act": "DPDP", "year": 2023, "jurisdiction": "India"}, "references": [], "clause_text": "\\"Consent Manager\\" means a person registered with the Board, who acts as a single point of contact to enable a Data Principal to give, manage, review and withdraw her consent through an accessible, transparent and interoperable platform.", "source_files": [4], "conflict_notes": [], "retrieval_text": "Section 2 subsection g of the Digital Personal Data Protection Act 2023 (DPDP Act). Definition - Consent Manager Defines a Consent Manager as a Board-registered person who serves as a single point of contact for managing Data Principal consent. Topics: compliance, consent. Keywords: Consent Manager, consent, Data Principal, platform, interoperable.", "section_number": "2", "subsection_number": "g", "validation_status": "validated", "plain_english_summary": "Defines a Consent Manager as a Board-registered person who serves as a single point of contact for managing Data Principal consent."}	[0.5611135,1.077239,-2.844415,-0.7704727,0.7614715,0.50314856,0.5368003,-0.26396763,0.4083915,0.04500909,-0.28634542,-0.16964373,0.57270485,-0.5129981,0.089680605,-0.35778597,0.12137648,-1.5254933,-0.56733817,-0.25932118,-0.2993306,-0.82586044,-1.1448262,-0.08856227,1.4928483,0.12260431,1.3580025,-0.61408854,0.16458999,-0.8413296,0.08979979,0.91920877,0.3153621,-0.5724918,-0.8372328,-1.5940046,0.16119763,0.520242,-0.84224045,-0.12027129,0.656911,-0.06262276,-0.07664481,-1.5096927,0.40058148,-0.22563684,-0.29112417,-0.6862638,1.0745689,-0.60478723,0.6756125,-0.5819499,0.53131706,-0.054295987,0.912628,0.49828842,0.25381795,0.35706073,-1.1866143,-1.1229581,1.6397537,1.2744737,-0.42240322,1.6202576,1.138479,0.345