226	{"act": "DPDP", "title": "Definition - Data Principal", "doc_id": "DPDP_SEC_2_SUB_j", "topics": ["children_data", "compliance", "data_processing", "user_rights"], "entities": ["Data Principal"], "keywords": ["Data Principal", "individual", "child", "guardian", "disability", "personal data"], "metadata": {"act": "DPDP", "year": 2023, "jurisdiction": "India"}, "references": [], "clause_text": "\\"Data Principal\\" means the individual to whom the personal data relates and where such individual is— (i) a child, includes the parents or lawful guardian of such a child; (ii) a person with disability, includes her lawful guardian, acting on her behalf.", "source_files": [4], "conflict_notes": [], "retrieval_text": "Section 2 subsection j of the Digital Personal Data Protection Act 2023 (DPDP Act). Definition - Data Principal Defines Data Principal as the individual whose personal data is being processed, including parents or guardians for children and persons with disabilities. Topics: children_data, compliance, data_processing, user_rights. Keywords: Data Principal, individual, child, guardian, disability, personal data.", "section_number": "2", "subsection_number": "j", "validation_status": "validated", "plain_english_summary": "Defines Data Principal as the individual whose personal data is being processed, including parents or guardians for children and persons with disabilities."}	[0.7446447,0.9962168,-2.9452045,-1.4070781,-0.028265864,0.960852,0.62201643,-0.47204167,0.17073302,-0.6148895,-0.2855118,0.43878266,0.7603846,-1.2010602,-0.42264062,-0.52916914,-0.27703413,-1.2530962,-0.55370706,0.13477811,0.00026254708,-0.42117304,-1.2371708,0.34454268,1.8747641,0.1260508,1.2263027,-1.1131359,-0.15417899,-0.8393765,-0.16485693,0.3851193,0.31682754,-0.049786776,-1.3010471,-1.0734324,0.6408305,1.3524243,0.024236428,-0.059854053,0.12436804,-0.19109415,-0.2337433,-1.2733287,-0.69751686,0.096073315,-0.045518544,-0.62853575,0.97399807,-0.19210973,0.3133878,-0.33028048,0.81110