229	{"act": "DPDP", "title": "Definition - Personal Data Breach", "doc_id": "DPDP_SEC_2_SUB_u", "topics": ["breach_reporting", "security"], "entities": [], "keywords": ["personal data breach", "unauthorised processing", "confidentiality", "integrity", "availability", "disclosure"], "metadata": {"act": "DPDP", "year": 2023, "jurisdiction": "India"}, "references": [], "clause_text": "\\"personal data breach\\" means any unauthorised processing of personal data or accidental disclosure, acquisition, sharing, use, alteration, destruction or loss of access to personal data, that compromises the confidentiality, integrity or availability of personal data.", "source_files": [4], "conflict_notes": [], "retrieval_text": "Section 2 subsection u of the Digital Personal Data Protection Act 2023 (DPDP Act). Definition - Personal Data Breach Defines a personal data breach as any unauthorised or accidental act that compromises the confidentiality, integrity, or availability of personal data. Topics: breach_reporting, security. Keywords: personal data breach, unauthorised processing, confidentiality, integrity, availability, disclosure.", "section_number": "2", "subsection_number": "u", "validation_status": "validated", "plain_english_summary": "Defines a personal data breach as any unauthorised or accidental act that compromises the confidentiality, integrity, or availability of personal data."}	[1.1097432,0.7604171,-3.1730382,-0.8842236,1.3233136,0.38419756,0.06072621,0.070905164,0.46253294,-0.4751417,-0.48584443,0.45987326,0.642634,-0.7040585,-0.3406212,-0.6302438,0.09070581,-1.3336868,-0.66253775,0.3143011,-0.54672354,-0.19282557,-1.1421171,0.16986322,1.2012283,-0.36986905,1.5707874,-0.82139236,-0.19110323,-0.7447561,-0.11123469,-0.09892904,-0.34637895,-0.66880333,-1.273317,-1.4419941,0.45623595,0.56632745,-0.29667833,-0.37828955,0.4689514,0.31470066,0.6000384,-1.351471,-0.41116276,0.3018361,-0.091885865,-0.010442505,0.46321672,-0.21405567,0.29269168,-0.37241662,0.8138883,-0.36