231	{"act": "DPDP", "title": "Application - Territorial Scope within India", "doc_id": "DPDP_SEC_3_SUB_a", "topics": ["compliance", "data_processing"], "entities": [], "keywords": ["digital personal data", "processing", "territory of India", "digitised", "scope"], "metadata": {"act": "DPDP", "year": 2023, "jurisdiction": "India"}, "references": [], "clause_text": "Subject to the provisions of this Act, it shall apply to the processing of digital personal data within the territory of India where the personal data is collected— (i) in digital form; or (ii) in non-digital form and digitised subsequently.", "source_files": [4], "conflict_notes": [], "retrieval_text": "Section 3 subsection a of the Digital Personal Data Protection Act 2023 (DPDP Act). Application - Territorial Scope within India This Act applies to processing of digital personal data collected within India, whether originally in digital form or digitised subsequently. Topics: compliance, data_processing. Keywords: digital personal data, processing, territory of India, digitised, scope.", "section_number": "3", "subsection_number": "a", "validation_status": "validated", "plain_english_summary": "This Act applies to processing of digital personal data collected within India, whether originally in digital form or digitised subsequently."}	[0.8321436,0.61411333,-2.9934504,-1.154111,0.85977006,-0.0071099647,0.13034984,-0.3410222,0.27569553,-0.6192532,0.08187411,0.19089249,2.1345935,-1.1031351,-0.16914943,-0.60775274,-0.6260823,-1.109535,-0.650984,0.48093268,-0.029959107,0.7089448,-1.0192314,-0.3494244,0.8550592,-0.3405832,1.9406073,-0.6815957,-0.4219731,-0.46700215,0.12276803,0.24264492,-0.030420091,-0.58717036,-0.07802404,-1.5008296,1.3081359,0.104277894,-0.4688407,0.03880337,1.0183825,-0.2537346,-0.1430878,-0.95360523,0.87342924,0.1977561,0.80918837,-0.15406698,0.64997065,-0.19408493,-0.53014636,-0.019057702,0.10662791,-0.76508033,0.6240667,0.39102852,-1.5427506,-0.20374002,-0.121957764,-0.56749266,1.678212