234	{"act": "DPDP", "title": "Grounds for Processing Personal Data", "doc_id": "DPDP_SEC_4_SUB_1", "topics": ["consent", "data_processing"], "entities": ["Data Principal", "Data Fiduciary"], "keywords": ["lawful purpose", "consent", "legitimate uses", "processing", "personal data"], "metadata": {"act": "DPDP", "year": 2023, "jurisdiction": "India"}, "references": ["DPDP_SEC_7"], "clause_text": "A person may process the personal data of a Data Principal only in accordance with the provisions of this Act and for a lawful purpose,— (a) for which the Data Principal has given her consent; or (b) for certain legitimate uses.", "source_files": [4], "conflict_notes": [], "retrieval_text": "Section 4 subsection 1 of the Digital Personal Data Protection Act 2023 (DPDP Act). Grounds for Processing Personal Data Personal data may only be processed lawfully, either with the Data Principal's consent or for certain legitimate uses as defined in the Act. Topics: consent, data_processing. Keywords: lawful purpose, consent, legitimate uses, processing, personal data.", "section_number": "4", "subsection_number": "1", "validation_status": "validated", "plain_english_summary": "Personal data may only be processed lawfully, either with the Data Principal's consent or for certain legitimate uses as defined in the Act."}	[1.1746606,1.2332964,-2.7968564,-1.0994891,0.678644,0.022370232,0.17835559,0.01505214,0.23818834,-0.24668887,0.09680716,0.16697244,0.7633993,-1.0222379,-0.53806055,-0.103306174,-0.09350936,-1.0330615,-0.5062196,0.14827897,-0.29106113,-0.0766737,-1.7092252,-0.014378718,1.1853416,-0.7527517,1.3830038,-0.7927588,-0.074147865,-0.6958273,-0.23152262,0.44858766,0.3443211,-0.06537649,-0.9819392,-2.1827369,0.95868856,0.29798016,-0.71721226,-0.32024005,1.2306353,0.027536605,0.4073985,-0.9386121,0.22143479,0.0631604,0.7087269,-0.4166348,0.6259523,-0.33894438,0.58499897,-0.21091804,-0.030272275,-0.54372793,1.5224593,0.83795077,-0.43883523,0.3038283,-0.86112183,-0.94021,2.3084972,1.9