235	{"act": "DPDP", "title": "Notice - Pre-Consent Requirements", "doc_id": "DPDP_SEC_5_SUB_1", "topics": ["consent", "data_processing", "user_rights"], "entities": ["Data Fiduciary", "Data Principal", "Board"], "keywords": ["notice", "consent request", "Data Principal", "rights", "complaint", "purpose"], "metadata": {"act": "DPDP", "year": 2023, "jurisdiction": "India"}, "references": ["DPDP_SEC_6", "DPDP_SEC_13"], "clause_text": "Every request made to a Data Principal under section 6 for consent shall be accompanied or preceded by a notice given by the Data Fiduciary to the Data Principal, informing her,— (i) the personal data and the purpose for which the same is proposed to be processed; (ii) the manner in which she may exercise her rights under sub-section (4) of section 6 and section 13; and (iii) the manner in which the Data Principal may make a complaint to the Board, in such manner and as may be prescribed.", "source_files": [4], "conflict_notes": [], "retrieval_text": "Section 5 subsection 1 of the Digital Personal Data Protection Act 2023 (DPDP Act). Notice - Pre-Consent Requirements Every consent request must be preceded or accompanied by a notice informing the Data Principal of the data to be processed, her rights, and how to complain to the Board. Topics: consent, data_processing, user_rights. Keywords: notice, consent request, Data Principal, rights, complaint, purpose.", "section_number": "5", "subsection_number": "1", "validation_status": "validated", "plain_english_summary": "Every consent request must be preceded or accompanied by a notice informing the Data Principal of the data to be processed, her rights, and how to complain to the Board."}	[0.57405996,1.0725164,-2.8037536,-0.95375854,0.6148499,-0.008524575,0.38216752,0.15767978,0.3709158,0.05688925,-0.054700762,0.7659936,0.6972356,-0.05627784,0.10111723,-0.17773438,-0.2048243,-1.6904227,-0.76983577,0.23434302,0.0021766135,-0.412684,-1.9457856,-0.12977083,1.0646102,-0.28976852,1.3728815,-0.4648