236	{"act": "DPDP", "title": "Notice - Pre-Commencement Consent", "doc_id": "DPDP_SEC_5_SUB_2", "topics": ["compliance", "consent", "data_processing", "user_rights"], "entities": ["Data Fiduciary", "Data Principal", "Board"], "keywords": ["pre-commencement", "notice", "consent", "withdrawal", "Data Fiduciary", "Data Principal"], "metadata": {"act": "DPDP", "year": 2023, "jurisdiction": "India"}, "references": ["DPDP_SEC_6", "DPDP_SEC_13"], "clause_text": "Where a Data Principal has given her consent for the processing of her personal data before the date of commencement of this Act,— (a) the Data Fiduciary shall, as soon as it is reasonably practicable, give to the Data Principal a notice informing her,— (i) the personal data and the purpose for which the same has been processed; (ii) the manner in which she may exercise her rights under sub-section (4) of section 6 and section 13; and (iii) the manner in which the Data Principal may make a complaint to the Board, in such manner and as may be prescribed. (b) the Data Fiduciary may continue to process the personal data until and unless the Data Principal withdraws her consent.", "source_files": [4], "conflict_notes": [], "retrieval_text": "Section 5 subsection 2 of the Digital Personal Data Protection Act 2023 (DPDP Act). Notice - Pre-Commencement Consent Where consent was obtained before the Act's commencement, the Data Fiduciary must issue a notice as soon as practicable and may continue processing until consent is withdrawn. Topics: compliance, consent, data_processing, user_rights. Keywords: pre-commencement, notice, consent, withdrawal, Data Fiduciary, Data Principal.", "section_number": "5", "subsection_number": "2", "validation_status": "validated", "plain_english_summary": "Where consent was obtained before the Act's commencement, the Data Fiduciary must issue a notice as soon as practicable and may continue processing until consent is withdrawn."}	[0.8543091,0.46591175,-2.7312472,-1.2581707,0.37462467,0.2508