238	{"act": "DPDP", "title": "Consent - Requirements", "doc_id": "DPDP_SEC_6_SUB_1", "topics": ["consent", "user_rights"], "entities": ["Data Principal"], "keywords": ["consent", "free", "specific", "informed", "unconditional", "unambiguous", "affirmative action", "specified purpose", "necessity"], "metadata": {"act": "DPDP", "year": 2023, "jurisdiction": "India"}, "references": [], "clause_text": "The consent given by the Data Principal shall be free, specific, informed, unconditional and unambiguous with a clear affirmative action, and shall signify an agreement to the processing of her personal data for the specified purpose and be limited to such personal data as is necessary for such specified purpose.", "source_files": [4], "conflict_notes": [], "retrieval_text": "Section 6 subsection 1 of the Digital Personal Data Protection Act 2023 (DPDP Act). Consent - Requirements Consent must be free, specific, informed, unconditional, unambiguous, given through a clear affirmative action, and limited to personal data necessary for the specified purpose. Topics: consent, user_rights. Keywords: consent, free, specific, informed, unconditional, unambiguous, affirmative action, specified purpose, necessity.", "section_number": "6", "subsection_number": "1", "validation_status": "validated", "plain_english_summary": "Consent must be free, specific, informed, unconditional, unambiguous, given through a clear affirmative action, and limited to personal data necessary for the specified purpose."}	[0.5610397,1.5003934,-2.5587978,-0.8359825,0.8506497,0.8628514,0.13663383,0.14446214,0.6823232,0.6482608,-0.11692973,0.20647214,1.2255318,-0.2167678,0.18611772,-0.05136219,-0.17213069,-1.4640591,-0.1982604,0.57485664,-0.4116068,-0.2711773,-1.9172847,0.04876424,1.2494402,-0.3960022,1.6614476,-0.36948144,-0.5293539,-0.8830244,-0.14425795,0.6974473,0.8864924,0.0055445638,-0.62433064,-1.744608,0.6705151,0.36683998,-0.9737884,-0.16483842,1.0822432,0.37683615,-0.37665197,-0.8315861,0.4188956