239	{"act": "DPDP", "title": "Consent - Invalidity of Non-Compliant Consent", "doc_id": "DPDP_SEC_6_SUB_2", "topics": ["compliance", "consent", "user_rights"], "entities": ["Data Principal"], "keywords": ["invalid consent", "infringement", "partial invalidity"], "metadata": {"act": "DPDP", "year": 2023, "jurisdiction": "India"}, "references": ["DPDP_SEC_6_SUB_1"], "clause_text": "Any part of consent referred in sub-section (1) which constitutes an infringement of the provisions of this Act or the rules made thereunder or any other law for the time being in force shall be invalid to the extent of such infringement.", "source_files": [4], "conflict_notes": [], "retrieval_text": "Section 6 subsection 2 of the Digital Personal Data Protection Act 2023 (DPDP Act). Consent - Invalidity of Non-Compliant Consent Any portion of consent that violates this Act or other applicable laws is invalid to the extent of that violation. Topics: compliance, consent, user_rights. Keywords: invalid consent, infringement, partial invalidity.", "section_number": "6", "subsection_number": "2", "validation_status": "validated", "plain_english_summary": "Any portion of consent that violates this Act or other applicable laws is invalid to the extent of that violation."}	[1.2414448,1.0194006,-2.7277417,-0.65238553,0.82190025,0.87669134,0.060875494,0.4097108,1.2362187,0.16332598,-0.014981216,0.010674267,0.24228922,-0.8477989,-0.235409,-0.22483832,0.01870076,-1.2498978,-0.34322098,0.5857111,-0.3947436,0.016088678,-1.8302298,-0.5725365,1.3766084,-0.33846727,1.5419793,-0.45030218,-0.79216355,-0.5860882,0.11266885,0.5624675,0.5442089,-1.1598788,-1.0317581,-1.141909,0.9623928,-0.06075001,-0.59673774,0.28545523,0.79003555,0.28529567,0.22862326,-0.8609583,0.14463478,-0.2921965,0.51731044,0.3441068,0.4801958,-0.6999459,0.80561423,-0.46127683,0.3125556,-0.55011696,0.7842348,0.900238,-1.1322322,-0.43908134,-0.8892191,-1.2475946,1.4493978,1.5986136,-0.35008687,1.520331,0.59811896,-0.4982934,-1.023477,0.5700