240	{"act": "DPDP", "title": "Consent - Plain Language and Contact Details", "doc_id": "DPDP_SEC_6_SUB_3", "topics": ["compliance", "consent", "user_rights"], "entities": ["Data Principal", "Data Fiduciary", "Data Protection Officer"], "keywords": ["plain language", "consent request", "language", "Eighth Schedule", "Data Protection Officer", "contact details"], "metadata": {"act": "DPDP", "year": 2023, "jurisdiction": "India"}, "references": [], "clause_text": "Every request for consent under the provisions of this Act or the rules made thereunder shall be presented to the Data Principal in a clear and plain language, giving her the option to access such request in English or any language specified in the Eighth Schedule to the Constitution and providing the contact details of a Data Protection Officer, where applicable, or of any other person authorised by the Data Fiduciary to respond to any communication from the Data Principal for the purpose of exercise of her rights under the provisions of this Act.", "source_files": [4], "conflict_notes": [], "retrieval_text": "Section 6 subsection 3 of the Digital Personal Data Protection Act 2023 (DPDP Act). Consent - Plain Language and Contact Details Consent requests must be in plain language, available in scheduled languages, and include contact details of the Data Protection Officer or authorised representative. Topics: compliance, consent, user_rights. Keywords: plain language, consent request, language, Eighth Schedule, Data Protection Officer, contact details.", "section_number": "6", "subsection_number": "3", "validation_status": "validated", "plain_english_summary": "Consent requests must be in plain language, available in scheduled languages, and include contact details of the Data Protection Officer or authorised representative."}	[0.55047137,0.7270899,-2.8129013,-1.310198,0.6265281,0.17431708,-0.33209023,-0.044255074,0.77985954,0.07847134,-0.31902954,0.07961135,0.6404303,-0.818159,0.008577676,-0.4019416,0.050412