241	{"act": "DPDP", "title": "Consent - Right to Withdraw", "doc_id": "DPDP_SEC_6_SUB_4", "topics": ["consent", "user_rights"], "entities": ["Data Principal"], "keywords": ["consent withdrawal", "right to withdraw", "ease of withdrawal", "Data Principal"], "metadata": {"act": "DPDP", "year": 2023, "jurisdiction": "India"}, "references": [], "clause_text": "Where consent given by the Data Principal is the basis of processing of personal data, such Data Principal shall have the right to withdraw her consent at any time, with the ease of doing so being comparable to the ease with which such consent was given.", "source_files": [4], "conflict_notes": [], "retrieval_text": "Section 6 subsection 4 of the Digital Personal Data Protection Act 2023 (DPDP Act). Consent - Right to Withdraw A Data Principal can withdraw consent at any time, and the withdrawal process must be as easy as the process of giving consent. Topics: consent, user_rights. Keywords: consent withdrawal, right to withdraw, ease of withdrawal, Data Principal.", "section_number": "6", "subsection_number": "4", "validation_status": "validated", "plain_english_summary": "A Data Principal can withdraw consent at any time, and the withdrawal process must be as easy as the process of giving consent."}	[1.1844792,1.316431,-2.632108,-0.98196614,0.6219244,0.4374179,0.51652974,0.46678758,0.7683368,0.40417394,-0.22333428,-0.055622168,0.29284588,-1.0067179,0.68902874,-0.26081043,-0.11217317,-1.8349447,-0.82207155,0.08073168,-0.5138055,-0.29678455,-1.5248209,-0.5751379,1.5433226,-0.4608839,1.0351696,-0.75908047,-0.30744207,-0.32636434,0.38846862,0.5059073,0.6438693,-0.11596546,-1.3084041,-1.2410321,0.67208743,0.6373043,-1.2116128,-0.53275025,0.8947896,0.019371476,0.65804505,-0.49174502,0.7995116,-0.2368031,0.38585794,-0.5880205,0.65261567,-0.33588022,0.85232556,-0.66380656,-0.18757416,-0.4061224,0.410063,0.26409978,-0.21383359,-0.084872924,-0.32845226,-1.4769201,1.9142745,1.327526,-1.1665726,1.561997,0.9110587,-0.2617686