242	{"act": "DPDP", "title": "Consent - Consequences of Withdrawal", "doc_id": "DPDP_SEC_6_SUB_5", "topics": ["consent", "data_processing", "user_rights"], "entities": ["Data Principal"], "keywords": ["consent withdrawal", "consequences", "legality", "prior processing"], "metadata": {"act": "DPDP", "year": 2023, "jurisdiction": "India"}, "references": ["DPDP_SEC_6_SUB_4"], "clause_text": "The consequences of the withdrawal referred to in sub-section (4) shall be borne by the Data Principal, and such withdrawal shall not affect the legality of processing of the personal data based on consent before its withdrawal.", "source_files": [4], "conflict_notes": [], "retrieval_text": "Section 6 subsection 5 of the Digital Personal Data Protection Act 2023 (DPDP Act). Consent - Consequences of Withdrawal Withdrawal of consent does not retroactively invalidate previous processing; the Data Principal bears the consequences of withdrawal. Topics: consent, data_processing, user_rights. Keywords: consent withdrawal, consequences, legality, prior processing.", "section_number": "6", "subsection_number": "5", "validation_status": "validated", "plain_english_summary": "Withdrawal of consent does not retroactively invalidate previous processing; the Data Principal bears the consequences of withdrawal."}	[1.7690045,0.8118464,-2.349191,-1.0958204,0.6045895,0.61398077,0.45944312,0.52568394,0.9924904,0.19451846,-0.5439345,0.4007995,0.77777785,-0.69332886,0.44267896,-0.51986057,-0.13762447,-1.2621251,-0.6888828,0.3065192,-0.2593736,0.33609763,-1.8637221,-0.59412175,0.7916021,-0.3543326,1.5306879,-0.7230431,-0.79944134,-0.25567743,0.78117746,0.7049633,0.20899117,-0.6041223,-1.521129,-1.2232332,1.1010897,0.33771393,-0.9785504,-0.5707329,1.0420467,0.23198819,0.747313,-0.74549365,0.37254602,-0.06548992,0.8495472,-0.1667117,0.57105356,-0.20668001,1.0293878,-0.10036066,-0.16136758,-0.29707885,0.5546959,0.40138778,-0.3430614,-0.25744432,-0.38801423,-1.3333564,1.4952058,1.3165615,-0.85179204,1.408