243	{"act": "DPDP", "title": "Consent - Cessation of Processing Post-Withdrawal", "doc_id": "DPDP_SEC_6_SUB_6", "topics": ["consent", "data_processing", "data_retention", "user_rights"], "entities": ["Data Fiduciary", "Data Principal", "Data Processor"], "keywords": ["consent withdrawal", "cessation", "Data Fiduciary", "Data Processor", "reasonable time"], "metadata": {"act": "DPDP", "year": 2023, "jurisdiction": "India"}, "references": ["DPDP_SEC_6_SUB_5"], "clause_text": "If a Data Principal withdraws her consent to the processing of personal data under sub-section (5), the Data Fiduciary shall, within a reasonable time, cease and cause its Data Processors to cease processing the personal data of such Data Principal unless such processing without her consent is required or authorised under the provisions of this Act or the rules made thereunder or any other law for the time being in force in India.", "source_files": [4], "conflict_notes": [], "retrieval_text": "Section 6 subsection 6 of the Digital Personal Data Protection Act 2023 (DPDP Act). Consent - Cessation of Processing Post-Withdrawal Upon consent withdrawal, the Data Fiduciary must stop and ensure its Data Processors stop processing the Data Principal's data within a reasonable time, unless processing is otherwise legally authorised. Topics: consent, data_processing, data_retention, user_rights. Keywords: consent withdrawal, cessation, Data Fiduciary, Data Processor, reasonable time.", "section_number": "6", "subsection_number": "6", "validation_status": "validated", "plain_english_summary": "Upon consent withdrawal, the Data Fiduciary must stop and ensure its Data Processors stop processing the Data Principal's data within a reasonable time, unless processing is otherwise legally authorised."}	[1.6617707,0.9467315,-2.624392,-1.1558055,0.6518945,0.08646596,0.5087337,0.59722227,0.5423526,0.2918235,-0.51457554,0.35464033,0.5046911,-0.7565157,0.49260598,-0.28180107,-0.10628001,-1.3278164,-1.0702673,0.5401151