245	{"act": "DPDP", "title": "Consent Manager - Accountability", "doc_id": "DPDP_SEC_6_SUB_8", "topics": ["compliance", "consent", "user_rights"], "entities": ["Consent Manager", "Data Principal"], "keywords": ["Consent Manager", "accountability", "Data Principal", "obligations"], "metadata": {"act": "DPDP", "year": 2023, "jurisdiction": "India"}, "references": [], "clause_text": "The Consent Manager shall be accountable to the Data Principal and shall act on her behalf in such manner and subject to such obligations as may be prescribed.", "source_files": [4], "conflict_notes": [], "retrieval_text": "Section 6 subsection 8 of the Digital Personal Data Protection Act 2023 (DPDP Act). Consent Manager - Accountability A Consent Manager is accountable to the Data Principal and must act on the Data Principal's behalf as prescribed. Topics: compliance, consent, user_rights. Keywords: Consent Manager, accountability, Data Principal, obligations.", "section_number": "6", "subsection_number": "8", "validation_status": "validated", "plain_english_summary": "A Consent Manager is accountable to the Data Principal and must act on the Data Principal's behalf as prescribed."}	[0.6002336,0.7111757,-2.9125745,-0.8188456,0.76330817,0.25722343,0.4990641,-0.08396656,1.0536498,0.43538833,-0.24274981,-0.06584179,0.8686281,-0.27720794,0.52130926,-0.039532196,0.35312262,-1.3084749,-0.56621623,-0.018707596,-0.002837203,-0.8158292,-1.5960367,-0.22298743,1.6624904,0.17223224,1.2371057,-0.68673295,0.06527865,-0.39034683,0.38295028,0.87094283,0.31361318,-1.0173558,-0.78672326,-1.4620407,0.516331,0.76972,-0.8330939,-0.11829448,0.5262637,-0.33537883,-0.357092,-0.9022341,0.29384577,-0.36958563,0.043635517,-0.33975774,0.83382237,0.0932764,0.48208672,-0.49924776,0.49938777,-0.0363861,0.8276688,0.41274577,0.006410043,-0.13051027,-0.91441476,-1.4809958,2.0914006,1.2286016,-0.502096,1.6704468,1.0173862,0.011616588,-0.52881277,1.037287,-0.46883112,-1.0000135,0.7993445,0.8592366,0.21444297,0.34216776,0.3