247	{"act": "DPDP", "title": "Consent - Burden of Proof", "doc_id": "DPDP_SEC_6_SUB_10", "topics": ["compliance", "consent"], "entities": ["Data Fiduciary", "Data Principal"], "keywords": ["burden of proof", "consent", "proceeding", "notice", "Data Fiduciary"], "metadata": {"act": "DPDP", "year": 2023, "jurisdiction": "India"}, "references": [], "clause_text": "Where a consent given by the Data Principal is the basis of processing of personal data and a question arises in this regard in a proceeding, the Data Fiduciary shall be obliged to prove that a notice was given by her to the Data Principal and consent was given by such Data Principal to the Data Fiduciary in accordance with the provisions of this Act and the rules made thereunder.", "source_files": [4], "conflict_notes": [], "retrieval_text": "Section 6 subsection 10 of the Digital Personal Data Protection Act 2023 (DPDP Act). Consent - Burden of Proof In any proceeding, the burden of proof lies with the Data Fiduciary to demonstrate that valid notice was given and consent was properly obtained. Topics: compliance, consent. Keywords: burden of proof, consent, proceeding, notice, Data Fiduciary.", "section_number": "6", "subsection_number": "10", "validation_status": "validated", "plain_english_summary": "In any proceeding, the burden of proof lies with the Data Fiduciary to demonstrate that valid notice was given and consent was properly obtained."}	[1.4923819,1.2734938,-2.953349,-1.4515591,0.9242622,0.117984764,0.73939705,0.22139674,0.7536374,0.6316407,-0.15453433,0.012614295,0.8784342,0.04339918,0.53287226,-0.2621099,0.37446633,-1.6800414,-0.42078838,0.31807283,-0.3723142,0.3692751,-2.2413685,-0.41412035,1.1424258,-0.5214103,1.1329455,-0.63782495,-0.08498787,-1.0193648,0.18728597,0.45765674,0.4370929,-1.1045369,-1.1147043,-1.9582931,0.70928365,0.7432324,-0.85206693,-0.24857615,1.2543153,0.12673983,-0.5760394,-0.66228867,-0.36844343,0.25357234,0.5421462,-0.2055662,0.4436579,-0.4927102,0.37577865,-0.4777625,0