248	{"act": "DPDP", "title": "Certain Legitimate Uses", "doc_id": "DPDP_SEC_7", "topics": ["compliance", "data_processing"], "entities": ["Data Fiduciary", "Data Principal", "State"], "keywords": ["legitimate uses", "voluntary", "State", "legal obligation", "medical emergency", "public health", "disaster", "employment", "processing"], "metadata": {"act": "DPDP", "year": 2023, "jurisdiction": "India"}, "references": [], "clause_text": "A Data Fiduciary may process personal data of a Data Principal for any of following uses, namely:— (a) for the specified purpose for which the Data Principal has voluntarily provided her personal data to the Data Fiduciary, and in respect of which she has not indicated to the Data Fiduciary that she does not consent to the use of her personal data. (b) for the State and any of its instrumentalities to provide or issue to the Data Principal such subsidy, benefit, service, certificate, licence or permit as may be prescribed... (c) for the performance by the State or any of its instrumentalities of any function under any law for the time being in force in India or in the interest of sovereignty and integrity of India or security of the State; (d) for fulfilling any obligation under any law for the time being in force in India on any person to disclose any information to the State or any of its instrumentalities...; (e) for compliance with any judgment or decree or order...; (f) for responding to a medical emergency involving a threat to the life or immediate threat to the health of the Data Principal or any other individual; (g) for taking measures to provide medical treatment or health services to any individual during an epidemic, outbreak of disease, or any other threat to public health; (h) for taking measures to ensure safety of, or provide assistance or services to, any individual during any disaster...; or (i) for the purposes of employment or those related to safeguarding the employer from loss or liability, such as prevention of corporate espionage, maintenance of confidentiality of trade secrets, intellectual property, classified information or provision of any service or benefit sought by a Data Principal who is an employee.", "source_files": [4], "conflict_notes": [], "retrieval_text": "Section 7 of the Digital Personal Data Protection Act 2023 (DPDP Act). Certain Legitimate Uses Lists specific legitimate purposes for which a Data Fiduciary may process personal data without explicit consent, including voluntary provision, State functions, legal obligations, medical emergencies, public health, disaster management, and employment. Topics: compliance, data_processing. Keywords: legitimate uses, voluntary, State, legal obligation, medical emergency, public health, disaster, employment, processing.", "section_number": "7", "subsection_number": null, "validation_status": "validated", "plain_english_summary": "Lists specific legitimate purposes for which a Data Fiduciary may process personal data without explicit consent, including voluntary provision, State functions, legal obligations, medical emergencies, public health, disaster management, and employment."}	[0.8083257,1.1256646,-3.441655,-0.969444,0.877063,-0.46449724,-0.0849622,0.43481398,0.8709417,-0.267528,-0.36042634,-0.056337774,1.1803179,-0.67642677,-0.2576241,-0.17123093,-0.5148854,-0.7345732,-0.73945475,0.22080055,-0.54968643,-0.11244229,-1.1967776,0.29529646,0.91723984,-0.5017378,1.7131844,-0.2786276,-0.08403642,-1.019592,-0.26816726,0.32637694,0.590975,-0.39866772,-0.81332284,-1.5836471,0.5962708,0.74150497,0.26905212,-0.08677908,0.36567447,0.19499412,0.4526896,-0.9435245,0.2774728,0.35399297,0.68159026,0.12373835,0.24125774,-0.7318438,0.7218342,-0.45899442,0.26281506,-0.060081188,1.5645031,0.22589953,-0.5218498,0.3614556,-1.0304729,-0.7457898,1.8777649,1.7375683,-0.33414438,0.9592146,1.0659964,-0.2342148,-0.5864087,0.45802155,0.13962562,-0.23354502,1.047361,-0.0029739263,0.167613,0.10512738,0.10892622,-0.4035924,-0.8725681,-0.534