249	{"act": "DPDP", "title": "General Obligations - Data Fiduciary Responsibility", "doc_id": "DPDP_SEC_8_SUB_1", "topics": ["compliance", "data_processing"], "entities": ["Data Fiduciary", "Data Principal", "Data Processor"], "keywords": ["Data Fiduciary", "responsibility", "compliance", "Data Processor"], "metadata": {"act": "DPDP", "year": 2023, "jurisdiction": "India"}, "references": [], "clause_text": "A Data Fiduciary shall, irrespective of any agreement to the contrary or failure of a Data Principal to carry out the duties provided under this Act, be responsible for complying with the provisions of this Act and the rules made thereunder in respect of any processing undertaken by it or on its behalf by a Data Processor.", "source_files": [4], "conflict_notes": [], "retrieval_text": "Section 8 subsection 1 of the Digital Personal Data Protection Act 2023 (DPDP Act). General Obligations - Data Fiduciary Responsibility The Data Fiduciary remains responsible for compliance with the Act regardless of any contrary agreement or the Data Principal's failure to fulfil duties. Topics: compliance, data_processing. Keywords: Data Fiduciary, responsibility, compliance, Data Processor.", "section_number": "8", "subsection_number": "1", "validation_status": "validated", "plain_english_summary": "The Data Fiduciary remains responsible for compliance with the Act regardless of any contrary agreement or the Data Principal's failure to fulfil duties."}	[0.65669537,0.8071349,-3.059384,-1.4367857,0.80774295,-0.16763276,0.6522883,-0.16076054,0.45593625,0.046990197,-0.47676805,0.12833504,0.7524921,-0.37406817,0.1055895,0.45199773,0.046669785,-0.8082402,-0.7054888,0.40406483,-0.11690591,0.047799658,-1.6538489,-0.35125947,1.1995015,-0.35376585,1.1818856,-1.2930515,-0.38968572,-0.5562565,0.25814235,0.5314045,0.18303894,-1.1922039,-0.97520363,-1.6682496,0.75261205,1.081785,0.14204943,0.07316909,-0.0843873,-0.068384014,-0.062454253,-0.8349674,0.45039186,-0.07053113,0.6140977,-0.25076976,