250	{"act": "DPDP", "title": "General Obligations - Data Processor Contract", "doc_id": "DPDP_SEC_8_SUB_2", "topics": ["compliance", "data_processing"], "entities": ["Data Fiduciary", "Data Processor"], "keywords": ["Data Processor", "valid contract", "Data Fiduciary", "engagement", "goods and services"], "metadata": {"act": "DPDP", "year": 2023, "jurisdiction": "India"}, "references": [], "clause_text": "A Data Fiduciary may engage, appoint, use or otherwise involve a Data Processor to process personal data on its behalf for any activity related to offering of goods or services to Data Principals only under a valid contract.", "source_files": [4], "conflict_notes": [], "retrieval_text": "Section 8 subsection 2 of the Digital Personal Data Protection Act 2023 (DPDP Act). General Obligations - Data Processor Contract A Data Fiduciary may only engage a Data Processor to process personal data under a valid contract. Topics: compliance, data_processing. Keywords: Data Processor, valid contract, Data Fiduciary, engagement, goods and services.", "section_number": "8", "subsection_number": "2", "validation_status": "validated", "plain_english_summary": "A Data Fiduciary may only engage a Data Processor to process personal data under a valid contract."}	[0.33102807,1.1076771,-3.112065,-1.2083025,1.0353401,-0.3493024,0.25105047,-0.07450748,0.38141,-0.09993598,-0.61781555,0.59462756,0.60157716,-1.1372354,-0.055037785,0.41543558,-0.15664244,-1.0749022,-0.68508196,0.6949326,-0.111640036,-0.56628805,-1.2818251,-0.53578347,0.9301404,-0.62458855,1.1065141,-0.75824714,-0.49028736,-0.4116964,0.059262235,0.3021601,0.6113247,-0.9335956,-1.0637181,-1.8058634,0.89086586,0.45183718,-0.1385018,0.00646549,0.42426834,-0.09505303,0.12380523,-0.7878901,0.8623595,0.106243394,0.56129664,-0.46557197,0.35683703,-0.5012485,0.47758394,-0.1915238,0.40679443,-0.06660107,0.9986191,0.90906006,-0.9706868,0.9170332,-1.2586812,-0.7065185,1.6726264,2.0734758,-0.35486683,1.3877864,0.72859776,-0.8023369,-0.7