251	{"act": "DPDP", "title": "General Obligations - Data Accuracy", "doc_id": "DPDP_SEC_8_SUB_3", "topics": ["compliance", "data_processing"], "entities": ["Data Fiduciary", "Data Principal"], "keywords": ["data accuracy", "completeness", "consistency", "decision-making", "Data Fiduciary"], "metadata": {"act": "DPDP", "year": 2023, "jurisdiction": "India"}, "references": [], "clause_text": "Where personal data processed by a Data Fiduciary is likely to be— (a) used to make a decision that affects the Data Principal; or (b) disclosed to another Data Fiduciary, the Data Fiduciary processing such personal data shall ensure its completeness, accuracy and consistency.", "source_files": [4], "conflict_notes": [], "retrieval_text": "Section 8 subsection 3 of the Digital Personal Data Protection Act 2023 (DPDP Act). General Obligations - Data Accuracy When personal data will be used for decisions affecting the Data Principal or shared with another Data Fiduciary, the processing Data Fiduciary must ensure data is complete, accurate, and consistent. Topics: compliance, data_processing. Keywords: data accuracy, completeness, consistency, decision-making, Data Fiduciary.", "section_number": "8", "subsection_number": "3", "validation_status": "validated", "plain_english_summary": "When personal data will be used for decisions affecting the Data Principal or shared with another Data Fiduciary, the processing Data Fiduciary must ensure data is complete, accurate, and consistent."}	[1.0090883,0.32718468,-3.247671,-1.1752837,1.3104563,0.11840163,0.6687165,-0.13110809,0.09515576,0.24983016,-0.081715465,0.07331626,0.8521507,-0.6040905,-0.44966286,0.09336449,-0.24496187,-1.3222345,-0.45701516,0.79677683,0.2942742,0.289844,-1.6169679,-0.55245477,0.94102526,-0.30921495,1.0136639,-0.95825714,-0.25818273,-0.6771538,0.17912985,0.5178505,0.37209007,-0.9910475,-1.025225,-1.3095927,0.7906045,0.75667644,0.61971086,0.0653816,0.3719104,0.28295168,0.018079959,-0.80890846,0.60393196,0.18258594,0.57