253	{"act": "DPDP", "title": "General Obligations - Security Safeguards", "doc_id": "DPDP_SEC_8_SUB_5", "topics": ["breach_reporting", "security"], "entities": ["Data Fiduciary", "Data Processor"], "keywords": ["security safeguards", "personal data breach", "Data Fiduciary", "Data Processor", "protection"], "metadata": {"act": "DPDP", "year": 2023, "jurisdiction": "India"}, "references": [], "clause_text": "A Data Fiduciary shall protect personal data in its possession or under its control, including in respect of any processing undertaken by it or on its behalf by a Data Processor, by taking reasonable security safeguards to prevent personal data breach.", "source_files": [4], "conflict_notes": [], "retrieval_text": "Section 8 subsection 5 of the Digital Personal Data Protection Act 2023 (DPDP Act). General Obligations - Security Safeguards Data Fiduciaries must take reasonable security safeguards to protect personal data in their possession or control from breaches. Topics: breach_reporting, security. Keywords: security safeguards, personal data breach, Data Fiduciary, Data Processor, protection.", "section_number": "8", "subsection_number": "5", "validation_status": "validated", "plain_english_summary": "Data Fiduciaries must take reasonable security safeguards to protect personal data in their possession or control from breaches."}	[0.5384652,1.0117587,-3.2665024,-1.2793356,1.1122574,-0.24736969,0.15710461,-0.07302707,0.51390874,-0.6014621,-0.8693612,0.2303847,0.21256112,-0.7480402,-0.076611765,0.053947017,0.037541997,-0.8371189,-0.32351238,0.1385478,-0.20081016,-0.43881026,-1.6425526,0.05238367,1.264063,0.24350418,1.4568973,-1.0272611,-0.27692607,-0.4616295,0.33522484,0.14333913,-0.13708335,-0.7478807,-0.7922173,-1.8760641,0.4766068,1.1926074,-0.9996966,-0.2928613,0.9637614,0.4803833,0.22332686,-0.8964132,0.20850042,0.3267695,0.48258984,-0.7798507,0.7937992,-0.26685405,0.20333727,-0.2557084,0.91718197,-0.4251353,1.0660121,0.067458786,-0.465964,-0.13771425,-0.58