254	{"act": "DPDP", "title": "General Obligations - Breach Notification", "doc_id": "DPDP_SEC_8_SUB_6", "topics": ["breach_reporting", "security"], "entities": ["Data Fiduciary", "Board", "Data Principal"], "keywords": ["personal data breach", "notification", "Board", "Data Principal", "intimation"], "metadata": {"act": "DPDP", "year": 2023, "jurisdiction": "India"}, "references": [], "clause_text": "In the event of a personal data breach, the Data Fiduciary shall give the Board and each affected Data Principal, intimation of such breach in such form and manner as may be prescribed.", "source_files": [4], "conflict_notes": [], "retrieval_text": "Section 8 subsection 6 of the Digital Personal Data Protection Act 2023 (DPDP Act). General Obligations - Breach Notification In the event of a personal data breach, the Data Fiduciary must notify both the Board and all affected Data Principals in the prescribed form. Topics: breach_reporting, security. Keywords: personal data breach, notification, Board, Data Principal, intimation.", "section_number": "8", "subsection_number": "6", "validation_status": "validated", "plain_english_summary": "In the event of a personal data breach, the Data Fiduciary must notify both the Board and all affected Data Principals in the prescribed form."}	[0.63515925,0.56544876,-3.1997972,-1.0925486,1.0157641,-0.4314036,0.3890779,0.10565437,0.6527113,-0.57967687,-0.80216914,0.6983877,0.7169091,-0.25296497,0.121793926,-0.40449998,0.0095205335,-1.4719293,-0.53849655,0.21240613,-0.1958992,-0.33184943,-1.4664406,0.46519694,1.2366034,0.20037189,1.4661515,-0.5019312,0.089587264,-0.36909717,-0.012091831,0.4316819,-0.52534974,-1.0480385,-1.2203082,-1.2796029,0.07225978,0.5232109,-0.9792771,-0.5040015,0.90976626,-0.09433652,-0.07964725,-1.0471876,0.035972472,0.0878114,0.2117866,-0.31479073,1.0761806,0.18918966,0.18266268,-0.85824263,0.7814574,-0.51259905,0.82643044,0.45888403,-0.17332192,-0.27606013,-0.5947889,-1.2379329,1.6900443,2.0373013,-0.2902591,0.6