255	{"act": "DPDP", "title": "General Obligations - Data Erasure", "doc_id": "DPDP_SEC_8_SUB_7", "topics": ["consent", "data_retention"], "entities": ["Data Fiduciary", "Data Principal", "Data Processor"], "keywords": ["erasure", "deletion", "data retention", "specified purpose", "consent withdrawal", "Data Processor"], "metadata": {"act": "DPDP", "year": 2023, "jurisdiction": "India"}, "references": [], "clause_text": "A Data Fiduciary shall, unless retention is necessary for compliance with any law for the time being in force,— (a) erase personal data, upon the Data Principal withdrawing her consent or as soon as it is reasonable to assume that the specified purpose is no longer being served, whichever is earlier; and (b) cause its Data Processor to erase any personal data that was made available by the Data Fiduciary for processing to such Data Processor.", "source_files": [4], "conflict_notes": [], "retrieval_text": "Section 8 subsection 7 of the Digital Personal Data Protection Act 2023 (DPDP Act). General Obligations - Data Erasure Data Fiduciaries must erase personal data once the specified purpose is no longer served or consent is withdrawn, and must direct Data Processors to do the same, unless law requires retention. Topics: consent, data_retention. Keywords: erasure, deletion, data retention, specified purpose, consent withdrawal, Data Processor.", "section_number": "8", "subsection_number": "7", "validation_status": "validated", "plain_english_summary": "Data Fiduciaries must erase personal data once the specified purpose is no longer served or consent is withdrawn, and must direct Data Processors to do the same, unless law requires retention."}	[1.4352604,0.9426651,-2.6569688,-1.52782,1.2941626,0.2836041,-0.10574688,0.4813061,0.46557197,0.61216956,-0.8742977,0.7773867,0.64878047,-0.3724816,0.0074211094,-0.031093445,-0.5395127,-0.91665477,-0.5489389,0.5896847,0.19133246,-0.19696596,-1.3086369,-0.41262257,1.0027128,-0.37530676,1.5536414,-0.8909975,-0.3455