256	{"act": "DPDP", "title": "General Obligations - Deemed Purpose Completion", "doc_id": "DPDP_SEC_8_SUB_8", "topics": ["data_retention"], "entities": ["Data Fiduciary", "Data Principal"], "keywords": ["deemed purpose", "inactivity", "retention period", "Data Fiduciary", "Data Principal", "rights"], "metadata": {"act": "DPDP", "year": 2023, "jurisdiction": "India"}, "references": ["DPDP_SEC_8_SUB_7"], "clause_text": "The purpose referred to in clause (a) of sub-section (7) shall be deemed to no longer be served, if the Data Principal does not— (a) approach the Data Fiduciary for the performance of the specified purpose; and (b) exercise any of her rights in relation to such processing, for such time period as may be prescribed, and different time periods may be prescribed for different classes of Data Fiduciaries and for different purposes.", "source_files": [4], "conflict_notes": [], "retrieval_text": "Section 8 subsection 8 of the Digital Personal Data Protection Act 2023 (DPDP Act). General Obligations - Deemed Purpose Completion The specified purpose is deemed no longer served if the Data Principal does not contact the Data Fiduciary or exercise any rights for a prescribed time period. Topics: data_retention. Keywords: deemed purpose, inactivity, retention period, Data Fiduciary, Data Principal, rights.", "section_number": "8", "subsection_number": "8", "validation_status": "validated", "plain_english_summary": "The specified purpose is deemed no longer served if the Data Principal does not contact the Data Fiduciary or exercise any rights for a prescribed time period."}	[0.95048404,0.3621907,-3.182534,-1.8614656,0.86807853,0.22794649,0.57617927,-0.23331451,0.5532257,0.08073587,-0.80459034,0.7343422,0.72718143,-0.4459747,0.13240926,-0.13607998,-0.1519235,-0.9309399,-1.2851756,0.37317196,0.3305675,-0.25567967,-1.0182679,-0.2313624,0.77356935,0.11418103,1.644237,-0.70555013,-0.09162089,-0.17915712,0.1445591,0.61406535,0.44095045,-0.38046107,-0.9257675,-1.6125598,