257	{"act": "DPDP", "title": "General Obligations - Publishing DPO Contact", "doc_id": "DPDP_SEC_8_SUB_9", "topics": ["compliance", "governance", "grievance_redressal", "user_rights"], "entities": ["Data Fiduciary", "Data Protection Officer", "Data Principal"], "keywords": ["Data Protection Officer", "contact information", "publication", "Data Principal", "queries"], "metadata": {"act": "DPDP", "year": 2023, "jurisdiction": "India"}, "references": [], "clause_text": "A Data Fiduciary shall publish, in such manner as may be prescribed, the business contact information of a Data Protection Officer, if applicable, or a person who is able to answer on behalf of the Data Fiduciary, the questions, if any, raised by the Data Principal about the processing of her personal data.", "source_files": [4], "conflict_notes": [], "retrieval_text": "Section 8 subsection 9 of the Digital Personal Data Protection Act 2023 (DPDP Act). General Obligations - Publishing DPO Contact Data Fiduciaries must publicly publish contact information for a Data Protection Officer or designated representative for Data Principal queries. Topics: compliance, governance, grievance_redressal, user_rights. Keywords: Data Protection Officer, contact information, publication, Data Principal, queries.", "section_number": "8", "subsection_number": "9", "validation_status": "validated", "plain_english_summary": "Data Fiduciaries must publicly publish contact information for a Data Protection Officer or designated representative for Data Principal queries."}	[0.33471856,0.61359465,-3.1586287,-1.2403362,1.0152484,0.12791963,0.20874439,-0.26672295,0.63108194,0.0049103512,-0.06914154,-0.034025237,0.42948806,-1.281066,-0.27261198,-0.246074,-0.01024256,-1.6357752,-1.1819638,-0.27037734,-0.23195142,-0.79109234,-1.6572788,-0.15281463,1.4753488,0.05920502,1.3299941,-1.2219336,-0.29144734,-0.5991212,-0.19402896,0.90376407,0.11102569,-0.23593237,-0.8129848,-1.1892276,0.6512742,0.6510484,-0.48260042,0.01879121,1.4329638,-