259	{"act": "DPDP", "title": "Processing of Children's Data - Parental Consent", "doc_id": "DPDP_SEC_9_SUB_1", "topics": ["children_data", "consent"], "entities": ["Data Fiduciary", "Data Principal"], "keywords": ["child", "disability", "parental consent", "verifiable consent", "guardian", "Data Fiduciary"], "metadata": {"act": "DPDP", "year": 2023, "jurisdiction": "India"}, "references": [], "clause_text": "The Data Fiduciary shall, before processing any personal data of a child or a person with disability who has a lawful guardian obtain verifiable consent of the parent of such child or the lawful guardian, as the case may be, in such manner as may be prescribed.", "source_files": [4], "conflict_notes": [], "retrieval_text": "Section 9 subsection 1 of the Digital Personal Data Protection Act 2023 (DPDP Act). Processing of Children's Data - Parental Consent Data Fiduciaries must obtain verifiable parental or guardian consent before processing personal data of a child or a person with disability. Topics: children_data, consent. Keywords: child, disability, parental consent, verifiable consent, guardian, Data Fiduciary.", "section_number": "9", "subsection_number": "1", "validation_status": "validated", "plain_english_summary": "Data Fiduciaries must obtain verifiable parental or guardian consent before processing personal data of a child or a person with disability."}	[1.1783779,0.8213802,-2.6491854,-1.4460179,0.48350522,0.65091133,0.048238896,0.13690002,0.5423723,-0.21257874,-0.5637589,0.033199735,1.1578355,-0.47102404,-0.51703584,-0.13583425,-0.768389,-1.1676666,-0.37431526,0.3631902,-0.48670843,0.19462831,-2.1589484,0.35915908,1.9753004,-0.366326,0.96631175,-0.80968535,-0.38283467,-0.49180487,0.18284737,0.6336526,0.37715667,-0.44271305,-1.0798494,-1.8635913,1.2361752,0.6394539,-0.9894058,0.07258792,0.8002524,0.4517643,-0.28117064,-1.0855545,-0.2996569,-0.266778,0.85470474,-0.3582408,0.8303434,-0.44555795,0.50534385,-0.19735475,0.5609695,-0.30872732,1.2112622,0.60