260	{"act": "DPDP", "title": "Processing of Children's Data - Prohibition on Detrimental Processing", "doc_id": "DPDP_SEC_9_SUB_2", "topics": ["children_data", "compliance"], "entities": ["Data Fiduciary"], "keywords": ["child", "detrimental effect", "well-being", "prohibition", "Data Fiduciary"], "metadata": {"act": "DPDP", "year": 2023, "jurisdiction": "India"}, "references": [], "clause_text": "A Data Fiduciary shall not undertake such processing of personal data that is likely to cause any detrimental effect on the well-being of a child.", "source_files": [4], "conflict_notes": [], "retrieval_text": "Section 9 subsection 2 of the Digital Personal Data Protection Act 2023 (DPDP Act). Processing of Children's Data - Prohibition on Detrimental Processing Data Fiduciaries are prohibited from processing personal data in ways that are likely to harm a child's well-being. Topics: children_data, compliance. Keywords: child, detrimental effect, well-being, prohibition, Data Fiduciary.", "section_number": "9", "subsection_number": "2", "validation_status": "validated", "plain_english_summary": "Data Fiduciaries are prohibited from processing personal data in ways that are likely to harm a child's well-being."}	[1.0806772,0.9935307,-2.711391,-1.76225,0.17510039,0.5621682,0.380654,-0.037586696,0.08512723,-0.57116485,-0.49658394,0.27730843,1.1154164,-0.5240997,-0.4709519,-0.16435105,-0.74812436,-0.3141646,-0.59578055,0.47388452,-0.027764972,0.26560536,-1.7174413,-0.054753806,1.30178,0.19373171,1.2891619,-0.99017304,-0.08393164,-0.03330623,0.30866668,0.36176056,-0.16412923,-0.7091037,-1.6849746,-1.2228427,1.556396,0.94459987,-0.00453426,-0.042113435,0.7614994,0.63339573,0.3165436,-1.2809405,-0.680887,-0.3415527,0.6978768,-0.15171224,0.99548817,-0.9496719,1.0207034,-0.7678504,0.6125512,-0.31720972,1.5431908,0.45438442,-0.5099679,-0.21293284,-1.2167361,-0.6854045,2.1413305,1.7977246,-1.3115144,1.092144,0.9697944,-0.61823595,-1.0628796,0.46432644,-0.3581292,-0.04247344,1.4384964