261	{"act": "DPDP", "title": "Processing of Children's Data - Prohibition on Tracking and Targeted Advertising", "doc_id": "DPDP_SEC_9_SUB_3", "topics": ["children_data", "compliance"], "entities": ["Data Fiduciary"], "keywords": ["children", "tracking", "behavioural monitoring", "targeted advertising", "prohibition"], "metadata": {"act": "DPDP", "year": 2023, "jurisdiction": "India"}, "references": [], "clause_text": "A Data Fiduciary shall not undertake tracking or behavioural monitoring of children or targeted advertising directed at children.", "source_files": [4], "conflict_notes": [], "retrieval_text": "Section 9 subsection 3 of the Digital Personal Data Protection Act 2023 (DPDP Act). Processing of Children's Data - Prohibition on Tracking and Targeted Advertising Data Fiduciaries are prohibited from tracking, behaviourally monitoring, or directing targeted advertising at children. Topics: children_data, compliance. Keywords: children, tracking, behavioural monitoring, targeted advertising, prohibition.", "section_number": "9", "subsection_number": "3", "validation_status": "validated", "plain_english_summary": "Data Fiduciaries are prohibited from tracking, behaviourally monitoring, or directing targeted advertising at children."}	[0.53437185,1.0755482,-2.9321213,-1.0977722,0.4069479,0.6189092,1.0761249,-0.21441483,0.39379615,-0.35428026,-0.32327786,0.5768186,1.1167895,-0.58495367,-0.77772427,-0.47971043,-0.67719,-0.76192963,-0.6760115,0.4254147,0.7856174,0.5571764,-1.3497603,-0.5063918,1.1952884,-0.1775069,1.5048003,-1.1380287,-0.052938275,-0.27139714,0.49331275,0.5226426,-0.4761284,-0.37427968,-0.85872847,-0.99960816,1.18853,0.71258473,-1.2142866,0.13820732,1.2267232,0.8349447,-0.056564845,-0.6946031,-0.7927597,-0.2241416,0.7370299,0.3881921,1.2274569,-0.51602346,0.7574138,-0.6025877,0.2734443,-0.6509653,1.5888183,0.3558332,-0.5359697,-0.19705567,-1.0278012,-0.57236034,2.4040694,1.913083,-1.4901776,0.96473074,1.3762589,-0.74677145,-0.88225603,0.19678172,-0