262	{"act": "DPDP", "title": "Processing of Children's Data - Exemptions", "doc_id": "DPDP_SEC_9_SUB_4", "topics": ["children_data", "exemptions"], "entities": ["Data Fiduciary"], "keywords": ["children", "exemption", "Data Fiduciary", "prescribed conditions"], "metadata": {"act": "DPDP", "year": 2023, "jurisdiction": "India"}, "references": ["DPDP_SEC_9_SUB_1", "DPDP_SEC_9_SUB_3"], "clause_text": "The provisions of sub-sections (1) and (3) shall not be applicable to processing of personal data of a child by such classes of Data Fiduciaries or for such purposes, and subject to such conditions, as may be prescribed.", "source_files": [4], "conflict_notes": [], "retrieval_text": "Section 9 subsection 4 of the Digital Personal Data Protection Act 2023 (DPDP Act). Processing of Children's Data - Exemptions Certain classes of Data Fiduciaries or purposes may be exempted from the parental consent and tracking/advertising restrictions for children, as prescribed. Topics: children_data, exemptions. Keywords: children, exemption, Data Fiduciary, prescribed conditions.", "section_number": "9", "subsection_number": "4", "validation_status": "validated", "plain_english_summary": "Certain classes of Data Fiduciaries or purposes may be exempted from the parental consent and tracking/advertising restrictions for children, as prescribed."}	[0.29314324,1.224645,-2.7874157,-1.6515694,-0.11781775,0.6851274,0.22562106,-0.1900627,0.29605758,-0.30394787,-0.60253954,0.1525719,1.0565265,-0.61485046,-0.6372855,-0.26435354,-1.1812738,-0.5219874,-0.36617106,0.13885435,0.3311869,0.35062054,-1.7613097,0.14098021,1.5744921,-0.115216054,1.2242228,-1.2723871,-0.72398406,-0.5973409,0.24105842,0.32358104,0.50083494,-0.17227395,-1.3109922,-1.1712291,1.2486259,0.95228547,-0.9746216,-0.3368361,1.0971904,0.5285832,-0.3339685,-0.43890902,-0.67193115,-0.2558067,0.7336377,-0.023271648,0.9785071,-0.6500839,1.1840484,-0.42523816,0.4665008,-0.23063266,1.4962999,0.22534648,-0.5943371,-0.00849638,-0.7888232,-0.