263	{"act": "DPDP", "title": "Significant Data Fiduciary - Designation Criteria", "doc_id": "DPDP_SEC_10_SUB_1", "topics": ["compliance", "governance", "security"], "entities": ["Central Government", "Data Fiduciary", "Significant Data Fiduciary"], "keywords": ["Significant Data Fiduciary", "designation", "Central Government", "volume", "sensitivity", "national security", "electoral democracy"], "metadata": {"act": "DPDP", "year": 2023, "jurisdiction": "India"}, "references": [], "clause_text": "The Central Government may notify any Data Fiduciary or class of Data Fiduciaries as Significant Data Fiduciary, on the basis of an assessment of such relevant factors as it may determine, including— (a) the volume and sensitivity of personal data processed; (b) risk to the rights of Data Principal; (c) potential impact on the sovereignty and integrity of India; (d) risk to electoral democracy; (e) security of the State; and (f) public order.", "source_files": [4], "conflict_notes": [], "retrieval_text": "Section 10 subsection 1 of the Digital Personal Data Protection Act 2023 (DPDP Act). Significant Data Fiduciary - Designation Criteria The Central Government may designate any Data Fiduciary as a Significant Data Fiduciary based on volume and sensitivity of data, risks to Data Principal rights, national security, electoral democracy, and public order. Topics: compliance, governance, security. Keywords: Significant Data Fiduciary, designation, Central Government, volume, sensitivity, national security, electoral democracy.", "section_number": "10", "subsection_number": "1", "validation_status": "validated", "plain_english_summary": "The Central Government may designate any Data Fiduciary as a Significant Data Fiduciary based on volume and sensitivity of data, risks to Data Principal rights, national security, electoral democracy, and public order."}	[0.72558045,1.5007669,-3.6043472,-1.3151557,1.2486858,0.18087518,0.16073686,0.3948331,0.41077077,-0.085903555,-0.08435594,-0.07