264	{"act": "DPDP", "title": "Significant Data Fiduciary - Additional Obligations", "doc_id": "DPDP_SEC_10_SUB_2", "topics": ["audit", "compliance", "governance"], "entities": ["Significant Data Fiduciary", "Data Protection Officer"], "keywords": ["Significant Data Fiduciary", "Data Protection Officer", "data auditor", "DPIA", "Data Protection Impact Assessment", "audit", "grievance redressal"], "metadata": {"act": "DPDP", "year": 2023, "jurisdiction": "India"}, "references": [], "clause_text": "The Significant Data Fiduciary shall— (a) appoint a Data Protection Officer who shall— (i) represent the Significant Data Fiduciary under the provisions of this Act; (ii) be based in India; (iii) be an individual responsible to the Board of Directors or similar governing body of the Significant Data Fiduciary; and (iv) be the point of contact for the grievance redressal mechanism under the provisions of this Act; (b) appoint an independent data auditor to carry out data audit, who shall evaluate the compliance of the Significant Data Fiduciary in accordance with the provisions of this Act; and (c) undertake the following other measures, namely:— (i) periodic Data Protection Impact Assessment...; (ii) periodic audit; and (iii) such other measures, consistent with the provisions of this Act, as may be prescribed.", "source_files": [4], "conflict_notes": [], "retrieval_text": "Section 10 subsection 2 of the Digital Personal Data Protection Act 2023 (DPDP Act). Significant Data Fiduciary - Additional Obligations Significant Data Fiduciaries must appoint a Data Protection Officer based in India, an independent data auditor, and conduct periodic Data Protection Impact Assessments and audits. Topics: audit, compliance, governance. Keywords: Significant Data Fiduciary, Data Protection Officer, data auditor, DPIA, Data Protection Impact Assessment, audit, grievance redressal.", "section_number": "10", "subsection_number": "2", "validation_status": "validated", "plain_english_summary": "Significant Data Fiduciaries must appoint a Data Protection Officer based in India, an independent data auditor, and conduct periodic Data Protection Impact Assessments and audits."}	[0.5618362,1.1602389,-3.3755996,-1.3194404,1.0881118,-0.23128904,0.520087,0.3782043,0.52585495,-0.1435803,0.009955785,0.31699955,0.98475885,-0.69109035,0.52920306,-0.08691488,0.017635692,-0.77334505,-1.1074624,-0.06746457,-0.36830688,-0.44877642,-1.4609412,-0.35414293,1.4514273,0.12421336,1.5783864,-0.9916689,0.14853369,-0.7424417,0.19272201,0.49863172,0.13301879,-0.87683356,-0.6409346,-0.9689432,0.7083564,1.0494753,0.1432619,-0.42286694,0.59848803,-0.0714903,-0.047700107,-0.9336925,0.104991145,0.4673199,0.6763185,-0.6032979,0.83862275,-0.43499562,0.18315867,0.008914199,1.212521,-0.09168058,0.10801797,0.39687446,-0.8219442,-0.25280496,-0.63909334,-0.92998147,1.5557789,1.1173615,-0.8339363,0.8442799,0.3598809,-0.4957526,-0.25698298,0.47281253,0.07662634,-0.55093443,0.6705105,0.07208772,0.08467837,-0.05059127,0.45331088,-0.4926219,-0.4976055,-0.79451287,0.08987753,0.58913064,0.47589484,-0.079679966,1.5375214,0.13793099,0.29551342,-0.11226401,-0.29806834,0.1919858,-0.2684956,0.96922964,0.4488927,-0.11536896,0.051945332,0.32712469,-0.9050755,0.22794345,0.09056836,-0.17478469,-0.8571529,-0.5774798,-0.37528512,-0.054146223,0.8934466,0.6874085,0.65754116,0.8013844,0.22999375,0.71374905,-0.17545508,-0.35511634,-0.3902143,1.4092822,-0.34426713,0.05826305,1.2438701,0.32313243,1.5938407,-0.8870837,-0.15612854,1.5305277,0.2657653,-0.63006717,1.2453835,0.81152254,-0.4214449,-0.006249129,-1.8122952,0.5772684,0.8257111,-0.22814548,0.7258841,-0.35797557,-1.2846365,-0.19547784,0.46988872,0.41562262,0.11692954,-0.30642858,-0.25809017,0.46395037,0.5974958,0.9857232,-0.14846891,0.31931952,0.46477747,-1.1751941,1.5508784,-0.6182123,-0.09873504,-0.40071124,0.04351466,-0.0724107,-0.2631747,-0.37893566,0.75870216,-0.5398661,-0.67324513,-0.04107793,-0.051934,0.82582754,0.7522131,0.372363,-0.7320324,1.1201185