265	{"act": "DPDP", "title": "Right to Access Information About Personal Data", "doc_id": "DPDP_SEC_11_SUB_1", "topics": ["data_processing", "user_rights"], "entities": ["Data Principal", "Data Fiduciary", "Data Processor"], "keywords": ["right to access", "Data Principal", "data summary", "data sharing", "Data Fiduciary", "Data Processor"], "metadata": {"act": "DPDP", "year": 2023, "jurisdiction": "India"}, "references": ["DPDP_SEC_7"], "clause_text": "The Data Principal shall have the right to obtain from the Data Fiduciary to whom she has previously given consent, including consent as referred to in clause (a) of section 7, for processing of personal data, upon making to it a request in such manner as may be prescribed,— (a) a summary of personal data which is being processed by such Data Fiduciary and the processing activities undertaken by that Data Fiduciary with respect to such personal data; (b) the identities of all other Data Fiduciaries and Data Processors with whom the personal data has been shared by such Data Fiduciary, along with a description of the personal data so shared; and (c) any other information related to the personal data of such Data Principal and its processing, as may be prescribed.", "source_files": [4], "conflict_notes": [], "retrieval_text": "Section 11 subsection 1 of the Digital Personal Data Protection Act 2023 (DPDP Act). Right to Access Information About Personal Data Data Principals have the right to access a summary of their processed data, the identities of parties with whom data was shared, and any other prescribed information from the Data Fiduciary. Topics: data_processing, user_rights. Keywords: right to access, Data Principal, data summary, data sharing, Data Fiduciary, Data Processor.", "section_number": "11", "subsection_number": "1", "validation_status": "validated", "plain_english_summary": "Data Principals have the right to access a summary of their processed data, the identities of parties with whom data was shared,