266	{"act": "DPDP", "title": "Right to Correction and Erasure", "doc_id": "DPDP_SEC_12_SUB_1", "topics": ["data_retention", "user_rights"], "entities": ["Data Principal"], "keywords": ["right to correction", "erasure", "completion", "updating", "personal data", "Data Principal"], "metadata": {"act": "DPDP", "year": 2023, "jurisdiction": "India"}, "references": ["DPDP_SEC_7"], "clause_text": "A Data Principal shall have the right to correction, completion, updating and erasure of her personal data for the processing of which she has previously given consent, including consent as referred to in clause (a) of section 7, in accordance with any requirement or procedure under any law for the time being in force.", "source_files": [4], "conflict_notes": [], "retrieval_text": "Section 12 subsection 1 of the Digital Personal Data Protection Act 2023 (DPDP Act). Right to Correction and Erasure Data Principals have the right to correct, complete, update, or erase their personal data that was processed with their consent. Topics: data_retention, user_rights. Keywords: right to correction, erasure, completion, updating, personal data, Data Principal.", "section_number": "12", "subsection_number": "1", "validation_status": "validated", "plain_english_summary": "Data Principals have the right to correct, complete, update, or erase their personal data that was processed with their consent."}	[1.335371,0.4421557,-2.9624214,-1.0830474,1.0160639,0.21687041,0.3699611,0.354541,0.43673965,0.5098757,0.27007475,0.56291676,0.8433591,-0.41413048,-0.03238522,-0.05987172,-0.369334,-1.2027152,-0.96815646,0.6222639,0.6911951,-0.37074226,-1.8171632,-0.06994375,1.1785393,-0.0743339,1.3855295,-0.6248952,-0.2844184,-0.43882,0.7093205,0.7270489,-0.0355159,-0.3356564,-0.44509226,-1.1545602,1.187401,0.287909,-0.08146697,-0.3446497,1.5713047,0.11137652,0.18670051,-1.2470353,0.18100975,0.29500306,0.38252747,-0.43375814,1.1670256,0.12977801,0.6092482,-0.3229751,0.15780705,-0.34546784,0.726904,0.56346786,-