267	{"act": "DPDP", "title": "Right to Correction - Data Fiduciary Obligations", "doc_id": "DPDP_SEC_12_SUB_2", "topics": ["data_processing", "user_rights"], "entities": ["Data Fiduciary", "Data Principal"], "keywords": ["correction", "completion", "update", "inaccurate", "misleading", "personal data", "Data Fiduciary"], "metadata": {"act": "DPDP", "year": 2023, "jurisdiction": "India"}, "references": [], "clause_text": "A Data Fiduciary shall, upon receiving a request for correction, completion or updating from a Data Principal,— (a) correct the inaccurate or misleading personal data; (b) complete the incomplete personal data; and (c) update the personal data.", "source_files": [4], "conflict_notes": [], "retrieval_text": "Section 12 subsection 2 of the Digital Personal Data Protection Act 2023 (DPDP Act). Right to Correction - Data Fiduciary Obligations Upon a Data Principal's request, the Data Fiduciary must correct inaccurate, complete incomplete, and update outdated personal data. Topics: data_processing, user_rights. Keywords: correction, completion, update, inaccurate, misleading, personal data, Data Fiduciary.", "section_number": "12", "subsection_number": "2", "validation_status": "validated", "plain_english_summary": "Upon a Data Principal's request, the Data Fiduciary must correct inaccurate, complete incomplete, and update outdated personal data."}	[1.1400385,0.21657568,-3.109917,-1.14513,0.87548804,0.04549566,0.3069051,0.26370072,0.2757521,0.3854581,0.3384489,0.43635768,1.0117959,-0.33116996,0.06516205,0.030322257,0.060344905,-0.82827663,-0.75190705,0.5815692,0.44018313,-0.105578385,-1.9128343,0.013170114,1.0092777,-0.37398517,1.1733074,-0.47728974,-0.26038978,-0.307099,0.58025295,0.98895514,-0.13008846,-0.48637068,-1.073191,-1.0998381,1.369586,0.5239742,0.46524405,0.06302045,1.0524396,0.28260028,0.25605088,-1.151365,0.030805305,-0.3266734,0.7623059,-0.02079764,1.0893326,0.27822638,0.6258022,-0.06832494,0.557055,0.10272138,0.5857708,0.7813717,-0.6859674