268	{"act": "DPDP", "title": "Right to Erasure - Request Process", "doc_id": "DPDP_SEC_12_SUB_3", "topics": ["data_retention", "user_rights"], "entities": ["Data Fiduciary", "Data Principal"], "keywords": ["erasure", "right to erasure", "deletion", "retention", "legal compliance", "Data Fiduciary", "Data Principal"], "metadata": {"act": "DPDP", "year": 2023, "jurisdiction": "India"}, "references": [], "clause_text": "A Data Principal shall make a request in such manner as may be prescribed to the Data Fiduciary for erasure of her personal data, and upon receipt of such a request, the Data Fiduciary shall erase her personal data unless retention of the same is necessary for the specified purpose or for compliance with any law for the time being in force.", "source_files": [4], "conflict_notes": [], "retrieval_text": "Section 12 subsection 3 of the Digital Personal Data Protection Act 2023 (DPDP Act). Right to Erasure - Request Process A Data Principal may request erasure of personal data, and the Data Fiduciary must comply unless retention is required for the specified purpose or legal obligation. Topics: data_retention, user_rights. Keywords: erasure, right to erasure, deletion, retention, legal compliance, Data Fiduciary, Data Principal.", "section_number": "12", "subsection_number": "3", "validation_status": "validated", "plain_english_summary": "A Data Principal may request erasure of personal data, and the Data Fiduciary must comply unless retention is required for the specified purpose or legal obligation."}	[1.1186869,0.9755478,-2.9194279,-1.2227259,1.1847606,0.19216457,0.15436992,0.29183787,0.2598368,0.47290522,-0.3479123,0.5932629,0.68895274,-0.3952293,-0.024860099,-0.045795716,-0.44656762,-1.2263204,-0.9958356,0.47665685,0.10150167,-0.27433988,-1.4948893,-0.2731939,1.2368879,-0.43893808,1.6413087,-0.754742,-0.17328107,-0.47103608,0.3581945,0.7543714,0.2526243,-0.47990215,-0.57405114,-1.520772,1.0421945,0.67592937,-0.58239126,-0.39909473,1.624862,0.1276017,0