269	{"act": "DPDP", "title": "Right to Grievance Redressal", "doc_id": "DPDP_SEC_13_SUB_1", "topics": ["grievance_redressal", "user_rights"], "entities": ["Data Principal", "Data Fiduciary", "Consent Manager"], "keywords": ["grievance redressal", "Data Principal", "Data Fiduciary", "Consent Manager", "rights"], "metadata": {"act": "DPDP", "year": 2023, "jurisdiction": "India"}, "references": [], "clause_text": "A Data Principal shall have the right to have readily available means of grievance redressal provided by a Data Fiduciary or Consent Manager in respect of any act or omission of such Data Fiduciary or Consent Manager regarding the performance of its obligations in relation to the personal data of such Data Principal or the exercise of her rights under the provisions of this Act and the rules made thereunder.", "source_files": [4], "conflict_notes": [], "retrieval_text": "Section 13 subsection 1 of the Digital Personal Data Protection Act 2023 (DPDP Act). Right to Grievance Redressal Data Principals have a right to readily accessible grievance redressal from Data Fiduciaries or Consent Managers for any failure to meet obligations under this Act. Topics: grievance_redressal, user_rights. Keywords: grievance redressal, Data Principal, Data Fiduciary, Consent Manager, rights.", "section_number": "13", "subsection_number": "1", "validation_status": "validated", "plain_english_summary": "Data Principals have a right to readily accessible grievance redressal from Data Fiduciaries or Consent Managers for any failure to meet obligations under this Act."}	[1.13443,1.1635618,-3.4065359,-1.254231,1.4150513,-0.16030224,0.28477764,-0.003202648,0.7233515,0.08006118,0.23808372,0.4515528,0.7428968,-0.9741015,0.2994775,-0.03196574,-0.2029943,-0.38971505,-1.3518516,-0.14300422,0.1156333,-0.84999007,-1.7791251,-0.3571079,1.4210006,-0.031790055,1.1116397,-0.40308586,-0.15763733,-0.051489506,0.020878986,0.56801814,-0.012698089,-0.45415753,-0.7414056,-1.0519228,0.62850535,0.5203858