272	{"act": "DPDP", "title": "Right to Nominate", "doc_id": "DPDP_SEC_14_SUB_1", "topics": ["user_rights"], "entities": ["Data Principal"], "keywords": ["nomination", "right to nominate", "death", "incapacity", "Data Principal", "rights"], "metadata": {"act": "DPDP", "year": 2023, "jurisdiction": "India"}, "references": [], "clause_text": "A Data Principal shall have the right to nominate, in such manner as may be prescribed, any other individual, who shall, in the event of death or incapacity of the Data Principal, exercise the rights of the Data Principal in accordance with the provisions of this Act and the rules made thereunder.", "source_files": [4], "conflict_notes": [], "retrieval_text": "Section 14 subsection 1 of the Digital Personal Data Protection Act 2023 (DPDP Act). Right to Nominate A Data Principal may nominate another individual to exercise their data rights in the event of the Data Principal's death or incapacity. Topics: user_rights. Keywords: nomination, right to nominate, death, incapacity, Data Principal, rights.", "section_number": "14", "subsection_number": "1", "validation_status": "validated", "plain_english_summary": "A Data Principal may nominate another individual to exercise their data rights in the event of the Data Principal's death or incapacity."}	[0.32785714,0.68286806,-3.0843244,-1.1711346,1.0321914,0.32628062,0.27108794,0.65103376,0.44821313,0.027671743,-0.2276258,0.43161222,0.83930784,-0.61819804,0.20182146,-0.62388057,0.095859185,-1.2733918,-1.1115463,-0.03589836,-0.029452926,-1.1370915,-1.7426912,0.5368707,1.8435689,0.31395495,1.4139118,-0.56793517,-0.23317139,-0.19045231,0.3692426,1.1072392,0.6648457,-0.20285887,-0.2998167,-1.0995982,1.2333604,0.6588183,-0.20634106,-0.45624545,0.86920786,-0.4227136,0.10520275,-0.8811122,0.06509756,-0.31147027,1.1099592,0.10871038,0.9677842,-0.53375834,0.64568776,-0.5459481,1.121406,-0.639736,0.33784607,0.46448603,0.15611352,0.5471594,-0.9970671,-1.0146984,2.2430348,1.2855253,-0.85658824,0.8077