273	{"act": "DPDP", "title": "Duties of Data Principal", "doc_id": "DPDP_SEC_15", "topics": ["compliance", "penalty", "user_rights"], "entities": ["Data Principal", "Board", "Data Fiduciary"], "keywords": ["duties", "Data Principal", "impersonation", "false grievance", "authentic information", "compliance"], "metadata": {"act": "DPDP", "year": 2023, "jurisdiction": "India"}, "references": [], "clause_text": "A Data Principal shall perform the following duties, namely:— (a) comply with the provisions of all applicable laws for the time being in force while exercising rights under the provisions of this Act; (b) to ensure not to impersonate another person while providing her personal data for a specified purpose; (c) to ensure not to suppress any material information while providing her personal data for any document, unique identifier, proof of identity or proof of address issued by the State or any of its instrumentalities; (d) to ensure not to register a false or frivolous grievance or complaint with a Data Fiduciary or the Board; and (e) to furnish only such information as is verifiably authentic, while exercising the right to correction or erasure under the provisions of this Act or the rules made thereunder.", "source_files": [4], "conflict_notes": [], "retrieval_text": "Section 15 of the Digital Personal Data Protection Act 2023 (DPDP Act). Duties of Data Principal Data Principals must comply with applicable laws, avoid impersonation, not suppress material information, refrain from filing false grievances, and provide only authentic information when exercising rights. Topics: compliance, penalty, user_rights. Keywords: duties, Data Principal, impersonation, false grievance, authentic information, compliance.", "section_number": "15", "subsection_number": null, "validation_status": "validated", "plain_english_summary": "Data Principals must comply with applicable laws, avoid impersonation, not suppress material information, refrain from filing false grievances, 