274	{"act": "DPDP", "title": "Cross-Border Transfer - Restriction Power", "doc_id": "DPDP_SEC_16_SUB_1", "topics": ["compliance", "cross_border_transfer"], "entities": ["Central Government", "Data Fiduciary"], "keywords": ["cross-border transfer", "restriction", "Central Government", "notification", "Data Fiduciary", "outside India"], "metadata": {"act": "DPDP", "year": 2023, "jurisdiction": "India"}, "references": [], "clause_text": "The Central Government may, by notification, restrict the transfer of personal data by a Data Fiduciary for processing to such country or territory outside India as may be so notified.", "source_files": [4], "conflict_notes": [], "retrieval_text": "Section 16 subsection 1 of the Digital Personal Data Protection Act 2023 (DPDP Act). Cross-Border Transfer - Restriction Power The Central Government may restrict personal data transfers to specified countries or territories outside India by notification. Topics: compliance, cross_border_transfer. Keywords: cross-border transfer, restriction, Central Government, notification, Data Fiduciary, outside India.", "section_number": "16", "subsection_number": "1", "validation_status": "validated", "plain_english_summary": "The Central Government may restrict personal data transfers to specified countries or territories outside India by notification."}	[0.7461464,1.2542548,-3.446708,-0.7304554,1.0152471,0.39786267,0.004619829,-0.011536423,0.16293478,-0.18616998,-0.579867,0.2947993,1.1267582,-1.327434,0.53125024,-0.008611968,-0.18215992,-1.032388,-0.4196327,0.6692423,-0.185618,1.2566884,-1.35395,-0.043951724,1.0387672,-0.2563404,2.0722628,-0.91593516,-0.70557165,-0.77749425,0.60367143,-0.31066585,-0.3950567,-0.5540206,-0.54374063,-0.6179811,0.59877443,-0.24963634,-0.6867734,0.090376064,0.8206327,0.37993735,-0.7790783,-1.0275995,1.1668437,-0.2262531,1.1983017,0.021055661,0.72078174,-0.7705774,-0.3795755,0.12826717,-0.35112035,-0.2362473,0.47574693,0.21879433,-0.7317406,-0.06335199,-0.105145335,-0.5954