275	{"act": "DPDP", "title": "Cross-Border Transfer - Existing Laws Prevail", "doc_id": "DPDP_SEC_16_SUB_2", "topics": ["compliance", "cross_border_transfer"], "entities": ["Data Fiduciary"], "keywords": ["cross-border transfer", "higher protection", "existing laws", "Data Fiduciary"], "metadata": {"act": "DPDP", "year": 2023, "jurisdiction": "India"}, "references": [], "clause_text": "Nothing contained in this section shall restrict the applicability of any law for the time being in force in India that provides for a higher degree of protection for or restriction on transfer of personal data by a Data Fiduciary outside India in relation to any personal data or Data Fiduciary or class thereof.", "source_files": [4], "conflict_notes": [], "retrieval_text": "Section 16 subsection 2 of the Digital Personal Data Protection Act 2023 (DPDP Act). Cross-Border Transfer - Existing Laws Prevail Any existing law providing higher protection for cross-border data transfers than this section continues to apply. Topics: compliance, cross_border_transfer. Keywords: cross-border transfer, higher protection, existing laws, Data Fiduciary.", "section_number": "16", "subsection_number": "2", "validation_status": "validated", "plain_english_summary": "Any existing law providing higher protection for cross-border data transfers than this section continues to apply."}	[0.82812214,0.7988464,-3.5946362,-0.79651356,1.1130518,0.7122241,0.0019676283,0.033664763,0.10920486,0.08155939,-0.7938482,-0.33283025,0.7734055,-1.2085218,0.0911509,0.042914677,0.2147258,-1.1570004,-0.1912784,0.4091004,-0.34983414,0.5159248,-1.0532275,-0.91023785,1.0281146,-0.3369242,1.3283188,-0.7959739,-0.9096378,-0.8628024,0.65880996,-0.5236949,-0.1573332,-0.8200693,-0.620316,-0.55652076,0.5389918,0.04529732,-0.6248119,-0.1901925,0.8822806,0.41454008,-0.7167155,-0.7868559,1.321632,-0.445586,0.9209357,-0.220963,0.46881202,-0.7406511,-0.41985554,0.92042285,0.23178187,0.50653446,0.73750657,0.28117132,-0.4526611,-0.17745599,