276	{"act": "DPDP", "title": "Exemptions - General Grounds", "doc_id": "DPDP_SEC_17_SUB_1", "topics": ["exemptions"], "entities": ["Data Fiduciary", "Data Principal"], "keywords": ["exemptions", "legal proceedings", "law enforcement", "judicial", "merger", "default", "financial institution"], "metadata": {"act": "DPDP", "year": 2023, "jurisdiction": "India"}, "references": ["DPDP_SEC_8", "DPDP_SEC_16"], "clause_text": "The provisions of Chapter II, except sub-sections (1) and (5) of section 8, and those of Chapter III and section 16 shall not apply where— (a) the processing of personal data is necessary for enforcing any legal right or claim; (b) the processing of personal data by any court or tribunal or any other body in India which is entrusted by law with the performance of any judicial or quasi-judicial or regulatory or supervisory function, where such processing is necessary for the performance of such function; (c) personal data is processed in the interest of prevention, detection, investigation or prosecution of any offence or contravention of any law for the time being in force in India; (d) personal data of Data Principals not within the territory of India is processed pursuant to any contract entered into with any person outside the territory of India by any person based in India; (e) the processing is necessary for a scheme of compromise or arrangement or merger or amalgamation...; and (f) the processing is for the purpose of ascertaining the financial information and assets and liabilities of any person who has defaulted in payment due on account of a loan or advance taken from a financial institution...", "source_files": [4], "conflict_notes": [], "retrieval_text": "Section 17 subsection 1 of the Digital Personal Data Protection Act 2023 (DPDP Act). Exemptions - General Grounds Various provisions of Chapter II and III do not apply in specific situations including legal proceedings, law enforcement, judicial functions, offshore data processing, corporate restructuring, and loan default recovery. Topics: exemptions. Keywords: exemptions, legal proceedings, law enforcement, judicial, merger, default, financial institution.", "section_number": "17", "subsection_number": "1", "validation_status": "validated", "plain_english_summary": "Various provisions of Chapter II and III do not apply in specific situations including legal proceedings, law enforcement, judicial functions, offshore data processing, corporate restructuring, and loan default recovery."}	[0.66028273,1.2567931,-3.0341082,-1.1580462,0.5221124,0.84766424,0.08824624,0.26364645,0.085097864,-0.41745797,0.1782692,0.09515889,0.4283029,-0.8581304,-0.18622187,-0.873691,-0.72275555,-0.7185341,-0.8090195,-0.08749735,-0.24744853,0.04526299,-1.7456944,-0.20204517,1.5259209,-0.120666265,1.2614585,-0.74986184,-0.77315116,-0.50140786,-0.090434454,0.8242995,1.0773168,-0.5550953,-1.0137924,-1.0471712,1.3078779,0.95493186,-1.2051148,-0.7030023,0.69873995,0.31768975,-0.24666646,-0.71971095,0.5624205,0.18197758,1.0791367,-0.17387535,0.70054716,-0.2940791,1.044499,-0.08439942,0.683158,-0.39781356,0.32074127,0.48333958,-0.68404865,0.32015243,-0.80980194,-0.82654905,1.0935366,1.4277633,-0.6504184,0.80103844,0.39216462,-0.62529314,-0.39629674,0.8115504,0.47022825,-0.9686669,0.8129574,0.37502733,-0.29103994,-0.14031976,0.0957624,-0.89048,-0.593027,-0.676988,-0.29939768,0.67499393,0.4230967,0.062772036,0.62183833,0.26679856,0.21536428,0.8418245,-0.6807522,-0.22914377,-0.11042985,1.4475173,0.13249294,0.056644004,0.6980846,0.2356585,-0.7231948,0.41368786,0.64054173,0.11859535,-0.4924439,-0.5332227,-0.59982604,-0.35652962,1.6174355,0.69457316,0.40881652,0.85675675,0.89703965,0.54517853,-0.032910977,-0.4775695,-0.57055676,1.55291,-0.016861131,0.14430799,1.0199714,0.3063755,1.0682671,-0.057517357,-0.18173954,0.8178714,-0.090276375,-0.19502707,0.58622736,1.0172623,-0.82758504,0.23464884,-1.8386143,0.3336864,0.9672993,-1.0517845,0.6435729,-0.63001573,-0.6539166,0.46945977,0.67535436,0.