277	{"act": "DPDP", "title": "Exemptions - State and Research", "doc_id": "DPDP_SEC_17_SUB_2", "topics": ["exemptions"], "entities": ["Central Government", "State"], "keywords": ["State exemption", "national security", "research", "archiving", "statistical purposes", "Central Government"], "metadata": {"act": "DPDP", "year": 2023, "jurisdiction": "India"}, "references": [], "clause_text": "The provisions of this Act shall not apply in respect of the processing of personal data— (a) by such instrumentality of the State as the Central Government may notify, in the interests of sovereignty and integrity of India, security of the State, friendly relations with foreign States, maintenance of public order or preventing incitement to any cognizable offence relating to any of these, and the processing by the Central Government of any personal data that such instrumentality may furnish to it; and (b) necessary for research, archiving or statistical purposes if the personal data is not to be used to take any decision specific to a Data Principal and such processing is carried on in accordance with such standards as may be prescribed.", "source_files": [4], "conflict_notes": [], "retrieval_text": "Section 17 subsection 2 of the Digital Personal Data Protection Act 2023 (DPDP Act). Exemptions - State and Research The Act does not apply to State instrumentality processing for national security or public order, nor to research and statistical processing not used for individual decisions. Topics: exemptions. Keywords: State exemption, national security, research, archiving, statistical purposes, Central Government.", "section_number": "17", "subsection_number": "2", "validation_status": "validated", "plain_english_summary": "The Act does not apply to State instrumentality processing for national security or public order, nor to research and statistical processing not used for individual decisions."}	[0.25037596,1.4409994,-3.0395567,-1.1152911,0.62486744,0.7163873,0.25067696,0.5458