278	{"act": "DPDP", "title": "Exemptions - Startup Notification", "doc_id": "DPDP_SEC_17_SUB_3", "topics": ["compliance", "exemptions"], "entities": ["Central Government", "Data Fiduciary"], "keywords": ["startup", "exemption", "notification", "Central Government", "Data Fiduciary"], "metadata": {"act": "DPDP", "year": 2023, "jurisdiction": "India"}, "references": ["DPDP_SEC_5", "DPDP_SEC_8", "DPDP_SEC_10", "DPDP_SEC_11"], "clause_text": "The Central Government may, having regard to the volume and nature of personal data processed, notify certain Data Fiduciaries or class of Data Fiduciaries, including startups, as Data Fiduciaries to whom the provisions of section 5, sub-sections (3) and (7) of section 8 and sections 10 and 11 shall not apply.", "source_files": [4], "conflict_notes": [], "retrieval_text": "Section 17 subsection 3 of the Digital Personal Data Protection Act 2023 (DPDP Act). Exemptions - Startup Notification The Central Government may exempt certain Data Fiduciaries including startups from specific provisions on notice, data accuracy, erasure, Significant Data Fiduciary obligations, and access rights. Topics: compliance, exemptions. Keywords: startup, exemption, notification, Central Government, Data Fiduciary.", "section_number": "17", "subsection_number": "3", "validation_status": "validated", "plain_english_summary": "The Central Government may exempt certain Data Fiduciaries including startups from specific provisions on notice, data accuracy, erasure, Significant Data Fiduciary obligations, and access rights."}	[-0.01036888,1.3669322,-3.78667,-0.9434779,0.69658905,0.27286237,0.24031393,0.39877275,0.6111848,-0.58789915,-0.36192876,0.4550775,1.273251,-0.04514997,0.10077925,-0.23962685,-0.41491628,-0.9727971,-0.6193169,0.44370642,0.708084,0.17015798,-2.2172363,0.039387587,1.4538212,-0.29352298,1.4302416,-0.8727269,-0.39155835,-0.4711428,0.2981273,0.8546329,0.49061778,-0.5825199,-0.6958071,-1.3397498,0.46584776,0.28808123,-0.92961615,-0.65394723,0.7