279	{"act": "DPDP", "title": "Establishment of Data Protection Board of India", "doc_id": "DPDP_SEC_18_SUB_1", "topics": ["compliance", "governance"], "entities": ["Central Government", "Data Protection Board of India"], "keywords": ["Data Protection Board", "establishment", "Central Government", "notification"], "metadata": {"act": "DPDP", "year": 2023, "jurisdiction": "India"}, "references": [], "clause_text": "With effect from such date as the Central Government may, by notification, appoint, there shall be established, for the purposes of this Act, a Board to be called the Data Protection Board of India.", "source_files": [4], "conflict_notes": [], "retrieval_text": "Section 18 subsection 1 of the Digital Personal Data Protection Act 2023 (DPDP Act). Establishment of Data Protection Board of India The Central Government shall establish the Data Protection Board of India by notification on a date it appoints. Topics: compliance, governance. Keywords: Data Protection Board, establishment, Central Government, notification.", "section_number": "18", "subsection_number": "1", "validation_status": "validated", "plain_english_summary": "The Central Government shall establish the Data Protection Board of India by notification on a date it appoints."}	[0.33159074,1.1083546,-3.3837655,-0.75479263,1.6831399,0.026403487,0.28611788,0.14674303,0.2480672,-0.8457764,-0.3377207,0.4135927,1.0634338,-0.3624973,0.098833226,-0.26978436,-0.3785466,-1.1877939,-0.8177594,0.4256221,0.44464377,0.4374033,-1.4630132,0.19121107,2.032529,0.23874749,1.388862,-0.8756107,0.3275835,-0.4379761,0.10439662,0.4466409,0.24573721,-1.1740181,0.2203725,-1.3713868,0.66825086,0.07627523,-0.8253782,-0.61619323,0.8471623,-0.13195595,-0.6198532,-1.3079832,0.16322981,0.32881054,0.7676557,-0.4761995,0.8251247,-0.52329564,-0.100535564,-0.30039722,1.1744827,-0.5131026,0.054578166,0.80249083,-0.6499488,-0.12867562,-0.6579852,-0.8411716,1.6477084,1.3694731,-0.7900917,1.0155853,0.974332,-0.2577931,-0.122141294,1.03