280	{"act": "DPDP", "title": "Powers and Functions of Board", "doc_id": "DPDP_SEC_27_SUB_1", "topics": ["breach_reporting", "compliance", "governance", "penalty"], "entities": ["Board", "Data Principal", "Data Fiduciary", "Consent Manager", "Central Government"], "keywords": ["Board powers", "inquiry", "personal data breach", "penalty", "complaint", "remedial measures"], "metadata": {"act": "DPDP", "year": 2023, "jurisdiction": "India"}, "references": ["DPDP_SEC_8", "DPDP_SEC_37"], "clause_text": "The Board shall exercise and perform the following powers and functions, namely:— (a) on receipt of an intimation of personal data breach under sub-section (6) of section 8, to direct any urgent remedial or mitigation measures in the event of a personal data breach, and to inquire into such personal data breach and impose penalty as provided in this Act; (b) on a complaint made by a Data Principal in respect of a personal data breach or a breach in observance by a Data Fiduciary of its obligations in relation to her personal data or the exercise of her rights under the provisions of this Act..., to inquire into such breach and impose penalty as provided in this Act; (c) on a complaint made by a Data Principal in respect of a breach in observance by a Consent Manager of its obligations...; (d) on receipt of an intimation of breach of any condition of registration of a Consent Manager...; and (e) on a reference made by the Central Government in respect of the breach in observance of the provisions of sub-section (2) of section 37 by an intermediary...", "source_files": [4], "conflict_notes": [], "retrieval_text": "Section 27 subsection 1 of the Digital Personal Data Protection Act 2023 (DPDP Act). Powers and Functions of Board The Board is empowered to act on breach intimations, complaints from Data Principals, Consent Manager violations, and government references, and may direct remedial measures and impose penalties. Topics: breach_reporting, compliance, governance, penalty. Keywords: Board powers, inquiry, personal data breach, penalty, complaint, remedial measures.", "section_number": "27", "subsection_number": "1", "validation_status": "validated", "plain_english_summary": "The Board is empowered to act on breach intimations, complaints from Data Principals, Consent Manager violations, and government references, and may direct remedial measures and impose penalties."}	[0.89323384,1.5880182,-3.4685612,-0.9045042,1.4603275,-0.54659796,0.49428558,0.47292286,0.78923035,-0.30215302,-0.020793375,0.4397294,0.20704767,-0.34538516,0.066258796,-0.7999032,-0.26252562,-1.6021885,-0.2885563,-0.20508048,0.06952524,-0.37377352,-1.5147133,0.26962528,1.3006669,0.3843281,1.5517051,-0.91425264,0.13918503,-0.45852566,-0.18409313,0.5554719,-0.049483206,-0.928293,-0.418586,-0.7004387,1.1470224,0.16794233,-1.1171986,-0.20947708,0.6030108,-0.37312505,-0.37493792,-1.3878764,0.05998295,-0.252971,0.45612213,-0.51687646,0.9519461,-0.6181101,0.3209906,-0.98087716,1.078008,-0.6353626,0.7160892,0.13839321,-0.39582786,-0.1971674,-0.69186145,-0.83417755,1.3339263,1.5940201,-0.18693528,0.7723736,0.87153697,-0.11211486,-0.49599832,1.1577863,0.06070553,-0.6861223,1.0538099,0.0026832335,0.19262855,-0.015702035,-0.12375294,-0.55216885,-0.15542431,-0.6429712,-0.018567698,0.6857797,0.8094236,-0.33443514,1.3899305,0.6444989,0.1397343,0.050272435,-0.9388633,-0.18558222,-0.30720216,1.3364305,0.11856063,-0.6073968,0.8034708,0.027187657,-0.8115179,0.25919977,0.7731888,-0.73150015,-0.15261947,0.12155141,-0.497036,-0.32333305,0.96874595,1.1729448,-0.36936817,1.3232701,0.37373728,0.31254572,0.048654765,-0.20009851,-0.5999547,1.1762764,-0.09459425,0.10923731,1.7435552,0.6144118,0.7866926,-0.7807909,-0.928074,1.46771,0.16030778,-0.32809034,0.31970564,0.5232147,-0.32613963,0.4223691,-1.5353703,0.8471033,0.46689278,-0.31414095,0.008378155,-0.24994473,-1.1377476,0.27635482,0.7970772,0.9469902,0.31225502,-0.36947986,-0.09175993,-0.2666742,0.63731015,0.75509167,-0.34061542,0.85221016,