282	{"act": "DPDP", "title": "Appeal - Time Limit and Form", "doc_id": "DPDP_SEC_29_SUB_2", "topics": ["compliance", "governance"], "entities": ["Appellate Tribunal"], "keywords": ["appeal", "sixty days", "limitation period", "fee", "form"], "metadata": {"act": "DPDP", "year": 2023, "jurisdiction": "India"}, "references": ["DPDP_SEC_29_SUB_1"], "clause_text": "Every appeal under sub-section (1) shall be filed within a period of sixty days from the date of receipt of the order or direction appealed against and it shall be in such form and manner and shall be accompanied by such fee as may be prescribed.", "source_files": [4], "conflict_notes": [], "retrieval_text": "Section 29 subsection 2 of the Digital Personal Data Protection Act 2023 (DPDP Act). Appeal - Time Limit and Form Appeals must be filed within sixty days of receiving the Board's order, in the prescribed form and accompanied by the prescribed fee. Topics: compliance, governance. Keywords: appeal, sixty days, limitation period, fee, form.", "section_number": "29", "subsection_number": "2", "validation_status": "validated", "plain_english_summary": "Appeals must be filed within sixty days of receiving the Board's order, in the prescribed form and accompanied by the prescribed fee."}	[0.71933097,1.6597005,-3.4681854,-0.78514105,0.42395523,0.040423837,0.7405995,-0.012205728,0.8972639,0.0493471,0.18521656,0.6501068,0.7598582,-0.3732867,0.21537338,-0.7081628,-0.19319887,-1.5274332,-1.4499391,0.001601653,0.5692919,-0.29719898,-1.4879138,-0.25101125,0.6829708,0.17057684,1.7099199,-0.54943764,-0.5147264,0.44750082,0.29555112,0.5051742,0.55176824,-0.5569691,-0.2075026,-0.67828625,0.65184295,-0.054933455,-0.8545905,-0.48362178,0.9886304,-0.6629156,0.2410095,-0.21919233,0.90895545,-0.33407104,0.6778911,0.41590616,-0.44650757,-0.96890604,0.4024773,-0.4152,0.15011719,-0.5393081,0.15782234,0.33296508,-1.2489593,0.32181963,-0.06777545,-0.026352251,2.0001037,1.28883,-0.4705466,1.3022486,1.5048472,-0.67097676,-0.17259221,0