283	{"act": "DPDP", "title": "Penalties - Imposition", "doc_id": "DPDP_SEC_33_SUB_1", "topics": ["breach_reporting", "compliance", "penalty"], "entities": ["Board"], "keywords": ["penalty", "monetary penalty", "breach", "inquiry", "Board", "Schedule"], "metadata": {"act": "DPDP", "year": 2023, "jurisdiction": "India"}, "references": [], "clause_text": "If the Board determines on conclusion of an inquiry that breach of the provisions of this Act or the rules made thereunder by a person is significant, it may, after giving the person an opportunity of being heard, impose such monetary penalty specified in the Schedule.", "source_files": [4], "conflict_notes": [], "retrieval_text": "Section 33 subsection 1 of the Digital Personal Data Protection Act 2023 (DPDP Act). Penalties - Imposition The Board may impose a monetary penalty on any person found to have significantly breached the Act after conducting an inquiry and granting a hearing. Topics: breach_reporting, compliance, penalty. Keywords: penalty, monetary penalty, breach, inquiry, Board, Schedule.", "section_number": "33", "subsection_number": "1", "validation_status": "validated", "plain_english_summary": "The Board may impose a monetary penalty on any person found to have significantly breached the Act after conducting an inquiry and granting a hearing."}	[1.2689561,1.6629841,-3.261513,-0.9462032,1.2412491,-0.2969215,0.71608657,0.21247065,0.669548,0.30284515,-0.26891467,0.2800391,0.017094959,-0.4058289,0.05075022,-1.1136482,0.079431586,-1.4125438,-0.6951314,0.059982233,0.022968404,0.12970306,-1.7828354,-0.2598997,1.0355785,0.0050152983,1.7055218,-0.5914921,-0.5247048,0.3309965,-0.10232422,0.110832915,-0.2589858,-1.0795637,-1.0097024,-1.0156201,1.5020946,0.34859243,-1.1182178,-0.69258404,0.79674965,-0.40642348,-0.29626465,-1.0397521,0.17231742,-0.1729706,1.1269647,0.14462835,0.22742163,-0.46007577,0.32562914,-0.21300367,0.7674878,-0.6973656,0.7129087,0.8857913,-0.7889685,-0.21789767,-0.13425215,-0.34637603,1.8460