284	{"act": "DPDP", "title": "Penalties - Determining Factors", "doc_id": "DPDP_SEC_33_SUB_2", "topics": ["breach_reporting", "penalty"], "entities": ["Board"], "keywords": ["penalty determination", "gravity", "duration", "proportionality", "mitigation", "gain", "impact", "repetition"], "metadata": {"act": "DPDP", "year": 2023, "jurisdiction": "India"}, "references": ["DPDP_SEC_33_SUB_1"], "clause_text": "While determining the amount of monetary penalty to be imposed under sub-section (1), the Board shall have regard to the following matters, namely:— (a) the nature, gravity and duration of the breach; (b) the type and nature of the personal data affected by the breach; (c) repetitive nature of the breach; (d) whether the person, as a result of the breach, has realised a gain or avoided any loss; (e) whether the person took any action to mitigate the effects and consequences of the breach, and the timeliness and effectiveness of such action; (f) whether the monetary penalty to be imposed is proportionate and effective, having regard to the need to secure observance of and deter breach of the provisions of this Act; and (g) the likely impact of the imposition of the monetary penalty on the person.", "source_files": [4], "conflict_notes": [], "retrieval_text": "Section 33 subsection 2 of the Digital Personal Data Protection Act 2023 (DPDP Act). Penalties - Determining Factors The Board must consider factors such as breach severity, data type, recurrence, financial gain, mitigation efforts, proportionality, and impact when determining the monetary penalty amount. Topics: breach_reporting, penalty. Keywords: penalty determination, gravity, duration, proportionality, mitigation, gain, impact, repetition.", "section_number": "33", "subsection_number": "2", "validation_status": "validated", "plain_english_summary": "The Board must consider factors such as breach severity, data type, recurrence, financial gain, mitigation efforts, proportionality, and impact when determining the monetary penalty amount."}	[1.7586194,1.6893128,-3.4630055,-0.9167061,1.5737541,-0.22434275,1.0455947,-0.055393696,0.09312119,0.3380843,-0.25540474,0.45173392,0.80856085,-0.35386083,0.51566553,-0.9110046,0.018746037,-1.3915447,-0.14105673,0.37972087,-0.10842822,-0.4171719,-1.7610804,-0.69309217,0.67193705,0.36094552,1.51546,-0.46886668,-0.74020576,0.31271586,-0.3890803,0.24125013,-0.4350915,-1.2615209,-1.3476485,-0.7787786,1.3561584,0.38040188,-0.79408985,-0.64336884,0.59184426,-0.6292281,-0.33812279,-0.64827555,-0.1383443,0.047114294,1.2497982,0.09833335,0.38749784,-0.16738348,-0.029437806,-0.21353285,0.65334505,-0.61903644,0.68308467,0.36606178,-1.194765,-0.3729932,-0.253474,-0.33776018,1.5868698,2.130445,-0.6178625,0.43959397,0.8540481,-0.33637062,-0.658694,1.1031271,-0.27566543,-0.6032312,0.6930821,0.27463904,-0.1840114,0.0985362,-0.00045405517,0.05967067,-0.8885538,0.31609505,0.060511854,0.8390543,0.47361922,0.1353151,1.220532,0.42535162,0.4748515,-0.2109067,-0.52662486,-0.058729805,-0.29483753,1.1086266,-0.70802796,-0.7095831,0.63007176,0.60520715,-1.3860162,0.16205949,0.4558375,0.013087164,-0.21032326,0.2297342,-0.44111073,-0.2794485,1.0112556,0.76050276,-0.35593787,0.7943107,0.52138954,0.4139074,0.15189719,-0.7025374,-0.41530997,1.4238827,-0.33862558,-0.15891814,0.9363889,-0.034982547,1.069729,-0.16360912,-1.0505285,1.5003147,-0.2788939,-0.35283756,0.54035586,0.9264911,-0.9021703,0.41567412,-1.388174,1.0044572,1.1793857,-0.8496223,0.21248034,-0.37315238,-0.57426995,0.33242452,0.38516313,0.9785283,0.3527265,-0.27096072,-0.52194935,0.2332769,0.6000113,0.30710757,-0.3720029,0.6636214,-0.24702363,-0.556966,0.97382957,-0.38474745,-0.3409517,0.2243338,0.12014981,0.11629174,-0.014150438,-0.12849702,1.2645625,-0.81040066,-0.013830891,-0.57408106,-0.06734113,1.0928011,0.6154533,0.72685623,-0.4657641,0.7930973,-0.60845965,-0.14835925,-0.09388162,1.0006552,0.19813786,0.035662416,-0.41233733,-0.86305255,0.32100832,-0.7035713,0.7595605,0.3062477,0.40772772,-1.13976