285	{"act": "DPDP", "title": "Penalty - Failure to Implement Security Safeguards", "doc_id": "DPDP_SCHEDULE_1", "topics": ["breach_reporting", "penalty", "security"], "entities": ["Data Fiduciary"], "keywords": ["security safeguards", "penalty", "250 crore", "personal data breach", "Data Fiduciary"], "metadata": {"act": "DPDP", "year": 2023, "jurisdiction": "India"}, "references": ["DPDP_SEC_8_SUB_5"], "clause_text": "Breach in observing the obligation of Data Fiduciary to take reasonable security safeguards to prevent personal data breach under sub-section (5) of section 8. Penalty: May extend to two hundred and fifty crore rupees.", "source_files": [4], "conflict_notes": [], "retrieval_text": "Section Schedule subsection 1 of the Digital Personal Data Protection Act 2023 (DPDP Act). Penalty - Failure to Implement Security Safeguards Failure by a Data Fiduciary to implement reasonable security safeguards may attract a penalty of up to Rs. 250 crore. Topics: breach_reporting, penalty, security. Keywords: security safeguards, penalty, 250 crore, personal data breach, Data Fiduciary.", "section_number": "Schedule", "subsection_number": "1", "validation_status": "validated", "plain_english_summary": "Failure by a Data Fiduciary to implement reasonable security safeguards may attract a penalty of up to Rs. 250 crore."}	[0.85129344,1.5956537,-3.3225257,-0.7972717,1.6591216,-0.60721374,0.68727005,0.19867171,0.31567216,-0.12376728,-0.6248702,0.17671469,0.50708264,-0.7209665,0.27216,-0.15887111,0.1286791,-1.0497622,-0.70791143,-0.08979688,-0.22617507,0.07912869,-1.7261971,-0.022512758,1.2191515,0.12671584,1.8291984,-0.7850189,-0.4263019,0.17951848,0.40198237,0.1632196,-0.5641826,-0.8437139,-1.1833614,-1.1420817,0.79196495,0.60375285,-0.89212316,-1.0837002,1.5357938,-0.17626047,0.1400044,-0.7804568,-0.14125654,0.30170974,1.2976731,-0.010081827,0.7994465,-0.32429788,0.3335861,-0.28080156,0.6904692,-0.5945652,0.5196899,0.67892635,-1.3422523,-0.78731453,-0.13378543,-0.56481737,